fn decorate_tool_brief_with_archive_marker(brief: &str, archived: bool) -> String {
    if !archived {
        return brief.to_string();
    }
    let trimmed = brief.trim_end();
    if trimmed.is_empty() {
        return TOOL_EXTERNALIZED_MARKER.to_string();
    }
    if trimmed.ends_with(TOOL_EXTERNALIZED_MARKER) {
        return trimmed.to_string();
    }
    format!("{trimmed} {TOOL_EXTERNALIZED_MARKER}")
}

