const APP_NAME: &str = env!("CARGO_PKG_NAME");
const APP_VERSION: &str = env!("CARGO_PKG_VERSION");
pub(crate) const LEGACY_PROJECT_ROOT_REL_PATH: &str = "AItermux/projectying";

pub(crate) fn app_home_dir() -> PathBuf {
    current_home_override()
        .or_else(|| std::env::var("HOME").ok().map(PathBuf::from))
        .unwrap_or_else(|| PathBuf::from("."))
}

fn looks_like_app_project_root(path: &Path) -> bool {
    path.join("Cargo.toml").is_file() && path.join("src/main.rs").is_file()
}

fn find_app_project_root_from(start: &Path) -> Option<PathBuf> {
    start
        .ancestors()
        .find(|path| looks_like_app_project_root(path))
        .map(Path::to_path_buf)
}

pub(crate) fn app_project_root() -> PathBuf {
    if current_home_override().is_some() {
        return app_home_dir().join(LEGACY_PROJECT_ROOT_REL_PATH);
    }
    if let Ok(cwd) = std::env::current_dir()
        && let Some(root) = find_app_project_root_from(&cwd)
    {
        return root;
    }
    if let Ok(exe) = std::env::current_exe()
        && let Some(parent) = exe.parent()
        && let Some(root) = find_app_project_root_from(parent)
    {
        return root;
    }
    app_home_dir().join(LEGACY_PROJECT_ROOT_REL_PATH)
}

