pub(crate) fn write_text_file_atomically_shared(
    path: &Path,
    data: &str,
    label: &str,
    fallback_file_name: &str,
    missing_parent_message: &str,
    create_dir_message: &str,
) -> anyhow::Result<()> {
    ensure_parent_dir_shared(path, missing_parent_message, create_dir_message)?;
    let parent = path
        .parent()
        .with_context(|| missing_parent_message.to_string())?;
    let stamp = unix_timestamp_nanos_shared();
    let file_name = path
        .file_name()
        .and_then(|value| value.to_str())
        .unwrap_or(fallback_file_name);
    let tmp_path = parent.join(format!(".{file_name}.tmp-{stamp}-{}", std::process::id()));
    fs::write(&tmp_path, data)
        .with_context(|| format!("写入临时{label}失败：{}", tmp_path.display()))?;
    if let Err(rename_err) = fs::rename(&tmp_path, path) {
        fs::copy(&tmp_path, path).with_context(|| {
            format!(
                "替换{label}失败：{} -> {}（rename: {rename_err}）",
                tmp_path.display(),
                path.display()
            )
        })?;
        let _ = fs::remove_file(&tmp_path);
    }
    Ok(())
}

pub(crate) fn write_json_pretty_shared<T: serde::Serialize>(
    path: &Path,
    value: &T,
    label: &str,
    fallback_file_name: &str,
    missing_parent_message: &str,
    create_dir_message: &str,
) -> anyhow::Result<()> {
    let mut rendered =
        serde_json::to_string_pretty(value).with_context(|| format!("序列化{label}失败"))?;
    rendered.push('\n');
    write_text_file_atomically_shared(
        path,
        rendered.as_str(),
        label,
        fallback_file_name,
        missing_parent_message,
        create_dir_message,
    )
}

pub(crate) fn ensure_parent_dir_shared(
    path: &Path,
    missing_parent_message: &str,
    create_dir_message: &str,
) -> anyhow::Result<()> {
    let parent = path
        .parent()
        .with_context(|| missing_parent_message.to_string())?;
    fs::create_dir_all(parent)
        .with_context(|| format!("{create_dir_message}：{}", parent.display()))?;
    Ok(())
}

pub(crate) fn unix_timestamp_secs_shared() -> u64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|duration| duration.as_secs())
        .unwrap_or(0)
}

pub(crate) fn unix_timestamp_millis_shared() -> u128 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|duration| duration.as_millis())
        .unwrap_or(0)
}

pub(crate) fn unix_timestamp_millis_u64_shared() -> u64 {
    unix_timestamp_millis_shared().min(u64::MAX as u128) as u64
}

pub(crate) fn unix_timestamp_nanos_shared() -> u128 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|duration| duration.as_nanos())
        .unwrap_or(0)
}

pub(crate) fn read_json_or_default_shared<T>(path: &Path) -> anyhow::Result<T>
where
    T: serde::de::DeserializeOwned + Default,
{
    if !path.exists() {
        return Ok(T::default());
    }
    let data = fs::read_to_string(path)
        .with_context(|| format!("读取 JSON 文件失败：{}", path.display()))?;
    if data.trim().is_empty() {
        return Ok(T::default());
    }
    serde_json::from_str(&data).with_context(|| format!("解析 JSON 文件失败：{}", path.display()))
}

pub(crate) fn canonical_focus_mode_action(action: &str) -> String {
    match action.trim().to_ascii_lowercase().as_str() {
        "enter" | "task_enter" | "focus_enter" => "focus_enter".to_string(),
        "exit" | "task_exit" | "focus_exit" => "focus_exit".to_string(),
        other => other.to_string(),
    }
}

pub(crate) fn is_focus_mode_action(action: &str) -> bool {
    matches!(
        canonical_focus_mode_action(action).as_str(),
        "focus_enter" | "focus_exit"
    )
}

pub(crate) fn canonical_context_target_name(target: &str) -> Option<&'static str> {
    match target.trim().to_ascii_lowercase().as_str() {
        "context" => Some("context"),
        "toolcontext" | "tool_context" | "taskcontext" | "task_context" | "focuscontext"
        | "focus_context" => Some("focuscontext"),
        "fastmemory" | "fast_memory" => Some("fastmemory"),
        "prompt" | "system_prompt" | "systemprompt" | "codexprompt" | "codex_prompt" => {
            Some("prompt")
        }
        _ => None,
    }
}

pub(crate) fn is_focus_context_target(target: &str) -> bool {
    matches!(canonical_context_target_name(target), Some("focuscontext"))
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum CliExitStream {
    Stdout,
    Stderr,
}

#[derive(Debug, Clone, PartialEq, Eq)]
enum CliPreflight {
    RunTui,
    Exit {
        code: i32,
        stream: CliExitStream,
        text: String,
    },
}

fn projectying_cli_help_text() -> String {
    format!(
        "\
ProjectYing（交互式终端 UI）
用法：
  {APP_NAME}
  {APP_NAME} --help
  {APP_NAME} --version

说明：
  - 默认启动需要真实终端（TTY）。
  - 在普通命令通道、管道或重定向里，只支持 `--help` / `--version`。
  - 如果要由 AI 启动真实界面，请使用 `pty_run`。
"
    )
}

fn evaluate_cli_preflight(
    args: &[String],
    stdin_is_tty: bool,
    stdout_is_tty: bool,
) -> CliPreflight {
    match args {
        [] => {
            if stdin_is_tty && stdout_is_tty {
                CliPreflight::RunTui
            } else {
                CliPreflight::Exit {
                    code: 2,
                    stream: CliExitStream::Stderr,
                    text: format!(
                        "ProjectYing 只能在真实终端中直接启动。\n如需查看帮助，请改用 `{} --help`；如需由 AI 打开真实界面，请使用 `pty_run`。\n",
                        APP_NAME
                    ),
                }
            }
        }
        [flag] if flag == "--help" || flag == "-h" => CliPreflight::Exit {
            code: 0,
            stream: CliExitStream::Stdout,
            text: projectying_cli_help_text(),
        },
        [flag] if flag == "--version" || flag == "-V" => CliPreflight::Exit {
            code: 0,
            stream: CliExitStream::Stdout,
            text: format!("{APP_NAME} {APP_VERSION}\n"),
        },
        _ => CliPreflight::Exit {
            code: 2,
            stream: CliExitStream::Stderr,
            text: format!(
                "不支持的参数：{}\n\n{}",
                args.join(" "),
                projectying_cli_help_text()
            ),
        },
    }
}

