fn web_search_request_mode_label(mode: WebSearchRequestMode) -> &'static str {
    match mode {
        WebSearchRequestMode::LiveRequested => "REQUEST LIVE",
    }
}

fn web_search_action_kind(action: &WebSearchAction) -> &'static str {
    match action {
        WebSearchAction::Search { .. } => "search",
        WebSearchAction::OpenPage { .. } => "open_page",
        WebSearchAction::FindInPage { .. } => "find_in_page",
        WebSearchAction::Other => "web_search",
    }
}

fn web_search_action_detail(action: &WebSearchAction) -> String {
    match action {
        WebSearchAction::Search { query, queries } => query
            .clone()
            .filter(|value| !value.trim().is_empty())
            .unwrap_or_else(|| {
                let first = queries
                    .as_ref()
                    .and_then(|items| items.iter().find(|item| !item.trim().is_empty()))
                    .cloned()
                    .unwrap_or_default();
                if queries.as_ref().is_some_and(|items| items.len() > 1) && !first.is_empty() {
                    format!("{first} ...")
                } else {
                    first
                }
            }),
        WebSearchAction::OpenPage { url } => url.clone().unwrap_or_default(),
        WebSearchAction::FindInPage { url, pattern } => match (pattern, url) {
            (Some(pattern), Some(url)) if !pattern.trim().is_empty() && !url.trim().is_empty() => {
                format!("'{pattern}' in {url}")
            }
            (Some(pattern), _) if !pattern.trim().is_empty() => pattern.clone(),
            (_, Some(url)) if !url.trim().is_empty() => url.clone(),
            _ => String::new(),
        },
        WebSearchAction::Other => String::new(),
    }
}

fn web_search_action_items(action: &WebSearchAction) -> Vec<String> {
    match action {
        WebSearchAction::Search { query, queries } => {
            let mut items = Vec::new();
            if let Some(query) = query.as_ref().filter(|value| !value.trim().is_empty()) {
                items.push(query.clone());
            }
            if let Some(queries) = queries.as_ref() {
                for entry in queries {
                    if entry.trim().is_empty() || items.iter().any(|existing| existing == entry) {
                        continue;
                    }
                    items.push(entry.clone());
                }
            }
            items
        }
        WebSearchAction::OpenPage { url } => url
            .as_ref()
            .filter(|value| !value.trim().is_empty())
            .map(|value| vec![value.clone()])
            .unwrap_or_default(),
        WebSearchAction::FindInPage { pattern, url } => {
            let mut items = Vec::new();
            if let Some(pattern) = pattern.as_ref().filter(|value| !value.trim().is_empty()) {
                items.push(pattern.clone());
            }
            if let Some(url) = url.as_ref().filter(|value| !value.trim().is_empty()) {
                items.push(url.clone());
            }
            items
        }
        WebSearchAction::Other => Vec::new(),
    }
}

fn web_search_brief(meta: Option<&WebSearchToolMeta>) -> String {
    let Some(meta) = meta else {
        return "联网搜索".to_string();
    };
    match meta.action.as_ref() {
        Some(WebSearchAction::Search { .. }) => {
            let detail = meta
                .action
                .as_ref()
                .map(web_search_action_detail)
                .unwrap_or_default();
            if detail.trim().is_empty() {
                "搜索网页".to_string()
            } else {
                format!("搜索 {detail}")
            }
        }
        Some(WebSearchAction::OpenPage { url }) => url
            .as_ref()
            .filter(|value| !value.trim().is_empty())
            .map(|value| format!("打开页面 {value}"))
            .unwrap_or_else(|| "打开页面".to_string()),
        Some(WebSearchAction::FindInPage { pattern, url }) => {
            if let Some(pattern) = pattern.as_ref().filter(|value| !value.trim().is_empty()) {
                format!("页内查找 {pattern}")
            } else if let Some(url) = url.as_ref().filter(|value| !value.trim().is_empty()) {
                format!("页内查找 {url}")
            } else {
                "页内查找".to_string()
            }
        }
        Some(WebSearchAction::Other) | None => "联网搜索".to_string(),
    }
}

fn web_search_status_action_label(status: &str, completed: bool) -> &'static str {
    if completed {
        return "Searched";
    }
    match status.trim().to_ascii_lowercase().as_str() {
        "completed" => "Finishing",
        "searching" | "in_progress" | "open" => "Searching",
        _ => "Searching",
    }
}

fn embed_proposed_plan_block(text: &str, plan: Option<&str>) -> String {
    let trimmed_text = text.trim();
    let trimmed_plan = plan.map(str::trim).filter(|value| !value.is_empty());
    match (trimmed_text.is_empty(), trimmed_plan) {
        (true, None) => String::new(),
        (false, None) => trimmed_text.to_string(),
        (true, Some(plan)) => format!("<proposed_plan>\n{plan}\n</proposed_plan>"),
        (false, Some(plan)) => {
            format!("{trimmed_text}\n\n<proposed_plan>\n{plan}\n</proposed_plan>")
        }
    }
}

