#[derive(Debug, Clone)]
struct PersonaLedger<T> {
    matrix: T,
    advisor: T,
    coding: T,
    server: T,
}

impl<T> PersonaLedger<T> {
    fn new(matrix: T, advisor: T, coding: T, server: T) -> Self {
        Self {
            matrix,
            advisor,
            coding,
            server,
        }
    }

    fn get(&self, persona: PersonaKind) -> &T {
        match persona {
            PersonaKind::Matrix => &self.matrix,
            PersonaKind::Advisor => &self.advisor,
            PersonaKind::Coding => &self.coding,
            PersonaKind::Server => &self.server,
        }
    }

    fn get_mut(&mut self, persona: PersonaKind) -> &mut T {
        match persona {
            PersonaKind::Matrix => &mut self.matrix,
            PersonaKind::Advisor => &mut self.advisor,
            PersonaKind::Coding => &mut self.coding,
            PersonaKind::Server => &mut self.server,
        }
    }

    fn any(&self, mut predicate: impl FnMut(&T) -> bool) -> bool {
        predicate(&self.matrix)
            || predicate(&self.advisor)
            || predicate(&self.coding)
            || predicate(&self.server)
    }

    fn for_each_mut(&mut self, mut work: impl FnMut(PersonaKind, &mut T)) {
        work(PersonaKind::Matrix, &mut self.matrix);
        work(PersonaKind::Advisor, &mut self.advisor);
        work(PersonaKind::Coding, &mut self.coding);
        work(PersonaKind::Server, &mut self.server);
    }
}

impl<T: Default> Default for PersonaLedger<T> {
    fn default() -> Self {
        Self {
            matrix: T::default(),
            advisor: T::default(),
            coding: T::default(),
            server: T::default(),
        }
    }
}

