#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord)]
enum PendingSystemRequestKey {
    TerminalDone(u64),
    TerminalSnapshot(u64),
    BackgroundCommandSnapshot(u64),
    AgentSnapshot(String),
    ContextMaintenance(String),
    MemoryMaintenance(String),
}

impl PendingSystemRequestKey {
    fn dedupe_scope(&self) -> String {
        match self {
            Self::TerminalDone(session_id) => format!("terminal_done:{session_id}"),
            Self::TerminalSnapshot(session_id) => format!("terminal:{session_id}"),
            Self::BackgroundCommandSnapshot(job_id) => format!("background:{job_id}"),
            Self::AgentSnapshot(agent_id) => format!("agent:{agent_id}"),
            Self::ContextMaintenance(key) => {
                format!("context:{}", maintenance_request_dedupe_scope(key))
            }
            Self::MemoryMaintenance(key) => {
                format!("memory:{}", maintenance_request_dedupe_scope(key))
            }
        }
    }

    fn gates(&self, candidate: &PendingSystemRequestKey) -> bool {
        match (self, candidate) {
            (Self::MemoryMaintenance(_), Self::MemoryMaintenance(_))
            | (Self::ContextMaintenance(_), Self::ContextMaintenance(_))
            | (Self::TerminalDone(_), Self::TerminalDone(_))
            | (Self::TerminalSnapshot(_), Self::TerminalSnapshot(_))
            | (Self::BackgroundCommandSnapshot(_), Self::BackgroundCommandSnapshot(_))
            | (Self::AgentSnapshot(_), Self::AgentSnapshot(_)) => {
                self.dedupe_scope() == candidate.dedupe_scope()
            }
            _ => false,
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum PendingSystemRequestKind {
    Generic,
    TerminalDone,
    TerminalSnapshot,
    BackgroundDone,
    BackgroundSnapshot,
    AgentSnapshot,
    ContextMaintenance,
    MemoryMaintenance,
}

impl PendingSystemRequestKind {
    fn sys_type(self) -> &'static str {
        match self {
            Self::TerminalDone | Self::TerminalSnapshot => "TERMINAL",
            Self::BackgroundDone | Self::BackgroundSnapshot => "COMMAND",
            Self::AgentSnapshot => "AGENT",
            Self::ContextMaintenance => "CONTEXT",
            Self::MemoryMaintenance => "MEMORIE",
            Self::Generic => "SYSTEM",
        }
    }

    fn dispatch_delay(self) -> Duration {
        match self {
            Self::TerminalDone => Duration::from_secs(10),
            _ => Duration::from_millis(SYSTEM_REQUEST_DISPATCH_BUFFER_MS),
        }
    }
}

fn maintenance_request_dedupe_scope(key: &str) -> String {
    let mut parts = key.split(':').map(str::trim);
    let head = parts.next().unwrap_or_default();
    let second = parts.next().unwrap_or_default();
    match head {
        "fastmemory" if !second.is_empty() => format!("{head}:{second}"),
        _ if !head.is_empty() => head.to_string(),
        _ => key.trim().to_string(),
    }
}

const SYSTEM_REQUEST_REQUEUE_COOLDOWN_SECS: u64 = 60;
const MAINTENANCE_REQUEST_REQUEUE_COOLDOWN_SECS: u64 = 15 * 60;
const MEMORY_MAINTENANCE_REQUEUE_COOLDOWN_SECS: u64 = 10;
const SYSTEM_REQUEST_DISPATCH_BUFFER_MS: u64 = 1200;
const SYSTEM_REQUEST_POST_API_BUFFER_MS: u64 = 1200;
const AGENT_RUNTIME_SNAPSHOT_SECS: u64 = mcp::RUNNING_SNAPSHOT_INTERVAL_SECS;
const MESSAGE_EXPAND_SENTINEL: &str = "__message_expanded__";
const THOUGHT_SEGMENT_SENTINEL_PREFIX: &str = "__thought_segment__:";

fn system_request_requeue_cooldown(key: &PendingSystemRequestKey) -> Duration {
    match key {
        PendingSystemRequestKey::ContextMaintenance(_)
        | PendingSystemRequestKey::MemoryMaintenance(_) => {
            if matches!(key, PendingSystemRequestKey::MemoryMaintenance(_)) {
                Duration::from_secs(MEMORY_MAINTENANCE_REQUEUE_COOLDOWN_SECS)
            } else {
                Duration::from_secs(MAINTENANCE_REQUEST_REQUEUE_COOLDOWN_SECS)
            }
        }
        _ => Duration::from_secs(SYSTEM_REQUEST_REQUEUE_COOLDOWN_SECS),
    }
}

fn is_maintenance_system_request_key(key: &PendingSystemRequestKey) -> bool {
    matches!(
        key,
        PendingSystemRequestKey::ContextMaintenance(_)
            | PendingSystemRequestKey::MemoryMaintenance(_)
    )
}

