#[derive(Debug, Default)]
pub struct CommandPalette {
    pub items: Vec<CommandId>,
    pub selected: usize,
}

impl CommandPalette {
    pub fn rebuild(&mut self, persona: PersonaKind, matrix_shell_allowed: bool, query: &str) {
        let q = query.trim().to_ascii_uppercase();
        let mut all = vec![CommandId::Setting, CommandId::Help];
        if matches!(persona, PersonaKind::Matrix) && matrix_shell_allowed {
            all.push(CommandId::Terminal);
            all.push(CommandId::Quit);
        }
        self.items = all
            .into_iter()
            .filter(|cmd| q.is_empty() || cmd.label().starts_with(&q))
            .collect();
        if self.items.is_empty() {
            self.selected = 0;
        } else {
            self.selected = self.selected.min(self.items.len().saturating_sub(1));
        }
    }

    pub fn move_up(&mut self) {
        if self.items.is_empty() {
            return;
        }
        if self.selected == 0 {
            self.selected = self.items.len().saturating_sub(1);
        } else {
            self.selected = self.selected.saturating_sub(1);
        }
    }

    pub fn move_down(&mut self) {
        if self.items.is_empty() {
            return;
        }
        self.selected = (self.selected + 1) % self.items.len();
    }

    pub fn selected(&self) -> Option<CommandId> {
        self.items.get(self.selected).copied()
    }
}

