    pub(crate) fn with_test_context_home<T>(f: impl FnOnce() -> T) -> T {
        let _guard = crate::mcp::home_override_test_lock()
            .lock()
            .unwrap_or_else(|poisoned| poisoned.into_inner());

        let ts = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .expect("time")
            .as_nanos();
        let root = std::env::temp_dir().join(format!("projectying-app-test-{ts}"));
        fs::create_dir_all(root.join("AItermux/projectying")).expect("create project root");
        crate::set_thread_home_override_for_test(Some(root.clone()));
        context::set_persona(PersonaKind::Matrix);
        crate::mcp::set_tool_persona(PersonaKind::Matrix);
        crate::mcp::set_tool_projection_override(None);
        let result = f();
        crate::mcp::set_tool_projection_override(None);
        crate::mcp::set_tool_persona(PersonaKind::Matrix);
        context::set_persona(PersonaKind::Matrix);
        crate::set_thread_home_override_for_test(None);
        let _ = fs::remove_dir_all(&root);
        result
    }

