    #[test]
    fn coding_context_maintenance_routes_to_advisor_system_request() {
        with_test_context_home(|| {
            context::set_persona(PersonaKind::Coding);
            context::clear_messages().expect("clear");
            for index in 0..48 {
                let round_id = context::begin_round().expect("begin round");
                let payload = format!("触发维护测试消息 {index} {}", "内容".repeat(800));
                context::append_round_message(round_id, ContextRole::User, None, payload.as_str())
                    .expect("append user");
            }

            let mut app = sample_app();
            app.settings.set_context_max_size_kb_for_tests(32);
            app.active_persona = PersonaKind::Coding;
            app.bind_active_persona_runtime();
            context::set_persona(PersonaKind::Coding);

            app.sync_context_runtime_state();

            let request = app
                .pending_system_requests
                .iter()
                .find(|item| {
                    item.target.persona == PersonaKind::Advisor
                        && matches!(
                            item.key.as_ref(),
                            Some(PendingSystemRequestKey::ContextMaintenance(_))
                        )
                })
                .expect("coding context maintenance should route to Advisor");
            assert!(
                request
                    .key
                    .as_ref()
                    .is_some_and(|key| key.dedupe_scope().contains("coding"))
            );
            assert!(request.text.contains("context_manage"));
            assert!(request.text.contains("focus-mode payload"));
            assert!(request.text.contains("不要再调用 focus_mode.enter"));
            assert!(!request.text.contains("最后调用 focus_mode.exit"));
            assert!(request.text.contains("persona_scope: coding"));
            assert!(request.text.contains("target persona context snapshot"));
            assert!(request.text.contains("触发维护测试消息"));
        });
    }

