    #[test]
    fn role_targeted_system_request_dispatches_into_dynamic_role_runtime() {
        with_test_context_home(|| {
            write_valid_test_provider_for_persona(PersonaKind::Matrix);
            let context_root = app_project_root().join("context");
            fs::create_dir_all(context_root.as_path()).expect("create context");
            fs::write(
                context_root.join("roles.json"),
                r#"{"version":1,"roles":[{"id":"worker","display_name":"工","glyph":"工","context_dir":"Role_worker","base_persona":"matrix","default_tools":["context_compact","context_summary"],"enabled":true,"context_governance":{"mode":"self_compact","manage_threshold_kb":200,"compact_threshold_kb":32,"report_to_matrix":true}}]}"#,
            )
            .expect("write roles");

            let mut app = sample_app();
            app.pending_system_requests.clear();
            app.pending_system_requests.push_back(PendingSystemRequest {
                target: PendingSystemRequestTarget::dynamic_role(PersonaKind::Matrix, "worker"),
                key: Some(PendingSystemRequestKey::ContextMaintenance(
                    "worker:context:self_compact".to_string(),
                )),
                kind: PendingSystemRequestKind::ContextMaintenance,
                source_label: "上下文自管压缩".to_string(),
                text: "[sys:context_self_compact]\npersona: 工\npersona_scope: worker\nurgency: soft\nrule: test dispatch"
                    .to_string(),
                absorbed_keys: Vec::new(),
                available_at: Instant::now(),
            });

            assert!(app.maybe_send_next_system_request());
            assert!(
                app.active_request.is_none(),
                "Matrix main runtime should stay idle"
            );
            assert!(
                app.dynamic_role_session("worker")
                    .and_then(|session| session.active_request.as_ref())
                    .is_some(),
                "worker role runtime should own the active request"
            );
        });
    }

    #[test]
    fn persona_context_maintenance_payload_is_advisor_context_free() {
        with_test_context_home(|| {
            context::set_persona(PersonaKind::Matrix);
            context::clear_messages().expect("clear matrix");
            let round_id = context::begin_round().expect("round");
            context::append_round_message(
                round_id,
                ContextRole::User,
                None,
                "MATRIX_STANDARD_CONTEXT_SHOULD_NOT_ENTER_PERSONA_MAINTENANCE",
            )
            .expect("append matrix context");

            let mut app = sample_app();
            app.active_persona = PersonaKind::Matrix;
            app.bind_active_persona_runtime();
            let messages = app
                .load_provider_messages_with_extra_system_or_report(
                    "上下文维护",
                    "[sys:persona_context_maintenance]\npersona: Coding\n[target persona context snapshot start]\n- e1 r1 用户:message · CODING_CONTEXT_SNAPSHOT_OK\n[target persona context snapshot end]",
                )
                .expect("persona context maintenance messages");
            let joined = messages
                .iter()
                .map(|message| message.content.as_str())
                .collect::<Vec<_>>()
                .join("\n");
            assert!(joined.contains("mode: persona-context-maintenance"));
            assert!(joined.contains("[focus mode area start]"));
            assert!(joined.contains("Current Task: 司上下文治理"));
            assert!(joined.contains("不要调用 focus_mode.enter"));
            assert!(joined.contains("CODING_CONTEXT_SNAPSHOT_OK"));
            assert!(
                !joined.contains("MATRIX_STANDARD_CONTEXT_SHOULD_NOT_ENTER_PERSONA_MAINTENANCE")
            );

            let batch_messages = app
                .load_provider_messages_with_extra_system_or_report(
                    "System Batch · 2 · ",
                    "[sys:persona_context_maintenance]\npersona: Coding\n[target persona context snapshot start]\n- e2 r1 用户:message · BATCHED_CONTEXT_SNAPSHOT_OK\n[target persona context snapshot end]",
                )
                .expect("batched persona context maintenance messages");
            let batch_joined = batch_messages
                .iter()
                .map(|message| message.content.as_str())
                .collect::<Vec<_>>()
                .join("\n");
            assert!(batch_joined.contains("mode: persona-context-maintenance"));
            assert!(batch_joined.contains("BATCHED_CONTEXT_SNAPSHOT_OK"));
            assert!(
                !batch_joined
                    .contains("MATRIX_STANDARD_CONTEXT_SHOULD_NOT_ENTER_PERSONA_MAINTENANCE")
            );
        });
    }

