    fn sample_user_input_request(question_count: usize) -> mcp::UserInputRequest {
        let (response_tx, _response_rx) = mpsc::channel();
        mcp::UserInputRequest {
            call_id: "ask_overlay".to_string(),
            questions: (0..question_count)
                .map(|index| mcp::UserInputQuestion {
                    id: format!("item_{}", index + 1),
                    header: format!("项目{}", index + 1),
                    question: format!("第 {} 题怎么处理？", index + 1),
                    is_other: true,
                    is_secret: false,
                    options: vec![
                        mcp::UserInputOption {
                            label: "方案A".to_string(),
                            description: "推荐方案".to_string(),
                        },
                        mcp::UserInputOption {
                            label: "方案B".to_string(),
                            description: "备选方案".to_string(),
                        },
                        mcp::UserInputOption {
                            label: "方案C".to_string(),
                            description: "保守方案".to_string(),
                        },
                    ],
                })
                .collect(),
            response_tx,
        }
    }

    #[test]
    fn user_input_overlay_supports_question_shortcuts_and_custom_answers() {
        let mut overlay = UserInputOverlayState::new(sample_user_input_request(10));
        assert!(overlay.select_question_by_number_key('0'));
        assert_eq!(overlay.current_index, 9);
        assert!(overlay.activate_custom_input());
        overlay.insert_char('自');
        overlay.insert_char('定');
        overlay.insert_char('义');
        assert_eq!(
            overlay.confirm_current_answer(),
            OverlayConfirmResult::Moved
        );
        assert_eq!(overlay.current_index, 0);
        assert_eq!(overlay.answered_count(), 1);
        assert_eq!(
            overlay
                .answers
                .get("item_10")
                .map(|answer| answer.answers.clone()),
            Some(vec![format!(
                "{}自定义",
                mcp::REQUEST_USER_INPUT_OTHER_NOTE_PREFIX
            )])
        );
    }

