    #[test]
    fn maybe_send_next_system_request_prefers_current_persona_queue() {
        with_test_context_home(|| {
            context::clear_messages().expect("clear context");
            let mut app = sample_app();
            app.pending_system_requests.clear();
            app.enqueue_system_request_for_persona(
                PersonaKind::Matrix,
                "Matrix维护",
                "matrix-only",
            );
            app.enqueue_system_request_for_persona(
                PersonaKind::Coding,
                "Coding维护",
                "coding-only",
            );
            for item in app.pending_system_requests.iter_mut() {
                item.available_at = Instant::now();
            }
            app.active_persona = PersonaKind::Coding;
            app.bind_active_persona_runtime();

            assert!(!app.maybe_send_next_system_request());
            assert_eq!(app.pending_system_requests.len(), 1);
            assert_eq!(
                app.pending_system_requests[0].target.persona,
                PersonaKind::Matrix
            );

            context::set_persona(PersonaKind::Coding);
            let joined = context::load_provider_messages()
                .expect("load provider messages")
                .into_iter()
                .map(|message| message.content)
                .collect::<Vec<_>>()
                .join("\n");
            assert!(!joined.contains("coding-only"));
            assert!(!joined.contains("matrix-only"));
        });
    }

