    #[test]
    fn toggle_selected_tool_only_affects_current_tool() {
        let mut app = sample_app();
        app.select_tool(chat::ToolKey {
            message_index: 0,
            call_id: "call_1".to_string(),
        });
        app.toggle_selected_message_expanded();
        assert_eq!(
            app.expanded_tools,
            vec![chat::ToolKey {
                message_index: 0,
                call_id: "call_1".to_string(),
            }]
        );
        app.select_tool(chat::ToolKey {
            message_index: 0,
            call_id: "call_2".to_string(),
        });
        app.toggle_selected_message_expanded();
        assert_eq!(app.expanded_tools.len(), 2);
        app.toggle_selected_message_expanded();
        assert_eq!(
            app.expanded_tools,
            vec![chat::ToolKey {
                message_index: 0,
                call_id: "call_1".to_string(),
            }]
        );
        app.select_tool(chat::ToolKey {
            message_index: 0,
            call_id: "call_1".to_string(),
        });
        assert!(app.collapse_selected_expanded_tools());
        assert!(app.expanded_tools.is_empty());
    }

