    #[test]
    fn request_failure_notice_keeps_summary_and_attempt_lines() {
        assert_eq!(
            App::format_request_failure_notice(
                "连续重连失败：5/5\n重试明细：\n初始尝试：authorization-raw HTTP 503 | unavailable\n第1次重试：authorization-raw HTTP 503 | unavailable"
            ),
            "请求失败\n类型：供应商临时错误；通常是上游 429/5xx/代理波动，可重试或切换供应商。\n连续重连失败：5/5\n重试明细：\n初始尝试：authorization-raw HTTP 503 | unavailable\n第1次重试：authorization-raw HTTP 503 | unavailable"
        );
        assert_eq!(
            App::format_request_failure_notice(
                "请求失败\n连续重连失败：5/5\n重试明细：\n初始尝试：authorization-raw HTTP 503 | unavailable\n第1次重试：authorization-raw HTTP 503 | unavailable"
            ),
            "请求失败\n类型：供应商临时错误；通常是上游 429/5xx/代理波动，可重试或切换供应商。\n连续重连失败：5/5\n重试明细：\n初始尝试：authorization-raw HTTP 503 | unavailable\n第1次重试：authorization-raw HTTP 503 | unavailable"
        );
        assert_eq!(
            App::format_request_failure_notice(
                "第1次：request or response body error: error reading a body from connection: Connection timed out (os error 110)"
            ),
            "请求失败\n类型：流式响应读取超时；请求已被服务端接受，失败发生在 SSE stream 停止传输或 body 读取阶段。\n第1次：request or response body error: error reading a body from connection: Connection timed out (os error 110)"
        );
    }

    #[test]
    fn retrying_clears_partial_assistant_draft_before_next_attempt() {
        with_test_context_home(|| {
            let mut app = sample_app();
            app.chat.clear();
            let mut msg = chat::ChatMessage::assistant_streaming("Matrix", "萤");
            msg.append_thinking("partial thinking");
            msg.append_text("partial text");
            app.chat.push(msg);
            app.active_request = Some(ActiveRequestState {
                request_id: 71,
                assistant_index: 0,
                round_id: None,
                persona: PersonaKind::Matrix,
                cancelled: Arc::new(AtomicBool::new(false)),
                system_request_keys: Vec::new(),
                estimated_input_tokens: 0,
                debug_session_id: None,
            });
            app.api_active = true;

            app.apply_model_task_output(ModelTaskOutput::Retrying {
                request_id: 71,
                retry: provider::RequestRetryNotice {
                    attempt: 1,
                    max_attempts: 3,
                    reason: "SSE response body read failed after request accepted: timeout"
                        .to_string(),
                },
            });

            assert_eq!(app.chat.len(), 1);
            assert_eq!(app.chat[0].display, "");
            assert!(app.chat[0].thinking.is_none());
            assert!(app.chat[0].streaming);
        });
    }

