    #[test]
    fn active_agent_panel_defaults_to_latest_agent_and_cycles_cleanly() {
        let mut app = sample_app();
        app.agent_snapshots = vec![
            mcp::AgentUiSnapshot {
                id: "agent-1".to_string(),
                nickname: Some("Agent #1".to_string()),
                agent_type: Some("worker".to_string()),
                status: mcp::AgentStatusValue::Running,
                task_preview: "检查主目录".to_string(),
                event_lines: vec![
                    "·/ Ls · ./src".to_string(),
                    "● Read · src/main.rs".to_string(),
                ],
                log_path: "./memory/output/multiagent/agent-1.log".to_string(),
                created_at: 1,
            },
            mcp::AgentUiSnapshot {
                id: "agent-2".to_string(),
                nickname: Some("Agent #2".to_string()),
                agent_type: Some("worker".to_string()),
                status: mcp::AgentStatusValue::Completed(Some("已返回结论".to_string())),
                task_preview: "汇总结论".to_string(),
                event_lines: vec![
                    "○ Search · Cargo.toml".to_string(),
                    "❥ 我先给出结论".to_string(),
                    "✓ 已返回结论".to_string(),
                ],
                log_path: "./memory/output/multiagent/agent-2.log".to_string(),
                created_at: 2,
            },
        ];

        app.normalize_active_agent_state();
        assert_eq!(
            app.active_agent_snapshot()
                .map(|snapshot| snapshot.id.as_str()),
            Some("agent-2")
        );
        assert_eq!(app.agent_panel_scroll, 2);

        assert!(app.scroll_agent_panel(-99));
        assert_eq!(app.agent_panel_scroll, 0);

        assert!(app.cycle_agent_snapshot(false));
        assert_eq!(
            app.active_agent_snapshot()
                .map(|snapshot| snapshot.id.as_str()),
            Some("agent-1")
        );
        assert_eq!(app.agent_panel_scroll, 1);
    }

