    #[test]
    fn terminal_done_reports_extend_shared_batch_window() {
        let mut app = sample_app();
        app.apply_terminal_event(TerminalEvent::DoneReport {
            persona: PersonaKind::Matrix,
            session_id: 7,
            tool_text: "Terminal Done\nsession_id:7".to_string(),
        });
        let first_ready_at = app.pending_system_requests[0].available_at;
        std::thread::sleep(Duration::from_millis(10));
        app.apply_terminal_event(TerminalEvent::DoneReport {
            persona: PersonaKind::Matrix,
            session_id: 8,
            tool_text: "Terminal Done\nsession_id:8".to_string(),
        });
        assert_eq!(app.pending_system_requests.len(), 2);
        let ready_times = app
            .pending_system_requests
            .iter()
            .map(|item| item.available_at)
            .collect::<Vec<_>>();
        assert!(
            ready_times
                .iter()
                .all(|ready_at| *ready_at >= first_ready_at)
        );
        assert_eq!(ready_times[0], ready_times[1]);
    }

