    #[test]
    fn terminal_snapshot_notice_mentions_elapsed_and_guidance() {
        let app = sample_app();
        let items = vec![PendingSystemRequest {
            target: PendingSystemRequestTarget::persona(PersonaKind::Matrix),
            key: Some(PendingSystemRequestKey::TerminalSnapshot(4)),
            kind: PendingSystemRequestKind::TerminalSnapshot,
            source_label: "Terminal #4 · ".to_string(),
            text: "Terminal Progress\nsession_id:4 | status:running | elapsed_ms:420015"
                .to_string(),
            absorbed_keys: Vec::new(),
            available_at: Instant::now(),
        }];

        let (sys_type, detail) = app.build_system_request_notice_text(
            items.as_slice(),
            PendingSystemRequestKind::TerminalSnapshot,
        );

        assert_eq!(sys_type, "TERMINAL");
        assert!(detail.contains("PTY运行7分钟，触发自动观察"));
        assert!(detail.contains("Status：已回传日志头尾摘要；完整详情请查看外部日志。"));
        assert!(detail.contains("Hint：若连续两次自动观察仍无新动作，可自行决策后续操作。"));
    }

