    #[test]
    fn context_mode_switch_rotates_active_request_round() {
        with_test_context_home(|| {
            context::set_persona(PersonaKind::Matrix);
            context::clear_messages().expect("clear context");
            let mut app = App::new();
            let assistant_index = app.chat.len();
            app.chat
                .push(chat::ChatMessage::assistant_streaming("Matrix", "萤"));
            let original_round = context::begin_round().expect("begin round");
            app.active_request = Some(ActiveRequestState {
                request_id: 1,
                assistant_index,
                round_id: Some(original_round),
                persona: PersonaKind::Matrix,
                cancelled: Arc::new(AtomicBool::new(false)),
                system_request_keys: Vec::new(),
                estimated_input_tokens: 0,
                debug_session_id: None,
            });
            context::manage_request(ContextManageRequest::FocusEnter {
                brief: "测试任务".to_string(),
                task: "模拟模式切换".to_string(),
                user_goal: None,
                reason: None,
                plan_a: None,
                plan_b: None,
                fallback: None,
                expected_result: None,
                exit_condition: None,
            })
            .expect("switch context mode");
            app.sync_context_runtime_state();
            assert_eq!(
                context::current_mode().expect("current mode"),
                ContextMode::Focus
            );
            let rotated_round = app.rotate_active_request_round(1).expect("rotated round");
            assert_ne!(rotated_round, original_round);
            assert_eq!(
                app.active_request
                    .as_ref()
                    .and_then(|active| active.round_id),
                Some(rotated_round)
            );
        });
    }

    #[test]
    fn persona_command_send_is_consumed_by_target_persona_runtime() {
        with_test_context_home(|| {
            write_valid_test_provider_for_persona(PersonaKind::Matrix);
            write_valid_test_provider_for_persona(PersonaKind::Coding);
            let mut app = App::new();
            assert!(app.switch_persona(PersonaKind::Coding));
            assert!(app.switch_persona(PersonaKind::Matrix));
            let request = PersonaCommandRequest {
                id: "test-persona-command".to_string(),
                action: PersonaCommandAction::Send,
                persona: "coding".to_string(),
                message: Some("请检查 command 工具 schema".to_string()),
                brief: Some("工具支持".to_string()),
                reason: Some("Matrix 需要施工工具".to_string()),
                source_persona: Some("Matrix".to_string()),
                source_role: None,
                source_role_label: None,
                source_role_context_dir: None,
                target_role: None,
                target_role_label: None,
                target_role_context_dir: None,
                interrupt_active: false,
                created_at_ms: unix_timestamp_millis_u64_shared(),
            };
            App::requeue_persona_command(&request).expect("queue command");

            assert!(app.maybe_consume_persona_commands());
            assert!(app.persona_request_busy(PersonaKind::Coding));
            assert!(app.persona_tabs().contains(&PersonaKind::Coding));
            let tool_chat = &app.persona_session(PersonaKind::Coding).chat;
            assert!(
                tool_chat
                    .iter()
                    .any(|message| message.display.contains("请检查 command 工具 schema"))
            );
            let inbound = tool_chat
                .iter()
                .find(|message| message.display.contains("请检查 command 工具 schema"))
                .expect("inbound message");
            assert_eq!(inbound.role, chat::Role::User);
            assert_eq!(inbound.source_channel, chat::SourceChannel::Persona);
            assert_eq!(inbound.who_en, "Matrix");
            assert_eq!(inbound.who_zh, "萤");
            assert!(!App::persona_command_queue_path().exists());
        });
    }

