    #[test]
    fn aidebug_inbox_created_before_app_start_is_skipped() {
        with_test_context_home(|| {
            write_valid_test_provider_for_persona(PersonaKind::Coding);
            let mut app = App::new();
            let inbox = aidebug::inbox_dir(app_project_root().as_path());
            fs::create_dir_all(inbox.as_path()).expect("create inbox");
            fs::write(
                inbox.join("stale-debug-task.json"),
                serde_json::to_string(&json!({
                    "created_at_ms": app.app_started_at_ms.saturating_sub(1),
                    "persona": "coding",
                    "text": "这条 Aidebug 重启前任务不应继续执行"
                }))
                .expect("serialize stale inbox"),
            )
            .expect("write inbox");

            assert!(app.maybe_consume_aidebug_inbox());
            assert!(!app.persona_request_busy(PersonaKind::Coding));
            assert!(
                app.persona_session(PersonaKind::Coding)
                    .chat
                    .iter()
                    .all(|message| !message.display.contains("重启前任务"))
            );
            assert!(
                fs::read_dir(aidebug::failed_dir(app_project_root().as_path()))
                    .expect("failed dir")
                    .any(|entry| entry
                        .expect("failed entry")
                        .file_name()
                        .to_string_lossy()
                        .contains("stale-debug-task"))
            );
        });
    }

