    #[test]
    fn persona_command_send_to_dynamic_role_uses_target_role_session() {
        with_test_context_home(|| {
            write_valid_test_provider_for_persona(PersonaKind::Matrix);
            let context_root = app_project_root().join("context");
            fs::create_dir_all(context_root.as_path()).expect("create context");
            fs::write(
                context_root.join("roles.json"),
                r#"{"version":1,"roles":[{"id":"worker","display_name":"工","glyph":"工","context_dir":"Role_worker","base_persona":"matrix","default_tools":[],"enabled":true}]}"#,
            )
            .expect("write roles");
            let mut app = App::new();
            app.chat
                .push(chat::ChatMessage::system("INFO", "Matrix page"));
            let request = PersonaCommandRequest {
                id: "matrix-to-worker".to_string(),
                action: PersonaCommandAction::Send,
                persona: "matrix".to_string(),
                message: Some("请进入工位并处理新任务。".to_string()),
                brief: Some("角色投递".to_string()),
                reason: Some("Matrix 需要工独立接手".to_string()),
                source_persona: Some("Matrix".to_string()),
                source_role: None,
                source_role_label: None,
                source_role_context_dir: None,
                target_role: Some("worker".to_string()),
                target_role_label: Some("工".to_string()),
                target_role_context_dir: Some("Role_worker".to_string()),
                interrupt_active: false,
                created_at_ms: unix_timestamp_millis_u64_shared(),
            };
            App::requeue_persona_command(&request).expect("queue command");

            assert!(app.maybe_consume_persona_commands());
            assert!(
                app.dynamic_role_request_busy("worker", PersonaKind::Matrix),
                "worker role should own the active request"
            );
            assert!(
                app.chat
                    .iter()
                    .all(|message| !message.display.contains("请进入工位并处理新任务"))
            );

            let role_chat = &app
                .dynamic_role_session("worker")
                .expect("role session")
                .chat;
            let inbound = role_chat
                .iter()
                .find(|message| message.display.contains("请进入工位并处理新任务"))
                .expect("role inbound message");
            assert_eq!(inbound.role, chat::Role::User);
            assert_eq!(inbound.source_channel, chat::SourceChannel::Persona);
            assert_eq!(inbound.who_en, "Matrix");
            assert_eq!(inbound.who_zh, "萤");
        });
    }

