    #[test]
    fn esc_cancels_request_then_pauses_queue_then_returns_to_input() {
        let mut app = sample_app();
        app.focus = FocusArea::Chat;
        app.api_active = true;
        app.chat
            .push(chat::ChatMessage::assistant_streaming("Matrix", "萤"));
        app.active_request = Some(ActiveRequestState {
            request_id: 1,
            assistant_index: 0,
            round_id: None,
            persona: PersonaKind::Matrix,
            cancelled: Arc::new(AtomicBool::new(false)),
            system_request_keys: Vec::new(),
            estimated_input_tokens: 0,
            debug_session_id: None,
        });
        app.message_queue
            .push("队列消息".to_string(), None, Vec::new());

        handle_key(
            &mut app,
            Instant::now(),
            KeyEvent::new(KeyCode::Esc, KeyModifiers::NONE),
            Rect::new(0, 0, 80, 24),
        )
        .expect("first esc");
        assert!(!app.api_active);
        assert!(!app.message_queue.is_paused());
        assert_eq!(app.focus, FocusArea::Chat);

        handle_key(
            &mut app,
            Instant::now(),
            KeyEvent::new(KeyCode::Esc, KeyModifiers::NONE),
            Rect::new(0, 0, 80, 24),
        )
        .expect("second esc");
        assert!(app.message_queue.is_paused());
        assert_eq!(app.focus, FocusArea::Chat);

        handle_key(
            &mut app,
            Instant::now(),
            KeyEvent::new(KeyCode::Esc, KeyModifiers::NONE),
            Rect::new(0, 0, 80, 24),
        )
        .expect("third esc");
        assert_eq!(app.focus, FocusArea::Input);
    }

