    #[test]
    fn system_request_payload_is_request_local_until_model_succeeds() {
        with_test_context_home(|| {
            context::clear_messages().expect("clear context");
            let round_id = context::begin_round().expect("round");
            context::append_round_message(round_id, ContextRole::User, None, "baseline")
                .expect("append user");
            let before_latest = context::latest_active_entry_stable_id().expect("latest before");
            let mut app = sample_app();
            app.chat.clear();
            app.pending_system_requests.clear();

            let request_messages = app
                .load_provider_messages_with_extra_system_or_report(
                    "Terminal #7 · ",
                    "[sys:terminal_snapshot]\nMATRIX_RETRY_LOCAL_ONLY",
                )
                .expect("request-local provider messages");
            assert!(
                request_messages
                    .iter()
                    .any(|message| message.content.contains("MATRIX_RETRY_LOCAL_ONLY"))
            );

            let after_latest = context::latest_active_entry_stable_id().expect("latest after");
            assert_eq!(after_latest, before_latest);
            let persisted = context::load_chat_messages()
                .expect("persisted messages")
                .into_iter()
                .map(|message| message.text)
                .collect::<Vec<_>>()
                .join("\n");
            assert!(!persisted.contains("MATRIX_RETRY_LOCAL_ONLY"));
        });
    }

    #[test]
    fn memory_maintenance_payload_is_advisor_scoped_and_context_free() {
        with_test_context_home(|| {
            context::clear_messages().expect("clear context");
            let round_id = context::begin_round().expect("round");
            context::append_round_message(
                round_id,
                ContextRole::User,
                None,
                "标准上下文不应进入记忆维护",
            )
            .expect("append context");
            context::manage_request(ContextManageRequest::Write {
                target: context::ContextTarget::FastMemory,
                section: Some(context::FastMemorySection::Surface),
                role: None,
                kind: None,
                round_id: None,
                text: "fastmemory 不应进入记忆维护".to_string(),
            })
            .expect("write fastmemory");
            context::manage_request(ContextManageRequest::FocusEnter {
                brief: "focus 不应进入记忆维护".to_string(),
                task: "focuscontext 不应进入记忆维护".to_string(),
                user_goal: Some("focus user goal 不应进入记忆维护".to_string()),
                reason: None,
                plan_a: None,
                plan_b: None,
                fallback: None,
                expected_result: None,
                exit_condition: None,
            })
            .expect("enter focus");
            let mut app = sample_app();
            app.chat.clear();
            app.chat.push(chat::ChatMessage::user(
                app.settings.user_name_en(),
                app.settings.user_name_zh(),
                "用户消息用于允许维护触发",
                Vec::new(),
            ));
            app.pending_system_requests.clear();
            crate::memory::append_user_message(
                Some(1),
                "Ryo",
                "江山谣",
                &"很长的 datememory 可见消息".repeat(20_000),
                &"很长的 datememory 原始正文".repeat(20_000),
            )
            .expect("append datememorycontext entry");

            app.sync_context_runtime_state();

            assert!(
                app.pending_system_requests.iter().any(|item| {
                    item.target.persona == PersonaKind::Advisor
                        && matches!(
                            item.key.as_ref(),
                            Some(PendingSystemRequestKey::MemoryMaintenance(_))
                        )
                }),
                "datememory maintenance should be queued for Advisor"
            );
            let messages = app
                .load_provider_messages_with_extra_system_or_report(
                    "永久记忆维护",
                    "[sys:memory_maintenance]\n[datememorycontext start]\n#1\n[datememorycontext end]",
                )
                .expect("memory maintenance provider messages");
            let joined = messages
                .iter()
                .map(|message| message.content.as_str())
                .collect::<Vec<_>>()
                .join("\n");
            assert!(joined.contains("mode: datememory-only"));
            assert!(joined.contains("[datememorycontext start]"));
            assert!(!joined.contains("[context area start]"));
            assert!(!joined.contains("[focuscontext area start]"));
            assert!(!joined.contains("[fastmemory area start]"));
            assert!(!joined.contains("标准上下文不应进入记忆维护"));
            assert!(!joined.contains("fastmemory 不应进入记忆维护"));
            assert!(!joined.contains("focuscontext 不应进入记忆维护"));
        });
    }

    #[test]
