    #[test]
    fn dynamic_role_selection_marks_role_tab_without_suffix() {
        with_test_context_home(|| {
            let context_root = app_project_root().join("context");
            fs::create_dir_all(context_root.as_path()).expect("create context");
            fs::write(
                context_root.join("roles.json"),
                r#"{"version":1,"roles":[{"id":"observe_probe","display_name":"观","glyph":"观","context_dir":"Role_observe_probe","base_persona":"matrix","default_tools":["memory_read"],"enabled":true}]}"#,
            )
            .expect("write roles");
            let mut app = App::new();
            app.chat
                .push(chat::ChatMessage::system("INFO", "Matrix page"));

            assert!(app.select_dynamic_role("observe_probe"));
            assert_eq!(app.active_dynamic_role_id(), Some("observe_probe"));
            assert_eq!(app.active_persona(), PersonaKind::Matrix);
            assert_eq!(app.focus, FocusArea::PersonaTabs);
            assert!(
                app.chat
                    .iter()
                    .all(|message| !message.display.contains("Matrix page"))
            );
            app.chat
                .push(chat::ChatMessage::system("INFO", "Role page"));
            let round_id = context::begin_round().expect("role round");
            context::append_round_message(round_id, ContextRole::User, None, "role context")
                .expect("append role context");
            assert!(
                fs::read_to_string(context_root.join("Role_observe_probe/state.json"))
                    .expect("read role state")
                    .contains("role context")
            );
            assert!(
                !fs::read_to_string(context_root.join("Matrix/state.json"))
                    .unwrap_or_default()
                    .contains("role context")
            );

            assert!(app.switch_persona(PersonaKind::Matrix));
            assert!(app.active_dynamic_role_id().is_none());
            assert!(
                app.chat
                    .iter()
                    .any(|message| message.display.contains("Matrix page"))
            );
            assert!(
                app.chat
                    .iter()
                    .all(|message| !message.display.contains("Role page"))
            );

            assert!(app.select_dynamic_role("observe_probe"));
            assert!(
                app.chat
                    .iter()
                    .any(|message| message.display.contains("Role page"))
            );
        });
    }

