    #[test]
    fn hard_context_pause_drops_stale_messages_and_waits_for_resume() {
        let mut app = sample_app();
        app.pending_system_requests
            .push_back(App::build_pending_system_request(
                PendingSystemRequestTarget::persona(PersonaKind::Advisor),
                Some(PendingSystemRequestKey::ContextMaintenance(
                    "matrix:context:summary".to_string(),
                )),
                PendingSystemRequestKind::ContextMaintenance,
                "上下文维护".to_string(),
                "[sys:persona_context_maintenance]\npersona_scope: matrix\nurgency: hard"
                    .to_string(),
                Vec::new(),
            ));

        let outcome =
            app.launch_provider_request(test_launch_request(vec![provider::ApiMessage::user(
                "旧上下文 payload",
            )]));

        assert_eq!(outcome, LaunchProviderOutcome::Paused);
        let paused = app
            .paused_launches
            .get(PersonaKind::Matrix)
            .as_ref()
            .expect("paused launch");
        assert!(
            paused.request.messages.is_empty(),
            "paused request must not retain stale provider payload"
        );
        assert_eq!(
            app.active_request
                .as_ref()
                .map(|request| request.request_id),
            None
        );
    }

