// =============================================================================
// 城市公用设施：消息导出、剪贴板与标题抽取
// =============================================================================

fn message_export_dir() -> anyhow::Result<PathBuf> {
    let root = app_project_root();
    if !root.exists() {
        return Err(anyhow::anyhow!(
            "ProjectYing 根目录不存在：{}",
            root.display()
        ));
    }
    Ok(app_output_message_dir())
}

fn export_message_text(text: &str) -> anyhow::Result<PathBuf> {
    let dir = message_export_dir()?;
    fs::create_dir_all(&dir).with_context(|| format!("创建消息导出目录失败：{}", dir.display()))?;
    let stamp = unix_timestamp_millis_shared();
    let path = dir.join(format!("message_{stamp}.txt"));
    fs::write(&path, text).with_context(|| format!("写入消息导出文件失败：{}", path.display()))?;
    Ok(path)
}

fn copy_text_to_clipboard(text: &str) -> anyhow::Result<()> {
    let mut child = Command::new("termux-clipboard-set")
        .stdin(Stdio::piped())
        .spawn()
        .context("执行 termux-clipboard-set 失败")?;
    if let Some(stdin) = child.stdin.as_mut() {
        stdin
            .write_all(text.as_bytes())
            .context("写入剪贴板内容失败")?;
    }
    let status = child.wait().context("等待剪贴板命令完成失败")?;
    if !status.success() {
        anyhow::bail!("termux-clipboard-set 返回非 0");
    }
    Ok(())
}

// =============================================================================
// 城门与城标：程序入口、历史回放与标题识别
// =============================================================================

fn main() -> anyhow::Result<()> {
    let cli_args = std::env::args().skip(1).collect::<Vec<_>>();
    match evaluate_cli_preflight(
        cli_args.as_slice(),
        io::stdin().is_terminal(),
        io::stdout().is_terminal(),
    ) {
        CliPreflight::RunTui => {}
        CliPreflight::Exit { code, stream, text } => {
            match stream {
                CliExitStream::Stdout => print!("{text}"),
                CliExitStream::Stderr => eprint!("{text}"),
            }
            if code == 0 {
                return Ok(());
            }
            std::process::exit(code);
        }
    }

    let should_quit = Arc::new(AtomicBool::new(false));
    signal_hook::flag::register(SIGTERM, should_quit.clone()).ok();
    signal_hook::flag::register(SIGINT, should_quit.clone()).ok();
    signal_hook::flag::register(SIGHUP, should_quit.clone()).ok();

    enable_raw_mode().context("启用 raw mode 失败")?;
    let mut stdout = io::stdout();
    execute!(
        stdout,
        SetTitle(TERMUX_SESSION_TITLE),
        EnterAlternateScreen,
        EnableMouseCapture,
        EnableBracketedPaste
    )
    .context("初始化终端失败")?;

    let backend = CrosstermBackend::new(stdout);
    let mut terminal = Terminal::new(backend).context("创建 Terminal 失败")?;
    terminal.clear().ok();

    let result = run_loop(&mut terminal, should_quit);

    disable_raw_mode().ok();
    execute!(
        terminal.backend_mut(),
        DisableMouseCapture,
        DisableBracketedPaste,
        LeaveAlternateScreen
    )
    .ok();
    terminal.show_cursor().ok();

    result
}

