fn extract_processing_title(msg: &chat::ChatMessage) -> Option<String> {
    extract_latest_bold_title(msg.thinking.as_deref()?)
}

fn parse_terminal_session_id(text: &str) -> Option<u64> {
    for line in text.lines() {
        let trimmed = line.trim();
        if let Some(rest) = trimmed.strip_prefix("session_id:") {
            return rest.split_whitespace().next()?.parse().ok();
        }
        if let Some(rest) = trimmed.strip_prefix("Session ID:") {
            return rest.split_whitespace().next()?.parse().ok();
        }
    }
    None
}

fn parse_terminal_elapsed_ms(text: &str) -> Option<u64> {
    for line in text.lines() {
        let trimmed = line.trim();
        if let Some(rest) = trimmed.split("elapsed_ms:").nth(1) {
            return rest
                .split(|ch: char| !ch.is_ascii_digit())
                .find(|part| !part.is_empty())?
                .parse()
                .ok();
        }
    }
    None
}

fn format_elapsed_for_audit(elapsed_ms: u64) -> String {
    let total_secs = elapsed_ms / 1000;
    if total_secs >= 60 {
        format!("{}分钟", total_secs / 60)
    } else {
        format!("{}秒", total_secs.max(1))
    }
}

// =============================================================================
// 霓虹标题塔：thinking brief 提取唯一来源
// =============================================================================

// 只从 thinking buffer 中提取“最新一个已闭合的 **...** 标题”。
// - 允许尾部继续流入未闭合的 `**`，此时保留最近一次已闭合标题；
// - 如果还没有任何已闭合粗体，则返回 None。
fn extract_latest_bold_title(s: &str) -> Option<String> {
    let bytes = s.as_bytes();
    let mut i = 0usize;
    let mut latest = None;
    while i + 1 < bytes.len() {
        if bytes[i] == b'*' && bytes[i + 1] == b'*' {
            let start = i + 2;
            let mut j = start;
            while j + 1 < bytes.len() {
                if bytes[j] == b'*' && bytes[j + 1] == b'*' {
                    let trimmed = s[start..j].trim();
                    if !trimmed.is_empty() {
                        latest = Some(trimmed.to_string());
                    }
                    i = j + 2;
                    break;
                }
                j += 1;
            }
            if j + 1 >= bytes.len() {
                break;
            }
            continue;
        }
        i += 1;
    }
    latest
}

