#[cfg(test)]
mod status_title_tests {
    use super::*;

    #[test]
    fn codex_style_extracts_latest_closed_bold_title() {
        let reasoning = "\n\n**Reviewing constants and timing**\n\nMore details...\n";
        assert_eq!(
            extract_latest_bold_title(reasoning),
            Some("Reviewing constants and timing".to_string())
        );
    }

    #[test]
    fn codex_style_ignores_display_body_markdown() {
        let mut msg = chat::ChatMessage::assistant("Matrix", "萤", "**正文标题**");
        msg.thinking = Some("先想想".to_string());
        assert_eq!(extract_processing_title(&msg), None);
    }

    #[test]
    fn codex_style_updates_to_newest_bold_title() {
        let reasoning = "\n**Planning**\n细节\n**Running checks**\n";
        assert_eq!(
            extract_latest_bold_title(reasoning),
            Some("Running checks".to_string())
        );
    }

    #[test]
    fn codex_style_keeps_last_closed_title_when_tail_is_unclosed() {
        let reasoning = "**Planning**\n细节\n**Still streaming";
        assert_eq!(
            extract_latest_bold_title(reasoning),
            Some("Planning".to_string())
        );
    }

    #[test]
    fn codex_style_returns_none_when_first_title_is_unclosed() {
        let reasoning = "**Reviewing constants and timing";
        assert_eq!(extract_latest_bold_title(reasoning), None);
    }

    #[test]
    fn background_status_stays_static_without_fast_tick() {
        let mut status = StatusMachine::new();
        status.set_background_progress("Attention! 1 jobs in background");
        let before = status.line();
        let changed = status.tick(Instant::now() + Duration::from_millis(120));
        let after = status.line();
        assert!(changed);
        assert_eq!(before, "● Attention! 1 jobs in background ...");
        assert_eq!(after, "● Attention! 1 jobs in background .  ");
        assert!(status.wants_tick());
    }
}

