    #[test]
    fn chat_growth_keeps_bottom_only_when_already_at_bottom() {
        let mut app = App::new();
        app.chat = vec![sample_multiline_message(12)];
        app.mark_chat_mutated();
        app.update_chat_viewport(40, 5);
        assert_eq!(app.chat_scroll, 0);

        let previous_lines = app.rendered_chat_line_count();
        app.chat.push(sample_multiline_message(6));
        app.mark_chat_mutated();
        app.on_chat_content_changed(previous_lines, true);
        assert_eq!(app.chat_scroll, 0);

        app.chat_scroll = 1;
        let previous_lines = app.rendered_chat_line_count();
        app.chat.push(sample_multiline_message(4));
        app.mark_chat_mutated();
        app.on_chat_content_changed(previous_lines, app.should_follow_chat_tail());
        assert!(app.chat_scroll > 0);
    }

    #[test]
    fn toggling_tool_details_keeps_selected_tool_visible_row_stable() {
        let mut app = App::new();
        let mut msg = chat::ChatMessage::assistant("Matrix", "萤", "这里有两条工具记录。");
        msg.finish_tool(chat::ToolRun {
            call_id: "call_1".to_string(),
            name: "exec_command".to_string(),
            brief: "第一条工具".to_string(),
            kind_label: "Command".to_string(),
            action_label: "Ran".to_string(),
            command_preview: "printf first".to_string(),
            output_preview: "first".to_string(),
            completed: true,
            meta: None,
        });
        app.chat.push(msg);
        for index in 0..24 {
            app.chat.insert(
                0,
                chat::ChatMessage::assistant("Matrix", "萤", format!("历史消息 {index}")),
            );
        }
        app.mark_chat_mutated();
        app.update_chat_viewport(48, 8);
        let selected = chat::ToolKey {
            message_index: app.chat.len().saturating_sub(1),
            call_id: "call_1".to_string(),
        };
        app.select_tool(selected.clone());
        let key = chat::SelectionKey::Tool(selected);
        if let Some(scroll) = chat::scroll_to_reveal_selection(
            &app.chat,
            app.chat_view_width,
            app.chat_view_height,
            app.chat_scroll,
            &key,
            app.expanded_tools.as_slice(),
        ) {
            app.chat_scroll = scroll;
        }
        let (before_reveal, before_total) = chat::selection_reveal_line(
            &app.chat,
            app.chat_view_width,
            &key,
            app.expanded_tools.as_slice(),
        )
        .expect("before reveal");
        let before_window =
            chat::visible_window(before_total, app.chat_view_height, app.chat_scroll);
        let before_row = before_reveal.saturating_sub(before_window.start);

        app.toggle_selected_message_expanded();

        let (after_reveal, after_total) = chat::selection_reveal_line(
            &app.chat,
            app.chat_view_width,
            &key,
            app.expanded_tools.as_slice(),
        )
        .expect("after reveal");
        let after_window = chat::visible_window(after_total, app.chat_view_height, app.chat_scroll);
        let after_row = after_reveal.saturating_sub(after_window.start);
        assert_eq!(before_row, after_row);
    }

