    #[test]
    fn on_tick_yields_tool_start_done_and_completion_across_frames() {
        crate::app_tests::with_test_context_home(|| {
            let mut app = App::new();
            app.chat.clear();
            app.chat
                .push(chat::ChatMessage::assistant_streaming("Matrix", "萤"));
            app.active_request = Some(ActiveRequestState {
                request_id: 42,
                assistant_index: 0,
                round_id: None,
                persona: PersonaKind::Matrix,
                cancelled: Arc::new(AtomicBool::new(false)),
                system_request_keys: Vec::new(),
                estimated_input_tokens: 0,
                debug_session_id: None,
            });
            app.api_active = true;
            app.update_chat_viewport(56, 10);
            app.scroll_chat_to_bottom();

            let tx = app.model_task_tx.clone();
            tx.send(ModelTaskOutput::ToolCallStart {
                request_id: 42,
                tool: provider::ToolCallStart {
                    call_id: "call_tick_boundary".to_string(),
                    name: "exec_command".to_string(),
                    brief: "读取目录".to_string(),
                    kind_label: "Command".to_string(),
                    action_label: "Ran".to_string(),
                    command_preview: "ls".to_string(),
                    meta: None,
                },
            })
            .expect("send tool start");
            tx.send(ModelTaskOutput::ToolCallDone {
                request_id: 42,
                tool: provider::ToolCallDone {
                    call_id: "call_tick_boundary".to_string(),
                    name: "exec_command".to_string(),
                    brief: "读取目录".to_string(),
                    kind_label: "Command".to_string(),
                    action_label: "Ran".to_string(),
                    command_preview: "ls".to_string(),
                    output_preview: "Cargo.toml\nsrc".to_string(),
                    exit_code: Some(0),
                    toolmemory_entry_id: None,
                    archived_output: None,
                    meta: None,
                    replay_call_item_json: None,
                    replay_output_item_jsons: Vec::new(),
                },
            })
            .expect("send tool done");
            tx.send(ModelTaskOutput::Completed {
                request_id: 42,
                completion: provider::ChatCompletion {
                    thinking: None,
                    plan: None,
                    text: "最终正文".to_string(),
                },
            })
            .expect("send completion");

            assert!(app.on_tick(Instant::now()));
            assert!(
                app.active_request.is_some(),
                "第一帧必须停在工具开始态，不能直接吞到 completion"
            );
            assert_eq!(app.chat[0].tool_runs.len(), 1);
            assert!(!app.chat[0].tool_runs[0].completed);
            let frame_one = app
                .visible_chat_lines(app.chat_view_width, app.chat_view_height)
                .iter()
                .map(line_text)
                .collect::<Vec<_>>()
                .join("\n");
            assert!(frame_one.contains("读取目录"));
            assert!(!frame_one.contains("最终正文"));

            assert!(app.on_tick(Instant::now()));
            assert!(app.active_request.is_some());
            assert!(app.chat[0].tool_runs[0].completed);
            assert_eq!(app.chat[0].display.trim(), "");
            let frame_two = app
                .visible_chat_lines(app.chat_view_width, app.chat_view_height)
                .iter()
                .map(line_text)
                .collect::<Vec<_>>()
                .join("\n");
            assert!(frame_two.contains("Cargo.toml"));
            assert!(!frame_two.contains("最终正文"));

            assert!(app.on_tick(Instant::now()));
            assert!(app.active_request.is_none());
            assert_eq!(app.chat[0].display.trim(), "最终正文");
            let frame_three = app
                .visible_chat_lines(app.chat_view_width, app.chat_view_height)
                .iter()
                .map(line_text)
                .collect::<Vec<_>>()
                .join("\n");
            assert!(frame_three.contains("最终正文"));
            assert!(frame_three.contains("读取目录"));
        });
    }

