// =============================================================================
// 交通枢纽：事件循环与鼠标/键盘/设置页总分发
// =============================================================================

fn run_loop(
    terminal: &mut Terminal<CrosstermBackend<Stdout>>,
    should_quit: Arc<AtomicBool>,
) -> anyhow::Result<()> {
    let mut app = App::new();
    app.queue_startup_tasks();
    let tick_rate = Duration::from_millis(TICK_RATE_MS);
    let mut last_tick = Instant::now();
    let mut needs_redraw = true;
    let mut last_term_size: Option<(u16, u16)> = None;
    let mut term_w: u16 = 80;
    let mut term_h: u16 = 24;
    let mut last_layout_log: Option<(u16, u16, u16, u16, u16, u16, u16)> = None;
    let mut last_ui_draw_perf_log_at: Option<Instant> = None;
    let mut last_ui_tick_perf_log_at: Option<Instant> = None;

    loop {
        if should_quit.load(Ordering::SeqCst) {
            return Ok(());
        }

        if let Ok(size) = terminal.size() {
            let cur = (size.width, size.height);
            if last_term_size != Some(cur) {
                last_term_size = Some(cur);
                term_w = size.width;
                term_h = size.height;
                needs_redraw = true;
                let _ = departmentrs::log_event(
                    "DEBUG",
                    "ui.resize",
                    json!({
                        "width": size.width,
                        "height": size.height,
                    }),
                );
            }
        }

        let viewport = ui::layout(
            Rect::new(0, 0, term_w.max(1), term_h.max(1)),
            ui::palette_height(&app),
            ui::attention_height(&app),
            app.terminal_panel_active(),
            ui::input_top_height(&app),
            ui::status_height(&app),
            ui::requested_input_height(&app, Rect::new(0, 0, term_w.max(1), term_h.max(1))),
        );
        let chat_area = ui::chat_content_area(viewport.main);
        let layout_snapshot = (
            term_w,
            term_h,
            viewport.main.height,
            viewport.input_top.height,
            viewport.input.height,
            viewport.input_status.height,
            chat_area.height,
        );
        if last_layout_log != Some(layout_snapshot) {
            last_layout_log = Some(layout_snapshot);
            let _ = departmentrs::log_event(
                "DEBUG",
                "ui.layout",
                json!({
                    "term_w": term_w,
                    "term_h": term_h,
                    "main_h": viewport.main.height,
                    "input_top_h": viewport.input_top.height,
                    "input_h": viewport.input.height,
                    "status_h": viewport.input_status.height,
                    "chat_inner_h": chat_area.height,
                    "focus": format!("{:?}", app.focus),
                    "screen": format!("{:?}", app.screen),
                    "chat_scroll": app.chat_scroll,
                }),
            );
        }
        app.update_chat_viewport(
            chat_area.width.max(1) as usize,
            chat_area.height.max(1) as usize,
        );

        if needs_redraw {
            let draw_started_at = Instant::now();
            terminal
                .draw(|frame| ui::draw(frame, &mut app))
                .context("绘制 UI 失败")?;
            let draw_elapsed_ms = draw_started_at.elapsed().as_millis();
            if draw_elapsed_ms >= u128::from(AIDEBUG_UI_DRAW_WARN_MS) {
                let perf_now = Instant::now();
                let should_log = last_ui_draw_perf_log_at
                    .is_none_or(|last| perf_now.duration_since(last) >= Duration::from_secs(1));
                if should_log {
                    last_ui_draw_perf_log_at = Some(perf_now);
                    let _ = aidebug::write_interface_event(
                        app_project_root().as_path(),
                        "ui.draw",
                        json!({
                            "elapsed_ms": u64::try_from(draw_elapsed_ms).unwrap_or(u64::MAX),
                            "threshold_ms": AIDEBUG_UI_DRAW_WARN_MS,
                            "term_w": term_w,
                            "term_h": term_h,
                            "chat_messages": app.chat.len(),
                            "active_persona": app.active_persona.context_dir_name(),
                            "context_mode": format!("{:?}", app.context_mode),
                        }),
                    );
                }
            }
            if app.wants_visible_cursor() {
                terminal.show_cursor().ok();
            } else {
                terminal.hide_cursor().ok();
            }
            needs_redraw = false;

            //（1）Termux 下某些“软键盘弹出/收回”不稳定触发 Event::Resize。
            //（2）为保证 UI 能及时重绘并同步尺寸，这里每轮 draw 后做一次 size 探测。
            if let Ok(size) = terminal.size() {
                let cur = (size.width, size.height);
                if last_term_size != Some(cur) {
                    last_term_size = Some(cur);
                    term_w = size.width;
                    term_h = size.height;
                    needs_redraw = true;
                    let _ = departmentrs::log_event(
                        "DEBUG",
                        "ui.resize.post_draw",
                        json!({
                            "width": size.width,
                            "height": size.height,
                        }),
                    );
                }
            }
        }

        if app.input.has_deferred_paste_work() {
            if let Some(msg) = app.input.process_deferred_paste_work(Instant::now()) {
                app.apply_status_message(msg);
            }
            needs_redraw = true;
            continue;
        }

        let now = Instant::now();
        if last_tick.elapsed() >= tick_rate {
            let tick_started_at = Instant::now();
            let tick_changed = app.on_tick(now);
            let tick_elapsed_ms = tick_started_at.elapsed().as_millis();
            if tick_elapsed_ms >= u128::from(AIDEBUG_UI_TICK_WARN_MS) {
                let perf_now = Instant::now();
                let should_log = last_ui_tick_perf_log_at
                    .is_none_or(|last| perf_now.duration_since(last) >= Duration::from_secs(1));
                if should_log {
                    last_ui_tick_perf_log_at = Some(perf_now);
                    let active_request_snapshot =
                        app.active_request_status_snapshots().into_iter().next();
                    let _ = aidebug::write_interface_event(
                        app_project_root().as_path(),
                        "ui.tick",
                        json!({
                            "elapsed_ms": u64::try_from(tick_elapsed_ms).unwrap_or(u64::MAX),
                            "threshold_ms": AIDEBUG_UI_TICK_WARN_MS,
                            "changed": tick_changed,
                            "api_active": app.any_persona_api_active(),
                            "active_request": active_request_snapshot.is_some(),
                            "active_request_persona": active_request_snapshot.as_ref().map(|request| request.persona.context_dir_name()),
                            "active_request_role_id": active_request_snapshot.as_ref().and_then(|request| request.role_id.as_deref()),
                            "pending_system_requests": app.pending_system_requests.len(),
                            "queued_user_messages": app.message_queue.len(),
                            "active_persona": app.active_persona.context_dir_name(),
                        }),
                    );
                }
            }
            needs_redraw |= tick_changed;
            last_tick = now;
            continue;
        }

        let now = Instant::now();
        let mut poll_timeout = if app.wants_tick() {
            tick_rate.saturating_sub(last_tick.elapsed())
        } else {
            Duration::from_millis(IDLE_POLL_MS)
        };
        if let Some(hint) = app.input.poll_timeout_hint(now) {
            poll_timeout = poll_timeout.min(hint);
        }

        if !event::poll(poll_timeout).context("读取事件失败")? {
            continue;
        }

        let slice_started = Instant::now();
        let mut drained = 0usize;
        let mut drain_limit = app.input.drain_limit();
        let mut bulk_mode = app.input.bulk_mode();

        'drain: loop {
            if drained > 0 {
                if !bulk_mode && app.input.bulk_mode() {
                    bulk_mode = true;
                    drain_limit = app.input.drain_limit();
                }
                if bulk_mode
                    && slice_started.elapsed() >= Duration::from_millis(BULK_DRAIN_SLICE_MS.max(1))
                {
                    break 'drain;
                }
                if drained >= drain_limit {
                    break 'drain;
                }
                if !event::poll(Duration::from_millis(0)).context("读取事件失败")? {
                    break 'drain;
                }
            }

            drained = drained.saturating_add(1);
            let now = Instant::now();
            if let Ok(size) = terminal.size() {
                let cur = (size.width, size.height);
                if last_term_size != Some(cur) {
                    last_term_size = Some(cur);
                    term_w = size.width;
                    term_h = size.height;
                    needs_redraw = true;
                    let _ = departmentrs::log_event(
                        "DEBUG",
                        "ui.resize.during_drain",
                        json!({
                            "width": size.width,
                            "height": size.height,
                        }),
                    );
                }
            }
            match event::read().context("读取事件失败")? {
                Event::Key(key) => {
                    if handle_key(
                        &mut app,
                        now,
                        key,
                        Rect::new(0, 0, term_w.max(1), term_h.max(1)),
                    )? == AppAction::Quit
                    {
                        return Ok(());
                    }
                    needs_redraw = true;
                    if app.input.has_deferred_paste_work() {
                        break 'drain;
                    }
                }
                Event::Paste(pasted) => {
                    if app.screen == Screen::Settings
                        || (app.screen == Screen::Main
                            && !app.input.should_ignore_bracketed_paste(now))
                    {
                        app.on_paste_event(now, pasted);
                        needs_redraw = true;
                    }
                }
                Event::Mouse(mouse) => {
                    handle_mouse(&mut app, Rect::new(0, 0, term_w, term_h), now, mouse);
                    needs_redraw = true;
                }
                Event::Resize(w, h) => {
                    term_w = w;
                    term_h = h;
                    last_term_size = Some((w, h));
                    app.chat_render_cache.clear();
                    needs_redraw = true;
                }
                _ => {}
            }

            let tick_now = Instant::now();
            if last_tick.elapsed() >= tick_rate {
                needs_redraw |= app.on_tick(tick_now);
                last_tick = tick_now;
            }
        }
    }
}

fn handle_mouse(app: &mut App, area: Rect, now: Instant, mouse: event::MouseEvent) {
    if app.has_user_input_overlay() {
        return;
    }
    let layout = ui::layout(
        area,
        ui::palette_height(app),
        ui::attention_height(app),
        app.terminal_panel_active(),
        ui::input_top_height(app),
        ui::status_height(app),
        ui::requested_input_height(app, area),
    );
    let focus_before = app.focus;
    let drag_before = app.drag_target;
    let chat_scroll_before = app.chat_scroll;
    let pos = Position::new(mouse.column, mouse.row);
    let attention_rect = layout.attention;
    let persona_rect = layout.input_top;
    let persona_hits = ui::persona_tab_hits(persona_rect, app);
    let dynamic_role_hits = ui::dynamic_role_tab_hits(persona_rect);
    let attention_hits = ui::attention_lane_hits(attention_rect, app);
    let chat_rect = ui::chat_content_area(layout.main);
    let terminal_rect = ui::terminal_panel_area(&layout, app.terminal_panel_active());
    let chat_drag_zone = |pos: Position| {
        layout.main.contains(pos)
            || layout.input_top.contains(pos)
            || layout.input_status.contains(pos)
    };
    let top_panel_contains = |pos: Position| terminal_rect.is_some_and(|rect| rect.contains(pos));
    let main_drag_zone = |pos: Position| chat_drag_zone(pos) || layout.input_inner.contains(pos);
    let chat_width = chat_rect.width.max(1) as usize;
    let chat_height = chat_rect.height.max(1) as usize;
    let input_width = layout.input_inner.width.max(1) as usize;

    if app.screen == Screen::Main && try_forward_terminal_mouse_event(app, terminal_rect, &mouse) {
        return;
    }

    match mouse.kind {
        MouseEventKind::Down(MouseButton::Left) => {}
        MouseEventKind::ScrollUp => {
            //（1）Termux 触控滚动常用 ScrollUp/Down 表达，且可能不配对 Down/Up。
            //（2）为避免遗留的 drag_target 导致“需要滑几次才动/误选中”，滚轮时先清理拖拽状态。
            app.clear_touch_drag();
            if app.screen == Screen::Settings {
                app.settings
                    .scroll_list(-1, layout.main.height.max(1) as usize);
            } else if app.screen == Screen::Help {
                app.move_help_section(-1);
            } else if app.terminal_panel_active()
                && (top_panel_contains(pos) || app.focus == FocusArea::Terminal)
                && matches!(app.expanded_topbar_lane, Some(TopLaneKind::Agent))
            {
                app.set_focus(FocusArea::Terminal);
                let _ = app.scroll_agent_panel(-1);
            } else if app.terminal_panel_active()
                && (top_panel_contains(pos) || app.focus == FocusArea::Terminal)
                && matches!(app.expanded_topbar_lane, Some(TopLaneKind::Terminal))
                && app.active_terminal_session_id().is_some()
            {
                app.input.clear_after_non_text_key();
                app.set_focus(FocusArea::Terminal);
                app.terminal_touch_focus_armed = false;
                terminal::apply_mouse_wheel_to_terminal_view(
                    &mut app.terminal_tabs,
                    app.terminal_active_idx,
                    true,
                    2,
                );
            } else if app.terminal_panel_active() && top_panel_contains(pos) {
                app.set_focus(FocusArea::Terminal);
            } else if chat_drag_zone(pos) || app.focus == FocusArea::Chat {
                app.input.clear_after_non_text_key();
                app.set_focus(FocusArea::Chat);
                app.scroll_chat_lines(2, chat_width, chat_height);
                let _ = departmentrs::log_event(
                    "DEBUG",
                    "ui.mouse.scroll",
                    json!({
                        "kind": "ScrollUp",
                        "focus_before": format!("{focus_before:?}"),
                        "drag_before": drag_before.map(|v| format!("{v:?}")),
                        "chat_scroll_before": chat_scroll_before,
                        "chat_scroll_after": app.chat_scroll,
                        "chat_height": chat_height,
                        "chat_width": chat_width,
                    }),
                );
            }
            return;
        }
        MouseEventKind::ScrollDown => {
            app.clear_touch_drag();
            if app.screen == Screen::Settings {
                app.settings
                    .scroll_list(1, layout.main.height.max(1) as usize);
            } else if app.screen == Screen::Help {
                app.move_help_section(1);
            } else if app.terminal_panel_active()
                && (top_panel_contains(pos) || app.focus == FocusArea::Terminal)
                && matches!(app.expanded_topbar_lane, Some(TopLaneKind::Agent))
            {
                app.set_focus(FocusArea::Terminal);
                let _ = app.scroll_agent_panel(1);
            } else if app.terminal_panel_active()
                && (top_panel_contains(pos) || app.focus == FocusArea::Terminal)
                && matches!(app.expanded_topbar_lane, Some(TopLaneKind::Terminal))
                && app.active_terminal_session_id().is_some()
            {
                app.input.clear_after_non_text_key();
                app.set_focus(FocusArea::Terminal);
                app.terminal_touch_focus_armed = false;
                terminal::apply_mouse_wheel_to_terminal_view(
                    &mut app.terminal_tabs,
                    app.terminal_active_idx,
                    false,
                    2,
                );
            } else if app.terminal_panel_active() && top_panel_contains(pos) {
                app.set_focus(FocusArea::Terminal);
            } else if chat_drag_zone(pos) || app.focus == FocusArea::Chat {
                app.input.clear_after_non_text_key();
                app.set_focus(FocusArea::Chat);
                app.scroll_chat_lines(-2, chat_width, chat_height);
                let _ = departmentrs::log_event(
                    "DEBUG",
                    "ui.mouse.scroll",
                    json!({
                        "kind": "ScrollDown",
                        "focus_before": format!("{focus_before:?}"),
                        "drag_before": drag_before.map(|v| format!("{v:?}")),
                        "chat_scroll_before": chat_scroll_before,
                        "chat_scroll_after": app.chat_scroll,
                        "chat_height": chat_height,
                        "chat_width": chat_width,
                    }),
                );
            }
            return;
        }
        MouseEventKind::Drag(MouseButton::Left) => {
            if app.screen == Screen::Main {
                //（1）Termux 触控有时会丢失 Down/Up，导致 drag_target 为空或残留在旧区域。
                //（2）这里按当前坐标“自愈”推断目标，避免出现需要多滑几次才开始滚动的体验。
                if app.drag_target.is_none() {
                    let _ = departmentrs::log_event(
                        "DEBUG",
                        "ui.mouse.drag.self_heal",
                        json!({
                            "focus_before": format!("{focus_before:?}"),
                            "drag_before": drag_before.map(|v| format!("{v:?}")),
                            "row": mouse.row,
                            "col": mouse.column,
                        }),
                    );
                    if top_panel_contains(pos) {
                        app.set_focus(FocusArea::Terminal);
                        if matches!(
                            app.expanded_topbar_lane,
                            Some(TopLaneKind::Terminal) | Some(TopLaneKind::Agent)
                        ) {
                            app.begin_touch_drag(FocusArea::Terminal, mouse.row, mouse.column);
                            if matches!(app.expanded_topbar_lane, Some(TopLaneKind::Terminal))
                                && app.active_terminal_session_id().is_some()
                            {
                                app.terminal_touch_focus_armed = false;
                            }
                        }
                    } else if main_drag_zone(pos) {
                        //（1）Termux 偶发丢失 Down，只剩首个 Drag；
                        //（2）消息查看优先：这种情况下统一按 Chat 处理，
                        //    避免手指下滑到输入区附近时被误判成 Input，造成“滑动停顿/跑偏”。
                        app.set_focus(FocusArea::Chat);
                        app.clamp_chat_scroll(chat_width, chat_height);
                        app.begin_touch_drag(FocusArea::Chat, mouse.row, mouse.column);
                    }
                }
            }

            match app.screen {
                Screen::Main => match app.drag_target {
                    Some(FocusArea::Input) => {
                        app.set_focus(FocusArea::Input);
                        //（1）出现 Drag 就视为“用户在拖拽”，不应在 Up 阶段误当成 tap 去选消息。
                        app.touch_drag_moved = true;
                        let prev_row = app.touch_drag_last_row.unwrap_or(mouse.row);
                        let prev_col = app.touch_drag_last_col.unwrap_or(mouse.column);
                        app.touch_drag_last_row = Some(mouse.row);
                        app.touch_drag_last_col = Some(mouse.column);

                        let dx = mouse.column as i32 - prev_col as i32;
                        let dy = mouse.row as i32 - prev_row as i32;
                        let step_x = dx.unsigned_abs().min(8) as usize;
                        let step_y = dy.unsigned_abs().min(6) as usize;
                        if dx != 0 || dy != 0 {
                            app.touch_drag_moved = true;
                        }

                        if step_x > 0 || step_y > 0 {
                            app.flush_before_user_edit(now);
                        }
                        for _ in 0..step_x {
                            if dx > 0 {
                                app.input.move_right();
                            } else if dx < 0 {
                                app.input.move_left();
                            }
                        }
                        for _ in 0..step_y {
                            if dy > 0 {
                                app.input.move_down(input_width);
                            } else if dy < 0 {
                                app.input.move_up(input_width);
                            }
                        }
                    }
                    Some(FocusArea::Chat) => {
                        app.set_focus(FocusArea::Chat);
                        app.touch_drag_moved = true;
                        let anchor_row = app.touch_drag_anchor_row.unwrap_or(mouse.row);
                        let base_scroll =
                            app.touch_drag_anchor_chat_scroll.unwrap_or(app.chat_scroll);
                        //（1）对齐 system 的触控语义：anchor_row - cur_row
                        //（2）上滑（row 变小）=> dy_total > 0 => 往“底部”走（chat_scroll 变小）
                        let dy_total = anchor_row as i32 - mouse.row as i32;
                        app.touch_drag_last_row = Some(mouse.row);
                        app.touch_drag_last_col = Some(mouse.column);
                        if dy_total != 0 {
                            //（1）Termux 拖拽坐标是格子级，dy_total 容易跳变；
                            //（2）拖拽目标在一次手势内必须保持稳定；中途切到 input 会重置锚点，
                            //    表现成“下滑停顿/拖不动”。
                            //（3）聊天区跟随 system：约 2 行手势 -> 1 行内容，不再额外限制到 4 行。
                            let abs = dy_total.unsigned_abs().min(128) as usize;
                            let delta = abs.div_ceil(2).max(1);
                            let max_scroll = app.chat_max_scroll(chat_width, chat_height);
                            app.chat_scroll = if dy_total > 0 {
                                base_scroll.saturating_sub(delta)
                            } else {
                                base_scroll.saturating_add(delta).min(max_scroll)
                            };
                            let _ = departmentrs::log_event(
                                "DEBUG",
                                "ui.mouse.drag.chat",
                                json!({
                                    "dy_total": dy_total,
                                    "delta": delta,
                                    "chat_scroll_before": chat_scroll_before,
                                    "chat_scroll_after": app.chat_scroll,
                                    "anchor_row": anchor_row,
                                    "base_scroll": base_scroll,
                                }),
                            );
                        }
                    }
                    Some(FocusArea::Terminal) => {
                        app.set_focus(FocusArea::Terminal);
                        app.touch_drag_moved = true;
                        let prev_row = app.touch_drag_last_row.unwrap_or(mouse.row);
                        app.touch_drag_last_row = Some(mouse.row);
                        app.touch_drag_last_col = Some(mouse.column);
                        let dy = mouse.row as i32 - prev_row as i32;
                        if dy != 0 {
                            if matches!(app.expanded_topbar_lane, Some(TopLaneKind::Terminal))
                                && app.active_terminal_session_id().is_some()
                            {
                                app.touch_drag_moved = true;
                                let delta = (dy.unsigned_abs() as u16).div_ceil(3).max(1);
                                terminal::apply_touch_drag_to_terminal_view(
                                    &mut app.terminal_tabs,
                                    app.terminal_active_idx,
                                    dy,
                                    delta,
                                );
                            } else if matches!(app.expanded_topbar_lane, Some(TopLaneKind::Agent)) {
                                let delta = (dy.unsigned_abs() as usize).div_ceil(2).max(1);
                                let _ = app.scroll_agent_panel(if dy > 0 {
                                    -(delta as i32)
                                } else {
                                    delta as i32
                                });
                            }
                        }
                    }
                    Some(FocusArea::PersonaTabs) => {}
                    None => {}
                },
                Screen::Settings | Screen::Help => {}
            }
            return;
        }
        MouseEventKind::Up(MouseButton::Left) => {
            if app.screen == Screen::Main
                && app.drag_target == Some(FocusArea::Chat)
                && !app.touch_drag_moved
                && chat_rect.contains(pos)
                && app.focus == FocusArea::Chat
                && app.chat_select_on_release
            {
                let row = mouse.row.saturating_sub(chat_rect.y) as usize;
                let col = mouse.column.saturating_sub(chat_rect.x) as usize;
                if let Some(toggle_hit) = chat::toggle_hit_at_visible_position(
                    &app.chat,
                    chat_width,
                    chat_height,
                    app.chat_scroll,
                    row,
                    col,
                    app.expanded_tools.as_slice(),
                ) {
                    app.select_item(toggle_hit);
                    app.toggle_selected_message_expanded();
                    app.clear_touch_drag();
                    return;
                }
                if let Some(item) = app.selection_at_chat_row(chat_width, chat_height, row) {
                    let same = app
                        .selected_item
                        .as_ref()
                        .is_some_and(|selected| selected == &item);
                    if same {
                        if app.clear_selected_item_only() {
                            app.apply_status_message("已取消消息选中".to_string());
                        }
                    } else {
                        app.select_item(item);
                    }
                }
            }
            if app.screen == Screen::Main
                && app.drag_target == Some(FocusArea::Terminal)
                && top_panel_contains(pos)
            {
                app.set_focus(FocusArea::Terminal);
                app.terminal_touch_focus_armed = false;
            }
            app.clear_touch_drag();
            return;
        }
        _ => return,
    }

    match app.screen {
        Screen::Main => {
            //（1）每次新的触摸起点都先清理旧 drag 状态；
            //（2）Termux 偶发丢 Up，若不重置，下一次手势可能沿用上一次的旧目标。
            app.clear_touch_drag();

            if persona_rect.contains(pos) {
                if let Some(hit) = persona_hits.iter().find(|hit| hit.rect.contains(pos)) {
                    app.set_focus(FocusArea::PersonaTabs);
                    let _ = app.switch_persona(hit.persona);
                    return;
                }
                if let Some(hit) = dynamic_role_hits.iter().find(|hit| hit.rect.contains(pos)) {
                    let _ = app.select_dynamic_role(hit.role_id.as_str());
                    return;
                }
                return;
            }

            if attention_rect.contains(pos) {
                app.set_focus(FocusArea::Terminal);
                if let Some(hit) = attention_hits.iter().find(|hit| hit.rect.contains(pos)) {
                    let _ = app.set_selected_topbar_lane(hit.lane);
                }
                return;
            }

            if top_panel_contains(pos) {
                app.set_focus(FocusArea::Terminal);
                if matches!(
                    app.expanded_topbar_lane,
                    Some(TopLaneKind::Terminal) | Some(TopLaneKind::Agent)
                ) {
                    app.begin_touch_drag(FocusArea::Terminal, mouse.row, mouse.column);
                    if matches!(app.expanded_topbar_lane, Some(TopLaneKind::Terminal))
                        && app.active_terminal_session_id().is_some()
                    {
                        app.terminal_touch_focus_armed = false;
                    }
                }
                return;
            }

            if layout.palette.contains(pos) {
                if app.message_queue.is_visible() {
                    app.set_focus(FocusArea::Input);
                    if !app.message_queue.is_editing() {
                        let row = mouse.row.saturating_sub(layout.palette.y) as usize;
                        if row > 0 {
                            let index = row.saturating_sub(1);
                            let same_selected = app
                                .message_queue
                                .selected()
                                .zip(app.message_queue.items().get(index))
                                .is_some_and(|(selected, hit)| selected.id == hit.id);
                            if let Some(item_id) =
                                app.message_queue.items().get(index).map(|item| item.id)
                            {
                                app.message_queue.select_index(index);
                                if same_selected {
                                    app.begin_queue_edit();
                                } else {
                                    app.apply_status_message(format!("已选中队列 #{}", item_id));
                                }
                            }
                        }
                    }
                    return;
                }

                if app.input.is_command_mode() && !app.palette.items.is_empty() {
                    app.set_focus(FocusArea::Input);
                    let row = mouse.row.saturating_sub(layout.palette.y) as usize;
                    if let Some(cmd) = app.palette.items.get(row).copied() {
                        app.palette.selected = row.min(app.palette.items.len().saturating_sub(1));
                        app.apply_status_message(format!("已选中命令 {}", cmd.label()));
                    }
                    return;
                }
            }

            if layout.input_inner.contains(pos) {
                app.set_focus(FocusArea::Input);
                app.flush_before_user_edit(now);
                let x = mouse.column.saturating_sub(layout.input_inner.x) as usize;
                let y = mouse.row.saturating_sub(layout.input_inner.y) as usize;
                app.input.set_cursor_from_click(
                    input_width,
                    layout.input_inner.height.max(1) as usize,
                    x,
                    y,
                );
                //（1）主界面输入框保留“点击定位光标”；
                //（2）但不再把它作为触控 Drag 目标，避免与“滑动查看消息”争抢手势。
                return;
            }

            if chat_drag_zone(pos) {
                let select_on_release = app.focus == FocusArea::Chat;
                app.set_focus(FocusArea::Chat);
                app.clamp_chat_scroll(chat_width, chat_height);
                app.chat_select_on_release = select_on_release;
                app.begin_touch_drag(FocusArea::Chat, mouse.row, mouse.column);
                return;
            }
            app.clear_touch_drag();
        }
        Screen::Settings => {
            if layout.input_inner.contains(pos) && app.settings.is_editing() {
                app.set_focus(FocusArea::Input);
                let x = mouse.column.saturating_sub(layout.input_inner.x) as usize;
                let y = mouse.row.saturating_sub(layout.input_inner.y) as usize;
                let height = layout.input_inner.height.max(1) as usize;
                let (buffer, cursor) = app.settings.default_input_text();
                let (_, cursor_y) = crate::input::cursor_xy(
                    layout.input_inner.width.max(1) as usize,
                    buffer,
                    cursor,
                );
                let scroll_y = cursor_y.saturating_sub(height.saturating_sub(1));
                let target_y = scroll_y.saturating_add(y);
                app.settings.edit_set_cursor_from_click(
                    layout.input_inner.width.max(1) as usize,
                    x,
                    target_y,
                );
                return;
            }

            if layout.main.contains(pos)
                && let Some(target) = app.settings.find_hit(layout.main, mouse.column, mouse.row)
            {
                app.settings
                    .handle_click(target, layout.main.height.max(1) as usize);
                if app.settings.is_editing() {
                    app.set_focus(FocusArea::Input);
                } else {
                    app.set_focus(FocusArea::Chat);
                }
            }
            app.clear_touch_drag();
        }
        Screen::Help => {
            if layout.main.contains(pos) {
                let row = mouse.row.saturating_sub(layout.main.y) as usize;
                if (2..=5).contains(&row) {
                    app.help_section = HelpSection::from_index(row.saturating_sub(2));
                    app.apply_status_message(app.help_status_line());
                }
            }
            app.clear_touch_drag();
        }
    }
}

fn try_forward_terminal_mouse_event(
    app: &mut App,
    terminal_rect: Option<Rect>,
    mouse: &event::MouseEvent,
) -> bool {
    let Some(rect) = terminal_rect else {
        return false;
    };
    if rect.width == 0
        || rect.height == 0
        || !matches!(app.expanded_topbar_lane, Some(TopLaneKind::Terminal))
        || app.active_terminal_session_id().is_none()
    {
        return false;
    }

    let pos = Position::new(mouse.column, mouse.row);
    let inside = rect.contains(pos);
    let dragging_terminal = app.drag_target == Some(FocusArea::Terminal);
    if !inside && !dragging_terminal {
        return false;
    }

    let local_col = mouse
        .column
        .saturating_sub(rect.x)
        .min(rect.width.saturating_sub(1));
    let local_row = mouse
        .row
        .saturating_sub(rect.y)
        .min(rect.height.saturating_sub(1));

    let Some((session_id, bytes)) = terminal::build_mouse_input_for_active_terminal(
        &mut app.terminal_tabs,
        app.terminal_active_idx,
        local_col,
        local_row,
        *mouse,
    ) else {
        return false;
    };

    app.set_focus(FocusArea::Terminal);
    app.terminal_touch_focus_armed = false;

    match mouse.kind {
        MouseEventKind::Down(_) => {
            app.begin_touch_drag(FocusArea::Terminal, mouse.row, mouse.column);
            app.touch_drag_moved = false;
        }
        MouseEventKind::Drag(_) => {
            if app.drag_target != Some(FocusArea::Terminal) {
                app.begin_touch_drag(FocusArea::Terminal, mouse.row, mouse.column);
            }
            app.touch_drag_moved = true;
            app.touch_drag_last_row = Some(mouse.row);
            app.touch_drag_last_col = Some(mouse.column);
        }
        MouseEventKind::Up(_) => {
            app.clear_touch_drag();
        }
        MouseEventKind::ScrollUp
        | MouseEventKind::ScrollDown
        | MouseEventKind::ScrollLeft
        | MouseEventKind::ScrollRight => {
            app.clear_touch_drag();
        }
        MouseEventKind::Moved => {}
    }

    let _ = terminal::send_input_bytes(session_id, bytes);
    true
}

fn handle_key(
    app: &mut App,
    now: Instant,
    key: KeyEvent,
    term_area: Rect,
) -> anyhow::Result<AppAction> {
    let layout = ui::layout(
        term_area,
        ui::palette_height(app),
        ui::attention_height(app),
        app.terminal_panel_active(),
        ui::input_top_height(app),
        ui::status_height(app),
        ui::requested_input_height(app, term_area),
    );
    let chat_rect = ui::chat_content_area(layout.main);
    let input_width = layout.input.width.max(1) as usize;
    let chat_width = chat_rect.width.max(1) as usize;
    let chat_height = chat_rect.height.max(1) as usize;
    let settings_height = layout.main.height.max(1) as usize;

    if key.kind == KeyEventKind::Release {
        return Ok(AppAction::Continue);
    }

    if app.has_user_input_overlay() {
        return handle_user_input_overlay_key(app, key);
    }

    if app.screen == Screen::Help {
        return handle_help_key(app, key);
    }

    if app.screen == Screen::Settings {
        return handle_settings_key(app, now, key, settings_height);
    }

    if key.modifiers.is_empty() && matches!(key.code, KeyCode::Esc) {
        app.input.clear_after_non_text_key();
        app.clear_touch_drag();
        if app.screen == Screen::Main && app.cancel_active_request() {
            return Ok(AppAction::Continue);
        }
        if app.screen == Screen::Main {
            if app.message_queue.is_visible() {
                app.close_queue_palette();
                return Ok(AppAction::Continue);
            }
            if app.pause_message_queue_for_escape() {
                return Ok(AppAction::Continue);
            }
        }
    }

    if handle_persona_tabs_key(app, key) {
        return Ok(AppAction::Continue);
    }

    if app.has_topbar_items()
        && app.focus == FocusArea::Terminal
        && handle_terminal_key(app, now, key)?
    {
        return Ok(AppAction::Continue);
    }

    if app.focus != FocusArea::Terminal
        && let Some(msg) = app.input.try_swallow_ime_injection(now, key)
    {
        app.apply_status_message(msg);
        return Ok(AppAction::Continue);
    }

    match (key.modifiers, key.code) {
        (KeyModifiers::CONTROL, KeyCode::Char('c')) => return Ok(AppAction::Quit),
        (KeyModifiers::CONTROL, KeyCode::Up) => {
            if app.api_active {
                app.enqueue_current_input(now);
            } else {
                app.send_force(now);
            }
            return Ok(AppAction::Continue);
        }
        (KeyModifiers::SHIFT, KeyCode::Up) if app.focus == FocusArea::Input => {
            app.open_queue_palette();
            return Ok(AppAction::Continue);
        }
        (KeyModifiers::ALT, KeyCode::Up) => {
            if app.focus == FocusArea::Input {
                app.restore_previous_user_message_for_edit();
            } else if app.focus == FocusArea::Chat {
                app.copy_selected_chat_item().context("复制消息详情失败")?;
            }
            return Ok(AppAction::Continue);
        }
        (KeyModifiers::ALT, KeyCode::Down) => {
            if app.focus == FocusArea::Chat {
                app.paste_selected_chat_item_to_input(now);
            } else if app.focus == FocusArea::Input {
                app.on_shift_newline(now);
            }
            return Ok(AppAction::Continue);
        }
        (KeyModifiers::SHIFT, KeyCode::Down) | (KeyModifiers::CONTROL, KeyCode::Down)
            if app.focus == FocusArea::Input =>
        {
            app.on_shift_newline(now);
            return Ok(AppAction::Continue);
        }
        _ => {}
    }

    if app.message_queue.is_visible() && !app.message_queue.is_editing() {
        match key.code {
            KeyCode::Up => {
                app.message_queue.move_up();
                return Ok(AppAction::Continue);
            }
            KeyCode::Down => {
                app.message_queue.move_down();
                return Ok(AppAction::Continue);
            }
            KeyCode::Backspace => {
                app.delete_selected_queue_item();
                return Ok(AppAction::Continue);
            }
            _ => {}
        }
    }

    if key.modifiers.contains(KeyModifiers::CONTROL) || key.modifiers.contains(KeyModifiers::ALT) {
        app.input.clear_after_non_text_key();
        return Ok(AppAction::Continue);
    }

    match key.code {
        KeyCode::Esc => {
            app.input.clear_after_non_text_key();
            app.clear_touch_drag();
            match app.screen {
                Screen::Settings => app.exit_settings(),
                Screen::Help => app.exit_help(),
                Screen::Main => {
                    if app.focus == FocusArea::Chat && app.clear_selected_item_only() {
                        app.apply_status_message("已退出消息查看".to_string());
                    } else if app.focus == FocusArea::Input && app.input.is_command_mode() {
                        app.flush_before_user_edit(now);
                        app.input.clear();
                        app.apply_status_message("已退出命令输入".to_string());
                    } else if app.focus != FocusArea::Input {
                        app.set_focus(FocusArea::Input);
                        app.apply_status_message("焦点: 输入".to_string());
                    }
                }
            }
        }
        KeyCode::Enter => return Ok(app.on_enter(now)),
        KeyCode::Up => {
            if app.focus == FocusArea::Input && app.input.is_command_mode() {
                app.palette.move_up();
            } else if app.focus == FocusArea::Chat {
                app.input.clear_after_non_text_key();
                app.scroll_chat_lines(1, chat_width, chat_height);
            } else {
                app.set_focus(FocusArea::Input);
                app.flush_before_user_edit(now);
                app.input.move_up(input_width.max(1));
            }
        }
        KeyCode::Down => {
            if app.focus == FocusArea::Input && app.input.is_command_mode() {
                app.palette.move_down();
            } else if app.focus == FocusArea::Chat {
                app.input.clear_after_non_text_key();
                app.scroll_chat_lines(-1, chat_width, chat_height);
            } else {
                app.set_focus(FocusArea::Input);
                app.flush_before_user_edit(now);
                app.input.move_down(input_width.max(1));
            }
        }
        KeyCode::PageUp => {
            app.input.clear_after_non_text_key();
            app.cycle_focus(false);
        }
        KeyCode::PageDown => {
            app.input.clear_after_non_text_key();
            app.cycle_focus(true);
        }
        KeyCode::Left => {
            if app.focus == FocusArea::Chat {
                app.input.clear_after_non_text_key();
                app.select_chat_prev_message(chat_width, chat_height);
            } else {
                app.set_focus(FocusArea::Input);
                app.flush_before_user_edit(now);
                app.input.move_left();
            }
        }
        KeyCode::Right => {
            if app.focus == FocusArea::Chat {
                app.input.clear_after_non_text_key();
                app.select_chat_next_message(chat_width, chat_height);
            } else {
                app.set_focus(FocusArea::Input);
                app.flush_before_user_edit(now);
                app.input.move_right();
            }
        }
        KeyCode::End => {
            if app.focus == FocusArea::Chat {
                app.input.clear_after_non_text_key();
                app.jump_chat_to_bottom(chat_width, chat_height);
            } else {
                app.input.clear_after_non_text_key();
                app.set_focus(FocusArea::Input);
                app.flush_before_user_edit(now);
                app.input.move_end();
            }
        }
        KeyCode::Tab if app.focus == FocusArea::Chat => {
            app.input.clear_after_non_text_key();
            if app.selected_item.is_some() {
                app.toggle_selected_message_expanded();
            } else {
                app.apply_status_message("请先选择消息".to_string());
            }
        }
        KeyCode::Tab => {
            app.set_focus(FocusArea::Input);
            app.on_shift_newline(now);
        }
        KeyCode::Home => {
            app.input.clear_after_non_text_key();
            if app.focus == FocusArea::Chat {
                if let Some(status) = app.handle_home_from_chat() {
                    app.apply_status_message(status);
                } else {
                    app.set_focus(FocusArea::Input);
                    app.apply_status_message("焦点: 输入".to_string());
                }
            } else if app.focus != FocusArea::Input {
                app.set_focus(FocusArea::Input);
                app.apply_status_message("焦点: 输入".to_string());
            }
        }
        KeyCode::Insert => {
            if app.focus == FocusArea::Chat {
                app.input.clear_after_non_text_key();
                app.restore_chat_from_bottom(chat_width, chat_height);
            } else {
                app.input.clear_after_non_text_key();
                app.set_focus(FocusArea::Input);
                app.flush_before_user_edit(now);
                app.input.move_home();
            }
        }
        KeyCode::Backspace => {
            app.set_focus(FocusArea::Input);
            app.backspace(now);
        }
        KeyCode::Char(ch) => {
            app.on_plain_char(now, ch);
        }
        _ => {
            app.input.clear_after_non_text_key();
        }
    }

    Ok(AppAction::Continue)
}

fn handle_user_input_overlay_key(app: &mut App, key: KeyEvent) -> anyhow::Result<AppAction> {
    if matches!(
        (key.modifiers, key.code),
        (KeyModifiers::CONTROL, KeyCode::Char('c'))
    ) {
        return Ok(AppAction::Quit);
    }
    if matches!(key.code, KeyCode::Esc) {
        app.cancel_active_user_input();
        return Ok(AppAction::Continue);
    }

    let mut submit = false;
    let mut status_message = None;
    {
        let Some(overlay) = app.active_user_input_request.as_mut() else {
            return Ok(AppAction::Continue);
        };

        match (key.modifiers, key.code) {
            (_, KeyCode::Up) if !overlay.editing_note => {
                overlay.move_selection_up();
            }
            (_, KeyCode::Down) if !overlay.editing_note => {
                overlay.move_selection_down();
            }
            (_, KeyCode::BackTab) => {
                if overlay.editing_note {
                    overlay.editing_note = false;
                    status_message = Some("结束自定义输入".to_string());
                }
            }
            (_, KeyCode::Tab) => {
                if !overlay.note_enabled() {
                } else if overlay.editing_note {
                    overlay.editing_note = false;
                    status_message = Some("结束自定义输入".to_string());
                } else if overlay.activate_custom_input() {
                    status_message = Some("进入自定义输入".to_string());
                }
            }
            (_, KeyCode::Enter) => match overlay.confirm_current_answer() {
                OverlayConfirmResult::Stay => {
                    if overlay.selected_is_other() {
                        status_message = Some("请输入自定义内容后再回车确认".to_string());
                    }
                }
                OverlayConfirmResult::Moved => {
                    if let Some(question) = overlay.current_question() {
                        status_message = Some(format!("继续对账 · {}", question.header.trim()));
                    }
                }
                OverlayConfirmResult::Submit => {
                    submit = true;
                }
            },
            (_, KeyCode::Left) if overlay.editing_note => {
                overlay.move_note_left();
            }
            (_, KeyCode::Right) if overlay.editing_note => {
                overlay.move_note_right();
            }
            (_, KeyCode::Home) if overlay.editing_note => {
                overlay.move_note_home();
            }
            (_, KeyCode::End) if overlay.editing_note => {
                overlay.move_note_end();
            }
            (_, KeyCode::Backspace) if overlay.editing_note => {
                overlay.backspace_note();
            }
            (_, KeyCode::Delete) if overlay.editing_note => {
                overlay.delete_note();
            }
            (_, KeyCode::Char(ch)) if overlay.editing_note => {
                overlay.insert_char(ch);
            }
            (_, KeyCode::Char(ch)) if !overlay.editing_note => {
                let lower = ch.to_ascii_lowercase();
                if overlay.select_question_by_number_key(lower) {
                    if let Some(question) = overlay.current_question() {
                        status_message = Some(format!("切换对账项 · {}", question.header.trim()));
                    }
                } else {
                    let quick_option = match lower {
                        'a' => Some(0usize),
                        'b' => Some(1usize),
                        'c' => Some(2usize),
                        _ => None,
                    };
                    if let Some(option_index) = quick_option {
                        if overlay.select_option(option_index) {
                            match overlay.confirm_current_answer() {
                                OverlayConfirmResult::Stay => {}
                                OverlayConfirmResult::Moved => {
                                    if let Some(question) = overlay.current_question() {
                                        status_message =
                                            Some(format!("继续对账 · {}", question.header.trim()));
                                    }
                                }
                                OverlayConfirmResult::Submit => {
                                    submit = true;
                                }
                            }
                        }
                    } else if lower == 'd' && overlay.activate_custom_input() {
                        status_message = Some("进入自定义输入".to_string());
                    }
                }
            }
            _ => {}
        }
    }

    if let Some(message) = status_message {
        app.apply_status_message(message);
    }
    if submit {
        app.submit_active_user_input();
    }
    Ok(AppAction::Continue)
}

fn handle_persona_tabs_key(app: &mut App, key: KeyEvent) -> bool {
    if app.focus != FocusArea::PersonaTabs {
        return false;
    }
    let ctrl = key.modifiers.contains(KeyModifiers::CONTROL);
    let alt = key.modifiers.contains(KeyModifiers::ALT);
    if ctrl || alt {
        return false;
    }
    let personas = app.persona_tabs();
    if personas.is_empty() {
        return false;
    }
    let current_index = personas
        .iter()
        .position(|persona| *persona == app.active_persona())
        .unwrap_or(0);
    let switch_to = |app: &mut App, index: usize| {
        let target = personas[index % personas.len()];
        app.switch_persona(target)
    };
    match key.code {
        KeyCode::Left => switch_to(app, (current_index + personas.len() - 1) % personas.len()),
        KeyCode::Right | KeyCode::Tab => switch_to(app, (current_index + 1) % personas.len()),
        KeyCode::Esc | KeyCode::Home => {
            app.set_focus(FocusArea::Input);
            app.apply_status_message("焦点: 输入".to_string());
            true
        }
        KeyCode::PageUp => {
            app.cycle_focus(false);
            true
        }
        KeyCode::PageDown => {
            app.cycle_focus(true);
            true
        }
        _ => false,
    }
}

fn handle_terminal_key(app: &mut App, now: Instant, key: KeyEvent) -> anyhow::Result<bool> {
    if app.focus != FocusArea::Terminal || !app.has_topbar_items() {
        return Ok(false);
    }

    let ctrl = key.modifiers.contains(KeyModifiers::CONTROL);
    let alt = key.modifiers.contains(KeyModifiers::ALT);
    let shift_only = key.modifiers == KeyModifiers::SHIFT;
    let selected_lane = app.selected_topbar_lane;
    let expanded_lane = app.expanded_topbar_lane;

    if !ctrl && !alt && matches!(key.code, KeyCode::PageUp | KeyCode::PageDown) {
        app.cycle_focus(matches!(key.code, KeyCode::PageDown));
        return Ok(true);
    }

    if !ctrl && alt && matches!(key.code, KeyCode::Up) {
        app.copy_active_topbar_snapshot()
            .context("复制顶部任务快照失败")?;
        return Ok(true);
    }

    if !ctrl && alt && matches!(key.code, KeyCode::Down) {
        app.paste_active_topbar_snapshot_to_input(now);
        return Ok(true);
    }

    if ctrl && !alt && matches!(key.code, KeyCode::Esc) {
        match selected_lane {
            Some(TopLaneKind::Terminal) => {
                if let Some(session_id) = app.active_terminal_session_id() {
                    terminal::kill_session(session_id)
                        .with_context(|| format!("结束 Terminal #{} 失败", session_id))?;
                    app.apply_status_message(format!("已请求结束 Terminal #{}", session_id));
                }
            }
            Some(TopLaneKind::Command) => {
                if let Some(snapshot) = app.active_background_command() {
                    mcp::kill_background_command(snapshot.job_id)
                        .with_context(|| format!("结束后台命令 #{} 失败", snapshot.job_id))?;
                    app.apply_status_message(format!("已请求结束后台命令 #{}", snapshot.job_id));
                }
            }
            _ => {
                app.apply_status_message("当前顶部任务不支持 Ctrl+Esc 终止".to_string());
            }
        }
        app.terminal_last_esc_at = None;
        return Ok(true);
    }

    if matches!(expanded_lane, Some(TopLaneKind::Terminal)) && shift_only {
        let page = app
            .active_terminal_tab()
            .map(|tab| tab.rows.saturating_sub(2).max(6))
            .unwrap_or(12);
        if matches!(key.code, KeyCode::Up | KeyCode::Down) {
            if app.scroll_active_terminal_view(matches!(key.code, KeyCode::Up), page) {
                app.apply_status_message("Terminal 视图已翻页".to_string());
            }
            return Ok(true);
        }
    }

    if !ctrl && !alt && matches!(key.code, KeyCode::Up | KeyCode::Down) {
        if matches!(expanded_lane, Some(TopLaneKind::Agent)) {
            if app.scroll_agent_panel(if matches!(key.code, KeyCode::Down) {
                1
            } else {
                -1
            }) {
                app.apply_status_message("子代理日志已滚动".to_string());
            }
            return Ok(true);
        }
        if matches!(expanded_lane, Some(TopLaneKind::Terminal)) {
            if app.scroll_active_terminal_view(matches!(key.code, KeyCode::Up), 1) {
                app.apply_status_message("Terminal 视图已滚动".to_string());
            }
            return Ok(true);
        }
        if app.cycle_topbar_lane(matches!(key.code, KeyCode::Down))
            && let Some((active, total)) = app.topbar_lane_index()
        {
            app.apply_status_message(format!("顶栏状态切换到 {active}/{total}"));
        }
        return Ok(true);
    }

    if !ctrl && !alt && matches!(key.code, KeyCode::Left | KeyCode::Right) {
        if matches!(expanded_lane, Some(TopLaneKind::Agent)) {
            if app.cycle_agent_snapshot(matches!(key.code, KeyCode::Right))
                && let Some((active, total)) = app.active_agent_index()
            {
                app.apply_status_message(format!("子代理切换到 {active}/{total}"));
            }
            return Ok(true);
        }
        if let Some(lane @ (TopLaneKind::Terminal | TopLaneKind::Command)) = expanded_lane {
            if app.cycle_lane_item(lane, matches!(key.code, KeyCode::Right))
                && let Some((active, total)) = app.lane_item_index(lane)
            {
                app.apply_status_message(format!("顶部任务条目切换到 {active}/{total}"));
            }
            return Ok(true);
        }
    }

    if !ctrl && !alt && matches!(key.code, KeyCode::Tab) {
        let opened = if app.expanded_topbar_lane == app.selected_topbar_lane {
            app.collapse_topbar_panel();
            false
        } else {
            app.toggle_selected_topbar_lane();
            true
        };
        app.apply_status_message(if opened {
            "已展开顶部任务栏".to_string()
        } else {
            "已收起顶部任务栏".to_string()
        });
        return Ok(true);
    }

    if !ctrl && !alt && matches!(key.code, KeyCode::Home) {
        app.set_focus(FocusArea::Input);
        app.apply_status_message("焦点: 输入".to_string());
        return Ok(true);
    }

    if matches!(expanded_lane, Some(TopLaneKind::Terminal))
        && !ctrl
        && !alt
        && matches!(key.code, KeyCode::Insert)
    {
        if app.jump_active_terminal_view_top() {
            app.apply_status_message("Terminal 视图已回到顶部".to_string());
        }
        return Ok(true);
    }

    if matches!(expanded_lane, Some(TopLaneKind::Terminal))
        && !ctrl
        && !alt
        && matches!(key.code, KeyCode::End)
    {
        if app.jump_active_terminal_view_bottom() {
            app.apply_status_message("Terminal 视图已回到底部".to_string());
        }
        return Ok(true);
    }

    if !ctrl && !alt && matches!(key.code, KeyCode::Esc) {
        if matches!(expanded_lane, Some(TopLaneKind::Terminal))
            && app.terminal_panel_active()
            && let Some(session_id) = app.active_terminal_session_id()
        {
            if let Some(previous) = app.terminal_last_esc_at
                && now.saturating_duration_since(previous) <= Duration::from_millis(320)
            {
                terminal::kill_session(session_id)
                    .with_context(|| format!("结束 Terminal #{} 失败", session_id))?;
                app.apply_status_message(format!("已请求结束 Terminal #{}", session_id));
                app.terminal_last_esc_at = None;
                return Ok(true);
            }
            app.terminal_last_esc_at = Some(now);
            terminal::send_input_bytes(session_id, vec![0x1B])
                .with_context(|| format!("向 Terminal #{} 发送 Esc 失败", session_id))?;
            return Ok(true);
        }
        app.terminal_last_esc_at = None;
        if app.collapse_topbar_panel() {
            app.apply_status_message("已收起顶部任务栏".to_string());
        } else {
            app.set_focus(FocusArea::Input);
            app.apply_status_message("焦点: 输入".to_string());
        }
        return Ok(true);
    }
    app.terminal_last_esc_at = None;

    if !matches!(expanded_lane, Some(TopLaneKind::Terminal)) {
        return Ok(true);
    }

    let Some(session_id) = app.active_terminal_session_id() else {
        return Ok(true);
    };
    if !app.terminal_panel_active() {
        return Ok(true);
    }

    let terminal_bytes = app
        .active_terminal_tab()
        .and_then(|tab| tab.key_bytes(key.code, key.modifiers))
        .or_else(|| terminal::key_to_terminal_bytes(key.code, key.modifiers));
    if let Some(bytes) = terminal_bytes {
        terminal::send_input_bytes(session_id, bytes)
            .with_context(|| format!("向 Terminal #{} 发送输入失败", session_id))?;
        return Ok(true);
    }

    Ok(true)
}

fn handle_settings_key(
    app: &mut App,
    now: Instant,
    key: KeyEvent,
    settings_height: usize,
) -> anyhow::Result<AppAction> {
    match (key.modifiers, key.code) {
        (KeyModifiers::CONTROL, KeyCode::Char('c')) => return Ok(AppAction::Quit),
        (KeyModifiers::SHIFT, KeyCode::Up) => {
            app.paste_clipboard(now).context("剪贴板粘贴失败")?;
            return Ok(AppAction::Continue);
        }
        _ => {}
    }

    if key.modifiers.contains(KeyModifiers::CONTROL) || key.modifiers.contains(KeyModifiers::ALT) {
        return Ok(AppAction::Continue);
    }

    match key.code {
        KeyCode::Esc => {
            if !app.settings.close_overlays_or_edit() {
                app.exit_settings();
            }
        }
        KeyCode::Enter => {
            if app.settings.is_editing() {
                app.settings.commit_edit();
            } else {
                app.settings.activate_selected();
            }
        }
        KeyCode::Tab => {
            if !app.settings.has_overlay_open() && !app.settings.is_editing() {
                app.settings.cycle_tab(1);
            }
        }
        KeyCode::Up => app.settings.move_prev(settings_height),
        KeyCode::Down => app.settings.move_next(settings_height),
        KeyCode::Left => {
            if app.settings.is_editing() {
                app.settings.edit_move_left();
            } else if app.settings.adjust_selected_value(-1) {
                return Ok(AppAction::Continue);
            }
        }
        KeyCode::Right => {
            if app.settings.is_editing() {
                app.settings.edit_move_right();
            } else if app.settings.adjust_selected_value(1) {
                return Ok(AppAction::Continue);
            }
        }
        KeyCode::Home | KeyCode::Insert => {
            if app.settings.is_editing() {
                app.settings.edit_move_home();
            }
        }
        KeyCode::End => {
            if app.settings.is_editing() {
                app.settings.edit_move_end();
            }
        }
        KeyCode::Backspace => {
            if app.settings.is_editing() {
                app.settings.edit_backspace();
            }
        }
        KeyCode::Delete => {
            if app.settings.is_editing() {
                app.settings.edit_delete();
            }
        }
        KeyCode::Char(ch) => {
            if !app.settings.is_editing()
                && !app.settings.has_overlay_open()
                && let Some(index) = ch.to_digit(10).map(|value| value as usize)
                && let Some(tab) = app.settings.visible_tabs().get(index.saturating_sub(1))
            {
                app.settings.select_tab(*tab);
                return Ok(AppAction::Continue);
            }
            if app.settings.is_editing() {
                app.set_focus(FocusArea::Input);
                app.settings.edit_insert_char(ch);
            }
        }
        _ => {}
    }

    Ok(AppAction::Continue)
}

fn handle_help_key(app: &mut App, key: KeyEvent) -> anyhow::Result<AppAction> {
    match (key.modifiers, key.code) {
        (KeyModifiers::CONTROL, KeyCode::Char('c')) => return Ok(AppAction::Quit),
        (_, KeyCode::Esc) => app.exit_help(),
        (_, KeyCode::Up) => app.move_help_section(-1),
        (_, KeyCode::Down) => app.move_help_section(1),
        (_, KeyCode::Char(ch)) if key.modifiers.is_empty() => {
            if app.set_help_section_by_digit(ch) {
                app.apply_status_message(app.help_status_line());
            }
        }
        _ => {}
    }
    Ok(AppAction::Continue)
}

