    pub fn tool_key_exists(messages: &[ChatMessage], key: &ToolKey) -> bool {
        messages.get(key.message_index).is_some_and(|msg| {
            if let Some(segment_index) = thought_segment_index_from_call_id(key.call_id.as_str()) {
                return thought_segment_text(msg, segment_index).is_some();
            }
            msg.tool_runs.iter().any(|run| run.call_id == key.call_id)
        })
    }

    pub fn message_key_exists(messages: &[ChatMessage], key: &MessageKey) -> bool {
        key.message_index < messages.len()
    }

    pub fn selection_key_exists(messages: &[ChatMessage], key: &SelectionKey) -> bool {
        match key {
            SelectionKey::Message(message) => message_key_exists(messages, message),
            SelectionKey::Tool(tool) => tool_key_exists(messages, tool),
        }
    }

    pub fn latest_tool_key(messages: &[ChatMessage]) -> Option<ToolKey> {
        for (message_index, msg) in messages.iter().enumerate().rev() {
            if let Some(run) = msg
                .tool_runs
                .iter()
                .rev()
                .find(|run| !run.call_id.is_empty())
            {
                return Some(ToolKey {
                    message_index,
                    call_id: run.call_id.clone(),
                });
            }
        }
        None
    }

    pub fn tool_keys_in_message(messages: &[ChatMessage], message_index: usize) -> Vec<ToolKey> {
        messages
            .get(message_index)
            .map(|msg| {
                msg.tool_runs
                    .iter()
                    .filter(|run| !run.call_id.is_empty())
                    .map(|run| ToolKey {
                        message_index,
                        call_id: run.call_id.clone(),
                    })
                    .collect()
            })
            .unwrap_or_default()
    }

    #[cfg(test)]
    pub fn previous_selection_key(
        messages: &[ChatMessage],
        current: &SelectionKey,
    ) -> Option<SelectionKey> {
        let ordered = ordered_selection_keys(messages);
        let index = ordered.iter().position(|key| key == current)?;
        index
            .checked_sub(1)
            .and_then(|prev| ordered.get(prev).cloned())
    }

    #[cfg(test)]
    pub fn next_selection_key(
        messages: &[ChatMessage],
        current: &SelectionKey,
    ) -> Option<SelectionKey> {
        let ordered = ordered_selection_keys(messages);
        let index = ordered.iter().position(|key| key == current)?;
        ordered.get(index.saturating_add(1)).cloned()
    }

    #[cfg(test)]
    pub fn selection_at_visible_row(
        messages: &[ChatMessage],
        width: usize,
        height: usize,
        scroll: usize,
        row: usize,
        expanded_tools: &[ToolKey],
    ) -> Option<SelectionKey> {
        if row >= height.max(1) {
            return None;
        }
        let view = render_view(
            messages,
            width,
            RenderOptions {
                theme: measure_theme(),
                cursor_visible: false,
                pending_phase: 0,
                selected_item: None,
                expanded_tools,
            },
        );
        if view.lines.is_empty() {
            return None;
        }
        let window = visible_window(view.lines.len(), height.max(1), scroll);
        let absolute_row = window.start.saturating_add(row);

        if let Some(tool) = view
            .tool_ranges
            .into_iter()
            .find(|range| range.lines.start <= absolute_row && absolute_row < range.lines.end)
            .map(|range| range.key)
        {
            return Some(SelectionKey::Tool(tool));
        }
        view.message_ranges
            .into_iter()
            .find(|range| range.lines.start <= absolute_row && absolute_row < range.lines.end)
            .map(|range| SelectionKey::Message(range.key))
    }

