    #[cfg(test)]
    pub fn scroll_to_reveal_selection(
        messages: &[ChatMessage],
        width: usize,
        height: usize,
        scroll: usize,
        key: &SelectionKey,
        expanded_tools: &[ToolKey],
    ) -> Option<usize> {
        let view = render_view(
            messages,
            width.max(1),
            RenderOptions {
                theme: measure_theme(),
                cursor_visible: false,
                pending_phase: 0,
                selected_item: None,
                expanded_tools,
            },
        );
        let range = selection_ranges(&view)
            .into_iter()
            .find(|range| &range.key == key)?;
        let window = visible_window(view.lines.len(), height.max(1), scroll);
        if range.reveal_line < window.start {
            let new_end = (range.reveal_line + height.max(1)).min(view.lines.len());
            return Some(view.lines.len().saturating_sub(new_end));
        }
        if range.lines.end > window.end {
            return Some(view.lines.len().saturating_sub(range.lines.end));
        }
        Some(scroll)
    }

    #[cfg(test)]
    pub fn selection_reveal_line(
        messages: &[ChatMessage],
        width: usize,
        key: &SelectionKey,
        expanded_tools: &[ToolKey],
    ) -> Option<(usize, usize)> {
        let view = render_view(
            messages,
            width.max(1),
            RenderOptions {
                theme: measure_theme(),
                cursor_visible: false,
                pending_phase: 0,
                selected_item: None,
                expanded_tools,
            },
        );
        let range = selection_ranges(&view)
            .into_iter()
            .find(|range| &range.key == key)?;
        Some((range.reveal_line, view.lines.len()))
    }

    #[cfg(test)]
    fn ordered_selection_keys(messages: &[ChatMessage]) -> Vec<SelectionKey> {
        let mut out = Vec::new();
        for (message_index, msg) in messages.iter().enumerate() {
            out.push(SelectionKey::Message(MessageKey { message_index }));
            for (segment_index, segment) in msg.ordered_segments().into_iter().enumerate() {
                match segment {
                    MessageSegment::Thinking(text) if !text.trim().is_empty() => {
                        out.push(SelectionKey::Tool(thought_segment_key(
                            message_index,
                            segment_index,
                        )));
                    }
                    MessageSegment::ToolCall(call_id) => {
                        out.push(SelectionKey::Tool(ToolKey {
                            message_index,
                            call_id,
                        }));
                    }
                    _ => {}
                }
            }
        }
        out
    }

    #[cfg(test)]
    fn visible_selection_keys(
        messages: &[ChatMessage],
        width: usize,
        height: usize,
        scroll: usize,
        expanded_tools: &[ToolKey],
    ) -> Vec<SelectionKey> {
        let view = render_view(
            messages,
            width.max(1),
            RenderOptions {
                theme: measure_theme(),
                cursor_visible: false,
                pending_phase: 0,
                selected_item: None,
                expanded_tools,
            },
        );
        let ranges = selection_ranges(&view);
        if ranges.is_empty() {
            return Vec::new();
        }
        let window = visible_window(view.lines.len(), height.max(1), scroll);
        ranges
            .into_iter()
            .filter(|range| range.lines.end > window.start && range.lines.start < window.end)
            .map(|range| range.key)
            .collect()
    }

    #[cfg(test)]
    fn visible_message_keys(
        messages: &[ChatMessage],
        width: usize,
        height: usize,
        scroll: usize,
        expanded_tools: &[ToolKey],
    ) -> Vec<MessageKey> {
        let view = render_view(
            messages,
            width.max(1),
            RenderOptions {
                theme: measure_theme(),
                cursor_visible: false,
                pending_phase: 0,
                selected_item: None,
                expanded_tools,
            },
        );
        if view.message_ranges.is_empty() {
            return Vec::new();
        }
        let window = visible_window(view.lines.len(), height.max(1), scroll);
        view.message_ranges
            .into_iter()
            .filter(|range| range.lines.end > window.start && range.lines.start < window.end)
            .map(|range| range.key)
            .collect()
    }

    #[cfg(test)]
    fn message_key_at_visible_row(
        messages: &[ChatMessage],
        width: usize,
        height: usize,
        scroll: usize,
        row: usize,
        expanded_tools: &[ToolKey],
    ) -> Option<MessageKey> {
        if row >= height.max(1) {
            return None;
        }
        let view = render_view(
            messages,
            width.max(1),
            RenderOptions {
                theme: measure_theme(),
                cursor_visible: false,
                pending_phase: 0,
                selected_item: None,
                expanded_tools,
            },
        );
        if view.lines.is_empty() {
            return None;
        }
        let window = visible_window(view.lines.len(), height.max(1), scroll);
        let absolute_row = window.start.saturating_add(row);
        view.message_ranges
            .into_iter()
            .find(|range| range.lines.start <= absolute_row && absolute_row < range.lines.end)
            .map(|range| range.key)
    }

    fn selection_ranges(view: &RenderedView) -> Vec<SelectableLineRange> {
        let mut ranges = Vec::with_capacity(
            view.message_ranges
                .len()
                .saturating_add(view.tool_ranges.len()),
        );
        ranges.extend(
            view.message_ranges
                .iter()
                .cloned()
                .map(|range| SelectableLineRange {
                    key: SelectionKey::Message(range.key),
                    reveal_line: range.header_line,
                    lines: range.lines,
                }),
        );
        ranges.extend(
            view.tool_ranges
                .iter()
                .cloned()
                .map(|range| SelectableLineRange {
                    key: SelectionKey::Tool(range.key.clone()),
                    reveal_line: range.lines.start,
                    lines: range.lines,
                }),
        );
        ranges.sort_by(|left, right| {
            left.reveal_line
                .cmp(&right.reveal_line)
                .then_with(|| left.lines.start.cmp(&right.lines.start))
        });
        ranges
    }

    pub fn visible_window(total_lines: usize, height: usize, scroll: usize) -> Range<usize> {
        let height = height.max(1);
        let max_scroll = total_lines.saturating_sub(height);
        let scroll = scroll.min(max_scroll);
        let end = total_lines.saturating_sub(scroll);
        let start = end.saturating_sub(height);
        start..end
    }

    #[cfg(test)]
    fn render_view(
        messages: &[ChatMessage],
        width: usize,
        options: RenderOptions<'_>,
    ) -> RenderedView {
        let mut out = RenderedView {
            lines: Vec::new(),
            message_ranges: Vec::new(),
            tool_ranges: Vec::new(),
        };
        for (message_index, msg) in messages.iter().enumerate() {
            let rendered = render_one(msg, message_index, width, options);
            let base = out.lines.len();
            out.lines.extend(rendered.lines);
            out.message_ranges
                .extend(rendered.message_ranges.into_iter().map(
                    |MessageLineRange {
                         key,
                         lines,
                         header_line,
                     }| MessageLineRange {
                        key,
                        lines: (lines.start + base)..(lines.end + base),
                        header_line: header_line + base,
                    },
                ));
            out.tool_ranges.extend(rendered.tool_ranges.into_iter().map(
                |ToolLineRange {
                     key,
                     lines,
                     header_line,
                 }| ToolLineRange {
                    key,
                    lines: (lines.start + base)..(lines.end + base),
                    header_line: header_line + base,
                },
            ));
        }
        if !out.lines.is_empty() && !out.lines.first().is_some_and(line_is_trim_ignorable) {
            out.lines.insert(0, Line::from(""));
            for range in &mut out.message_ranges {
                range.lines = (range.lines.start + 1)..(range.lines.end + 1);
                range.header_line = range.header_line.saturating_add(1);
            }
            for range in &mut out.tool_ranges {
                range.lines = (range.lines.start + 1)..(range.lines.end + 1);
                range.header_line = range.header_line.saturating_add(1);
            }
        }
        while out.lines.len() > 1
            && out.lines.last().is_some_and(line_is_trim_ignorable)
            && out
                .lines
                .get(out.lines.len().saturating_sub(2))
                .is_some_and(line_is_trim_ignorable)
        {
            out.lines.pop();
        }
        out
    }

    #[cfg(test)]
    fn line_is_trim_ignorable(line: &Line<'_>) -> bool {
        line.spans
            .iter()
            .all(|span| span.content.trim().is_empty() && span.style.bg.is_none())
    }

    fn render_one(
        msg: &ChatMessage,
        message_index: usize,
        width: usize,
        options: RenderOptions<'_>,
    ) -> RenderedView {
        let mut lines = Vec::new();
        let mut message_ranges = Vec::new();
        let mut tool_ranges = Vec::new();
        let width = width.max(1);
        let is_system = msg.role == Role::System;
        let card_bg = (msg.source_channel == SourceChannel::User).then_some(options.theme.user_bg);

        if msg.role == Role::Assistant
            && msg.streaming
            && !msg.has_content()
            && msg.display.trim().is_empty()
            && msg
                .thinking
                .as_deref()
                .is_none_or(|value| value.trim().is_empty())
        {
            return RenderedView {
                lines,
                message_ranges,
                tool_ranges,
            };
        }

        if let Some(bg) = card_bg {
            lines.push(Line::from(""));
            lines.push(background_fill_line(width, bg));
        }
        let selected_message = options
            .selected_item
            .is_some_and(|item| item == &SelectionKey::Message(MessageKey { message_index }));
        let message_expanded = options
            .expanded_tools
            .iter()
            .any(|expanded| expanded.message_index == message_index);
        let system_expandable = is_system && message_can_expand(msg);
        if system_expandable {
            lines.push(build_system_frame_line(
                system_frame_width(msg, width),
                selected_message,
            ));
        }
        let header_line = lines.len();
        let (header, _) = build_header_line(
            msg,
            options.theme,
            options.pending_phase,
            selected_message,
            width,
            if !msg.tool_runs.is_empty() || system_expandable {
                Some(message_expanded)
            } else {
                None
            },
        );
        lines.push(header);
        lines.push(Line::from(""));

        let body_style = if is_system {
            Style::default().fg(options.theme.sys_fg)
        } else {
            Style::default().fg(options.theme.fg)
        };

        let mut rendered_body = false;
        let mut prev_was_display = false;
        let segments = msg.ordered_segments();
        let mut segment_index = 0usize;
        while segment_index < segments.len() {
            let segment = &segments[segment_index];
            let is_tool = matches!(segment, MessageSegment::ToolCall(_));
            if rendered_body && !(is_system && prev_was_display && is_tool) {
                lines.push(Line::from(""));
            }
            prev_was_display = false;
            match segment {
                MessageSegment::ToolCall(_call_id) => {
                    let mut grouped_runs = Vec::new();
                    let mut scan_index = segment_index;
                    while let Some(MessageSegment::ToolCall(group_call_id)) =
                        segments.get(scan_index)
                    {
                        if let Some(run) = msg.tool_run(group_call_id.as_str()) {
                            grouped_runs.push(run.clone());
                        }
                        scan_index = scan_index.saturating_add(1);
                    }
                    if !grouped_runs.is_empty() {
                        let rendered = render_tool_runs(
                            grouped_runs.as_slice(),
                            message_index,
                            ToolRenderOptions {
                                width,
                                theme: options.theme,
                                blink_on: options.cursor_visible,
                                body_style,
                                compact: is_system,
                                selected_item: options.selected_item,
                                expanded_tools: options.expanded_tools,
                            },
                        );
                        let base = lines.len();
                        lines.extend(rendered.lines);
                        tool_ranges.extend(rendered.tool_ranges.into_iter().map(
                            |ToolLineRange {
                                 key,
                                 lines,
                                 header_line,
                             }| ToolLineRange {
                                key,
                                lines: (lines.start + base)..(lines.end + base),
                                header_line: header_line + base,
                            },
                        ));
                        rendered_body = true;
                    }
                    segment_index = scan_index;
                }
                MessageSegment::Plan(plan) => {
                    if !plan.trim().is_empty() {
                        lines.extend(render_proposed_plan_block(plan.as_str(), width, body_style));
                        rendered_body = true;
                    }
                    segment_index = segment_index.saturating_add(1);
                }
                MessageSegment::Thinking(thinking) => {
                    if !thinking.trim().is_empty() {
                        let key = thought_segment_key(message_index, segment_index);
                        let selected_key = SelectionKey::Tool(key.clone());
                        let highlighted = options
                            .selected_item
                            .is_some_and(|selected| selected == &selected_key);
                        let expanded =
                            msg.streaming || options.expanded_tools.iter().any(|tool| tool == &key);
                        let start = lines.len();
                        let header_line = start;
                        lines.push(build_thinking_header_line(
                            width,
                            body_style,
                            highlighted,
                            expanded,
                        ));
                        if expanded {
                            lines.extend(render_thinking_body_block(
                                thinking.as_str(),
                                width,
                                options.theme,
                                body_style,
                            ));
                        }
                        tool_ranges.push(ToolLineRange {
                            key,
                            lines: start..lines.len(),
                            header_line,
                        });
                        rendered_body = true;
                    }
                    segment_index = segment_index.saturating_add(1);
                }
                MessageSegment::Display(display) => {
                    if !display.trim().is_empty() {
                        let rendered = if is_system {
                            if message_expanded {
                                render_system_body_block(msg, width, body_style)
                            } else {
                                Vec::new()
                            }
                        } else {
                            render_markdown_block(
                                display.as_str(),
                                width,
                                MarkdownTheme {
                                    base_style: body_style,
                                    quote_style: body_style.fg(Color::DarkGray),
                                    list_style: body_style.fg(Color::LightMagenta),
                                    code_style: body_style
                                        .fg(Color::LightCyan)
                                        .add_modifier(Modifier::BOLD),
                                    code_block_gutter_style: body_style.fg(Color::DarkGray),
                                    code_block_text_style: body_style.fg(Color::LightGreen),
                                    heading_1_style: body_style
                                        .fg(Color::Magenta)
                                        .add_modifier(Modifier::BOLD),
                                    heading_2_style: body_style
                                        .fg(Color::LightMagenta)
                                        .add_modifier(Modifier::BOLD),
                                    heading_3_style: body_style
                                        .fg(Color::Cyan)
                                        .add_modifier(Modifier::BOLD),
                                    heading_n_style: body_style
                                        .fg(Color::Gray)
                                        .add_modifier(Modifier::BOLD),
                                    rule_style: body_style.fg(Color::DarkGray),
                                    html_style: body_style.fg(Color::DarkGray),
                                    link_style: body_style
                                        .fg(Color::Cyan)
                                        .add_modifier(Modifier::UNDERLINED),
                                    math_style: body_style
                                        .fg(Color::Cyan)
                                        .add_modifier(Modifier::ITALIC),
                                    placeholder_style: Style::default()
                                        .fg(options.theme.placeholder_fg)
                                        .bg(options.theme.placeholder_bg)
                                        .add_modifier(Modifier::BOLD),
                                },
                                &msg.pasted_placeholders,
                                body_style,
                            )
                        };
                        if !rendered.is_empty() {
                            lines.extend(rendered);
                            rendered_body = true;
                            prev_was_display = true;
                        }
                    }
                    segment_index = segment_index.saturating_add(1);
                }
            }
        }

        lines.push(Line::from(""));
        if let Some(bg) = card_bg {
            lines.push(Line::from(""));
            let start = 1usize.min(lines.len());
            let end = lines.len().saturating_sub(1);
            if start < end {
                apply_card_background(&mut lines[start..end], width, bg);
            }
        }
        normalize_rendered_line_widths(&mut lines, width);
        message_ranges.push(MessageLineRange {
            key: MessageKey { message_index },
            lines: 0..lines.len(),
            header_line,
        });
        RenderedView {
            lines,
            message_ranges,
            tool_ranges,
        }
    }

    fn normalize_rendered_line_widths(lines: &mut [Line<'static>], width: usize) {
        for line in lines.iter_mut() {
            let fill_style = line.spans.last().map(|span| span.style).unwrap_or_default();
            let spans = std::mem::take(&mut line.spans);
            *line = fit_spans_to_width(spans, width, fill_style);
        }
    }

