    fn build_thinking_header_line(
        width: usize,
        body_style: Style,
        highlighted: bool,
        expanded: bool,
    ) -> Line<'static> {
        let title_style = if highlighted {
            Style::default()
                .fg(Color::Rgb(214, 214, 214))
                .add_modifier(Modifier::BOLD | Modifier::UNDERLINED)
        } else if expanded {
            Style::default()
                .fg(Color::Rgb(176, 176, 176))
                .add_modifier(Modifier::DIM)
        } else {
            Style::default()
                .fg(Color::Rgb(148, 148, 148))
                .add_modifier(Modifier::DIM)
        };
        fit_spans_to_width(
            vec![
                Span::styled(" ".repeat(BODY_INDENT), body_style),
                Span::styled("✧ THOUGHTS".to_string(), title_style),
            ],
            width,
            body_style,
        )
    }

