    fn render_markdown_block(
        text: &str,
        width: usize,
        theme: MarkdownTheme,
        placeholders: &[String],
        indent_style: Style,
    ) -> Vec<Line<'static>> {
        render_markdown_block_with_indent(
            text,
            width,
            theme,
            placeholders,
            BODY_INDENT,
            indent_style,
        )
    }

    fn render_markdown_block_with_indent(
        text: &str,
        width: usize,
        theme: MarkdownTheme,
        placeholders: &[String],
        indent: usize,
        indent_style: Style,
    ) -> Vec<Line<'static>> {
        let rendered = messageline::render_markdown_to_lines(
            text,
            width.saturating_sub(indent),
            theme,
            MarkdownRenderSpec::default(),
            placeholders,
        );
        let mut out = Vec::with_capacity(rendered.len());
        for line in rendered {
            let mut spans = Vec::with_capacity(line.spans.len().saturating_add(1));
            spans.push(Span::styled(" ".repeat(indent), indent_style));
            spans.extend(line.spans.into_iter());
            out.push(Line::from(spans));
        }
        out
    }

    fn render_tool_runs(
        tool_runs: &[ToolRun],
        message_index: usize,
        options: ToolRenderOptions<'_>,
    ) -> RenderedView {
        let width = options.width.max(1);
        let theme = options.theme;
        let body_style = options.body_style;
        let selected_item = options.selected_item;
        let expanded_tools = options.expanded_tools;
        let compact = options.compact;
        let preview_spec = ToolPreviewSpec::new(width, body_style, options.blink_on);
        let mut lines = Vec::new();
        let mut tool_ranges = Vec::new();
        for (index, run) in tool_runs.iter().enumerate() {
            let chain_group = tool_chain_group_meta(tool_runs, index);
            let previous_chain_group = index
                .checked_sub(1)
                .and_then(|prev| tool_chain_group_meta(tool_runs, prev));
            let grouped_chain = chain_group.is_some();
            if index > 0 && !(grouped_chain && previous_chain_group.is_some()) {
                lines.push(Line::from(""));
            }
            let key = ToolKey {
                message_index,
                call_id: run.call_id.clone(),
            };
            let selected_key = SelectionKey::Tool(key.clone());
            let highlighted = selected_item.is_some_and(|selected| selected == &selected_key);
            let expanded = expanded_tools.iter().any(|tool| tool == &key);
            let start = lines.len();
            let mut header_line = start;
            let connector_style = if compact && !highlighted {
                body_style
            } else if highlighted {
                Style::default()
                    .fg(Color::Rgb(196, 170, 118))
                    .add_modifier(Modifier::BOLD)
            } else {
                Style::default()
                    .fg(Color::Rgb(118, 112, 92))
                    .add_modifier(Modifier::DIM)
            };

            if grouped_chain {
                let chain_meta = chain_group.clone().expect("tool chain meta");
                if !compact && chain_meta.leader {
                    lines.push(build_tool_frame_line_for_run(run, width, highlighted));
                }
                if chain_meta.parallel_batch && chain_meta.leader {
                    let (group_header, _) =
                        build_parallel_batch_header_line(run, width, body_style, highlighted);
                    lines.push(group_header);
                }
                header_line = lines.len();
                let (header, _) = if chain_meta.parallel_batch {
                    build_parallel_batch_item_header_line(
                        run,
                        width,
                        body_style,
                        highlighted,
                        expanded,
                    )
                } else if chain_meta.leader {
                    build_tool_header_line(run, theme, width, body_style, highlighted, expanded)
                } else {
                    build_tool_chain_header_line(
                        run,
                        chain_meta.title.as_str(),
                        width,
                        body_style,
                        highlighted,
                        expanded,
                    )
                };
                lines.push(header);
            } else if !compact {
                lines.push(build_tool_frame_line_for_run(run, width, highlighted));
                header_line = lines.len();
                let (header, _) =
                    build_tool_header_line(run, theme, width, body_style, highlighted, expanded);
                lines.push(header);
            }

            let has_output_line = run.completed || !run.output_preview.trim().is_empty();
            let is_apply_patch = is_apply_patch_tool(run);
            let is_rewrite_section = is_rewrite_section_tool(run);
            let is_update_plan = is_update_plan_tool(run);
            let is_parallel = is_parallel_tool(run);
            let is_view_image = is_view_image_tool(run);
            let is_web_search = is_web_search_tool(run);
            let is_tool_manage = is_tool_manage_tool(run);
            let is_persona_manage = is_persona_manage_tool(run);
            let is_context_manage = is_context_manage_tool(run);
            let is_memory = is_memory_tool(run);
            let is_ask_user = is_ask_user_tool(run);
            let is_agent = is_agent_tool(run);
            let is_batch = is_batch_tool(run);
            let is_parallel_batch = chain_group.as_ref().is_some_and(|meta| meta.parallel_batch);
            let apply_patch_failed = is_apply_patch && is_apply_patch_failed_run(run);
            let command_preview = normalize_tool_preview(run.command_preview.as_str(), false);
            let show_input = !compact || !command_preview.trim().is_empty();
            let output_connector = tool_chain_output_connector(chain_group.as_ref());
            let input_connector = tool_chain_input_connector(chain_group.as_ref(), has_output_line);

            if is_parallel {
                if let Some(parallel_lines) =
                    render_parallel_tool_block(run, width, body_style, expanded)
                {
                    lines.extend(parallel_lines);
                } else if expanded {
                    let output_preview = normalize_tool_preview(run.output_preview.as_str(), true);
                    if !command_preview.trim().is_empty() {
                        lines.extend(render_expanded_tool_section(
                            "[- INPUT -]:",
                            command_preview.as_str(),
                            width,
                            body_style,
                            Style::default().fg(Color::Rgb(220, 228, 236)),
                        ));
                    }
                    if !output_preview.trim().is_empty() {
                        lines.extend(render_expanded_tool_section(
                            "[- Output -]:",
                            output_preview.as_str(),
                            width,
                            body_style,
                            Style::default().fg(Color::Rgb(214, 222, 232)),
                        ));
                    }
                } else {
                    let preview_text = if run.completed && !run.output_preview.trim().is_empty() {
                        run.output_preview.as_str()
                    } else {
                        run.command_preview.as_str()
                    };
                    lines.push(build_tool_preview_line(
                        '└',
                        connector_style,
                        "[- Output -]:",
                        preview_text,
                        preview_spec,
                        Style::default().fg(Color::Rgb(214, 222, 232)),
                    ));
                }
            } else if is_parallel_batch {
                if expanded {
                    if show_input {
                        lines.extend(render_expanded_tool_section(
                            "[- INPUT -]:",
                            command_preview.as_str(),
                            width,
                            body_style,
                            Style::default().fg(Color::Rgb(150, 168, 190)),
                        ));
                    }
                    if has_output_line {
                        let output_preview =
                            normalize_tool_preview(run.output_preview.as_str(), true);
                        lines.extend(render_expanded_tool_section(
                            "[- Output -]:",
                            output_preview.as_str(),
                            width,
                            body_style,
                            Style::default().fg(Color::Rgb(160, 184, 206)),
                        ));
                    }
                }
            } else if is_update_plan {
                if show_input {
                    lines.extend(render_update_plan_block(
                        command_preview.as_str(),
                        width,
                        body_style,
                        connector_style,
                    ));
                }
            } else if is_apply_patch {
                if show_input {
                    if expanded && apply_patch_failed {
                        lines.extend(render_apply_patch_input_section(
                            command_preview.as_str(),
                            width,
                            body_style,
                        ));
                    } else {
                        lines.push(build_apply_patch_input_summary_line(
                            input_connector,
                            connector_style,
                            width,
                            body_style,
                            command_preview.as_str(),
                        ));
                    }
                }

                if has_output_line {
                    let output_preview = normalize_tool_preview(run.output_preview.as_str(), true);
                    lines.extend(render_apply_patch_output_section(
                        output_preview.as_str(),
                        width,
                        body_style,
                        connector_style,
                        output_connector,
                        if expanded || !apply_patch_failed {
                            if expanded { None } else { Some(7) }
                        } else {
                            Some(1)
                        },
                    ));
                }
            } else if is_rewrite_section {
                if show_input {
                    if expanded {
                        lines.extend(render_rewrite_section_input_section(
                            command_preview.as_str(),
                            width,
                            body_style,
                        ));
                    } else {
                        lines.push(build_tool_summary_preview_line(
                            input_connector,
                            connector_style,
                            "[- Path -]:",
                            rewrite_section_input_summary(command_preview.as_str()).as_str(),
                            command_preview.as_str(),
                            preview_spec,
                            Style::default().fg(Color::Rgb(150, 168, 190)),
                        ));
                    }
                }

                if has_output_line {
                    let output_preview = normalize_tool_preview(run.output_preview.as_str(), true);
                    if expanded {
                        lines.extend(render_rewrite_section_output_section(
                            output_preview.as_str(),
                            width,
                            body_style,
                        ));
                    } else {
                        let failed = is_rewrite_section_output_failure(output_preview.as_str());
                        lines.push(build_tool_summary_preview_line(
                            output_connector,
                            connector_style,
                            if failed {
                                "[- Output -]:"
                            } else {
                                "[- Edited -]:"
                            },
                            rewrite_section_output_summary(output_preview.as_str()).as_str(),
                            output_preview.as_str(),
                            preview_spec,
                            if failed {
                                Style::default().fg(Color::Rgb(226, 150, 150))
                            } else {
                                Style::default().fg(Color::Rgb(190, 222, 206))
                            },
                        ));
                    }
                }
            } else if is_view_image {
                let vision_preview = normalize_tool_preview(
                    if has_output_line {
                        run.output_preview.as_str()
                    } else {
                        command_preview.as_str()
                    },
                    has_output_line,
                );
                if expanded {
                    lines.extend(render_expanded_tool_section(
                        "[- Vision -]:",
                        vision_preview.as_str(),
                        width,
                        body_style,
                        Style::default().fg(Color::Rgb(214, 238, 255)),
                    ));
                } else {
                    lines.push(build_tool_preview_line(
                        output_connector,
                        connector_style,
                        "[- Vision -]:",
                        vision_preview.as_str(),
                        preview_spec,
                        Style::default().fg(Color::Rgb(214, 238, 255)),
                    ));
                }
            } else if is_web_search {
                let search_preview = web_search_search_block(run);
                if !search_preview.trim().is_empty() {
                    if expanded {
                        lines.extend(render_expanded_tool_section(
                            "[- Search -]",
                            search_preview.as_str(),
                            width,
                            body_style,
                            Style::default().fg(Color::Rgb(214, 238, 255)),
                        ));
                    } else {
                        lines.push(build_tool_preview_line(
                            output_connector,
                            connector_style,
                            "[- Search -]",
                            search_preview.as_str(),
                            preview_spec,
                            Style::default().fg(Color::Rgb(214, 238, 255)),
                        ));
                    }
                }
            } else if is_tool_manage {
                let input_label = tool_manage_input_label(run);
                let output_label = tool_manage_output_label(run);
                if expanded {
                    if show_input {
                        lines.extend(render_expanded_tool_section(
                            input_label,
                            command_preview.as_str(),
                            width,
                            body_style,
                            Style::default().fg(Color::Rgb(182, 222, 255)),
                        ));
                    }
                    if has_output_line {
                        let output_preview =
                            normalize_tool_preview(run.output_preview.as_str(), true);
                        lines.extend(render_expanded_tool_section(
                            output_label,
                            output_preview.as_str(),
                            width,
                            body_style,
                            Style::default().fg(Color::Rgb(214, 238, 255)),
                        ));
                    }
                } else {
                    let preview_text = if has_output_line {
                        normalize_tool_preview(run.output_preview.as_str(), true)
                    } else {
                        command_preview.clone()
                    };
                    lines.push(build_tool_preview_line(
                        output_connector,
                        connector_style,
                        if has_output_line {
                            output_label
                        } else {
                            input_label
                        },
                        preview_text.as_str(),
                        preview_spec,
                        Style::default().fg(Color::Rgb(214, 238, 255)),
                    ));
                }
            } else if is_persona_manage {
                let task_preview = normalize_tool_preview(run.command_preview.as_str(), false);
                let status_preview = normalize_tool_preview(run.output_preview.as_str(), true);
                if expanded {
                    if !task_preview.trim().is_empty() {
                        lines.extend(render_expanded_tool_section(
                            persona_manage_input_label(run),
                            task_preview.as_str(),
                            width,
                            body_style,
                            Style::default().fg(Color::Rgb(182, 222, 255)),
                        ));
                    }
                    if !status_preview.trim().is_empty() {
                        lines.extend(render_expanded_tool_section(
                            persona_manage_output_label(run),
                            status_preview.as_str(),
                            width,
                            body_style,
                            Style::default().fg(Color::Rgb(196, 248, 210)),
                        ));
                    }
                } else {
                    lines.push(build_tool_preview_line(
                        output_connector,
                        connector_style,
                        persona_manage_collapsed_label(run, status_preview.as_str()),
                        persona_manage_collapsed_preview(
                            run,
                            task_preview.as_str(),
                            status_preview.as_str(),
                        )
                        .as_str(),
                        preview_spec,
                        Style::default().fg(Color::Rgb(196, 248, 210)),
                    ));
                }
            } else if is_context_manage {
                if has_output_line {
                    let output_preview = normalize_tool_preview(run.output_preview.as_str(), true);
                    lines.extend(render_context_manage_output_section(
                        run,
                        output_preview.as_str(),
                        width,
                        body_style,
                        connector_style,
                        output_connector,
                        if expanded {
                            Some(CONTEXT_MANAGE_EXPANDED_MAX_LINES)
                        } else {
                            Some(CONTEXT_MANAGE_COLLAPSED_MAX_LINES)
                        },
                    ));
                } else if show_input {
                    let label = context_manage_section_label(run);
                    lines.push(build_single_line_tool_preview_line(
                        output_connector,
                        connector_style,
                        label.as_str(),
                        command_preview.as_str(),
                        width,
                        body_style,
                        Style::default().fg(Color::Rgb(182, 222, 255)),
                    ));
                }
            } else if is_memory {
                let input_label = memory_tool_input_label(run);
                let output_label = memory_tool_output_label(run);
                if show_input {
                    if expanded {
                        lines.extend(render_expanded_tool_section(
                            input_label,
                            command_preview.as_str(),
                            width,
                            body_style,
                            Style::default().fg(Color::Rgb(182, 222, 255)),
                        ));
                    } else {
                        lines.push(build_tool_preview_line(
                            input_connector,
                            connector_style,
                            input_label,
                            command_preview.as_str(),
                            preview_spec,
                            Style::default().fg(Color::Rgb(182, 222, 255)),
                        ));
                    }
                }
                if has_output_line {
                    let output_preview = normalize_tool_preview(run.output_preview.as_str(), true);
                    if expanded {
                        lines.extend(render_expanded_tool_section(
                            output_label,
                            output_preview.as_str(),
                            width,
                            body_style,
                            Style::default().fg(Color::Rgb(214, 238, 255)),
                        ));
                    } else {
                        lines.push(build_tool_preview_line(
                            output_connector,
                            connector_style,
                            output_label,
                            output_preview.as_str(),
                            preview_spec,
                            Style::default().fg(Color::Rgb(214, 238, 255)),
                        ));
                    }
                }
            } else if is_ask_user {
                if show_input {
                    if expanded {
                        lines.extend(render_expanded_tool_section(
                            "[- Selection -]:",
                            command_preview.as_str(),
                            width,
                            body_style,
                            Style::default().fg(Color::Rgb(182, 222, 255)),
                        ));
                    } else {
                        lines.push(build_tool_preview_line(
                            input_connector,
                            connector_style,
                            "[- Selection -]:",
                            command_preview.as_str(),
                            preview_spec,
                            Style::default().fg(Color::Rgb(182, 222, 255)),
                        ));
                    }
                }

                if has_output_line {
                    let output_preview = normalize_tool_preview(run.output_preview.as_str(), true);
                    if expanded {
                        lines.extend(render_expanded_tool_section(
                            "[- Result -]:",
                            output_preview.as_str(),
                            width,
                            body_style,
                            Style::default().fg(Color::Rgb(206, 236, 255)),
                        ));
                    } else {
                        lines.push(build_tool_preview_line(
                            output_connector,
                            connector_style,
                            "[- Result -]:",
                            output_preview.as_str(),
                            preview_spec,
                            Style::default().fg(Color::Rgb(206, 236, 255)),
                        ));
                    }
                }
            } else if is_agent {
                let task_preview = normalize_tool_preview(run.command_preview.as_str(), false);
                let status_preview = normalize_tool_preview(run.output_preview.as_str(), true);
                if expanded {
                    if !task_preview.trim().is_empty() {
                        lines.extend(render_expanded_tool_section(
                            agent_tool_input_label(run),
                            task_preview.as_str(),
                            width,
                            body_style,
                            Style::default().fg(Color::Rgb(182, 222, 255)),
                        ));
                    }
                    if !status_preview.trim().is_empty() {
                        lines.extend(render_expanded_tool_section(
                            agent_tool_output_label(run),
                            status_preview.as_str(),
                            width,
                            body_style,
                            Style::default().fg(Color::Rgb(196, 248, 210)),
                        ));
                    }
                } else {
                    lines.push(build_tool_preview_line(
                        output_connector,
                        connector_style,
                        agent_tool_collapsed_label(run, status_preview.as_str()),
                        agent_tool_collapsed_preview(
                            run,
                            task_preview.as_str(),
                            status_preview.as_str(),
                        )
                        .as_str(),
                        preview_spec,
                        Style::default().fg(Color::Rgb(196, 248, 210)),
                    ));
                }
            } else if is_batch {
                let input_label = batch_tool_input_label(run);
                if show_input {
                    if expanded {
                        lines.extend(render_expanded_tool_section(
                            input_label,
                            command_preview.as_str(),
                            width,
                            body_style,
                            Style::default().fg(Color::Rgb(255, 212, 162)),
                        ));
                    } else {
                        lines.push(build_tool_preview_line(
                            input_connector,
                            connector_style,
                            input_label,
                            command_preview.as_str(),
                            preview_spec,
                            Style::default().fg(Color::Rgb(255, 212, 162)),
                        ));
                    }
                }

                if has_output_line {
                    let output_preview = normalize_tool_preview(run.output_preview.as_str(), true);
                    if expanded {
                        lines.extend(render_expanded_tool_section(
                            "[- Result -]:",
                            output_preview.as_str(),
                            width,
                            body_style,
                            Style::default().fg(Color::Rgb(255, 232, 198)),
                        ));
                    } else {
                        lines.push(build_tool_preview_line(
                            output_connector,
                            connector_style,
                            "[- Result -]:",
                            output_preview.as_str(),
                            preview_spec,
                            Style::default().fg(Color::Rgb(255, 232, 198)),
                        ));
                    }
                }
            } else {
                let input_label = generic_tool_input_label(run);
                let output_label = generic_tool_output_label(run);
                if show_input {
                    if expanded {
                        lines.extend(render_expanded_tool_section(
                            input_label.as_str(),
                            command_preview.as_str(),
                            width,
                            body_style,
                            Style::default().fg(Color::Rgb(150, 168, 190)),
                        ));
                    } else if is_exec_preview_tool(run) {
                        lines.push(build_tool_summary_preview_line(
                            input_connector,
                            connector_style,
                            input_label.as_str(),
                            exec_command_input_summary(command_preview.as_str()).as_str(),
                            command_preview.as_str(),
                            preview_spec,
                            Style::default().fg(Color::Rgb(150, 168, 190)),
                        ));
                    } else {
                        lines.push(build_tool_preview_line(
                            input_connector,
                            connector_style,
                            input_label.as_str(),
                            command_preview.as_str(),
                            preview_spec,
                            Style::default().fg(Color::Rgb(150, 168, 190)),
                        ));
                    }
                }

                if has_output_line {
                    let output_preview = normalize_tool_preview(run.output_preview.as_str(), true);
                    if expanded {
                        lines.extend(render_expanded_tool_section(
                            output_label.as_str(),
                            output_preview.as_str(),
                            width,
                            body_style,
                            Style::default().fg(Color::Rgb(160, 184, 206)),
                        ));
                    } else if is_exec_preview_tool(run) {
                        lines.push(build_tool_summary_preview_line(
                            output_connector,
                            connector_style,
                            output_label.as_str(),
                            exec_command_output_summary(output_preview.as_str()).as_str(),
                            output_preview.as_str(),
                            preview_spec,
                            Style::default().fg(Color::Rgb(160, 184, 206)),
                        ));
                    } else {
                        lines.push(build_tool_preview_line(
                            output_connector,
                            connector_style,
                            output_label.as_str(),
                            output_preview.as_str(),
                            preview_spec,
                            Style::default().fg(Color::Rgb(160, 184, 206)),
                        ));
                    }
                }
            }
            if expanded {
                clamp_rendered_tool_receipt(
                    &mut lines,
                    start,
                    TOOL_EXPANDED_MAX_LINES,
                    width,
                    body_style,
                );
            }
            let end = lines.len();
            tool_ranges.push(ToolLineRange {
                key,
                lines: start..end,
                header_line,
            });
        }
        RenderedView {
            lines,
            message_ranges: Vec::new(),
            tool_ranges,
        }
    }

    fn clamp_rendered_tool_receipt(
        lines: &mut Vec<Line<'static>>,
        start: usize,
        max_lines: usize,
        width: usize,
        body_style: Style,
    ) {
        let len = lines.len().saturating_sub(start);
        if len <= max_lines {
            return;
        }
        let block = lines.drain(start..).collect::<Vec<_>>();
        let clamped = clamp_tool_detail_lines(
            block,
            max_lines,
            width,
            TOOL_BLOCK_INDENT,
            body_style,
            Style::default().fg(Color::Rgb(210, 176, 132)),
        );
        lines.extend(clamped);
    }

    fn finalize_header_with_toggle(
        spans: Vec<Span<'static>>,
        width: usize,
        filler_style: Style,
        _toggle: Option<bool>,
    ) -> (Line<'static>, Option<Range<usize>>) {
        (fit_spans_to_width(spans, width, filler_style), None)
    }

    fn build_tool_header_line(
        run: &ToolRun,
        _theme: Theme,
        width: usize,
        body_style: Style,
        highlighted: bool,
        expanded: bool,
    ) -> (Line<'static>, Option<Range<usize>>) {
        let toggle = if is_update_plan_tool(run) || is_web_search_tool(run) {
            None
        } else {
            Some(expanded)
        };
        if is_apply_patch_tool(run) || is_rewrite_section_tool(run) {
            return build_apply_patch_header_line(
                run,
                width,
                body_style,
                highlighted,
                toggle.unwrap_or(expanded),
            );
        }
        if is_parallel_tool(run) {
            return build_parallel_header_line(
                run,
                width,
                body_style,
                highlighted,
                toggle.unwrap_or(expanded),
            );
        }
        if is_parallel_batch_item(run) {
            return build_parallel_batch_item_header_line(
                run,
                width,
                body_style,
                highlighted,
                toggle.unwrap_or(expanded),
            );
        }
        if is_update_plan_tool(run) {
            return build_update_plan_header_line(run, width, body_style, highlighted, toggle);
        }
        if is_view_image_tool(run) {
            return build_view_image_header_line(
                run,
                width,
                body_style,
                highlighted,
                toggle.unwrap_or(expanded),
            );
        }
        if is_web_search_tool(run) {
            return build_web_search_header_line(run, width, body_style, highlighted, toggle);
        }
        if is_tool_manage_tool(run) {
            return build_tool_manage_header_line(
                run,
                width,
                body_style,
                highlighted,
                toggle.unwrap_or(expanded),
            );
        }
        if is_persona_manage_tool(run) {
            return build_persona_manage_header_line(
                run,
                width,
                body_style,
                highlighted,
                toggle.unwrap_or(expanded),
            );
        }
        if is_context_manage_tool(run) {
            return build_context_manage_header_line(
                run,
                width,
                body_style,
                highlighted,
                toggle.unwrap_or(expanded),
            );
        }
        if is_memory_tool(run) {
            return build_memory_header_line(
                run,
                width,
                body_style,
                highlighted,
                toggle.unwrap_or(expanded),
            );
        }
        if is_ask_user_tool(run) {
            return build_ask_user_header_line(
                run,
                width,
                body_style,
                highlighted,
                toggle.unwrap_or(expanded),
            );
        }
        if is_agent_tool(run) {
            return build_agent_header_line(
                run,
                width,
                body_style,
                highlighted,
                toggle.unwrap_or(expanded),
            );
        }
        if is_batch_tool(run) {
            return build_batch_header_line(
                run,
                width,
                body_style,
                highlighted,
                toggle.unwrap_or(expanded),
            );
        }
        if run.kind_label.trim().eq_ignore_ascii_case("terminal") {
            return build_terminal_tool_header_line(
                run,
                width,
                body_style,
                highlighted,
                toggle.unwrap_or(expanded),
            );
        }
        let action = if run.action_label.trim().is_empty() {
            if run.completed { "Ran" } else { "Run" }
        } else {
            run.action_label.as_str()
        };
        let kind = display_tool_kind(run);
        let run_style = if highlighted {
            Style::default()
                .fg(Color::Rgb(246, 214, 136))
                .add_modifier(Modifier::BOLD | Modifier::UNDERLINED)
        } else {
            Style::default()
                .fg(Color::Rgb(218, 184, 112))
                .add_modifier(Modifier::BOLD)
        };
        let tool_style = if highlighted {
            Style::default()
                .fg(Color::Rgb(250, 224, 154))
                .add_modifier(Modifier::BOLD | Modifier::UNDERLINED)
        } else {
            Style::default()
                .fg(Color::Rgb(228, 198, 126))
                .add_modifier(Modifier::BOLD)
        };
        let brief_style = if highlighted {
            Style::default()
                .fg(Color::Rgb(255, 235, 178))
                .add_modifier(Modifier::BOLD | Modifier::UNDERLINED)
        } else {
            Style::default()
                .fg(Color::Rgb(240, 214, 152))
                .add_modifier(Modifier::BOLD)
        };
        let action_text = format!("● {kind}");
        let max_line_w = width.saturating_sub(BODY_INDENT).saturating_sub(2).max(1);
        let sep = " · ";
        let sep_w = display_width(sep);
        let action_w = display_width(action_text.as_str());
        let kind_max = max_line_w
            .saturating_sub(action_w)
            .saturating_sub(sep_w)
            .max(0);
        let kind_shown = if kind_max == 0 {
            String::new()
        } else {
            truncate_to_width(action, kind_max)
        };

        let mut spans = vec![
            Span::styled(" ".repeat(BODY_INDENT), body_style),
            Span::styled(action_text, run_style),
            Span::styled(sep.to_string(), tool_style),
            Span::styled(kind_shown.clone(), tool_style),
        ];

        if !run.brief.trim().is_empty() {
            let used = action_w
                .saturating_add(sep_w)
                .saturating_add(display_width(kind_shown.as_str()));
            let remaining = max_line_w.saturating_sub(used);
            if remaining > sep_w {
                let brief_max = remaining.saturating_sub(sep_w);
                let brief_shown = truncate_to_width(run.brief.as_str(), brief_max);
                if !brief_shown.trim().is_empty() {
                    spans.push(Span::styled(sep.to_string(), tool_style));
                    spans.push(Span::styled(brief_shown, brief_style));
                }
            }
        }
        finalize_header_with_toggle(spans, width, body_style, toggle)
    }

    #[derive(Debug, Clone, Copy)]
    struct NamedToolHeaderSpec {
        width: usize,
        body_style: Style,
        highlighted: bool,
        expanded: bool,
        title_color: Color,
        brief_color: Color,
    }

    fn build_named_tool_header_line(
        title: &str,
        brief: &str,
        spec: NamedToolHeaderSpec,
    ) -> (Line<'static>, Option<Range<usize>>) {
        let highlight_modifier = if spec.highlighted {
            Modifier::BOLD | Modifier::UNDERLINED
        } else {
            Modifier::BOLD
        };
        let title_style = Style::default()
            .fg(spec.title_color)
            .add_modifier(highlight_modifier);
        let brief_style = Style::default()
            .fg(spec.brief_color)
            .add_modifier(highlight_modifier);
        let max_line_w = spec
            .width
            .saturating_sub(BODY_INDENT)
            .saturating_sub(2)
            .max(1);
        let sep = " · ";
        let sep_w = display_width(sep);
        let action_w = display_width(title);
        let brief_max = max_line_w.saturating_sub(action_w).saturating_sub(sep_w);
        let brief_shown = if brief.trim().is_empty() {
            String::new()
        } else {
            truncate_to_width(brief, brief_max.max(1))
        };
        let mut spans = vec![
            Span::styled(" ".repeat(BODY_INDENT), spec.body_style),
            Span::styled(title.to_string(), title_style),
        ];
        if !brief_shown.trim().is_empty() {
            spans.push(Span::styled(sep.to_string(), brief_style));
            spans.push(Span::styled(brief_shown, brief_style));
        }
        finalize_header_with_toggle(spans, spec.width, spec.body_style, Some(spec.expanded))
    }

    fn tool_header_action(run: &ToolRun, default: &'static str) -> String {
        let raw = run.action_label.trim();
        if raw.is_empty()
            || raw.eq_ignore_ascii_case("run")
            || raw.eq_ignore_ascii_case("ran")
            || raw.eq_ignore_ascii_case(default)
            || (default == "EDIT" && raw.eq_ignore_ascii_case("edit file"))
        {
            default.to_string()
        } else {
            raw.to_ascii_uppercase()
        }
    }

