    fn build_parallel_batch_item_header_line(
        run: &ToolRun,
        width: usize,
        body_style: Style,
        highlighted: bool,
        expanded: bool,
    ) -> (Line<'static>, Option<Range<usize>>) {
        let meta = parallel_batch_meta(run);
        let failed = run.action_label.trim().eq_ignore_ascii_case("failed");
        let action_style = if failed {
            Style::default()
                .fg(Color::Rgb(255, 184, 184))
                .add_modifier(Modifier::BOLD)
        } else if highlighted {
            Style::default()
                .fg(Color::Rgb(214, 242, 255))
                .add_modifier(Modifier::BOLD | Modifier::UNDERLINED)
        } else {
            Style::default()
                .fg(Color::Rgb(200, 236, 248))
                .add_modifier(Modifier::BOLD)
        };
        let brief_style = if failed {
            Style::default().fg(Color::Rgb(255, 216, 216))
        } else if highlighted {
            Style::default()
                .fg(Color::Rgb(232, 246, 252))
                .add_modifier(Modifier::BOLD | Modifier::UNDERLINED)
        } else {
            Style::default().fg(Color::Rgb(216, 240, 248))
        };
        let action = meta
            .map(|meta| meta.item_action.trim())
            .filter(|value: &&str| !value.is_empty())
            .unwrap_or("Run");
        let title = format!("○ {:<6}", action);
        let brief = if run.brief.trim().is_empty() {
            tool_chain_follower_label(run)
        } else {
            run.brief.trim().to_string()
        };
        let max_line_w = width.saturating_sub(BODY_INDENT).saturating_sub(2).max(1);
        let sep = " · ";
        let sep_w = display_width(sep);
        let title_w = display_width(title.as_str());
        let brief_max = max_line_w.saturating_sub(title_w).saturating_sub(sep_w);
        let brief_shown = truncate_to_width(brief.as_str(), brief_max.max(1));
        let mut spans = vec![
            Span::styled(" ".repeat(BODY_INDENT), body_style),
            Span::styled(title, action_style),
        ];
        if !brief_shown.trim().is_empty() {
            spans.push(Span::styled(sep.to_string(), brief_style));
            spans.push(Span::styled(brief_shown, brief_style));
        }
        finalize_header_with_toggle(spans, width, body_style, Some(expanded))
    }

