    fn tool_frame_width(run: &ToolRun, width: usize) -> usize {
        if is_apply_patch_tool(run) {
            let mut header = format!("● Edit File · {}", tool_header_action(run, "EDIT"));
            if !run.brief.trim().is_empty() {
                header.push_str(" · ");
                header.push_str(truncate_to_width(run.brief.as_str(), 24).as_str());
            }
            let header_width = display_width(header.as_str()).saturating_add(4);
            let min_width = tool_frame_min_width();
            let max_width = width
                .saturating_sub(TOOL_FRAME_INDENT)
                .max(min_width)
                .min(34usize.max(min_width));
            return header_width.clamp(min_width, max_width);
        }
        if is_parallel_tool(run) {
            let header = "● Explore".to_string();
            let header_width = display_width(header.as_str()).saturating_add(4);
            let min_width = tool_frame_min_width();
            let max_width = width
                .saturating_sub(TOOL_FRAME_INDENT)
                .max(min_width)
                .min(42usize.max(min_width));
            return header_width.clamp(min_width, max_width);
        }
        if is_parallel_batch_item(run) {
            let header = "● Explore".to_string();
            let header_width = display_width(header.as_str()).saturating_add(4);
            let min_width = tool_frame_min_width();
            let max_width = width
                .saturating_sub(TOOL_FRAME_INDENT)
                .max(min_width)
                .min(42usize.max(min_width));
            return header_width.clamp(min_width, max_width);
        }
        if is_context_manage_tool(run) {
            let meta = context_manage_render_meta(run);
            let mut header = context_manage_header_title(&meta).to_string();
            if !run.brief.trim().is_empty() {
                header.push_str(" · ");
                header.push_str(truncate_to_width(run.brief.as_str(), 32).as_str());
            }
            let header_width = display_width(header.as_str()).saturating_add(4);
            let min_width = tool_frame_min_width();
            let max_width = if meta.is_focus_mode() {
                width.saturating_sub(TOOL_FRAME_INDENT).max(min_width)
            } else {
                width
                    .saturating_sub(TOOL_FRAME_INDENT)
                    .max(min_width)
                    .min(44usize.max(min_width))
            };
            return header_width.clamp(min_width, max_width);
        }
        if is_tool_manage_tool(run) {
            let mut header = format!("● Toolbox · {}", tool_manage_action(run));
            if !run.brief.trim().is_empty() {
                header.push_str(" · ");
                header.push_str(truncate_to_width(run.brief.as_str(), 24).as_str());
            }
            let header_width = display_width(header.as_str()).saturating_add(4);
            let min_width = tool_frame_min_width();
            let max_width = width
                .saturating_sub(TOOL_FRAME_INDENT)
                .max(min_width)
                .min(44usize.max(min_width));
            return header_width.clamp(min_width, max_width);
        }
        if is_persona_manage_tool(run) {
            let mut header = format!("● Communicate · {}", persona_manage_action(run));
            if !run.brief.trim().is_empty() {
                header.push_str(" · ");
                header.push_str(truncate_to_width(run.brief.as_str(), 24).as_str());
            }
            let header_width = display_width(header.as_str()).saturating_add(4);
            let min_width = tool_frame_min_width();
            let max_width = width
                .saturating_sub(TOOL_FRAME_INDENT)
                .max(min_width)
                .min(44usize.max(min_width));
            return header_width.clamp(min_width, max_width);
        }
        if is_update_plan_tool(run) {
            let mut header = update_plan_header_title(run.command_preview.as_str()).to_string();
            if !run.brief.trim().is_empty() {
                header.push_str(" · ");
                header.push_str(truncate_to_width(run.brief.as_str(), 24).as_str());
            }
            let header_width = display_width(header.as_str()).saturating_add(4);
            let min_width = tool_frame_min_width();
            let max_width = width
                .saturating_sub(TOOL_FRAME_INDENT)
                .max(min_width)
                .min(36usize.max(min_width));
            return header_width.clamp(min_width, max_width);
        }
        if is_view_image_tool(run) {
            let mut header = format!("● View Image · {}", tool_header_action(run, "VIEW"));
            if !run.brief.trim().is_empty() {
                header.push_str(" · ");
                header.push_str(truncate_to_width(run.brief.as_str(), 24).as_str());
            }
            let header_width = display_width(header.as_str()).saturating_add(4);
            let min_width = tool_frame_min_width();
            let max_width = width
                .saturating_sub(TOOL_FRAME_INDENT)
                .max(min_width)
                .min(38usize.max(min_width));
            return header_width.clamp(min_width, max_width);
        }
        if is_ask_user_tool(run) {
            let mut header = "● Make Decision · ASK".to_string();
            if !run.brief.trim().is_empty() {
                header.push_str(" · ");
                header.push_str(truncate_to_width(run.brief.as_str(), 24).as_str());
            }
            let header_width = display_width(header.as_str()).saturating_add(4);
            let min_width = tool_frame_min_width();
            let max_width = width
                .saturating_sub(TOOL_FRAME_INDENT)
                .max(min_width)
                .min(40usize.max(min_width));
            return header_width.clamp(min_width, max_width);
        }
        if is_agent_tool(run) {
            let mut header = agent_tool_title(run).to_string();
            if !run.brief.trim().is_empty() {
                header.push_str(" · ");
                header.push_str(truncate_to_width(run.brief.as_str(), 24).as_str());
            }
            let header_width = display_width(header.as_str()).saturating_add(4);
            let min_width = tool_frame_min_width();
            let max_width = width
                .saturating_sub(TOOL_FRAME_INDENT)
                .max(min_width)
                .min(42usize.max(min_width));
            return header_width.clamp(min_width, max_width);
        }
        if is_batch_tool(run) {
            let mut header = batch_tool_title(run).to_string();
            if !run.brief.trim().is_empty() {
                header.push_str(" · ");
                header.push_str(truncate_to_width(run.brief.as_str(), 24).as_str());
            }
            let header_width = display_width(header.as_str()).saturating_add(4);
            let min_width = tool_frame_min_width();
            let max_width = width
                .saturating_sub(TOOL_FRAME_INDENT)
                .max(min_width)
                .min(42usize.max(min_width));
            return header_width.clamp(min_width, max_width);
        }
        let action = if run.action_label.trim().is_empty() {
            if run.completed { "Ran" } else { "Run" }
        } else {
            run.action_label.as_str()
        };
        let kind = display_tool_kind(run);
        let mut header = format!("● {kind} · {action}");
        if !run.brief.trim().is_empty() {
            header.push_str(" · ");
            header.push_str(truncate_to_width(run.brief.as_str(), 24).as_str());
        }
        let header_width = display_width(header.as_str()).saturating_add(4);
        let min_width = tool_frame_min_width();
        let frame_cap = if exec_command_family_label(run.command_preview.as_str()).is_some() {
            44usize
        } else {
            34usize
        };
        let max_width = width
            .saturating_sub(TOOL_FRAME_INDENT)
            .max(min_width)
            .min(frame_cap.max(min_width));
        header_width.clamp(min_width, max_width)
    }

    fn clamp_tool_detail_lines(
        lines: Vec<Line<'static>>,
        max_lines: usize,
        width: usize,
        indent: usize,
        body_style: Style,
        omitted_style: Style,
    ) -> Vec<Line<'static>> {
        if lines.len() <= max_lines {
            return lines;
        }
        if max_lines <= 1 {
            return lines.into_iter().take(max_lines).collect();
        }
        let head = max_lines.div_ceil(2);
        let tail = max_lines.saturating_sub(head + 1);
        let omitted = lines.len().saturating_sub(head + tail);
        let mut out = Vec::with_capacity(max_lines);
        out.extend(lines.iter().take(head).cloned());
        out.push(finalize_tool_preview_line(
            vec![
                Span::styled(" ".repeat(indent), body_style),
                Span::styled(format!("… +{omitted}"), omitted_style),
            ],
            width,
            body_style,
        ));
        out.extend(lines.iter().skip(lines.len().saturating_sub(tail)).cloned());
        out
    }

    fn build_tool_section_label_line(
        label: &str,
        width: usize,
        body_style: Style,
    ) -> Line<'static> {
        finalize_tool_preview_line(
            vec![
                Span::styled(" ".repeat(TOOL_BLOCK_INDENT), body_style),
                Span::styled(
                    label.to_string(),
                    Style::default().fg(Color::Rgb(168, 184, 204)),
                ),
            ],
            width,
            body_style,
        )
    }

    fn finalize_tool_preview_line(
        spans: Vec<Span<'static>>,
        width: usize,
        body_style: Style,
    ) -> Line<'static> {
        finalize_tool_preview_line_with_gutter(spans, width, body_style, 0)
    }

    fn finalize_tool_preview_line_with_gutter(
        spans: Vec<Span<'static>>,
        width: usize,
        body_style: Style,
        right_gutter: usize,
    ) -> Line<'static> {
        fit_spans_to_width_with_gutter(spans, width, body_style, right_gutter)
    }

    fn fit_spans_to_width(
        spans: Vec<Span<'static>>,
        width: usize,
        pad_style: Style,
    ) -> Line<'static> {
        fit_spans_to_width_with_gutter(spans, width, pad_style, 0)
    }

    fn fit_spans_to_width_with_gutter(
        spans: Vec<Span<'static>>,
        width: usize,
        pad_style: Style,
        right_gutter: usize,
    ) -> Line<'static> {
        let target_width = width.max(1);
        let content_width = target_width.saturating_sub(right_gutter).max(1);
        let mut used = 0usize;
        let mut out = Vec::new();
        for span in spans {
            if used >= content_width {
                break;
            }
            let remaining = content_width.saturating_sub(used);
            let fitted = truncate_to_width(span.content.as_ref(), remaining);
            let fitted_width = display_width(fitted.as_str());
            if fitted_width == 0 {
                continue;
            }
            out.push(Span::styled(fitted, span.style));
            used = used.saturating_add(fitted_width);
        }
        if used < target_width {
            out.push(Span::styled(" ".repeat(target_width - used), pad_style));
        }
        Line::from(out)
    }

    fn tool_preview_prefix_width(connector: char, label: &str) -> usize {
        BODY_INDENT
            .saturating_add(display_width(connector.to_string().as_str()))
            .saturating_add(2)
            .saturating_add(display_width(label))
            .saturating_add(1)
    }

    fn tool_preview_lines(text: &str) -> Vec<&str> {
        let mut lines = text
            .split('\n')
            .map(|line| line.trim_end_matches('\r'))
            .collect::<Vec<_>>();
        while lines.last().is_some_and(|line| line.trim().is_empty()) {
            lines.pop();
        }
        lines
    }

    fn collapsed_tool_preview_budget(
        raw_lines: &[&str],
        width: usize,
        prefix_width: usize,
        right_gutter: usize,
    ) -> (usize, usize, String) {
        let sampled_lines = raw_lines
            .iter()
            .take(TOOL_COLLAPSED_WRAP_SAMPLE_LINES)
            .map(|line| {
                line.chars()
                    .take(TOOL_COLLAPSED_WRAP_SAMPLE_CHARS)
                    .collect::<String>()
            })
            .collect::<Vec<_>>();
        let omitted_raw_lines = raw_lines.len().saturating_sub(sampled_lines.len());
        let mut preview_width = width
            .saturating_sub(prefix_width)
            .saturating_sub(right_gutter)
            .max(1);
        let mut settled_extra = 0usize;
        let mut settled_suffix = String::new();
        for _ in 0..6 {
            let wrapped_total = sampled_lines
                .iter()
                .map(|line| wrap_preformatted_line(line.as_str(), preview_width).len())
                .sum::<usize>()
                .max(1);
            let next_extra = wrapped_total
                .saturating_sub(1)
                .saturating_add(omitted_raw_lines);
            let next_suffix = if next_extra > 0 {
                format!(" +{next_extra}")
            } else {
                String::new()
            };
            let next_preview_width = width
                .saturating_sub(prefix_width)
                .saturating_sub(display_width(next_suffix.as_str()))
                .saturating_sub(right_gutter)
                .max(1);
            settled_extra = next_extra;
            settled_suffix = next_suffix;
            if next_preview_width == preview_width {
                break;
            }
            preview_width = next_preview_width;
        }
        (preview_width, settled_extra, settled_suffix)
    }

    fn collapse_tool_preview_text(text: &str, preview_width: usize) -> String {
        if text.trim().is_empty() {
            return String::from("(empty)");
        }
        let raw_w = display_width(text);
        if raw_w <= preview_width {
            text.to_string()
        } else if preview_width <= 3 {
            truncate_to_width(text, preview_width)
        } else {
            format!(
                "{}...",
                truncate_to_width(text, preview_width.saturating_sub(3))
            )
        }
    }

    fn build_tool_preview_line(
        connector: char,
        connector_style: Style,
        label: &str,
        text: &str,
        spec: ToolPreviewSpec,
        text_style: Style,
    ) -> Line<'static> {
        let width = spec.width.max(1);
        let body_style = spec.body_style;
        let preview_lines = tool_preview_lines(text);
        let first_line = preview_lines.first().copied().unwrap_or("");
        let prefix_width = tool_preview_prefix_width(connector, label);
        let (preview_width, extra_lines, suffix) = collapsed_tool_preview_budget(
            preview_lines.as_slice(),
            width,
            prefix_width,
            spec.right_gutter,
        );
        let preview = collapse_tool_preview_text(first_line, preview_width);
        let mut spans = vec![
            Span::styled(" ".repeat(BODY_INDENT), body_style),
            Span::styled(connector.to_string(), connector_style),
            Span::styled("  ", body_style),
            Span::styled(
                label.to_string(),
                Style::default().fg(Color::Rgb(168, 184, 204)),
            ),
            Span::styled(" ", body_style),
            Span::styled(preview, text_style),
        ];
        if extra_lines > 0 {
            spans.push(Span::styled(suffix, spec.suffix_style));
        }
        finalize_tool_preview_line_with_gutter(spans, width, body_style, spec.right_gutter)
    }

    fn build_tool_summary_preview_line(
        connector: char,
        connector_style: Style,
        label: &str,
        summary: &str,
        raw_text: &str,
        spec: ToolPreviewSpec,
        text_style: Style,
    ) -> Line<'static> {
        let width = spec.width.max(1);
        let body_style = spec.body_style;
        let raw_preview_lines = tool_preview_lines(raw_text);
        let prefix_width = tool_preview_prefix_width(connector, label);
        let (preview_width, extra_lines, suffix) = collapsed_tool_preview_budget(
            raw_preview_lines.as_slice(),
            width,
            prefix_width,
            spec.right_gutter,
        );
        let preview_text = if summary.trim().is_empty() {
            "(empty)"
        } else {
            summary.trim()
        };
        let preview = collapse_tool_preview_text(preview_text, preview_width);
        let mut spans = vec![
            Span::styled(" ".repeat(BODY_INDENT), body_style),
            Span::styled(connector.to_string(), connector_style),
            Span::styled("  ", body_style),
            Span::styled(
                label.to_string(),
                Style::default().fg(Color::Rgb(168, 184, 204)),
            ),
            Span::styled(" ", body_style),
            Span::styled(preview, text_style),
        ];
        if extra_lines > 0 {
            spans.push(Span::styled(suffix, spec.suffix_style));
        }
        finalize_tool_preview_line_with_gutter(spans, width, body_style, spec.right_gutter)
    }

    fn bound_expanded_tool_text(text: &str) -> String {
        let mut kept = Vec::new();
        let mut omitted_lines = 0usize;
        let mut used_chars = 0usize;
        let lines = text
            .split('\n')
            .map(|line| line.trim_end_matches('\r'))
            .collect::<Vec<_>>();
        for (index, line) in lines.iter().enumerate() {
            let line_chars = line.chars().count();
            if index >= TOOL_EXPANDED_RAW_LINE_BUDGET
                || used_chars.saturating_add(line_chars) > TOOL_EXPANDED_RAW_CHAR_BUDGET
            {
                omitted_lines = lines.len().saturating_sub(index);
                if index < TOOL_EXPANDED_RAW_LINE_BUDGET
                    && used_chars < TOOL_EXPANDED_RAW_CHAR_BUDGET
                {
                    let remaining = TOOL_EXPANDED_RAW_CHAR_BUDGET.saturating_sub(used_chars);
                    let mut snippet = line.chars().take(remaining).collect::<String>();
                    if snippet.chars().count() < line_chars {
                        snippet.push('…');
                    }
                    if !snippet.trim().is_empty() {
                        kept.push(snippet);
                    }
                }
                break;
            }
            kept.push((*line).to_string());
            used_chars = used_chars.saturating_add(line_chars).saturating_add(1);
        }
        if omitted_lines > 0 {
            kept.push(format!(
                "… raw output truncated before wrapping (+{omitted_lines} lines)"
            ));
        }
        while kept.last().is_some_and(|line| line.trim().is_empty()) {
            kept.pop();
        }
        kept.join("\n")
    }

    fn render_expanded_tool_section(
        label: &str,
        text: &str,
        width: usize,
        body_style: Style,
        text_style: Style,
    ) -> Vec<Line<'static>> {
        let bounded_text = bound_expanded_tool_text(text);
        let lines = render_preformatted_block_with_indent(
            bounded_text.as_str(),
            width,
            TOOL_BLOCK_INDENT,
            body_style,
            text_style,
        );
        let mut out = Vec::new();
        out.push(build_tool_section_label_line(label, width, body_style));
        let clamped = if lines.len() > TOOL_EXPANDED_SOFT_LIMIT {
            clamp_tool_detail_lines(
                lines,
                TOOL_EXPANDED_MAX_LINES,
                width,
                TOOL_BLOCK_INDENT,
                body_style,
                Style::default().fg(Color::Rgb(210, 176, 132)),
            )
        } else {
            lines
        };
        out.extend(clamped);
        out
    }

    fn build_parallel_item_title_line(
        item: &ParallelToolRenderItem,
        width: usize,
        body_style: Style,
    ) -> Line<'static> {
        let failed = item.status.as_deref() == Some("failed");
        let action_style = if failed {
            Style::default()
                .fg(Color::Rgb(255, 184, 184))
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default()
                .fg(Color::Rgb(200, 236, 248))
                .add_modifier(Modifier::BOLD)
        };
        let brief_style = if failed {
            Style::default().fg(Color::Rgb(255, 216, 216))
        } else {
            Style::default().fg(Color::Rgb(216, 240, 248))
        };
        let action = if item.action.trim().is_empty() {
            "Run".to_string()
        } else {
            format!("{:<6}", item.action.trim())
        };
        let title = format!("○ {}", action);
        let brief = parallel_tool_item_brief(item);
        let max_line_w = width.saturating_sub(BODY_INDENT).saturating_sub(2).max(1);
        let sep = " · ";
        let sep_w = display_width(sep);
        let title_w = display_width(title.as_str());
        let brief_max = max_line_w.saturating_sub(title_w).saturating_sub(sep_w);
        let brief_shown = truncate_to_width(brief.as_str(), brief_max.max(1));
        let mut spans = vec![
            Span::styled(" ".repeat(BODY_INDENT), body_style),
            Span::styled(title, action_style),
        ];
        if !brief_shown.trim().is_empty() {
            spans.push(Span::styled(sep.to_string(), brief_style));
            spans.push(Span::styled(brief_shown, brief_style));
        }
        fit_spans_to_width(spans, width, body_style)
    }

    fn render_parallel_tool_block(
        run: &ToolRun,
        width: usize,
        body_style: Style,
        expanded: bool,
    ) -> Option<Vec<Line<'static>>> {
        let payload = parallel_tool_payload(run)?;
        if payload.items.is_empty() {
            return Some(vec![build_tool_preview_line(
                '└',
                Style::default().fg(Color::Rgb(118, 112, 92)),
                "[- Output -]:",
                "(empty)",
                ToolPreviewSpec::new(width, body_style, false),
                Style::default().fg(Color::Rgb(188, 196, 204)),
            )]);
        }
        let mut lines = Vec::new();
        for (index, item) in payload.items.iter().enumerate() {
            if expanded && index > 0 {
                lines.push(Line::from(""));
            }
            lines.push(build_parallel_item_title_line(item, width, body_style));
            if expanded {
                lines.extend(render_expanded_tool_section(
                    "[- INPUT -]:",
                    item.input.as_str(),
                    width,
                    body_style,
                    Style::default().fg(Color::Rgb(220, 228, 236)),
                ));
                if let Some(output) = item.output.as_deref() {
                    lines.extend(render_expanded_tool_section(
                        "[- Output -]:",
                        output,
                        width,
                        body_style,
                        if item.status.as_deref() == Some("failed") {
                            Style::default().fg(Color::Rgb(255, 214, 214))
                        } else {
                            Style::default().fg(Color::Rgb(214, 222, 232))
                        },
                    ));
                }
            }
        }
        Some(lines)
    }

