    #[derive(Debug, Clone, PartialEq, Eq)]
    struct ToolChainGroupMeta {
        title: String,
        leader: bool,
        tail: bool,
        parallel_batch: bool,
    }

    fn is_apply_patch_tool(run: &ToolRun) -> bool {
        run.name.trim().eq_ignore_ascii_case("apply_patch")
    }

    fn is_rewrite_section_tool(run: &ToolRun) -> bool {
        run.name.trim().eq_ignore_ascii_case("rewrite_section")
    }

    fn is_exec_preview_tool(run: &ToolRun) -> bool {
        matches!(
            run.name.trim(),
            "exec_command" | "command" | "shell_command"
        )
    }

    fn looks_like_shell_heredoc(line: &str) -> bool {
        let line = line.trim();
        line.contains("<<")
            && (line.contains("PY")
                || line.contains("EOF")
                || line.contains("SH")
                || line.contains("BASH")
                || line.contains("NODE")
                || line.contains("RUST"))
    }

    fn exec_command_input_summary(text: &str) -> String {
        let normalized = normalize_tool_preview(text, false);
        let first = normalized
            .lines()
            .map(str::trim)
            .find(|line| !line.is_empty())
            .unwrap_or("(empty)");
        if looks_like_shell_heredoc(first) {
            return format!("{first} · heredoc");
        }
        first.to_string()
    }

    fn looks_like_exec_error_line(line: &str) -> bool {
        let lower = line.trim().to_ascii_lowercase();
        !lower.is_empty()
            && [
                "error",
                "failed",
                "exception",
                "traceback",
                "syntaxerror",
                "permission denied",
                "no such file",
                "not found",
                "panic",
                "fatal",
            ]
            .iter()
            .any(|needle| lower.contains(needle))
    }

    fn exec_command_output_summary(text: &str) -> String {
        let normalized = normalize_tool_preview(text, true);
        let lines = normalized
            .lines()
            .map(str::trim)
            .filter(|line| !line.is_empty())
            .collect::<Vec<_>>();
        if lines.is_empty() {
            return "(empty)".to_string();
        }
        if lines[0].starts_with("[Output saved") {
            return lines[0].to_string();
        }
        if let Some(line) = lines
            .iter()
            .rev()
            .find(|line| looks_like_exec_error_line(line))
        {
            return (*line).to_string();
        }
        lines[0].to_string()
    }

    fn command_preview_tokens(command_preview: &str) -> Vec<String> {
        command_preview
            .trim()
            .to_ascii_lowercase()
            .split(|ch: char| {
                ch.is_whitespace() || matches!(ch, ';' | '&' | '|' | '(' | ')' | '<' | '>')
            })
            .map(|token| token.trim_matches(|ch: char| matches!(ch, '"' | '\'' | '`')))
            .filter(|token| !token.is_empty())
            .map(str::to_string)
            .collect()
    }

