    fn persona_manage_target_from_status(status_preview: &str) -> Option<String> {
        let first = status_preview.lines().next()?.trim();
        if let Some(rest) = first.strip_prefix("To ") {
            return rest
                .split(" · persona_manage")
                .next()
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .map(str::to_string);
        }
        status_preview
            .lines()
            .find_map(|line| line.trim().strip_prefix("tab:").map(str::trim))
            .filter(|value| !value.is_empty())
            .map(str::to_string)
            .or_else(|| {
                status_preview
                    .lines()
                    .find_map(|line| line.trim().strip_prefix("persona:").map(str::trim))
                    .filter(|value| !value.is_empty())
                    .map(str::to_string)
            })
    }

