    fn context_manage_render_meta(run: &ToolRun) -> ContextManageRenderMeta {
        let mut action = None::<String>;
        let mut target = None::<String>;
        for raw_line in normalize_tool_preview(run.command_preview.as_str(), false).lines() {
            let Some((key, value)) = raw_line.split_once(':') else {
                continue;
            };
            match key.trim() {
                "action" => action = Some(crate::canonical_focus_mode_action(value.trim())),
                "target" => {
                    target = crate::canonical_context_target_name(value.trim()).map(str::to_string)
                }
                _ => {}
            }
        }
        let area = match action.as_deref() {
            Some(action) if crate::is_focus_mode_action(action) => "Focus".to_string(),
            _ => match target.as_deref() {
                Some("fastmemory") => "FastMemory".to_string(),
                Some(target) if crate::is_focus_context_target(target) => {
                    "FocusContext".to_string()
                }
                Some("context") => "Context".to_string(),
                _ if run.kind_label.trim().eq_ignore_ascii_case("focus")
                    || run.kind_label.trim().eq_ignore_ascii_case("task") =>
                {
                    "Focus".to_string()
                }
                _ => "Context".to_string(),
            },
        };
        ContextManageRenderMeta {
            action: action.unwrap_or_default(),
            area,
        }
    }

    impl ContextManageRenderMeta {
        fn is_focus_mode(&self) -> bool {
            crate::is_focus_mode_action(self.action.as_str())
        }
    }

