    fn render_update_plan_block(
        text: &str,
        width: usize,
        body_style: Style,
        connector_style: Style,
    ) -> Vec<Line<'static>> {
        let (summary, items) = parse_update_plan_display(text);
        let label = update_plan_preview_label(text);
        let mut out = vec![build_tool_preview_line(
            '└',
            connector_style,
            label,
            summary.as_str(),
            ToolPreviewSpec::new(width, body_style, false),
            Style::default()
                .fg(Color::Rgb(224, 224, 224))
                .add_modifier(Modifier::BOLD),
        )];
        let total_items = items.len();
        let mut items = items
            .into_iter()
            .take(UPDATE_PLAN_RENDER_STEP_LIMIT)
            .collect::<Vec<_>>();
        if total_items > UPDATE_PLAN_RENDER_STEP_LIMIT {
            items.push(StyledDetailLine {
                text: format!(
                    "… 另有 {} 步已折叠",
                    total_items.saturating_sub(UPDATE_PLAN_RENDER_STEP_LIMIT)
                ),
                style: Style::default().fg(Color::Rgb(150, 170, 184)),
            });
        }
        let rendered_items = render_styled_preformatted_lines_with_indent(
            items.as_slice(),
            width,
            TOOL_BLOCK_INDENT,
            body_style,
        );
        out.extend(rendered_items);
        out
    }

    fn update_plan_mode_from_preview(text: &str) -> &'static str {
        let normalized = normalize_tool_preview(text, true);
        for raw_line in normalized.lines().take(6) {
            let line = raw_line.trim();
            if line.to_ascii_lowercase().starts_with("mode:") {
                let value = line
                    .split_once(':')
                    .map(|(_, value)| value.trim().to_ascii_lowercase())
                    .unwrap_or_default();
                return match value.as_str() {
                    "decision" => "decision",
                    "blueprint" => "blueprint",
                    _ => "plan",
                };
            }
        }
        let first = normalized
            .lines()
            .map(str::trim)
            .find(|line| !line.is_empty())
            .unwrap_or_default()
            .to_ascii_lowercase();
        if first.starts_with("decision ") || first.starts_with("decision ·") {
            "decision"
        } else if first.starts_with("blueprint ") || first.starts_with("blueprint ·") {
            "blueprint"
        } else {
            "plan"
        }
    }

    fn update_plan_header_title(text: &str) -> &'static str {
        match update_plan_mode_from_preview(text) {
            "decision" => "● Plan · DECISION",
            "blueprint" => "● Plan · BLUEPRINT",
            _ => "● Plan · UPDATE",
        }
    }

    fn update_plan_preview_label(text: &str) -> &'static str {
        match update_plan_mode_from_preview(text) {
            "decision" => "[- Decision -]:",
            "blueprint" => "[- Blueprint -]:",
            _ => "[- PLAN -]:",
        }
    }

    fn parse_update_plan_display(text: &str) -> (String, Vec<StyledDetailLine>) {
        let normalized = normalize_tool_preview(text, true);
        let mut steps = Vec::new();
        let mut declared_steps = None;
        for raw_line in normalized.lines() {
            let line = raw_line.trim();
            if line.is_empty() {
                continue;
            }
            if declared_steps.is_none() {
                declared_steps = parse_update_plan_declared_count(line);
            }
            if let Some(text) = line.strip_prefix("[completed]") {
                steps.push(StyledDetailLine {
                    text: format!("● {}", text.trim()),
                    style: Style::default()
                        .fg(Color::Rgb(136, 214, 166))
                        .add_modifier(Modifier::BOLD),
                });
            } else if let Some(text) = line.strip_prefix("[in_progress]") {
                steps.push(StyledDetailLine {
                    text: format!("○ {}", text.trim()),
                    style: Style::default()
                        .fg(Color::Rgb(244, 244, 244))
                        .add_modifier(Modifier::BOLD),
                });
            } else if let Some(text) = line.strip_prefix("[pending]") {
                steps.push(StyledDetailLine {
                    text: format!("○ {}", text.trim()),
                    style: Style::default().fg(Color::Rgb(236, 236, 236)),
                });
            }
        }
        if steps.is_empty() {
            steps.push(StyledDetailLine {
                text: "○ (empty)".to_string(),
                style: Style::default().fg(Color::Rgb(236, 236, 236)),
            });
        }
        let count = declared_steps.unwrap_or(steps.len());
        (format!("{count} 步"), steps)
    }

    fn build_web_search_header_line(
        run: &ToolRun,
        width: usize,
        body_style: Style,
        highlighted: bool,
        toggle: Option<bool>,
    ) -> (Line<'static>, Option<Range<usize>>) {
        let title_style = if highlighted {
            Style::default()
                .fg(Color::Rgb(180, 236, 255))
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default()
                .fg(Color::Rgb(142, 214, 255))
                .add_modifier(Modifier::BOLD)
        };
        let brief_style = if highlighted {
            Style::default()
                .fg(Color::Rgb(224, 248, 255))
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default()
                .fg(Color::Rgb(192, 230, 255))
                .add_modifier(Modifier::BOLD)
        };
        let action_text = format!("● WEB · {}", web_search_header_action(run));
        let brief = if run.brief.trim().is_empty() {
            web_search_brief(web_search_meta(run))
        } else {
            run.brief.clone()
        };
        let max_line_w = width.saturating_sub(BODY_INDENT).saturating_sub(2).max(1);
        let sep = " · ";
        let sep_w = display_width(sep);
        let action_w = display_width(action_text.as_str());
        let brief_max = max_line_w.saturating_sub(action_w).saturating_sub(sep_w);
        let brief_shown = if brief.trim().is_empty() {
            String::new()
        } else {
            truncate_to_width(brief.as_str(), brief_max.max(1))
        };
        let mut spans = vec![
            Span::styled(" ".repeat(BODY_INDENT), body_style),
            Span::styled(action_text, title_style),
        ];
        if !brief_shown.trim().is_empty() {
            spans.push(Span::styled(sep.to_string(), brief_style));
            spans.push(Span::styled(brief_shown, brief_style));
        }
        finalize_header_with_toggle(spans, width, body_style, toggle)
    }

    fn build_context_manage_header_line(
        run: &ToolRun,
        width: usize,
        body_style: Style,
        highlighted: bool,
        expanded: bool,
    ) -> (Line<'static>, Option<Range<usize>>) {
        let meta = context_manage_render_meta(run);
        let title = context_manage_header_title(&meta);
        let title_color = if meta.area == "Task" || meta.area == "FocusContext" {
            if highlighted {
                Color::Rgb(212, 186, 255)
            } else {
                Color::Rgb(188, 156, 255)
            }
        } else if highlighted {
            Color::Rgb(182, 222, 255)
        } else {
            Color::Rgb(156, 208, 255)
        };
        let brief_color = if highlighted {
            Color::Rgb(232, 244, 255)
        } else {
            Color::Rgb(208, 232, 255)
        };
        build_named_tool_header_line(
            title,
            run.brief.as_str(),
            NamedToolHeaderSpec {
                width,
                body_style,
                highlighted,
                expanded,
                title_color,
                brief_color,
            },
        )
    }

    fn web_search_search_lines(run: &ToolRun) -> Vec<String> {
        let mut lines = Vec::new();
        let mut push_unique = |value: String| {
            let trimmed = value.trim();
            if trimmed.is_empty() {
                return;
            }
            let normalized = trimmed.to_string();
            if !lines.iter().any(|existing| existing == &normalized) {
                lines.push(normalized);
            }
        };

        if let Some(meta) = web_search_meta(run)
            && let Some(action) = meta.action.as_ref()
        {
            match action {
                crate::WebSearchAction::Search { query, queries } => {
                    if let Some(query) = query.as_ref() {
                        push_unique(query.clone());
                    }
                    if let Some(queries) = queries.as_ref() {
                        for entry in queries {
                            push_unique(entry.clone());
                        }
                    }
                }
                crate::WebSearchAction::OpenPage { url } => {
                    if let Some(url) = url.as_ref() {
                        push_unique(url.clone());
                    }
                }
                crate::WebSearchAction::FindInPage { .. } => {
                    let detail = web_search_action_detail(action);
                    if !detail.trim().is_empty() {
                        push_unique(detail);
                    }
                }
                crate::WebSearchAction::Other => {}
            }
        }

        lines
    }

    fn web_search_search_block(run: &ToolRun) -> String {
        let mut lines = web_search_search_lines(run);
        if !lines.is_empty() {
            return lines.join("\n");
        }

        let fallback = normalize_tool_preview(
            if run.completed && !run.output_preview.trim().is_empty() {
                run.output_preview.as_str()
            } else {
                run.command_preview.as_str()
            },
            run.completed,
        );
        if !fallback.trim().is_empty() {
            return fallback;
        }

        if let Some(meta) = web_search_meta(run)
            && !meta.status.trim().is_empty()
        {
            lines.push(format!("状态：{}", meta.status.trim()));
        }
        lines.join("\n")
    }

    fn parse_update_plan_declared_count(line: &str) -> Option<usize> {
        let prefix = "Plan · ";
        let rest = line.strip_prefix(prefix)?;
        let digits = rest.chars().take_while(|ch| ch.is_ascii_digit()).count();
        if digits == 0 {
            return None;
        }
        rest[..digits].parse::<usize>().ok()
    }

    fn build_apply_patch_input_summary_line(
        connector: char,
        connector_style: Style,
        width: usize,
        body_style: Style,
        text: &str,
    ) -> Line<'static> {
        let summary = apply_patch_input_summary(text);
        build_tool_preview_line(
            connector,
            connector_style,
            "[- Path -]:",
            summary.as_str(),
            ToolPreviewSpec::new(width, body_style, false),
            Style::default().fg(Color::Rgb(150, 168, 190)),
        )
    }

    fn render_apply_patch_input_section(
        text: &str,
        width: usize,
        body_style: Style,
    ) -> Vec<Line<'static>> {
        let mut lines = Vec::new();
        let payload = apply_patch_payload(text);
        for raw_line in payload.lines() {
            let line = raw_line.trim_end_matches('\r');
            if matches!(line, "*** Begin Patch" | "*** End Patch") {
                continue;
            }
            if line.starts_with(' ') || line.trim().is_empty() {
                continue;
            }
            let style = if line.starts_with('+') {
                Style::default().fg(Color::Rgb(132, 188, 144))
            } else if line.starts_with('-') {
                Style::default().fg(Color::Rgb(208, 146, 146))
            } else {
                Style::default()
                    .fg(Color::Rgb(170, 196, 230))
                    .add_modifier(Modifier::BOLD)
            };
            lines.push(StyledDetailLine {
                text: line.to_string(),
                style,
            });
        }
        render_styled_detail_section("[- INPUT -]:", lines, width, body_style)
    }

    fn render_apply_patch_output_section(
        text: &str,
        width: usize,
        body_style: Style,
        connector_style: Style,
        tail_connector: char,
        max_lines: Option<usize>,
    ) -> Vec<Line<'static>> {
        let mut lines = apply_patch_output_lines(text);
        if let Some(limit) = max_lines {
            lines = clamp_middle_styled_detail_lines(lines, limit);
        }
        if lines.is_empty() {
            lines.push(ApplyPatchDisplayLine {
                kind: ApplyPatchDisplayKind::Plain,
                text: "(empty)".to_string(),
                style: Style::default().fg(Color::Rgb(190, 198, 214)),
            });
        }
        render_apply_patch_preview_block(
            if is_apply_patch_output_failure(text) {
                "[- Output -]:"
            } else {
                "[- Edited -]:"
            },
            lines.as_slice(),
            width,
            body_style,
            connector_style,
            tail_connector,
        )
    }

    fn context_manage_output_lines(run: &ToolRun, text: &str) -> Vec<ApplyPatchDisplayLine> {
        if is_context_manage_failed_run(run) {
            return context_manage_error_lines(text);
        }
        let normalized = normalize_tool_preview(text, true);
        let meta = context_manage_render_meta(run);
        let mut raw_lines = normalized
            .lines()
            .map(|line| line.trim_end_matches('\r').to_string())
            .collect::<Vec<_>>();
        let success = raw_lines
            .first()
            .is_some_and(|line| line.starts_with("ContextManage succeeded"));
        if success {
            raw_lines.remove(0);
            while raw_lines.first().is_some_and(|line| line.trim().is_empty()) {
                raw_lines.remove(0);
            }
        }
        raw_lines = raw_lines
            .into_iter()
            .filter_map(|line| sanitize_context_manage_output_line(&meta, line.as_str()))
            .collect();
        raw_lines
            .into_iter()
            .filter(|line| !line.trim().is_empty())
            .map(|line| parse_apply_patch_output_line(line.as_str()))
            .collect()
    }

    fn context_manage_error_lines(text: &str) -> Vec<ApplyPatchDisplayLine> {
        let normalized = normalize_tool_preview(text, true);
        let mut out = Vec::new();
        for (index, raw_line) in normalized.lines().enumerate() {
            let line = raw_line.trim_end_matches('\r');
            if line.trim().is_empty() {
                continue;
            }
            let style = if index == 0 {
                Style::default()
                    .fg(Color::Rgb(226, 150, 150))
                    .add_modifier(Modifier::BOLD)
            } else {
                Style::default().fg(Color::Rgb(214, 182, 182))
            };
            out.push(ApplyPatchDisplayLine {
                kind: ApplyPatchDisplayKind::Plain,
                text: line.to_string(),
                style,
            });
        }
        if out.is_empty() {
            out.push(ApplyPatchDisplayLine {
                kind: ApplyPatchDisplayKind::Plain,
                text: "(empty)".to_string(),
                style: Style::default().fg(Color::Rgb(190, 198, 214)),
            });
        }
        out
    }

    fn context_manage_error_summary_line(text: &str) -> ApplyPatchDisplayLine {
        context_manage_error_lines(text)
            .into_iter()
            .find(|line| !line.text.trim().is_empty())
            .unwrap_or(ApplyPatchDisplayLine {
                kind: ApplyPatchDisplayKind::Plain,
                text: "context_manage failed".to_string(),
                style: Style::default()
                    .fg(Color::Rgb(226, 150, 150))
                    .add_modifier(Modifier::BOLD),
            })
    }

    fn sanitize_context_manage_output_line(
        meta: &ContextManageRenderMeta,
        raw_line: &str,
    ) -> Option<String> {
        let line = raw_line.trim();
        if line.is_empty() {
            return None;
        }
        if !meta.is_focus_mode() {
            return Some(raw_line.to_string());
        }
        if line.starts_with("• Task · ENTER")
            || line.starts_with("• Task · EXIT")
            || line.starts_with("Task Plan · DETAIL")
        {
            return None;
        }
        if line.contains("[系统/focus_")
            && (line.contains(" + ") || line.contains(" - ") || line.contains(" = "))
        {
            return None;
        }
        let cleaned = if let Some((_, tail)) = line.split_once('|') {
            tail.trim().to_string()
        } else {
            line.to_string()
        };
        if cleaned.starts_with("Task Brief:") || cleaned.starts_with("Task Action:") {
            return None;
        }
        (!cleaned.trim().is_empty()).then_some(cleaned)
    }

    fn truncate_single_line_with_ellipsis(text: &str, width: usize) -> String {
        if width == 0 {
            return String::new();
        }
        if display_width(text) <= width {
            return text.to_string();
        }
        if width == 1 {
            return truncate_to_width(text, width);
        }
        format!("{}…", truncate_to_width(text, width.saturating_sub(1)))
    }

    fn build_single_line_tool_preview_line(
        connector: char,
        connector_style: Style,
        label: &str,
        text: &str,
        width: usize,
        body_style: Style,
        text_style: Style,
    ) -> Line<'static> {
        let has_label = !label.trim().is_empty();
        let prefix_width = if has_label {
            tool_preview_prefix_width(connector, label)
        } else {
            BODY_INDENT
                .saturating_add(display_width(connector.to_string().as_str()))
                .saturating_add(2)
        };
        let preview_width = width
            .saturating_sub(prefix_width)
            .saturating_sub(TOOL_PREVIEW_RIGHT_GUTTER)
            .max(1);
        let preview = if text.trim().is_empty() {
            "(empty)".to_string()
        } else {
            truncate_single_line_with_ellipsis(text, preview_width)
        };
        let mut spans = vec![
            Span::styled(" ".repeat(BODY_INDENT), body_style),
            Span::styled(connector.to_string(), connector_style),
            Span::styled("  ", body_style),
        ];
        if has_label {
            spans.push(Span::styled(
                label.to_string(),
                Style::default().fg(Color::Rgb(168, 184, 204)),
            ));
            spans.push(Span::styled(" ", body_style));
        }
        spans.push(Span::styled(preview, text_style));
        finalize_tool_preview_line_with_gutter(spans, width, body_style, TOOL_PREVIEW_RIGHT_GUTTER)
    }

    fn render_context_manage_preview_block(
        label: &str,
        lines: &[ApplyPatchDisplayLine],
        width: usize,
        body_style: Style,
        connector_style: Style,
        tail_connector: char,
    ) -> Vec<Line<'static>> {
        if lines.is_empty() {
            return vec![build_single_line_tool_preview_line(
                tail_connector,
                connector_style,
                label,
                "(empty)",
                width,
                body_style,
                Style::default().fg(Color::Rgb(190, 198, 214)),
            )];
        }
        let first = &lines[0];
        let mut out = vec![build_single_line_tool_preview_line(
            if lines.len() > 1 {
                '│'
            } else {
                tail_connector
            },
            connector_style,
            label,
            context_manage_display_line_text(first).as_str(),
            width,
            body_style,
            first.style,
        )];
        for (index, line) in lines[1..].iter().enumerate() {
            let connector = if index + 2 == lines.len() {
                tail_connector
            } else {
                '│'
            };
            out.push(build_single_line_tool_preview_line(
                connector,
                connector_style,
                "",
                context_manage_display_line_text(line).as_str(),
                width,
                body_style,
                line.style,
            ));
        }
        out
    }

    fn render_context_manage_expanded_block(
        label: &str,
        lines: &[ApplyPatchDisplayLine],
        width: usize,
        body_style: Style,
    ) -> Vec<Line<'static>> {
        let styled = lines
            .iter()
            .map(|line| StyledDetailLine {
                text: context_manage_display_line_text(line),
                style: line.style,
            })
            .collect::<Vec<_>>();
        render_styled_detail_section(label, styled, width, body_style)
    }

    fn render_context_manage_output_section(
        run: &ToolRun,
        text: &str,
        width: usize,
        body_style: Style,
        connector_style: Style,
        tail_connector: char,
        max_lines: Option<usize>,
    ) -> Vec<Line<'static>> {
        let mut lines = context_manage_output_lines(run, text);
        if is_context_manage_failed_run(run) {
            if max_lines == Some(CONTEXT_MANAGE_COLLAPSED_MAX_LINES) {
                lines = vec![context_manage_error_summary_line(text)];
            } else if let Some(limit) = max_lines {
                lines = clamp_middle_styled_detail_lines(lines, limit);
            }
        } else if let Some(limit) = max_lines {
            lines = clamp_middle_styled_detail_lines(lines, limit);
        }
        if lines.is_empty() {
            lines.push(ApplyPatchDisplayLine {
                kind: ApplyPatchDisplayKind::Plain,
                text: "(empty)".to_string(),
                style: Style::default().fg(Color::Rgb(190, 198, 214)),
            });
        }
        if max_lines == Some(CONTEXT_MANAGE_EXPANDED_MAX_LINES) {
            return render_context_manage_expanded_block(
                context_manage_section_label(run).as_str(),
                lines.as_slice(),
                width,
                body_style,
            );
        }
        render_context_manage_preview_block(
            context_manage_section_label(run).as_str(),
            lines.as_slice(),
            width,
            body_style,
            connector_style,
            tail_connector,
        )
    }

    fn render_styled_detail_section(
        label: &str,
        lines: Vec<StyledDetailLine>,
        width: usize,
        body_style: Style,
    ) -> Vec<Line<'static>> {
        let rendered = render_styled_preformatted_lines_with_indent(
            lines.as_slice(),
            width,
            TOOL_BLOCK_INDENT,
            body_style,
        );
        let mut out = Vec::new();
        out.push(build_tool_section_label_line(label, width, body_style));
        let clamped = if rendered.len() > TOOL_EXPANDED_SOFT_LIMIT {
            clamp_tool_detail_lines(
                rendered,
                TOOL_EXPANDED_MAX_LINES,
                width,
                TOOL_BLOCK_INDENT,
                body_style,
                Style::default().fg(Color::Rgb(210, 176, 132)),
            )
        } else {
            rendered
        };
        out.extend(clamped);
        out
    }

    fn render_styled_preformatted_lines_with_indent(
        lines: &[StyledDetailLine],
        width: usize,
        indent: usize,
        indent_style: Style,
    ) -> Vec<Line<'static>> {
        let content_width = width.saturating_sub(indent).max(1);
        let mut out = Vec::new();
        for line in lines {
            let wrapped = wrap_preformatted_line(line.text.as_str(), content_width);
            for segment in wrapped {
                out.push(finalize_tool_preview_line(
                    vec![
                        Span::styled(" ".repeat(indent), indent_style),
                        Span::styled(segment, line.style),
                    ],
                    width,
                    indent_style,
                ));
            }
        }
        out
    }

    fn apply_patch_payload(text: &str) -> &str {
        text.split_once('\n').map(|(_, rest)| rest).unwrap_or("")
    }

    fn tool_preview_key_values(text: &str) -> BTreeMap<String, String> {
        let mut out = BTreeMap::new();
        for raw_line in normalize_tool_preview(text, false).lines() {
            let line = raw_line.trim();
            if let Some((key, value)) = line.split_once(':') {
                let key = key.trim();
                let value = value.trim();
                if !key.is_empty() && !value.is_empty() {
                    out.insert(key.to_string(), value.to_string());
                }
            }
        }
        out
    }

    fn apply_patch_input_summary(text: &str) -> String {
        let targets = apply_patch_target_paths(text);
        match targets.split_first() {
            Some((first, [])) => preview_tool_path_display(first),
            Some((first, rest)) => format!("{} +{}", preview_tool_path_display(first), rest.len()),
            None => apply_patch_payload(text)
                .lines()
                .map(str::trim)
                .find(|line| !line.is_empty())
                .unwrap_or("(empty)")
                .to_string(),
        }
    }

    fn preview_tool_path_display(path: &str) -> String {
        if let Some((from, to)) = path.split_once(" → ") {
            return format!(
                "{} → {}",
                preview_tool_path_display(from),
                preview_tool_path_display(to)
            );
        }
        let components = path
            .split(['/', '\\'])
            .filter(|segment| !segment.is_empty() && *segment != ".")
            .collect::<Vec<_>>();
        match components.as_slice() {
            [] => path.trim().to_string(),
            [name] => (*name).to_string(),
            [.., parent, name] => format!("./{parent}/{name}"),
        }
    }

    fn apply_patch_target_paths(text: &str) -> Vec<String> {
        let mut targets = Vec::new();
        for raw_line in apply_patch_payload(text).lines() {
            let line = raw_line.trim_end_matches('\r');
            if let Some(path) = line.strip_prefix("*** Update File: ") {
                targets.push(path.trim().to_string());
            } else if let Some(path) = line.strip_prefix("*** Add File: ") {
                targets.push(path.trim().to_string());
            } else if let Some(path) = line.strip_prefix("*** Delete File: ") {
                targets.push(path.trim().to_string());
            } else if let Some(path) = line.strip_prefix("*** Move to: ") {
                let moved_to = path.trim();
                if let Some(last) = targets.last_mut() {
                    let old = last.clone();
                    *last = format!("{old} → {moved_to}");
                } else {
                    targets.push(moved_to.to_string());
                }
            }
        }
        targets
    }

    fn apply_patch_output_lines(text: &str) -> Vec<ApplyPatchDisplayLine> {
        let normalized = normalize_tool_preview(text, true);
        let mut raw_lines = normalized
            .lines()
            .map(|line| line.trim_end_matches('\r'))
            .collect::<Vec<_>>();
        let success = raw_lines
            .first()
            .is_some_and(|line| line.starts_with("ApplyPatch succeeded"));
        if success {
            raw_lines.remove(0);
            while raw_lines.first().is_some_and(|line| line.trim().is_empty()) {
                raw_lines.remove(0);
            }
        }
        raw_lines
            .into_iter()
            .filter(|line| !line.trim().is_empty())
            .map(parse_apply_patch_output_line)
            .collect()
    }

    fn is_apply_patch_output_failure(text: &str) -> bool {
        text.trim_start().starts_with("apply_patch failed")
    }

    fn rewrite_section_input_summary(text: &str) -> String {
        let fields = tool_preview_key_values(text);
        let path = fields
            .get("path")
            .map(|value| preview_tool_path_display(value))
            .unwrap_or_else(|| "(empty)".to_string());
        let mode = fields
            .get("mode")
            .cloned()
            .unwrap_or_else(|| "未识别".to_string());
        let expected = fields
            .get("expected_matches")
            .cloned()
            .unwrap_or_else(|| "1".to_string());
        format!("{path} · {mode} · x{expected}")
    }

    fn is_rewrite_section_output_failure(text: &str) -> bool {
        text.trim_start().starts_with("rewrite_section failed")
    }

    fn rewrite_section_output_summary(text: &str) -> String {
        let normalized = normalize_tool_preview(text, true);
        let lines = normalized
            .lines()
            .map(str::trim)
            .filter(|line| !line.is_empty())
            .collect::<Vec<_>>();
        if lines.is_empty() {
            return "(empty)".to_string();
        }
        if is_rewrite_section_output_failure(text) {
            return lines[0].to_string();
        }
        let fields = tool_preview_key_values(text);
        let path = fields
            .get("path")
            .map(|value| preview_tool_path_display(value))
            .unwrap_or_else(|| "(unknown)".to_string());
        let mode = fields
            .get("mode")
            .cloned()
            .unwrap_or_else(|| "未识别".to_string());
        let matches = fields
            .get("matches")
            .cloned()
            .unwrap_or_else(|| "0".to_string());
        let delta_suffix = lines[0]
            .rsplit_once(" (")
            .and_then(|(_, tail)| tail.strip_suffix(')'))
            .map(|tail| format!(" ({tail})"))
            .unwrap_or_else(|| {
                if lines[0].contains("no text changes") {
                    " · no text changes".to_string()
                } else {
                    String::new()
                }
            });
        format!("{path} · {mode} · {matches} match(es){delta_suffix}")
    }

    fn rewrite_section_input_detail_lines(text: &str) -> Vec<StyledDetailLine> {
        let normalized = normalize_tool_preview(text, false);
        let mut out = Vec::new();
        for (index, raw_line) in normalized.lines().enumerate() {
            let line = raw_line.trim_end_matches('\r');
            if index == 0 || line.trim().is_empty() {
                continue;
            }
            let trimmed = line.trim_start();
            let style = if trimmed.starts_with("path:") {
                Style::default()
                    .fg(Color::Rgb(244, 214, 142))
                    .add_modifier(Modifier::BOLD)
            } else if trimmed.starts_with("mode:")
                || trimmed.starts_with("expected_matches:")
                || trimmed.starts_with("replace_scope:")
                || trimmed.starts_with("regex_flags:")
            {
                Style::default().fg(Color::Rgb(182, 222, 255))
            } else if trimmed.starts_with("replace:") {
                Style::default().fg(Color::Rgb(132, 188, 144))
            } else if trimmed.starts_with("match:")
                || trimmed.starts_with("start_marker:")
                || trimmed.starts_with("end_marker:")
                || trimmed.starts_with("pattern:")
            {
                Style::default().fg(Color::Rgb(224, 208, 164))
            } else {
                Style::default().fg(Color::Rgb(196, 204, 214))
            };
            out.push(StyledDetailLine {
                text: line.to_string(),
                style,
            });
        }
        if out.is_empty() {
            out.push(StyledDetailLine {
                text: "(empty)".to_string(),
                style: Style::default().fg(Color::Rgb(190, 198, 214)),
            });
        }
        out
    }

    fn render_rewrite_section_input_section(
        text: &str,
        width: usize,
        body_style: Style,
    ) -> Vec<Line<'static>> {
        render_styled_detail_section(
            "[- Input -]:",
            rewrite_section_input_detail_lines(text),
            width,
            body_style,
        )
    }

    fn rewrite_section_output_detail_lines(text: &str) -> Vec<StyledDetailLine> {
        let normalized = normalize_tool_preview(text, true);
        let mut out = Vec::new();
        for (index, raw_line) in normalized.lines().enumerate() {
            let line = raw_line.trim_end_matches('\r');
            if line.trim().is_empty() {
                continue;
            }
            let trimmed = line.trim_start();
            let style = if index == 0 {
                if is_rewrite_section_output_failure(text) {
                    Style::default()
                        .fg(Color::Rgb(226, 150, 150))
                        .add_modifier(Modifier::BOLD)
                } else {
                    Style::default()
                        .fg(Color::Rgb(190, 222, 206))
                        .add_modifier(Modifier::BOLD)
                }
            } else if trimmed.starts_with("path:")
                || trimmed.starts_with("mode:")
                || trimmed.starts_with("matches:")
            {
                Style::default().fg(Color::Rgb(182, 222, 255))
            } else if trimmed.starts_with("• lines") {
                Style::default()
                    .fg(Color::Rgb(244, 214, 142))
                    .add_modifier(Modifier::BOLD)
            } else if trimmed.starts_with("before:") || trimmed.starts_with("- before:") {
                Style::default().fg(Color::Rgb(208, 146, 146))
            } else if trimmed.starts_with("after:") || trimmed.starts_with("+ after:") {
                Style::default().fg(Color::Rgb(132, 188, 144))
            } else if trimmed.starts_with("state:") {
                Style::default()
                    .fg(Color::Rgb(176, 182, 194))
                    .add_modifier(Modifier::DIM)
            } else {
                Style::default().fg(Color::Rgb(196, 204, 214))
            };
            out.push(StyledDetailLine {
                text: line.to_string(),
                style,
            });
        }
        if out.is_empty() {
            out.push(StyledDetailLine {
                text: "(empty)".to_string(),
                style: Style::default().fg(Color::Rgb(190, 198, 214)),
            });
        }
        out
    }

    fn render_rewrite_section_output_section(
        text: &str,
        width: usize,
        body_style: Style,
    ) -> Vec<Line<'static>> {
        render_styled_detail_section(
            if is_rewrite_section_output_failure(text) {
                "[- Output -]:"
            } else {
                "[- Edited -]:"
            },
            rewrite_section_output_detail_lines(text),
            width,
            body_style,
        )
    }

    fn clamp_middle_styled_detail_lines(
        lines: Vec<ApplyPatchDisplayLine>,
        max_lines: usize,
    ) -> Vec<ApplyPatchDisplayLine> {
        if max_lines == 0 || lines.len() <= max_lines {
            return lines;
        }
        if max_lines == 1 {
            return vec![lines[0].clone()];
        }
        let head = max_lines.div_ceil(2);
        let tail = max_lines.saturating_sub(head + 1);
        let omitted = lines.len().saturating_sub(head + tail);
        let mut out = Vec::with_capacity(max_lines);
        out.extend(lines.iter().take(head).cloned());
        out.push(ApplyPatchDisplayLine {
            kind: ApplyPatchDisplayKind::Omitted,
            text: format!("… +{omitted}"),
            style: Style::default()
                .fg(Color::Rgb(255, 112, 112))
                .add_modifier(Modifier::DIM),
        });
        out.extend(lines.iter().skip(lines.len().saturating_sub(tail)).cloned());
        out
    }

    fn context_manage_display_line_text(line: &ApplyPatchDisplayLine) -> String {
        match line.kind {
            ApplyPatchDisplayKind::Diff { line_no, marker } => match marker {
                Some('+') => format!("+ #{line_no} {}", line.text),
                Some('-') => format!("- #{line_no} {}", line.text),
                Some(marker) => format!("{marker} #{line_no} {}", line.text),
                None => format!("... #{line_no} {}", line.text),
            },
            _ => line.text.clone(),
        }
    }

    fn render_apply_patch_preview_block(
        label: &str,
        lines: &[ApplyPatchDisplayLine],
        width: usize,
        body_style: Style,
        connector_style: Style,
        tail_connector: char,
    ) -> Vec<Line<'static>> {
        if lines.is_empty() {
            return vec![build_tool_preview_line(
                tail_connector,
                connector_style,
                label,
                "(empty)",
                ToolPreviewSpec::new(width, body_style, false),
                Style::default().fg(Color::Rgb(190, 198, 214)),
            )];
        }
        let mut out = Vec::new();
        let first = &lines[0];
        let first_preview = apply_patch_display_line_text(first);
        out.push(build_tool_preview_line(
            if lines.len() > 1 {
                '│'
            } else {
                tail_connector
            },
            connector_style,
            label,
            first_preview.as_str(),
            ToolPreviewSpec::new(width, body_style, false),
            first.style,
        ));
        out.extend(render_apply_patch_followup_lines(
            &lines[1..],
            width,
            body_style,
            connector_style,
            tail_connector,
        ));
        out
    }

    fn render_apply_patch_followup_lines(
        lines: &[ApplyPatchDisplayLine],
        width: usize,
        body_style: Style,
        connector_style: Style,
        tail_connector: char,
    ) -> Vec<Line<'static>> {
        let line_no_width = lines
            .iter()
            .filter_map(|line| match line.kind {
                ApplyPatchDisplayKind::Diff { line_no, .. } => Some(line_no.to_string().len()),
                _ => None,
            })
            .max()
            .unwrap_or(1);
        let diff_prefix_width = line_no_width + 3;
        let plain_content_width = width.saturating_sub(BODY_INDENT + 3).max(1);
        let diff_content_width = width
            .saturating_sub(BODY_INDENT + 3 + diff_prefix_width)
            .max(1);
        let mut out = Vec::new();
        for (index, line) in lines.iter().enumerate() {
            let connector = if index + 1 == lines.len() {
                tail_connector
            } else {
                '│'
            };
            match line.kind {
                ApplyPatchDisplayKind::Diff { line_no, marker } => {
                    let wrapped = wrap_preformatted_line(line.text.as_str(), diff_content_width);
                    for (segment_index, segment) in wrapped.into_iter().enumerate() {
                        let segment_connector = if segment_index == 0 { connector } else { ' ' };
                        let mut spans = vec![
                            Span::styled(" ".repeat(BODY_INDENT), body_style),
                            Span::styled(segment_connector.to_string(), connector_style),
                            Span::styled("  ", body_style),
                        ];
                        if segment_index == 0 {
                            spans.push(Span::styled(
                                format!("{line_no:>width$}", width = line_no_width),
                                Style::default()
                                    .fg(Color::Rgb(128, 136, 150))
                                    .add_modifier(Modifier::DIM),
                            ));
                            match marker {
                                Some('+') => {
                                    spans.push(Span::styled(
                                        " + ".to_string(),
                                        Style::default()
                                            .fg(Color::Rgb(132, 188, 144))
                                            .add_modifier(Modifier::BOLD),
                                    ));
                                }
                                Some('-') => {
                                    spans.push(Span::styled(
                                        " - ".to_string(),
                                        Style::default()
                                            .fg(Color::Rgb(208, 146, 146))
                                            .add_modifier(Modifier::BOLD),
                                    ));
                                }
                                _ => {
                                    spans.push(Span::styled(
                                        "   ".to_string(),
                                        Style::default()
                                            .fg(Color::Rgb(128, 136, 150))
                                            .add_modifier(Modifier::DIM),
                                    ));
                                }
                            }
                        } else {
                            spans.push(Span::styled(" ".repeat(diff_prefix_width), body_style));
                        }
                        spans.push(Span::styled(segment, line.style));
                        out.push(finalize_tool_preview_line(spans, width, body_style));
                    }
                }
                _ => {
                    let wrapped = wrap_preformatted_line(line.text.as_str(), plain_content_width);
                    for (segment_index, segment) in wrapped.into_iter().enumerate() {
                        let segment_connector = if segment_index == 0 { connector } else { ' ' };
                        out.push(finalize_tool_preview_line(
                            vec![
                                Span::styled(" ".repeat(BODY_INDENT), body_style),
                                Span::styled(segment_connector.to_string(), connector_style),
                                Span::styled("  ", body_style),
                                Span::styled(segment, line.style),
                            ],
                            width,
                            body_style,
                        ));
                    }
                }
            }
        }
        out
    }

    fn parse_apply_patch_output_line(line: &str) -> ApplyPatchDisplayLine {
        let trimmed = line.trim();
        if trimmed.starts_with('•') {
            return ApplyPatchDisplayLine {
                kind: ApplyPatchDisplayKind::FileHeader,
                text: preview_apply_patch_file_header(trimmed.trim_start_matches('•').trim()),
                style: Style::default()
                    .fg(Color::Rgb(244, 214, 142))
                    .add_modifier(Modifier::BOLD),
            };
        }
        if let Some((line_no, marker, text)) = parse_apply_patch_diff_line(line) {
            let style = match marker {
                Some('+') => Style::default().fg(Color::Rgb(132, 188, 144)),
                Some('-') => Style::default().fg(Color::Rgb(208, 146, 146)),
                None => Style::default().fg(Color::Rgb(176, 182, 194)),
                _ => Style::default().fg(Color::Rgb(190, 198, 214)),
            };
            return ApplyPatchDisplayLine {
                kind: ApplyPatchDisplayKind::Diff { line_no, marker },
                text,
                style,
            };
        }
        ApplyPatchDisplayLine {
            kind: ApplyPatchDisplayKind::Plain,
            text: line.to_string(),
            style: apply_patch_output_line_style(line),
        }
    }

    fn preview_apply_patch_file_header(text: &str) -> String {
        let prefix = "Edited ";
        let Some(rest) = text.strip_prefix(prefix) else {
            return text.to_string();
        };
        let Some((path, suffix)) = rest.rsplit_once(" (") else {
            return text.to_string();
        };
        format!(
            "{prefix}{} ({suffix}",
            preview_tool_path_display(path.trim())
        )
    }

    fn parse_apply_patch_diff_line(line: &str) -> Option<(usize, Option<char>, String)> {
        let trimmed = line.trim_start();
        let digit_count = trimmed.chars().take_while(|ch| ch.is_ascii_digit()).count();
        if digit_count == 0 {
            return None;
        }
        let line_no = trimmed[..digit_count].parse::<usize>().ok()?;
        let rest = &trimmed[digit_count..];
        if let Some(text) = rest.strip_prefix(" + ") {
            return Some((line_no, Some('+'), text.to_string()));
        }
        if let Some(text) = rest.strip_prefix(" - ") {
            return Some((line_no, Some('-'), text.to_string()));
        }
        if let Some(text) = rest.strip_prefix("   ") {
            return Some((line_no, None, text.to_string()));
        }
        None
    }

    fn apply_patch_display_line_text(line: &ApplyPatchDisplayLine) -> String {
        match line.kind {
            ApplyPatchDisplayKind::Diff { line_no, marker } => match marker {
                Some(marker) => format!("{line_no} {marker} {}", line.text),
                None => format!("{line_no} {}", line.text),
            },
            _ => line.text.clone(),
        }
    }

    fn apply_patch_output_line_style(line: &str) -> Style {
        if line.starts_with("ApplyPatch succeeded") {
            return Style::default()
                .fg(Color::Rgb(170, 206, 238))
                .add_modifier(Modifier::BOLD);
        }
        if line.trim_start().starts_with('•') {
            return Style::default()
                .fg(Color::Rgb(244, 214, 142))
                .add_modifier(Modifier::BOLD);
        }
        if is_patch_display_line_with_marker(line, '+') {
            return Style::default().fg(Color::Rgb(132, 188, 144));
        }
        if is_patch_display_line_with_marker(line, '-') {
            return Style::default().fg(Color::Rgb(208, 146, 146));
        }
        if looks_like_patch_display_context(line) {
            return Style::default().fg(Color::Rgb(176, 182, 194));
        }
        Style::default().fg(Color::Rgb(190, 198, 214))
    }

    fn is_patch_display_line_with_marker(line: &str, marker: char) -> bool {
        let trimmed = line.trim_start();
        let digits = trimmed.chars().take_while(|ch| ch.is_ascii_digit()).count();
        if digits == 0 {
            return false;
        }
        let rest = trimmed[digits..].trim_start();
        rest.starts_with(marker)
    }

    fn looks_like_patch_display_context(line: &str) -> bool {
        let trimmed = line.trim_start();
        let digits = trimmed.chars().take_while(|ch| ch.is_ascii_digit()).count();
        if digits == 0 {
            return false;
        }
        let rest = trimmed[digits..].trim_start();
        !rest.starts_with('+') && !rest.starts_with('-')
    }

    fn normalize_tool_preview(text: &str, collapse_blank_runs: bool) -> String {
        let text = if text.contains('\n') || text.contains('\r') {
            text.to_string()
        } else {
            decode_tool_preview_escapes(text)
        };
        let text = sanitize_tool_preview_text(text.as_str());
        let mut out = Vec::new();
        let mut blank_open = false;
        for raw_line in text.split('\n') {
            let line = raw_line.trim_end_matches('\r');
            let is_blank = line.trim().is_empty();
            if is_blank {
                if collapse_blank_runs {
                    if !blank_open {
                        out.push(String::new());
                    }
                    blank_open = true;
                } else {
                    out.push(String::new());
                }
                continue;
            }
            blank_open = false;
            out.push(line.to_string());
        }
        while out.last().is_some_and(|line| line.trim().is_empty()) {
            out.pop();
        }
        out.join("\n")
    }

    fn sanitize_tool_preview_text(text: &str) -> String {
        let mut out = String::with_capacity(text.len());
        let mut chars = text.chars().peekable();
        while let Some(ch) = chars.next() {
            match ch {
                '\u{1b}' => consume_terminal_escape(&mut chars),
                '\n' | '\r' => out.push(ch),
                '\t' => out.push_str("    "),
                _ if ch.is_control() => {}
                _ => out.push(ch),
            }
        }
        out
    }

    fn consume_terminal_escape<I>(chars: &mut std::iter::Peekable<I>)
    where
        I: Iterator<Item = char>,
    {
        match chars.next() {
            Some('[') => {
                for ch in chars.by_ref() {
                    if ('@'..='~').contains(&ch) {
                        break;
                    }
                }
            }
            Some(']') => {
                let mut prev = None::<char>;
                for ch in chars.by_ref() {
                    if ch == '\u{0007}' || (prev == Some('\u{1b}') && ch == '\\') {
                        break;
                    }
                    prev = Some(ch);
                }
            }
            Some('P' | 'X' | '^' | '_') => {
                let mut prev = None::<char>;
                for ch in chars.by_ref() {
                    if prev == Some('\u{1b}') && ch == '\\' {
                        break;
                    }
                    prev = Some(ch);
                }
            }
            Some(_) | None => {}
        }
    }

    fn decode_tool_preview_escapes(text: &str) -> String {
        if !text.contains('\\') {
            return text.to_string();
        }
        let mut out = String::with_capacity(text.len());
        let mut chars = text.chars().peekable();
        while let Some(ch) = chars.next() {
            if ch != '\\' {
                out.push(ch);
                continue;
            }
            match chars.peek().copied() {
                Some('r') => {
                    chars.next();
                    if chars.peek().copied() == Some('\\') {
                        chars.next();
                        if chars.peek().copied() == Some('n') {
                            chars.next();
                            out.push('\n');
                            continue;
                        }
                        out.push('\r');
                        out.push('\\');
                        continue;
                    }
                    out.push('\r');
                }
                Some('n') => {
                    chars.next();
                    out.push('\n');
                }
                Some('t') => {
                    chars.next();
                    out.push(' ');
                    out.push(' ');
                }
                Some(other) => {
                    out.push('\\');
                    out.push(other);
                    chars.next();
                }
                None => out.push('\\'),
            }
        }
        out
    }

    pub fn selection_detail_text(
        messages: &[ChatMessage],
        selected: &SelectionKey,
    ) -> Option<String> {
        match selected {
            SelectionKey::Message(message) => {
                Some(format_message_detail(messages.get(message.message_index)?))
            }
            SelectionKey::Tool(tool) => {
                let msg = messages.get(tool.message_index)?;
                if let Some(segment_index) =
                    thought_segment_index_from_call_id(tool.call_id.as_str())
                {
                    let thinking = thought_segment_text(msg, segment_index)?;
                    return Some(format_thinking_detail(thinking.as_str()));
                }
                let run = msg
                    .tool_runs
                    .iter()
                    .find(|run| run.call_id == tool.call_id)?;
                Some(format_tool_detail(run))
            }
        }
    }

    fn format_message_detail(msg: &ChatMessage) -> String {
        let mut out = Vec::new();
        out.push(plain_header_text(msg));
        for segment in msg.ordered_segments() {
            match segment {
                MessageSegment::Thinking(thinking) => {
                    if !thinking.trim().is_empty() {
                        out.push(String::new());
                        out.extend(thinking.lines().map(str::to_string));
                    }
                }
                MessageSegment::Plan(plan) => {
                    if !plan.trim().is_empty() {
                        out.push(String::new());
                        out.push("▓ PLAN · proposed".to_string());
                        out.extend(plan.lines().map(str::to_string));
                    }
                }
                MessageSegment::ToolCall(call_id) => {
                    if let Some(run) = msg.tool_run(call_id.as_str()) {
                        out.push(String::new());
                        out.extend(format_tool_detail(run).lines().map(str::to_string));
                    }
                }
                MessageSegment::Display(display) => {
                    if !display.trim().is_empty() {
                        out.push(String::new());
                        out.extend(display.lines().map(str::to_string));
                    }
                }
            }
        }
        out.join("\n")
    }

    fn format_thinking_detail(thinking: &str) -> String {
        let mut out = vec!["✧ THOUGHTS".to_string()];
        out.push(String::new());
        out.extend(thinking.lines().map(str::to_string));
        out.join("\n")
    }

    fn format_tool_detail(run: &ToolRun) -> String {
        if is_apply_patch_tool(run) {
            return format_apply_patch_tool_detail(run);
        }
        if is_parallel_tool(run) {
            return format_parallel_tool_detail(run);
        }
        if is_rewrite_section_tool(run) {
            return format_rewrite_section_tool_detail(run);
        }
        if is_ask_user_tool(run) {
            return format_ask_user_tool_detail(run);
        }
        if is_tool_manage_tool(run) {
            return format_tool_manage_tool_detail(run);
        }
        if is_persona_manage_tool(run) {
            return format_persona_manage_tool_detail(run);
        }
        if is_context_manage_tool(run) {
            return format_context_manage_tool_detail(run);
        }
        if is_memory_tool(run) {
            return format_memory_tool_detail(run);
        }
        if is_agent_tool(run) {
            return format_agent_tool_detail(run);
        }
        if is_batch_tool(run) {
            return format_batch_tool_detail(run);
        }
        if is_view_image_tool(run) {
            return format_view_image_tool_detail(run);
        }
        if is_web_search_tool(run) {
            return format_web_search_tool_detail(run);
        }
        let action = if run.action_label.trim().is_empty() {
            if run.completed { "Ran" } else { "Run" }
        } else {
            run.action_label.as_str()
        };
        let kind = display_tool_kind(run);
        let mut out = vec![format!("● {kind} · {action} · {}", run.brief.trim())];
        out.push(generic_tool_input_label(run));
        if run.command_preview.trim().is_empty() {
            out.push("(empty)".to_string());
        } else {
            out.extend(run.command_preview.lines().map(str::to_string));
        }
        if run.completed {
            out.push(generic_tool_output_label(run));
            if run.output_preview.trim().is_empty() {
                out.push("(empty)".to_string());
            } else {
                out.extend(run.output_preview.lines().map(str::to_string));
            }
        }
        out.join("\n")
    }

    fn format_tool_manage_tool_detail(run: &ToolRun) -> String {
        let mut out = vec![format!(
            "● Toolbox · {} · {}",
            tool_manage_action(run),
            run.brief.trim()
        )];
        out.push(tool_manage_input_label(run).to_string());
        if run.command_preview.trim().is_empty() {
            out.push("(empty)".to_string());
        } else {
            out.extend(run.command_preview.lines().map(str::to_string));
        }
        if run.completed {
            out.push(tool_manage_output_label(run).to_string());
            if run.output_preview.trim().is_empty() {
                out.push("(empty)".to_string());
            } else {
                out.extend(run.output_preview.lines().map(str::to_string));
            }
        }
        out.join("\n")
    }

