    fn format_parallel_tool_detail(run: &ToolRun) -> String {
        let title = "● Explore".to_string();
        let mut out = vec![title];
        if let Some(payload) = parallel_tool_payload(run) {
            if payload.items.is_empty() {
                out.push("[- Output -]:".to_string());
                out.push("(empty)".to_string());
                return out.join("\n");
            }
            for item in payload.items {
                out.push(format!(
                    "○ {} · {}",
                    if item.action.trim().is_empty() {
                        "Run"
                    } else {
                        item.action.trim()
                    },
                    parallel_tool_item_brief(&item)
                ));
                out.push("[- INPUT -]:".to_string());
                if item.input.trim().is_empty() {
                    out.push("(empty)".to_string());
                } else {
                    out.extend(item.input.lines().map(str::to_string));
                }
                if let Some(output) = item.output {
                    out.push("[- Output -]:".to_string());
                    if output.trim().is_empty() {
                        out.push("(empty)".to_string());
                    } else {
                        out.extend(output.lines().map(str::to_string));
                    }
                }
            }
            return out.join("\n");
        }
        out.push("[- INPUT -]:".to_string());
        if run.command_preview.trim().is_empty() {
            out.push("(empty)".to_string());
        } else {
            out.extend(run.command_preview.lines().map(str::to_string));
        }
        if run.completed {
            out.push("[- Output -]:".to_string());
            if run.output_preview.trim().is_empty() {
                out.push("(empty)".to_string());
            } else {
                out.extend(run.output_preview.lines().map(str::to_string));
            }
        }
        out.join("\n")
    }

