    fn format_apply_patch_tool_detail(run: &ToolRun) -> String {
        let failed = is_apply_patch_failed_run(run);
        let mut out = vec![format!(
            "● Edit File · {} · {}",
            tool_header_action(run, "EDIT"),
            run.brief.trim()
        )];
        out.push(
            if failed {
                "[- INPUT -]:"
            } else {
                "[- Path -]:"
            }
            .to_string(),
        );
        if failed {
            let mut input_lines = apply_patch_payload(run.command_preview.as_str())
                .lines()
                .map(str::to_string)
                .filter(|line| {
                    let trimmed = line.trim_end_matches('\r');
                    !matches!(trimmed, "*** Begin Patch" | "*** End Patch")
                        && !trimmed.starts_with(' ')
                        && !trimmed.trim().is_empty()
                })
                .collect::<Vec<_>>();
            if input_lines.is_empty() {
                out.push("(empty)".to_string());
            } else {
                out.append(&mut input_lines);
            }
        } else {
            out.push(apply_patch_input_summary(run.command_preview.as_str()));
        }
        if run.completed {
            out.push(
                if is_apply_patch_output_failure(run.output_preview.as_str()) {
                    "[- Output -]:"
                } else {
                    "[- Edited -]:"
                }
                .to_string(),
            );
            let output_lines = apply_patch_output_lines(run.output_preview.as_str())
                .into_iter()
                .map(|line| apply_patch_display_line_text(&line))
                .collect::<Vec<_>>();
            if output_lines.is_empty() {
                out.push("(empty)".to_string());
            } else {
                out.extend(output_lines);
            }
        }
        out.join("\n")
    }

    fn format_rewrite_section_tool_detail(run: &ToolRun) -> String {
        let normalized_input = normalize_tool_preview(run.command_preview.as_str(), false);
        let normalized_output = normalize_tool_preview(run.output_preview.as_str(), true);
        let failed = is_rewrite_section_output_failure(normalized_output.as_str());
        let mut out = vec![format!(
            "● Edit File · {} · {}",
            tool_header_action(run, "EDIT"),
            run.brief.trim()
        )];
        out.push("[- Path -]:".to_string());
        out.push(rewrite_section_input_summary(normalized_input.as_str()));
        out.push("[- Input -]:".to_string());
        out.extend(
            rewrite_section_input_detail_lines(normalized_input.as_str())
                .into_iter()
                .map(|line| line.text),
        );
        if run.completed {
            out.push(
                if failed {
                    "[- Output -]:"
                } else {
                    "[- Edited -]:"
                }
                .to_string(),
            );
            out.extend(
                rewrite_section_output_detail_lines(normalized_output.as_str())
                    .into_iter()
                    .map(|line| line.text),
            );
        }
        out.join("\n")
    }

    fn plain_header_text(msg: &ChatMessage) -> String {
        match msg.role {
            Role::System => plain_system_header_text(msg),
            Role::User => match msg.source_channel {
                SourceChannel::User => {
                    format!("●/.. {} ▪ {}", msg.who_en.trim(), msg.who_zh.trim())
                }
                SourceChannel::Persona => {
                    format!("●//. {} ▪ {}", msg.who_en.trim(), msg.who_zh.trim())
                }
                SourceChannel::AiDebug => {
                    format!("✣ DBG {} ▪ {}", msg.who_en.trim(), msg.who_zh.trim())
                }
                SourceChannel::System => {
                    format!("●/.. {} ▪ {}", msg.who_en.trim(), msg.who_zh.trim())
                }
            },
            Role::Assistant if msg.streaming && !msg.has_content() => "●/...".to_string(),
            Role::Assistant => format!("●//. {} ▪ {}", msg.who_en.trim(), msg.who_zh.trim()),
        }
    }

    fn plain_system_header_text(msg: &ChatMessage) -> String {
        let sys_type = msg.sys_type.as_deref().unwrap_or("INFO").trim();
        let summary = system_message_summary(msg);
        if summary.is_empty() {
            format!("✣ SYSTEM · {sys_type}")
        } else {
            format!("✣ SYSTEM · {sys_type} · {summary}")
        }
    }

    fn clean_system_text_line(raw: &str) -> String {
        let mut text = raw.trim();
        while let Some(first) = text.chars().next() {
            if matches!(first, '│' | '└' | '├' | '•') {
                text = text[first.len_utf8()..].trim_start();
            } else {
                break;
            }
        }
        text.trim().to_string()
    }

    fn split_system_detail_line(raw: &str) -> (Option<String>, String) {
        let cleaned = clean_system_text_line(raw);
        if let Some((key, value)) = cleaned.split_once('：') {
            return (Some(key.trim().to_string()), value.trim().to_string());
        }
        if let Some((key, value)) = cleaned.split_once(':') {
            return (Some(key.trim().to_string()), value.trim().to_string());
        }
        (None, cleaned)
    }

    fn parse_system_message(display: &str) -> (String, Vec<(Option<String>, String)>) {
        let lines = display
            .lines()
            .map(clean_system_text_line)
            .filter(|line| !line.trim().is_empty())
            .collect::<Vec<_>>();
        let Some((first, rest)) = lines.split_first() else {
            return (String::new(), Vec::new());
        };
        let (first_key, first_value) = split_system_detail_line(first);
        let mut summary = first.trim().to_string();
        let mut details = Vec::new();
        if let Some(key) = first_key
            && !key.trim().is_empty()
        {
            summary = key;
            if !first_value.trim().is_empty() {
                details.push((None, first_value));
            }
        }
        details.extend(
            rest.iter()
                .map(|line| split_system_detail_line(line))
                .collect::<Vec<_>>(),
        );
        (summary, details)
    }

    fn system_message_details(msg: &ChatMessage) -> Vec<(Option<String>, String)> {
        let (_, details) = parse_system_message(msg.display.as_str());
        details
    }

    pub fn message_can_expand(msg: &ChatMessage) -> bool {
        msg.role == Role::System && !system_message_details(msg).is_empty()
    }

    fn system_detail_label(msg: &ChatMessage) -> &'static str {
        match msg.sys_type.as_deref().unwrap_or("INFO").trim() {
            "ERROR" => "[- ERROR -]:",
            "WARNING" | "WARN" => "[- WARNING -]:",
            _ => "[- Detail -]:",
        }
    }

    fn system_message_summary(msg: &ChatMessage) -> String {
        let (summary, _) = parse_system_message(msg.display.as_str());
        summary
    }

    fn render_system_body_block(
        msg: &ChatMessage,
        width: usize,
        body_style: Style,
    ) -> Vec<Line<'static>> {
        let details = system_message_details(msg);
        if details.is_empty() {
            return Vec::new();
        }
        let label_style = body_style.add_modifier(Modifier::BOLD);
        let mut out = vec![finalize_tool_preview_line(
            vec![
                Span::styled(" ".repeat(BODY_INDENT), body_style),
                Span::styled("✣ ".to_string(), label_style),
                Span::styled(system_detail_label(msg).to_string(), label_style),
            ],
            width,
            body_style,
        )];
        out.push(finalize_tool_preview_line(
            vec![
                Span::styled(" ".repeat(BODY_INDENT), body_style),
                Span::styled("│".to_string(), body_style),
            ],
            width,
            body_style,
        ));
        for (key, value) in details.into_iter() {
            let first_prefix = match key.as_deref() {
                Some(key) => format!("{}│  {}： ", " ".repeat(BODY_INDENT), key),
                None => format!("{}│  ", " ".repeat(BODY_INDENT)),
            };
            let continuation_prefix = match key {
                Some(key) => format!(
                    "{}│  {}",
                    " ".repeat(BODY_INDENT),
                    " ".repeat(display_width(key.as_str()).saturating_add(2))
                ),
                None => format!("{}│  ", " ".repeat(BODY_INDENT)),
            };
            out.extend(render_wrapped_prefixed_block(
                value.as_str(),
                width,
                first_prefix.as_str(),
                continuation_prefix.as_str(),
                body_style,
                body_style,
            ));
        }
        clamp_tool_detail_lines(
            out,
            SYSTEM_EXPANDED_MAX_LINES,
            width,
            BODY_INDENT,
            body_style,
            Style::default().fg(Color::Rgb(210, 176, 132)),
        )
    }

    fn render_wrapped_prefixed_block(
        text: &str,
        width: usize,
        first_prefix: &str,
        continuation_prefix: &str,
        prefix_style: Style,
        text_style: Style,
    ) -> Vec<Line<'static>> {
        let mut out = Vec::new();
        let raw_lines = if text.is_empty() {
            vec![""]
        } else {
            text.split('\n').collect::<Vec<_>>()
        };
        for (line_index, raw_line) in raw_lines.into_iter().enumerate() {
            let line_text = raw_line.trim_end_matches('\r');
            let initial_prefix = if line_index == 0 {
                first_prefix
            } else {
                continuation_prefix
            };
            let content_width = width.saturating_sub(display_width(initial_prefix)).max(1);
            let mut wrapped = wrap_preformatted_line(line_text, content_width);
            if wrapped.is_empty() {
                wrapped.push(String::new());
            }
            for (segment_index, segment) in wrapped.into_iter().enumerate() {
                let prefix = if line_index == 0 && segment_index == 0 {
                    first_prefix
                } else {
                    continuation_prefix
                };
                out.push(finalize_tool_preview_line(
                    vec![
                        Span::styled(prefix.to_string(), prefix_style),
                        Span::styled(segment, text_style),
                    ],
                    width,
                    prefix_style,
                ));
            }
        }
        out
    }

    fn render_preformatted_block_with_indent(
        text: &str,
        width: usize,
        indent: usize,
        indent_style: Style,
        text_style: Style,
    ) -> Vec<Line<'static>> {
        let content_width = width.saturating_sub(indent).max(1);
        let mut out = Vec::new();
        for raw_line in text.split('\n') {
            let wrapped = wrap_preformatted_line(raw_line.trim_end_matches('\r'), content_width);
            for segment in wrapped {
                out.push(finalize_tool_preview_line(
                    vec![
                        Span::styled(" ".repeat(indent), indent_style),
                        Span::styled(segment, text_style),
                    ],
                    width,
                    indent_style,
                ));
            }
        }
        out
    }

    fn background_fill_line(width: usize, bg: Color) -> Line<'static> {
        Line::from(Span::styled(
            " ".repeat(width.max(1)),
            Style::default().bg(bg),
        ))
    }

    fn apply_card_background(lines: &mut [Line<'static>], width: usize, bg: Color) {
        for line in lines.iter_mut() {
            let mut used = 0usize;
            for span in line.spans.iter_mut() {
                used = used.saturating_add(display_width(span.content.as_ref()));
                if span.style.bg.is_none() {
                    span.style.bg = Some(bg);
                }
            }
            if used < width {
                line.spans.push(Span::styled(
                    " ".repeat(width.saturating_sub(used)),
                    Style::default().bg(bg),
                ));
            }
        }
    }

    fn wrap_preformatted_line(text: &str, max_width: usize) -> Vec<String> {
        if text.is_empty() {
            return vec![String::new()];
        }
        let max_width = max_width.max(1);
        let mut out = Vec::new();
        let mut current = String::new();
        let mut current_width = 0usize;

        let flush = |out: &mut Vec<String>, current: &mut String, current_width: &mut usize| {
            out.push(std::mem::take(current));
            *current_width = 0;
        };

        for ch in text.chars() {
            if ch == '\t' {
                for _ in 0..4 {
                    if current_width >= max_width && !current.is_empty() {
                        flush(&mut out, &mut current, &mut current_width);
                    }
                    current.push(' ');
                    current_width = current_width.saturating_add(1);
                }
                continue;
            }

            let ch_width = UnicodeWidthChar::width(ch).unwrap_or(0).max(1);
            if current_width.saturating_add(ch_width) > max_width && !current.is_empty() {
                flush(&mut out, &mut current, &mut current_width);
            }
            current.push(ch);
            current_width = current_width.saturating_add(ch_width);
            if current_width >= max_width {
                flush(&mut out, &mut current, &mut current_width);
            }
        }

        if !current.is_empty() {
            out.push(current);
        }
        if out.is_empty() {
            out.push(String::new());
        }
        out
    }

    fn build_header_line(
        msg: &ChatMessage,
        theme: Theme,
        pending_phase: usize,
        selected: bool,
        width: usize,
        toggle: Option<bool>,
    ) -> (Line<'static>, Option<Range<usize>>) {
        match msg.role {
            Role::System => build_system_header(theme, msg, selected, width, toggle),
            Role::User => match msg.source_channel {
                SourceChannel::User => {
                    build_person_header("●/..", msg, theme.user_bg, theme, selected, width, toggle)
                }
                SourceChannel::Persona => {
                    build_person_header("●//.", msg, Color::Reset, theme, selected, width, toggle)
                }
                SourceChannel::AiDebug => {
                    build_person_header("✣ DBG", msg, Color::Reset, theme, selected, width, toggle)
                }
                SourceChannel::System => {
                    build_person_header("●/..", msg, theme.user_bg, theme, selected, width, toggle)
                }
            },
            Role::Assistant if msg.streaming && !msg.has_content() => {
                build_pending_assistant_header(theme, pending_phase, selected, width, toggle)
            }
            Role::Assistant => {
                build_person_header("●//.", msg, theme.ai_bg, theme, selected, width, toggle)
            }
        }
    }

    fn build_pending_assistant_header(
        theme: Theme,
        pending_phase: usize,
        selected: bool,
        width: usize,
        toggle: Option<bool>,
    ) -> (Line<'static>, Option<Range<usize>>) {
        let dots = match pending_phase % 3 {
            0 => ".",
            1 => "..",
            _ => "...",
        };
        let prefix = format!("●/{dots}");
        let prefix_pad = padded_header_prefix(prefix.as_str());
        finalize_header_with_toggle(
            vec![Span::styled(
                prefix_pad,
                if selected {
                    Style::default()
                        .fg(Color::Rgb(255, 228, 196))
                        .add_modifier(Modifier::BOLD | Modifier::UNDERLINED)
                } else {
                    Style::default()
                        .fg(theme.who_zh_fg)
                        .add_modifier(Modifier::BOLD)
                },
            )],
            width,
            Style::default().fg(theme.fg),
            toggle,
        )
    }

    fn build_person_header(
        prefix: &str,
        msg: &ChatMessage,
        name_bg: Color,
        theme: Theme,
        selected: bool,
        width: usize,
        toggle: Option<bool>,
    ) -> (Line<'static>, Option<Range<usize>>) {
        let who_en = msg.who_en.trim();
        let who_zh = msg.who_zh.trim();
        let prefix_pad = padded_header_prefix(prefix);
        let who_en_pad_width = if msg.source_channel == SourceChannel::AiDebug {
            WHO_EN_PAD_W.max(12)
        } else {
            WHO_EN_PAD_W
        };
        let who_zh_pad_width = if msg.source_channel == SourceChannel::AiDebug {
            WHO_ZH_PAD_W.max(14)
        } else {
            WHO_ZH_PAD_W
        };
        let who_en_pad = pad_to_width(who_en, who_en_pad_width, PadAlign::Left);
        let who_zh_pad = pad_to_width(who_zh, who_zh_pad_width, PadAlign::Left);

        let who_en_style = if selected {
            Style::default()
                .fg(Color::Black)
                .bg(Color::Rgb(255, 228, 196))
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default()
                .fg(Color::Black)
                .bg(name_bg)
                .add_modifier(Modifier::BOLD)
        };

        finalize_header_with_toggle(
            vec![
                Span::styled(
                    prefix_pad,
                    if selected {
                        Style::default()
                            .fg(Color::Rgb(255, 228, 196))
                            .add_modifier(Modifier::BOLD | Modifier::UNDERLINED)
                    } else {
                        Style::default().fg(theme.fg).add_modifier(Modifier::BOLD)
                    },
                ),
                Span::styled(who_en_pad, who_en_style),
                Span::styled(
                    " ▪ ",
                    if selected {
                        Style::default()
                            .fg(Color::Rgb(255, 228, 196))
                            .add_modifier(Modifier::BOLD)
                    } else {
                        Style::default().fg(theme.fg)
                    },
                ),
                Span::styled(
                    who_zh_pad,
                    if selected {
                        Style::default()
                            .fg(Color::Rgb(255, 228, 196))
                            .add_modifier(Modifier::BOLD | Modifier::UNDERLINED)
                    } else {
                        Style::default()
                            .fg(theme.who_zh_fg)
                            .add_modifier(Modifier::BOLD)
                    },
                ),
            ],
            width,
            Style::default().fg(theme.fg),
            toggle,
        )
    }

    fn padded_header_prefix(prefix: &str) -> String {
        let target_width = display_width(prefix).saturating_add(1).max(ICON_PAD_W + 3);
        pad_to_width(prefix, target_width, PadAlign::Left)
    }

    fn system_frame_width(msg: &ChatMessage, width: usize) -> usize {
        let mut header = "✣ SYSTEM".to_string();
        if let Some(kind) = system_header_kind(msg.sys_type.as_deref().unwrap_or("INFO")) {
            header.push_str(" · ");
            header.push_str(kind.as_str());
        }
        let summary = system_message_summary(msg);
        if !summary.trim().is_empty() {
            header.push_str(" · ");
            header.push_str(truncate_to_width(summary.as_str(), 24).as_str());
        }
        let header_width = display_width(header.as_str()).saturating_add(4);
        let min_width = tool_frame_min_width();
        let max_width = width
            .saturating_sub(TOOL_FRAME_INDENT)
            .max(min_width)
            .min(46usize.max(min_width));
        header_width.clamp(min_width, max_width)
    }

    fn build_system_frame_line(width: usize, selected: bool) -> Line<'static> {
        let frame = build_tool_frame_pattern(width, true);
        let style = if selected {
            Style::default()
                .fg(Color::Rgb(192, 156, 156))
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default()
                .fg(Color::Rgb(146, 118, 118))
                .add_modifier(Modifier::DIM)
        };
        Line::from(vec![
            Span::styled(
                " ".repeat(TOOL_FRAME_INDENT),
                if selected {
                    Style::default().fg(Color::Rgb(170, 146, 146))
                } else {
                    Style::default().fg(Color::Rgb(120, 98, 98))
                },
            ),
            Span::styled(frame, style),
        ])
    }

    fn system_header_kind(sys_type: &str) -> Option<String> {
        let trimmed = sys_type.trim();
        if trimmed.is_empty()
            || trimmed.eq_ignore_ascii_case("SYSTEM")
            || trimmed.eq_ignore_ascii_case("INFO")
        {
            None
        } else {
            Some(trimmed.to_string())
        }
    }

    fn build_system_header(
        theme: Theme,
        msg: &ChatMessage,
        selected: bool,
        width: usize,
        toggle: Option<bool>,
    ) -> (Line<'static>, Option<Range<usize>>) {
        let sys_type = msg.sys_type.as_deref().unwrap_or("INFO");
        let summary = system_message_summary(msg);
        let sep = " · ";
        let fixed = if let Some(kind) = system_header_kind(sys_type) {
            format!("✣ SYSTEM{sep}{kind}")
        } else {
            "✣ SYSTEM".to_string()
        };
        let summary_max = width
            .saturating_sub(display_width(fixed.as_str()))
            .saturating_sub(display_width(sep))
            .max(1);
        let summary = truncate_to_width(summary.as_str(), summary_max);
        let icon_style = if selected {
            Style::default()
                .fg(Color::Rgb(255, 220, 220))
                .add_modifier(Modifier::BOLD | Modifier::UNDERLINED)
        } else {
            Style::default()
                .fg(theme.sys_fg)
                .add_modifier(Modifier::BOLD)
        };
        let label_style = if selected {
            Style::default()
                .fg(Color::Black)
                .bg(Color::Rgb(255, 220, 220))
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default()
                .fg(theme.sys_fg)
                .bg(theme.sys_bg)
                .add_modifier(Modifier::BOLD)
        };
        let kind_style = if selected {
            Style::default()
                .fg(Color::Rgb(255, 220, 220))
                .add_modifier(Modifier::BOLD | Modifier::UNDERLINED)
        } else {
            Style::default()
                .fg(theme.sys_fg)
                .add_modifier(Modifier::BOLD)
        };
        let summary_style = if selected {
            Style::default()
                .fg(Color::Rgb(255, 236, 236))
                .add_modifier(Modifier::BOLD)
        } else {
            Style::default()
                .fg(Color::Rgb(255, 230, 230))
                .add_modifier(Modifier::BOLD)
        };
        let mut spans = vec![
            Span::styled(
                if toggle.is_some() {
                    " ".repeat(BODY_INDENT)
                } else {
                    String::new()
                },
                Style::default().fg(theme.sys_fg),
            ),
            Span::styled("✣ ".to_string(), icon_style),
            Span::styled("SYSTEM".to_string(), label_style),
        ];
        if let Some(kind) = system_header_kind(sys_type) {
            spans.push(Span::styled(sep.to_string(), kind_style));
            spans.push(Span::styled(kind, kind_style));
        }
        if !summary.trim().is_empty() {
            spans.push(Span::styled(sep.to_string(), kind_style));
            spans.push(Span::styled(summary, summary_style));
        }
        finalize_header_with_toggle(spans, width, Style::default().fg(theme.sys_fg), toggle)
    }

    pub fn tool_kind_label(name: &str) -> &'static str {
        match name {
            "exec_command" | "command" | "shell_command" => "Command",
            "web_search" => "WEB",
            "view_image" => "Image",
            "apply_patch" | "rewrite_section" => "Patch",
            "update_plan" => "Plan",
            "tool_manage" | "toolbox_manage" => "Toolbox",
            "persona_manage" => "Communicate",
            "focus_mode" => "Focus",
            "context_manage" => "Context",
            "memory_add" | "memory_check" | "memory_read" => "Memory",
            "ask_user" => "对账",
            "spawn_agent" | "send_input" | "wait_agent" | "close_agent" => "Agent",
            "pty_run" | "pty_input" | "pty_wait" | "pty_list" | "pty_kill" => "Terminal",
            _ => "Tool",
        }
    }

    fn exec_command_family_label(command_preview: &str) -> Option<&'static str> {
        for token in command_preview_tokens(command_preview) {
            if token == "adb" || token.ends_with("/adb") {
                return Some("ADB");
            }
            if token.starts_with("termux-") || token.contains("/termux-") {
                return Some("TERMUX API");
            }
        }
        None
    }

    fn display_tool_kind(run: &ToolRun) -> String {
        let base = if run.kind_label.trim().is_empty() {
            tool_kind_label(run.name.as_str()).to_string()
        } else {
            run.kind_label.trim().to_string()
        };
        if !matches!(
            run.name.trim(),
            "exec_command" | "command" | "shell_command"
        ) {
            return base;
        }
        let Some(family) = exec_command_family_label(run.command_preview.as_str()) else {
            return base;
        };
        if base.eq_ignore_ascii_case(family) || base.contains(family) {
            return base;
        }
        if base.eq_ignore_ascii_case("command") {
            return family.to_string();
        }
        if base.eq_ignore_ascii_case("terminal") {
            return format!("TERMINAL / {family}");
        }
        format!("{base} / {family}")
    }

    fn tool_display_spec(run: &ToolRun) -> crate::mcp::ToolDisplaySpec {
        crate::mcp::tool_display_spec_for(
            run.name.as_str(),
            display_tool_kind(run).as_str(),
            run.action_label.as_str(),
        )
    }

    fn tool_display_section_label(raw: &str, fallback: &str) -> String {
        let label = raw.trim();
        if label.is_empty()
            || label.eq_ignore_ascii_case("input")
            || label.eq_ignore_ascii_case("output")
        {
            return fallback.to_string();
        }
        if label.starts_with("[-") || label.ends_with(':') {
            return label.to_string();
        }
        format!("[- {label} -]:")
    }

    fn generic_tool_input_label(run: &ToolRun) -> String {
        tool_display_section_label(tool_display_spec(run).input_label.as_str(), "[- INPUT -]:")
    }

    fn generic_tool_output_label(run: &ToolRun) -> String {
        tool_display_section_label(
            tool_display_spec(run).output_label.as_str(),
            "[- Output -]:",
        )
    }

    fn display_width(s: &str) -> usize {
        s.chars()
            .map(|ch| UnicodeWidthChar::width(ch).unwrap_or(0).max(1))
            .sum()
    }

    #[derive(Debug, Clone, Copy)]
    enum PadAlign {
        Left,
    }

    fn pad_to_width(s: &str, target_w: usize, align: PadAlign) -> String {
        let w = display_width(s);
        if w >= target_w {
            return truncate_to_width(s, target_w);
        }
        let pad = " ".repeat(target_w - w);
        match align {
            PadAlign::Left => format!("{s}{pad}"),
        }
    }

    fn truncate_to_width(s: &str, max_w: usize) -> String {
        if max_w == 0 {
            return String::new();
        }
        let mut w = 0usize;
        let mut out = String::new();
        for ch in s.chars() {
            let cw = UnicodeWidthChar::width(ch).unwrap_or(0).max(1);
            if w.saturating_add(cw) > max_w {
                break;
            }
            out.push(ch);
            w = w.saturating_add(cw);
        }
        out
    }

