        fn with_chat_test_home<T>(f: impl FnOnce(std::path::PathBuf) -> T) -> T {
            let _guard = crate::mcp::home_override_test_lock()
                .lock()
                .unwrap_or_else(|poisoned| poisoned.into_inner());
            let ts = std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .expect("time")
                .as_nanos();
            let root = std::env::temp_dir().join(format!("projectying-chat-test-{ts}"));
            let project_root = root.join(crate::LEGACY_PROJECT_ROOT_REL_PATH);
            std::fs::create_dir_all(project_root.as_path()).expect("create project root");
            crate::set_thread_home_override_for_test(Some(root.clone()));
            let result = f(project_root);
            crate::set_thread_home_override_for_test(None);
            let _ = std::fs::remove_dir_all(root);
            result
        }

        fn line_has_bg(line: &Line<'_>, bg: Color) -> bool {
            line.spans.iter().any(|span| span.style.bg == Some(bg))
        }

