        #[test]
        fn expanded_tool_output_middle_truncates_to_human_safe_window() {
            let command_preview = (1..=60)
                .map(|index| format!("input {index:04}"))
                .collect::<Vec<_>>()
                .join("\n");
            let output_preview = (1..=80)
                .map(|index| format!("output {index:04}"))
                .collect::<Vec<_>>()
                .join("\n");
            let expanded = vec![ToolKey {
                message_index: 0,
                call_id: "call_long".to_string(),
            }];
            let rendered = render_tool_runs(
                &[ToolRun {
                    call_id: "call_long".to_string(),
                    name: "exec_command".to_string(),
                    brief: "长回执".to_string(),
                    kind_label: "Command".to_string(),
                    action_label: "Ran".to_string(),
                    command_preview,
                    output_preview,
                    completed: true,
                    meta: None,
                }],
                0,
                ToolRenderOptions {
                    width: 96,
                    theme: measure_theme(),
                    blink_on: false,
                    body_style: Style::default(),
                    compact: false,
                    selected_item: None,
                    expanded_tools: expanded.as_slice(),
                },
            );
            let lines = rendered.lines.iter().map(line_text).collect::<Vec<_>>();
            let tool_lines = &rendered.tool_ranges[0].lines;

            assert!(tool_lines.len() <= TOOL_EXPANDED_MAX_LINES);
            assert!(lines.iter().any(|line| line.contains("input 0001")));
            assert!(lines.iter().any(|line| line.contains("output 0080")));
            assert!(lines.iter().any(|line| line.contains("… +")));
            assert!(!lines.iter().any(|line| line.contains("input 0040")));
        }

