        #[test]
        fn native_parallel_batch_runs_render_as_explore_group() {
            let batch_id = "native_parallel:0:call_a".to_string();
            let batch_brief = "并行探索 2 项".to_string();
            let rendered = render_tool_runs(
                &[
                    ToolRun {
                        call_id: "call_a".to_string(),
                        name: "exec_command".to_string(),
                        brief: "查找入口".to_string(),
                        kind_label: "Command".to_string(),
                        action_label: "Search".to_string(),
                        command_preview: "rg -n \"render_tool_runs\" src/main.rs".to_string(),
                        output_preview: "src/main.rs:11712:    fn render_tool_runs(".to_string(),
                        completed: true,
                        meta: Some(ToolRunMeta::ParallelBatch(ParallelBatchToolMeta {
                            batch_id: batch_id.clone(),
                            batch_brief: batch_brief.clone(),
                            item_action: "Search".to_string(),
                            item_index: 1,
                            item_count: 2,
                        })),
                    },
                    ToolRun {
                        call_id: "call_b".to_string(),
                        name: "exec_command".to_string(),
                        brief: "查看片段".to_string(),
                        kind_label: "Command".to_string(),
                        action_label: "Read".to_string(),
                        command_preview: "sed -n '11712,11740p' src/main.rs".to_string(),
                        output_preview: "fn render_tool_runs(...)".to_string(),
                        completed: true,
                        meta: Some(ToolRunMeta::ParallelBatch(ParallelBatchToolMeta {
                            batch_id,
                            batch_brief,
                            item_action: "Read".to_string(),
                            item_index: 2,
                            item_count: 2,
                        })),
                    },
                ],
                0,
                ToolRenderOptions {
                    width: 92,
                    theme: measure_theme(),
                    blink_on: false,
                    body_style: Style::default(),
                    compact: false,
                    selected_item: None,
                    expanded_tools: &[],
                },
            );
            let lines = rendered.lines.iter().map(line_text).collect::<Vec<_>>();
            assert!(lines.iter().any(|line| line.contains("● Explore")));
            assert!(!lines.iter().any(|line| line.contains("● Explore ·")));
            assert!(
                lines
                    .iter()
                    .any(|line| line.contains("○ Search · 查找入口"))
            );
            assert!(
                lines
                    .iter()
                    .any(|line| line.contains("○ Read   · 查看片段"))
            );
            assert!(
                !lines
                    .iter()
                    .any(|line| line.contains("● Command · Ran") || line.contains("● Search ·"))
            );
        }

