        #[test]
        fn thinking_keeps_position_before_tool_when_seen_first() {
            let mut msg = ChatMessage::assistant_streaming("Matrix", "萤");
            msg.append_thinking("先分析环境");
            msg.push_tool_start(ToolRun {
                call_id: "call_1".to_string(),
                name: "exec_command".to_string(),
                brief: "查看环境".to_string(),
                kind_label: "Command".to_string(),
                action_label: "Run".to_string(),
                command_preview: "pwd".to_string(),
                output_preview: String::new(),
                completed: false,
                meta: None,
            });
            msg.finish_tool(ToolRun {
                call_id: "call_1".to_string(),
                name: "exec_command".to_string(),
                brief: "查看环境".to_string(),
                kind_label: "Command".to_string(),
                action_label: "Ran".to_string(),
                command_preview: "pwd".to_string(),
                output_preview: "/tmp".to_string(),
                completed: true,
                meta: None,
            });
            msg.append_text("最终回答");
            let rendered = render_lines(&[msg], 80, measure_theme(), false, 0, None, &[]);
            let flattened = rendered.iter().map(line_text).collect::<Vec<_>>();
            let thinking_idx = flattened
                .iter()
                .position(|line| line.contains("先分析环境"))
                .expect("thinking line");
            let tool_idx = flattened
                .iter()
                .position(|line| line.contains("● Command · Ran"))
                .expect("tool line");
            let text_idx = flattened
                .iter()
                .position(|line| line.contains("最终回答"))
                .expect("text line");
            assert!(thinking_idx < tool_idx);
            assert!(tool_idx < text_idx);
        }

