        #[test]
        fn collapsed_tool_preview_keeps_suffix_visible_in_narrow_width() {
            let width = 46;
            let rendered = render_tool_runs(
                &[ToolRun {
                    call_id: "call_1".to_string(),
                    name: "exec_command".to_string(),
                    brief: "测试窄屏截断".to_string(),
                    kind_label: "Command".to_string(),
                    action_label: "Ran".to_string(),
                    command_preview: format!("{}\nline2\nline3", "x".repeat(200)),
                    output_preview: "/tmp".to_string(),
                    completed: true,
                    meta: None,
                }],
                0,
                ToolRenderOptions {
                    width,
                    theme: measure_theme(),
                    blink_on: false,
                    body_style: Style::default(),
                    compact: false,
                    selected_item: None,
                    expanded_tools: &[],
                },
            );
            let input_line = rendered
                .lines
                .iter()
                .find(|line| line_text(line).contains("[- INPUT -]:"))
                .expect("collapsed input line");
            let text = line_text(input_line);
            let extra_lines = text
                .split('+')
                .nth(1)
                .and_then(|rest| rest.split_whitespace().next())
                .and_then(|digits| digits.parse::<usize>().ok())
                .expect("wrapped line suffix");
            assert!(extra_lines > 2, "unexpected suffix: {text}");
            assert!(text.chars().rev().take_while(|ch| *ch == ' ').count() >= 3);
            assert!(display_width(text.as_str()) <= width);
        }

