        #[test]
        fn apply_patch_wrapped_tail_does_not_repeat_last_connector() {
            let rendered = render_tool_runs(
                &[ToolRun {
                    call_id: "call_patch".to_string(),
                    name: "apply_patch".to_string(),
                    brief: "扩展长文本".to_string(),
                    kind_label: "Patch".to_string(),
                    action_label: "Edit File".to_string(),
                    command_preview: "\
Edited +17 chars -3 chars · 1 file
*** Begin Patch
*** Update File: applypatch-demo.txt
@@
-old
+new
*** End Patch
"
                    .to_string(),
                    output_preview: "\
ApplyPatch succeeded · Edited +17 lines -3 lines · 1 file

• Edited applypatch-demo.txt (+17 -3)
  17 + 到这里，这个演示文件已经不再只是三行测试语句，而是成为了一段真正意义上的长文本。它可以继续被扩展，也可以作为后续补丁测试的基线版本保留下来。
"
                    .to_string(),
                    completed: true,
                    meta: None,
                }],
                0,
                ToolRenderOptions {
                    width: 52,
                    theme: measure_theme(),
                    blink_on: false,
                    body_style: Style::default(),
                    compact: false,
                    selected_item: None,
                    expanded_tools: &[],
                },
            );
            let flattened = rendered.lines.iter().map(line_text).collect::<Vec<_>>();
            let tail_lines = flattened
                .into_iter()
                .filter(|line| {
                    line.contains("到这里")
                        || line.contains("成为了一段")
                        || line.contains("基线版本")
                })
                .collect::<Vec<_>>();
            assert!(tail_lines.first().is_some_and(|line| line.contains("└")));
            assert!(
                tail_lines
                    .iter()
                    .skip(1)
                    .all(|line| !line.contains("└") && !line.contains("│"))
            );
        }

        #[test]
        fn expanded_apply_patch_lines_fill_available_width() {
            let key = ToolKey {
                message_index: 0,
                call_id: "call_patch_width".to_string(),
            };
            let width = 52;
            let rendered = render_tool_runs(
                &[ToolRun {
                    call_id: key.call_id.clone(),
                    name: "apply_patch".to_string(),
                    brief: "检查展开态宽度".to_string(),
                    kind_label: "Patch".to_string(),
                    action_label: "Failed".to_string(),
                    command_preview: "\
Edited +17 chars -3 chars · 1 file
*** Begin Patch
*** Update File: applypatch-demo.txt
@@
-old text block
+new text block with a very long replacement line
*** End Patch
"
                    .to_string(),
                    output_preview: "\
apply_patch failed: Failed to find expected lines in applypatch-demo.txt:
old text block

诊断:
- 全文件没有完全匹配的旧片段；可能是上下文已变化、缩进/转义不同，或该片段刚被前序 hunk 改过。
- 最接近候选:
  • line 17 · score 62 · old text block with a very long tail that should wrap visibly
"
                    .to_string(),
                    completed: true,
                    meta: None,
                }],
                0,
                ToolRenderOptions {
                    width,
                    theme: measure_theme(),
                    blink_on: false,
                    body_style: Style::default(),
                    compact: false,
                    selected_item: None,
                    expanded_tools: &[key],
                },
            );
            let flattened = rendered.lines.iter().map(line_text).collect::<Vec<_>>();
            let mismatched = flattened
                .iter()
                .filter(|line| {
                    line.contains("[- ")
                        || line.contains("│")
                        || line.contains("└")
                        || line.contains("  • ")
                        || line.contains(" + ")
                        || line.contains(" - ")
                })
                .filter(|line| display_width(line.as_str()) != width)
                .map(|line| format!("{} => {}", display_width(line.as_str()), line))
                .collect::<Vec<_>>();
            assert!(mismatched.is_empty(), "{mismatched:#?}");
        }

