        #[test]
        fn assistant_segments_keep_runtime_order() {
            let mut msg = ChatMessage::assistant_streaming("Matrix", "萤");
            msg.append_thinking("第一段思考");
            msg.push_tool_start(ToolRun {
                call_id: "call_runtime".to_string(),
                name: "exec_command".to_string(),
                brief: "查看目录".to_string(),
                kind_label: "Command".to_string(),
                action_label: "Run".to_string(),
                command_preview: "pwd".to_string(),
                output_preview: String::new(),
                completed: false,
                meta: None,
            });
            msg.append_thinking("第二段思考");
            msg.append_text("最终正文");

            let segments = msg.ordered_segments();
            assert!(matches!(
                segments.first(),
                Some(MessageSegment::Thinking(text)) if text == "第一段思考"
            ));
            assert!(matches!(
                segments.get(1),
                Some(MessageSegment::ToolCall(call_id)) if call_id == "call_runtime"
            ));
            assert!(matches!(
                segments.get(2),
                Some(MessageSegment::Thinking(text)) if text == "第二段思考"
            ));
            assert!(matches!(
                segments.get(3),
                Some(MessageSegment::Display(text)) if text == "最终正文"
            ));
        }

