    thread_local! {
        static ACTIVE_PERSONA: Cell<crate::PersonaKind> = const { Cell::new(crate::PersonaKind::Matrix) };
        static ACTIVE_DYNAMIC_ROLE_CONTEXT: RefCell<Option<ActiveDynamicRoleContext>> = const { RefCell::new(None) };
    }

    #[derive(Clone, Debug, PartialEq, Eq)]
    struct ActiveDynamicRoleContext {
        role_id: String,
        label: String,
        context_dir: String,
        base_persona: crate::PersonaKind,
    }

    pub fn set_persona(persona: crate::PersonaKind) {
        ACTIVE_PERSONA.with(|slot| slot.set(persona));
        ACTIVE_DYNAMIC_ROLE_CONTEXT.with(|slot| {
            slot.borrow_mut().take();
        });
    }

    pub fn set_dynamic_role_context(
        base_persona: crate::PersonaKind,
        role_id: &str,
        label: &str,
        context_dir: &str,
    ) {
        ACTIVE_PERSONA.with(|slot| slot.set(base_persona));
        ACTIVE_DYNAMIC_ROLE_CONTEXT.with(|slot| {
            *slot.borrow_mut() = Some(ActiveDynamicRoleContext {
                role_id: role_id.trim().to_string(),
                label: label.trim().to_string(),
                context_dir: context_dir.trim().to_string(),
                base_persona,
            });
        });
    }

    fn current_persona() -> crate::PersonaKind {
        ACTIVE_PERSONA.with(Cell::get)
    }

    fn current_dynamic_role_context() -> Option<ActiveDynamicRoleContext> {
        ACTIVE_DYNAMIC_ROLE_CONTEXT.with(|slot| slot.borrow().clone())
    }

    pub fn with_dynamic_role_context<R>(
        role: &crate::roles::DynamicRoleSpec,
        work: impl FnOnce() -> Result<R>,
    ) -> Result<R> {
        let previous_persona = current_persona();
        let previous_role = current_dynamic_role_context();
        let contract = role.contract();
        set_dynamic_role_context(
            contract.capability.base_persona,
            contract.identity.id.as_str(),
            contract.identity.header_badge.as_str(),
            contract.storage.context_dir.as_str(),
        );
        let result = work();
        ACTIVE_PERSONA.with(|slot| slot.set(previous_persona));
        ACTIVE_DYNAMIC_ROLE_CONTEXT.with(|slot| {
            *slot.borrow_mut() = previous_role;
        });
        result
    }

