    fn persona_fixed_tool_state(persona: crate::PersonaKind, tool_id: &str) -> ToolboxToolState {
        match crate::mcp::default_tool_projection_state(persona, tool_id) {
            crate::mcp::ToolProjectionState::Hidden => ToolboxToolState::Hidden,
            crate::mcp::ToolProjectionState::Closed => ToolboxToolState::Closed,
            crate::mcp::ToolProjectionState::Expanded => ToolboxToolState::Expanded,
        }
    }

    fn persona_projection_state_map(
        persona: crate::PersonaKind,
    ) -> BTreeMap<String, ToolboxToolState> {
        crate::mcp::all_codex_tools()
            .as_array()
            .into_iter()
            .flatten()
            .filter_map(|tool| tool.get("name").and_then(|value| value.as_str()))
            .map(|tool_id| {
                (
                    tool_id.to_string(),
                    persona_fixed_tool_state(persona, tool_id),
                )
            })
            .collect()
    }

