    struct ContextPersonaRouter {
        persona: crate::PersonaKind,
        role: Option<ActiveDynamicRoleContext>,
    }

    struct ContextLayoutPlan {
        legacy_roots: Vec<PathBuf>,
        fastmemory_legacy_sources: Vec<PathBuf>,
        legacy_prompt_txt_sources: Vec<PathBuf>,
        legacy_prompt_json_sources: Vec<PathBuf>,
        unsupported_root_assets: Vec<PathBuf>,
    }

    impl ContextPersonaRouter {
        fn new(persona: crate::PersonaKind) -> Self {
            let role = current_dynamic_role_context()
                .filter(|role| role.base_persona == persona && !role.context_dir.is_empty());
            Self { persona, role }
        }

        fn root(&self) -> PathBuf {
            self.role
                .as_ref()
                .map(|role| context_root().join(role.context_dir.as_str()))
                .unwrap_or_else(|| context_root().join(self.persona.context_dir_name()))
        }

        fn persona_json_path(&self, stem: &str) -> PathBuf {
            self.root().join(format!("{stem}.json"))
        }

        fn persona_text_path(&self, stem: &str) -> PathBuf {
            self.root().join(format!("{stem}.txt"))
        }

        fn prompt_store_path(&self) -> PathBuf {
            self.root().join(PROMPT_STORE_FILE)
        }

        fn layout_plan(&self) -> ContextLayoutPlan {
            if self.role.is_some() {
                return ContextLayoutPlan {
                    legacy_roots: vec![self.root()],
                    fastmemory_legacy_sources: vec![
                        self.root().join(FAST_MEMORY_FILE),
                        shared_context_family_root()
                            .join("Matrix")
                            .join(FAST_MEMORY_FILE),
                    ],
                    legacy_prompt_txt_sources: Vec::new(),
                    legacy_prompt_json_sources: Vec::new(),
                    unsupported_root_assets: Vec::new(),
                };
            }
            let roots = self
                .persona
                .legacy_context_rel_roots()
                .iter()
                .map(|relative| context_root().join(relative))
                .collect::<Vec<_>>();
            ContextLayoutPlan {
                legacy_roots: roots,
                fastmemory_legacy_sources: vec![
                    self.root().join(FAST_MEMORY_FILE),
                    shared_context_family_root()
                        .join("Matrix")
                        .join(FAST_MEMORY_FILE),
                    context_root().join(FAST_MEMORY_FILE),
                    context_root()
                        .join("codex")
                        .join("matrix")
                        .join(FAST_MEMORY_FILE),
                    context_root().join("codex").join(FAST_MEMORY_FILE),
                ],
                legacy_prompt_txt_sources: if self.persona.migrates_legacy_root_prompt_assets() {
                    vec![legacy_codex_prompt_path()]
                } else {
                    Vec::new()
                },
                legacy_prompt_json_sources: if self.persona.migrates_legacy_root_prompt_assets() {
                    vec![legacy_codex_prompt_json_path()]
                } else {
                    Vec::new()
                },
                unsupported_root_assets: vec![
                    context_root().join("codex").join("schema"),
                    context_root().join("codex").join("fastcontext.json"),
                ],
            }
        }

        fn standard_context_path(&self) -> PathBuf {
            self.persona_json_path("context")
        }

        fn state_path(&self) -> PathBuf {
            self.persona_json_path("state")
        }

        fn focus_context_path(&self) -> PathBuf {
            self.persona_json_path("focuscontext")
        }

        fn legacy_tool_context_path(&self) -> PathBuf {
            self.persona_json_path("toolcontext")
        }

        fn toolbox_state_path(&self) -> PathBuf {
            self.persona_json_path("toolbox")
        }

        fn context_meta_path(&self) -> PathBuf {
            self.persona_json_path("contextmeta")
        }

        fn codex_prompt_path(&self) -> PathBuf {
            self.persona_text_path("prompt")
        }
    }

