    fn with_persona_context<R>(
        persona: crate::PersonaKind,
        work: impl FnOnce() -> Result<R>,
    ) -> Result<R> {
        let original_persona = current_persona();
        let original_role = current_dynamic_role_context();
        set_persona(persona);
        let result = work();
        ACTIVE_PERSONA.with(|slot| slot.set(original_persona));
        ACTIVE_DYNAMIC_ROLE_CONTEXT.with(|slot| {
            *slot.borrow_mut() = original_role;
        });
        result
    }

    fn remove_path_if_exists(path: &Path) -> Result<()> {
        if !path.exists() {
            return Ok(());
        }
        if path.is_dir() {
            fs::remove_dir_all(path)
                .with_context(|| format!("删除旧目录失败：{}", path.display()))?;
        } else {
            fs::remove_file(path).with_context(|| format!("删除旧文件失败：{}", path.display()))?;
        }
        Ok(())
    }

    fn prune_empty_dir(path: &Path) -> Result<()> {
        if !path.is_dir() {
            return Ok(());
        }
        let is_empty = fs::read_dir(path)
            .with_context(|| format!("读取目录失败：{}", path.display()))?
            .next()
            .is_none();
        if is_empty {
            fs::remove_dir(path).with_context(|| format!("删除空目录失败：{}", path.display()))?;
        }
        Ok(())
    }

    fn cleanup_obsolete_context_layout() -> Result<()> {
        remove_path_if_exists(&context_root().join("advisor"))?;
        remove_path_if_exists(&context_root().join("codexcoding"))?;
        remove_path_if_exists(&context_root().join("codexcompanion"))?;
        remove_path_if_exists(&context_root().join("deepseek"))?;

        let legacy_codex_root = context_root().join("codex");
        for file_name in [
            "context.json",
            "contextmeta.json",
            "toolcontext.json",
            "focuscontext.json",
            "toolbox.json",
            "fastmemory.json",
            "codexprompt.txt",
            "codexprompt.json",
        ] {
            remove_path_if_exists(&legacy_codex_root.join(file_name))?;
        }
        remove_path_if_exists(&legacy_codex_root.join("schema"))?;
        remove_path_if_exists(&legacy_codex_root.join("fastcontext.json"))?;

        for persona in crate::PersonaKind::ALL {
            let slug = persona.slug();
            for stem in [
                "context",
                "state",
                "focuscontext",
                "toolcontext",
                "toolbox",
                "contextmeta",
            ] {
                remove_path_if_exists(&legacy_codex_root.join(format!("{stem}-{slug}.json")))?;
            }
            remove_path_if_exists(&legacy_codex_root.join(format!("prompt-{slug}.txt")))?;
        }

        for file_name in [
            STANDARD_CONTEXT_FILE,
            CONTEXT_META_FILE,
            FOCUS_CONTEXT_FILE,
            TOOLBOX_STATE_FILE,
            LEGACY_TOOL_CONTEXT_FILE,
            "codexprompt.txt",
            "schema",
        ] {
            remove_path_if_exists(&legacy_codex_root.join("companion").join(file_name))?;
        }
        remove_path_if_exists(&legacy_codex_root.join("state-companion.json"))?;

        for file_name in [
            STANDARD_CONTEXT_FILE,
            CONTEXT_META_FILE,
            FAST_MEMORY_FILE,
            "fastcontext.json",
            FOCUS_CONTEXT_FILE,
            TOOLBOX_STATE_FILE,
            LEGACY_TOOL_CONTEXT_FILE,
        ] {
            remove_path_if_exists(&legacy_codex_root.join("matrix").join(file_name))?;
            remove_path_if_exists(&legacy_codex_root.join("coding").join(file_name))?;
        }

        remove_path_if_exists(&legacy_codex_root.join("matrix").join("schema"))?;
        remove_path_if_exists(&legacy_codex_root.join("coding").join("schema"))?;
        prune_empty_dir(&legacy_codex_root.join("coding"))?;
        prune_empty_dir(&legacy_codex_root.join("matrix"))?;
        prune_empty_dir(&legacy_codex_root.join("companion"))?;
        prune_empty_dir(&legacy_codex_root)?;
        Ok(())
    }

