    fn copy_first_existing_context_file(candidates: &[PathBuf], target: &Path) -> Result<()> {
        if target.exists() {
            return Ok(());
        }
        let Some(source) = candidates.iter().find(|path| path.exists()) else {
            return Ok(());
        };
        crate::ensure_parent_dir_shared(target, "迁移目标路径缺少父目录", "创建迁移目录失败")?;
        fs::copy(source, target).with_context(|| {
            format!(
                "迁移旧上下文文件失败：{} -> {}",
                source.display(),
                target.display()
            )
        })?;
        Ok(())
    }

    pub fn migrate_legacy_persona_context_layout(persona: crate::PersonaKind) -> Result<()> {
        fs::create_dir_all(codex_context_root()).with_context(|| {
            format!("创建 context 目录失败：{}", codex_context_root().display())
        })?;
        let router = ContextPersonaRouter::new(persona);
        let plan = router.layout_plan();
        let candidates = |file_name: &str| {
            plan.legacy_roots
                .iter()
                .map(|root| root.join(file_name))
                .collect::<Vec<_>>()
        };
        copy_first_existing_context_file(
            &candidates(STANDARD_CONTEXT_FILE),
            router.standard_context_path().as_path(),
        )?;
        copy_first_existing_context_file(
            &[
                candidates(FOCUS_CONTEXT_FILE),
                candidates(LEGACY_TOOL_CONTEXT_FILE),
            ]
            .concat(),
            router.focus_context_path().as_path(),
        )?;
        copy_first_existing_context_file(
            &candidates(CONTEXT_META_FILE),
            router.context_meta_path().as_path(),
        )?;
        copy_first_existing_context_file(
            &candidates(TOOLBOX_STATE_FILE),
            router.toolbox_state_path().as_path(),
        )?;
        copy_first_existing_context_file(
            plan.fastmemory_legacy_sources.as_slice(),
            router.root().join(FAST_MEMORY_FILE).as_path(),
        )?;
        let _ = fs::remove_file(router.legacy_tool_context_path());
        for path in plan.unsupported_root_assets {
            if path.is_dir() {
                let _ = fs::remove_dir_all(&path);
            } else if path.is_file() {
                let _ = fs::remove_file(&path);
            }
        }
        Ok(())
    }

    fn normalize_text(text: &str) -> String {
        text.replace("\r\n", "\n")
            .replace('\r', "\n")
            .trim()
            .to_string()
    }

    fn normalize_optional_text(text: Option<&str>) -> Option<String> {
        text.map(normalize_text)
            .filter(|value| !value.trim().is_empty())
    }

    fn normalize_kind(raw: Option<&str>, fallback: &str) -> String {
        normalize_optional_text(raw)
            .unwrap_or_else(|| fallback.to_string())
            .replace(char::is_whitespace, "_")
            .to_ascii_lowercase()
    }

    fn codex_message_role(role: ContextRole) -> &'static str {
        match role {
            ContextRole::Assistant => "assistant",
            ContextRole::User => "user",
            ContextRole::System => "system",
        }
    }

    fn codex_message_content_type(role: ContextRole) -> &'static str {
        match role {
            ContextRole::Assistant => "output_text",
            ContextRole::User | ContextRole::System => "input_text",
        }
    }

    fn build_codex_message_item_json(role: ContextRole, text: &str) -> Option<String> {
        let text = normalize_text(text);
        if text.is_empty() {
            return None;
        }
        serde_json::to_string(&json!({
            "type": "message",
            "role": codex_message_role(role),
            "content": [{
                "type": codex_message_content_type(role),
                "text": text,
            }],
        }))
        .ok()
    }

    fn render_context_entry_content(entry: &ContextEntry) -> Option<String> {
        let thinking = normalize_optional_text(entry.thinking.as_deref());
        let content = normalize_text(entry.text.as_str());
        match (thinking, content.is_empty()) {
            (None, true) => None,
            (None, false) => Some(content),
            (Some(thinking), true) => Some(format!(
                "[stored thinking start]\n{thinking}\n[stored thinking end]"
            )),
            (Some(thinking), false) => Some(format!(
                "[stored thinking start]\n{thinking}\n[stored thinking end]\n\n{content}"
            )),
        }
    }

    fn build_context_entry_codex_item_json(entry: &ContextEntry) -> Option<String> {
        render_context_entry_content(entry)
            .and_then(|content| build_codex_message_item_json(entry.role, content.as_str()))
    }

    fn prompt_store_text_from_entries(entries: &[ContextItem]) -> String {
        entries
            .iter()
            .map(|item| normalize_text(item.text.as_str()))
            .filter(|text| !text.is_empty())
            .collect::<Vec<_>>()
            .join("\n")
    }

    fn prompt_store_from_text(text: &str) -> PromptStore {
        let entries = normalize_text(text)
            .lines()
            .map(normalize_text)
            .filter(|line| !line.is_empty())
            .enumerate()
            .map(|(index, line)| make_context_item(index as u64 + 1, index as u64 + 1, line))
            .collect::<Vec<_>>();
        let next_entry_id = entries
            .iter()
            .map(|entry| entry.stable_id.max(entry.id))
            .max()
            .unwrap_or(0)
            .saturating_add(1);
        PromptStore {
            version: default_context_version(),
            next_entry_id,
            entries,
        }
    }

    fn normalize_prompt_store(store: &mut PromptStore) {
        store.version = default_context_version();
        for (index, item) in store.entries.iter_mut().enumerate() {
            item.id = index as u64 + 1;
            if item.stable_id == 0 {
                item.stable_id = item.id;
            }
        }
        let next_entry_id = store
            .entries
            .iter()
            .map(|entry| entry.stable_id.max(entry.id))
            .max()
            .unwrap_or(0)
            .saturating_add(1);
        store.next_entry_id = store.next_entry_id.max(next_entry_id);
    }

    fn prompt_store_to_text(store: &PromptStore) -> String {
        prompt_store_text_from_entries(store.entries.as_slice())
    }

    fn prompt_store_paths() -> (PathBuf, PathBuf) {
        let router = ContextPersonaRouter::new(current_persona());
        (router.codex_prompt_path(), router.prompt_store_path())
    }

    fn prompt_store_path() -> PathBuf {
        prompt_store_paths().1
    }

    fn backup_invalid_prompt_store(path: &Path, data: &str) {
        if data.trim().is_empty() {
            return;
        }
        if let Some(parent) = path.parent() {
            let stamp = crate::unix_timestamp_secs_shared();
            let stem = path
                .file_stem()
                .and_then(|value| value.to_str())
                .unwrap_or("prompt");
            let ext = path
                .extension()
                .and_then(|value| value.to_str())
                .unwrap_or("json");
            let backup_path = parent.join(format!("{stem}.invalid-{stamp}.{ext}"));
            let _ = fs::write(backup_path, data);
        }
    }

    fn load_prompt_store_from_text(prompt_text_path: &Path) -> Result<PromptStore> {
        let prompt_text = if prompt_text_path.exists() {
            fs::read_to_string(prompt_text_path)
                .with_context(|| format!("读取 prompt 文件失败：{}", prompt_text_path.display()))?
        } else {
            default_persona_system_prompt(current_persona())
        };
        let prompt_store = prompt_store_from_text(prompt_text.as_str());
        crate::write_json_pretty_shared(
            &prompt_store_path(),
            &prompt_store,
            format!("JSON 文件 {}", prompt_store_path().display()).as_str(),
            "prompt.json",
            "prompt 路径缺少父目录，无法原子写入",
            "创建 prompt 目录失败",
        )?;
        Ok(prompt_store)
    }

    fn load_prompt_store() -> Result<PromptStore> {
        let (prompt_text_path, prompt_store_path) = prompt_store_paths();
        if !prompt_store_path.exists() {
            return load_prompt_store_from_text(prompt_text_path.as_path());
        }
        let store_text = fs::read_to_string(prompt_store_path.as_path())
            .with_context(|| format!("读取 prompt JSON 失败：{}", prompt_store_path.display()))?;
        let mut store = match serde_json::from_str::<PromptStore>(store_text.as_str()) {
            Ok(store) => store,
            Err(_err) => {
                backup_invalid_prompt_store(prompt_store_path.as_path(), store_text.as_str());
                return load_prompt_store_from_text(prompt_text_path.as_path());
            }
        };
        normalize_prompt_store(&mut store);
        if let Ok(text_meta) = fs::metadata(prompt_text_path.as_path())
            && let Ok(store_meta) = fs::metadata(prompt_store_path.as_path())
            && let (Ok(text_mtime), Ok(store_mtime)) = (text_meta.modified(), store_meta.modified())
            && text_mtime > store_mtime
        {
            return load_prompt_store_from_text(prompt_text_path.as_path());
        }
        Ok(store)
    }

    fn save_prompt_store(store: &mut PromptStore) -> Result<()> {
        normalize_prompt_store(store);
        let (prompt_text_path, prompt_store_path) = prompt_store_paths();
        let rendered_text = prompt_store_to_text(store);
        crate::write_json_pretty_shared(
            &prompt_store_path,
            store,
            format!("JSON 文件 {}", prompt_store_path.display()).as_str(),
            "prompt.json",
            "prompt 路径缺少父目录，无法原子写入",
            "创建 prompt 目录失败",
        )?;
        crate::write_text_file_atomically_shared(
            &prompt_text_path,
            format!("{}\n", rendered_text).as_str(),
            "prompt.txt",
            "prompt.txt",
            "prompt 路径缺少父目录",
            "创建 prompt 目录失败",
        )?;
        Ok(())
    }

    fn ensure_prompt_store() -> Result<()> {
        let mut store = load_prompt_store()?;
        save_prompt_store(&mut store)
    }

    fn prompt_entry_ref(item: &ContextItem) -> String {
        format!("#{} · p{}", item.id, item.stable_id)
    }

    fn prompt_entry_preview(item: &ContextItem) -> String {
        format!(
            "{} {}",
            prompt_entry_ref(item),
            preview_inline_text(item.text.as_str(), 240)
        )
    }

    fn prompt_entries_snapshot(entries: &[ContextItem], ids: &[u64]) -> Result<Vec<ContextItem>> {
        let id_set = ids.iter().copied().collect::<HashSet<_>>();
        let matched = entries
            .iter()
            .filter(|entry| id_set.contains(&entry.stable_id))
            .cloned()
            .collect::<Vec<_>>();
        if matched.len() != ids.len() {
            return Err(anyhow!("目标 prompt entry_ids 与现存 prompt 不一致"));
        }
        Ok(matched)
    }

    fn prompt_entries_for_range(
        entries: &[ContextItem],
        start_id: u64,
        end_id: u64,
    ) -> Result<Vec<u64>> {
        if start_id > end_id {
            return Err(anyhow!("prompt.entry_start_id 不能大于 entry_end_id"));
        }
        let ids = entries
            .iter()
            .filter(|entry| (start_id..=end_id).contains(&entry.stable_id))
            .map(|entry| entry.stable_id)
            .collect::<Vec<_>>();
        if ids.is_empty() {
            return Err(anyhow!(
                "prompt.entry range 命中了空区域；请改用当前快照里的编号或整区收口"
            ));
        }
        Ok(ids)
    }

    fn resolve_prompt_entry_ids(
        entries: &[ContextItem],
        entry_ids: &[u64],
        entry_start_id: Option<u64>,
        entry_end_id: Option<u64>,
    ) -> Result<Vec<u64>> {
        if !entry_ids.is_empty() {
            let current_ids = entries
                .iter()
                .map(|entry| entry.stable_id)
                .collect::<HashSet<_>>();
            let mut resolved = Vec::new();
            let mut seen = HashSet::new();
            for entry_id in entry_ids {
                if current_ids.contains(entry_id) && seen.insert(*entry_id) {
                    resolved.push(*entry_id);
                }
            }
            if resolved.is_empty() {
                return Err(anyhow!("prompt.entry_ids 与当前 prompt 不一致"));
            }
            return Ok(resolved);
        }
        match (entry_start_id, entry_end_id) {
            (Some(start_id), Some(end_id)) => prompt_entries_for_range(entries, start_id, end_id),
            (Some(_), None) | (None, Some(_)) => Err(anyhow!(
                "prompt.entry_start_id 与 entry_end_id 需要同时提供"
            )),
            (None, None) => Ok(entries.iter().map(|entry| entry.stable_id).collect()),
        }
    }

    fn replace_prompt_entries(
        entries: &mut Vec<ContextItem>,
        ids: &[u64],
        replacement: ContextItem,
    ) -> Result<usize> {
        let id_set = ids.iter().copied().collect::<HashSet<_>>();
        let mut matched = entries
            .iter()
            .enumerate()
            .filter(|(_, entry)| id_set.contains(&entry.stable_id))
            .map(|(index, _)| index)
            .collect::<Vec<_>>();
        if matched.len() != ids.len() {
            return Err(anyhow!("目标 prompt entry_ids 与现存 prompt 不一致"));
        }
        matched.sort_unstable();
        let insert_at = matched[0];
        entries.retain(|entry| !id_set.contains(&entry.stable_id));
        let insert_at = insert_at.min(entries.len());
        entries.insert(insert_at, replacement);
        Ok(insert_at)
    }

    fn append_prompt_entry(store: &mut PromptStore, text: String) -> ContextItem {
        let item = make_context_item(
            store.entries.len() as u64 + 1,
            store.next_entry_id.max(1),
            text,
        );
        store.next_entry_id = item.stable_id.saturating_add(1);
        store.entries.push(item.clone());
        item
    }

    fn prompt_manage_output_for_action(action: &str, area: &str, lines: Vec<String>) -> String {
        let label = match action {
            "summary" => "SUMMARY",
            _ => "WRITE",
        };
        let mut out = vec![context_manage_file_header(area, label)];
        out.extend(lines);
        context_manage_success_output(out)
    }

    fn manage_prompt_write(text: String) -> Result<ContextManageResult> {
        let text = normalize_text(text.as_str());
        if text.is_empty() {
            return Err(anyhow!(
                "write.text 不能为空；prompt write 必须提供实际要写入的新内容"
            ));
        }
        let mut store = load_prompt_store()?;
        let entry = append_prompt_entry(&mut store, text);
        save_prompt_store(&mut store)?;
        Ok(ContextManageResult {
            model_output: context_manage_model_output(vec![
                "Area: Prompt".to_string(),
                "Action: WRITE".to_string(),
                format!("Created: {}", prompt_entry_ref(&entry)),
            ]),
            output_preview: prompt_manage_output_for_action(
                "write",
                "Prompt",
                vec![format!("+ {}", prompt_entry_preview(&entry))],
            ),
        })
    }

    fn manage_prompt_summary(
        entry_ids: &[u64],
        entry_start_id: Option<u64>,
        entry_end_id: Option<u64>,
        text: String,
        scope_all: bool,
    ) -> Result<ContextManageResult> {
        let text = normalize_text(text.as_str());
        if text.is_empty() {
            return Err(anyhow!(
                "summary.text 不能为空；prompt summary 需要提供压缩后的新摘要文本"
            ));
        }
        let mut store = load_prompt_store()?;
        let selected_ids = if scope_all {
            store.entries.iter().map(|entry| entry.stable_id).collect()
        } else if entry_ids.is_empty() && entry_start_id.is_none() && entry_end_id.is_none() {
            return Err(anyhow!(
                "prompt summary 需要明确 entry_ids / range，或显式传 scope=\"all\""
            ));
        } else {
            resolve_prompt_entry_ids(
                store.entries.as_slice(),
                entry_ids,
                entry_start_id,
                entry_end_id,
            )?
        };
        if selected_ids.is_empty() {
            return Err(anyhow!(
                "prompt summary 需要明确 entry_ids / range，或显式传 scope=\"all\""
            ));
        }
        let stable_id = store.next_entry_id.max(1);
        store.next_entry_id = stable_id.saturating_add(1);
        let replacement = make_context_item(0, stable_id, text);
        let previous_entries =
            prompt_entries_snapshot(store.entries.as_slice(), selected_ids.as_slice())?;
        replace_prompt_entries(
            &mut store.entries,
            selected_ids.as_slice(),
            replacement.clone(),
        )?;
        renumber_context_items(&mut store.entries);
        let replacement = store
            .entries
            .iter()
            .find(|entry| entry.stable_id == stable_id)
            .cloned()
            .ok_or_else(|| anyhow!("替换后的 prompt 条目缺失"))?;
        save_prompt_store(&mut store)?;
        let mut preview_lines = previous_entries
            .iter()
            .map(|entry| format!("- {}", prompt_entry_preview(entry)))
            .collect::<Vec<_>>();
        preview_lines.push(format!("+ {}", prompt_entry_preview(&replacement)));
        Ok(ContextManageResult {
            model_output: context_manage_model_output(vec![
                "Area: Prompt".to_string(),
                "Action: SUMMARY".to_string(),
                summarize_id_refs("Replaced entry_ids", selected_ids.as_slice()),
                format!("Created: {}", prompt_entry_ref(&replacement)),
            ]),
            output_preview: prompt_manage_output_for_action("summary", "Prompt", preview_lines),
        })
    }

    // =============================================================================
    // Codex 协议桥：raw item 解析、摘要、持久化裁剪与回放入库统一在此收口
    // =============================================================================

    fn build_codex_replay_context_entry(
        entry_id: u64,
        stable_id: u64,
        round_id: u64,
        item_json: &str,
        fallback_kind: &str,
    ) -> ContextEntry {
        let parsed = ParsedCodexItem::parse(item_json);
        let summary = parsed
            .as_ref()
            .map(|item| item.summary(item_json))
            .unwrap_or_else(|| preview_inline_text(item_json, 200));
        let kind = parsed
            .as_ref()
            .map(|item| item.kind_or(fallback_kind))
            .unwrap_or_else(|| fallback_kind.to_string());
        make_context_entry(
            entry_id,
            stable_id,
            round_id,
            ContextRole::System,
            kind.as_str(),
            None,
            summary,
        )
    }

    fn preview_inline_text(text: &str, limit: usize) -> String {
        let normalized = normalize_text(text).replace('\n', " / ");
        let mut out = String::new();
        for (count, ch) in normalized.chars().enumerate() {
            if count >= limit {
                out.push('…');
                break;
            }
            out.push(ch);
        }
        out
    }

    #[derive(Debug, Clone)]
    struct ParsedCodexItem {
        value: serde_json::Value,
    }

    impl ParsedCodexItem {
        fn parse(item_json: &str) -> Option<Self> {
            serde_json::from_str::<serde_json::Value>(item_json)
                .ok()
                .map(|value| Self { value })
        }

        fn item_type(&self) -> Option<&str> {
            self.value.get("type").and_then(|value| value.as_str())
        }

        fn kind_or(&self, fallback_kind: &str) -> String {
            self.item_type()
                .map(str::to_string)
                .unwrap_or_else(|| fallback_kind.to_string())
        }

        fn summary(&self, fallback_json: &str) -> String {
            match self.item_type().unwrap_or("") {
                "function_call" => {
                    let name = self
                        .value
                        .get("name")
                        .and_then(|value| value.as_str())
                        .unwrap_or("unknown");
                    let call_id = self
                        .value
                        .get("call_id")
                        .and_then(|value| value.as_str())
                        .unwrap_or("-");
                    let arguments = self
                        .value
                        .get("arguments")
                        .and_then(|value| value.as_str())
                        .map(|value| preview_inline_text(value, 120))
                        .filter(|value| !value.trim().is_empty())
                        .unwrap_or_else(|| "(no arguments)".to_string());
                    format!("function_call · {name} · {call_id} · {arguments}")
                }
                "function_call_output" => {
                    let call_id = self
                        .value
                        .get("call_id")
                        .and_then(|value| value.as_str())
                        .unwrap_or("-");
                    let output = self
                        .value
                        .get("output")
                        .and_then(|value| value.as_str())
                        .map(|value| preview_inline_text(value, 180))
                        .unwrap_or_else(|| "(empty output)".to_string());
                    format!("function_call_output · {call_id} · {output}")
                }
                "message" => {
                    let role = self
                        .value
                        .get("role")
                        .and_then(|value| value.as_str())
                        .unwrap_or("user");
                    let parts = self
                        .value
                        .get("content")
                        .and_then(|value| value.as_array())
                        .map(|items| {
                            items
                                .iter()
                                .filter_map(|item| {
                                    let kind = item.get("type").and_then(|value| value.as_str())?;
                                    match kind {
                                        "input_text" | "output_text" | "text" => item
                                            .get("text")
                                            .and_then(|value| value.as_str())
                                            .map(|value| preview_inline_text(value, 120)),
                                        "input_image" => Some("[image omitted]".to_string()),
                                        other => Some(format!("[{other}]")),
                                    }
                                })
                                .collect::<Vec<_>>()
                        })
                        .unwrap_or_default();
                    if parts.is_empty() {
                        format!("message · {role}")
                    } else {
                        format!("message · {role} · {}", parts.join(" / "))
                    }
                }
                other if !other.is_empty() => {
                    format!("{other} · {}", preview_inline_text(fallback_json, 180))
                }
                _ => preview_inline_text(fallback_json, 180),
            }
        }
    }

    fn parse_legacy_codex_prompt_json(data: &str) -> Option<String> {
        let prompt = serde_json::from_str::<LegacyCodexPromptJsonFile>(data).ok()?;
        let system = normalize_text(prompt.system.as_str());
        (!system.is_empty()).then_some(system)
    }

    fn migrate_legacy_codex_prompt_txt(
        target_path: &Path,
        legacy_path: &Path,
    ) -> Result<Option<String>> {
        if target_path.exists() || !legacy_path.exists() {
            return Ok(None);
        }
        let prompt = normalize_text(fs::read_to_string(legacy_path).unwrap_or_default().as_str());
        if prompt.is_empty() {
            return Ok(None);
        }
        fs::write(target_path, format!("{prompt}\n")).with_context(|| {
            format!(
                "迁移 Codex prompt 文件失败：{} -> {}",
                legacy_path.display(),
                target_path.display()
            )
        })?;
        let _ = fs::remove_file(legacy_path);
        Ok(Some(prompt))
    }

    fn migrate_legacy_codex_prompt_json(
        target_path: &Path,
        legacy_path: &Path,
    ) -> Result<Option<String>> {
        if target_path.exists() || !legacy_path.exists() {
            return Ok(None);
        }
        let legacy_data = fs::read_to_string(legacy_path).unwrap_or_default();
        let Some(system) = parse_legacy_codex_prompt_json(&legacy_data) else {
            return Ok(None);
        };
        fs::write(target_path, format!("{system}\n")).with_context(|| {
            format!(
                "迁移 Codex prompt JSON 文件失败：{} -> {}",
                legacy_path.display(),
                target_path.display()
            )
        })?;
        let _ = fs::remove_file(legacy_path);
        Ok(Some(system))
    }

    fn parse_context_records(data: &str) -> Vec<ContextRecord> {
        let trimmed = data.trim();
        if trimmed.is_empty() {
            return Vec::new();
        }
        if let Ok(records) = serde_json::from_str::<Vec<ContextRecord>>(trimmed) {
            return records;
        }
        trimmed
            .lines()
            .filter_map(|line| serde_json::from_str::<ContextRecord>(line.trim()).ok())
            .collect()
    }

    fn record_to_role(role: &str) -> Option<ContextRole> {
        match role.trim() {
            "user" => Some(ContextRole::User),
            "assistant" => Some(ContextRole::Assistant),
            "system" => Some(ContextRole::System),
            _ => None,
        }
    }

    fn persona_state_from_bundle(bundle: &ContextStoreBundle) -> PersonaStateFile {
        PersonaStateFile {
            version: default_context_version(),
            standard: bundle.standard.clone(),
            focus: bundle.focus.clone(),
            meta: bundle.meta.clone(),
            toolbox: bundle.toolbox.clone(),
        }
    }

    fn bundle_from_persona_state(
        state: PersonaStateFile,
        fastmemory: FastMemoryStore,
    ) -> ContextStoreBundle {
        ContextStoreBundle {
            meta: state.meta,
            standard: state.standard,
            focus: state.focus,
            fastmemory,
            toolbox: state.toolbox,
        }
    }

    fn write_persona_state(path: &Path, state: &PersonaStateFile) -> Result<()> {
        crate::write_json_pretty_shared(
            path,
            state,
            format!("JSON 文件 {}", path.display()).as_str(),
            "context.json",
            "目标路径缺少父目录，无法原子写入",
            "创建目录失败",
        )
    }

    fn normalize_toolbox_store(store: &mut ToolboxStateStore) {
        let mut dedup = BTreeMap::<String, ToolboxToolState>::new();
        for entry in &store.entries {
            let tool_id = normalize_text(entry.tool_id.as_str());
            if tool_id.is_empty() {
                continue;
            }
            dedup.insert(tool_id, entry.state);
        }
        store.entries = dedup
            .into_iter()
            .map(|(tool_id, state)| ToolboxStateEntry { tool_id, state })
            .collect();
    }

    fn load_toolbox_store() -> Result<ToolboxStateStore> {
        ensure_context_store()?;
        let mut store =
            crate::read_json_or_default_shared::<PersonaStateFile>(&state_path())?.toolbox;
        normalize_toolbox_store(&mut store);
        Ok(store)
    }

    fn load_toolbox_store_read_only() -> Result<ToolboxStateStore> {
        let mut store =
            crate::read_json_or_default_shared::<PersonaStateFile>(&state_path())?.toolbox;
        normalize_toolbox_store(&mut store);
        Ok(store)
    }

    fn save_toolbox_store(store: &ToolboxStateStore) -> Result<()> {
        ensure_context_store()?;
        let mut normalized = store.clone();
        normalize_toolbox_store(&mut normalized);
        let mut state = crate::read_json_or_default_shared::<PersonaStateFile>(&state_path())?;
        state.toolbox = normalized;
        write_persona_state(&state_path(), &state)
    }

    pub fn purge_removed_toolbox_entries(tool_ids: &[String]) -> Result<usize> {
        let remove = tool_ids
            .iter()
            .map(|tool_id| normalize_text(tool_id))
            .filter(|tool_id| !tool_id.is_empty())
            .collect::<BTreeSet<_>>();
        if remove.is_empty() {
            return Ok(0);
        }
        let mut removed = 0usize;
        for persona in crate::PersonaKind::ALL {
            with_persona_context(persona, || {
                let path = state_path();
                let mut state = crate::read_json_or_default_shared::<PersonaStateFile>(&path)?;
                let before = state.toolbox.entries.len();
                state
                    .toolbox
                    .entries
                    .retain(|entry| !remove.contains(&normalize_text(entry.tool_id.as_str())));
                let after = state.toolbox.entries.len();
                if after != before {
                    normalize_toolbox_store(&mut state.toolbox);
                    write_persona_state(&path, &state)?;
                    removed = removed.saturating_add(before.saturating_sub(after));
                }
                Ok(())
            })?;
        }
        Ok(removed)
    }

    fn tool_schema_summary(description: &str) -> String {
        let normalized = normalize_text(description);
        if normalized.is_empty() {
            return "No summary.".to_string();
        }
        let first_line = normalized.lines().next().unwrap_or_default().trim();
        let first_sentence = first_line
            .split(['.', '。'])
            .next()
            .unwrap_or(first_line)
            .trim();
        preview_inline_text(first_sentence, 90)
    }

    fn toolbox_specs_from_schema() -> Vec<ToolboxSpec> {
        let tools = crate::mcp::all_codex_tools();
        let Some(items) = tools.as_array() else {
            return Vec::new();
        };
        items
            .iter()
            .filter_map(|tool| {
                let tool_id = tool.get("name").and_then(|value| value.as_str())?;
                if tool_id.trim().eq_ignore_ascii_case("tool_manage") {
                    return None;
                }
                let description = tool
                    .get("description")
                    .and_then(|value| value.as_str())
                    .unwrap_or_default();
                let summary = tool_schema_summary(description);
                Some(ToolboxSpec {
                    tool_id: tool_id.to_string(),
                    summary,
                })
            })
            .collect()
    }

    fn open_focus_gate_recovery_tools(state_map: &mut BTreeMap<String, ToolboxToolState>) {
        for tool_id in ["focus_mode", "command", "persona_manage"] {
            if let Some(state) = state_map.get_mut(tool_id)
                && !matches!(*state, ToolboxToolState::Hidden)
            {
                *state = ToolboxToolState::Expanded;
            }
        }
    }

    struct ToolboxProjectionGateway {
        specs: Vec<ToolboxSpec>,
        state_map: BTreeMap<String, ToolboxToolState>,
        manager_enabled: bool,
        fixed_projection: bool,
        store: Option<ToolboxStateStore>,
    }

    impl ToolboxProjectionGateway {
        fn load_for_current_persona() -> Result<Self> {
            Self::load_for_persona(current_persona(), false)
        }

        fn load_for_persona(
            persona: crate::PersonaKind,
            force_manager_enabled: bool,
        ) -> Result<Self> {
            Self::load_for_persona_with_extra_tools(persona, force_manager_enabled, &[])
        }

        fn load_for_persona_with_extra_tools(
            persona: crate::PersonaKind,
            force_manager_enabled: bool,
            extra_tools: &[String],
        ) -> Result<Self> {
            let specs = toolbox_specs_from_schema();
            let manager_enabled = force_manager_enabled || persona.tool_management_enabled();
            let fixed_projection = !manager_enabled;
            let mut state_map = persona_projection_state_map(persona);
            if manager_enabled {
                for spec in &specs {
                    if crate::mcp::external_tool_available(spec.tool_id.as_str()) {
                        state_map.insert(spec.tool_id.clone(), ToolboxToolState::Closed);
                    }
                }
            }
            for tool_id in extra_tools {
                if crate::mcp::external_tool_available(tool_id.as_str()) {
                    state_map.insert(tool_id.clone(), ToolboxToolState::Closed);
                }
            }
            let loaded_store = load_toolbox_store()?;
            for entry in &loaded_store.entries {
                let Some(current) = state_map.get_mut(entry.tool_id.as_str()) else {
                    continue;
                };
                if matches!(*current, ToolboxToolState::Hidden) {
                    continue;
                }
                *current = entry.state;
            }
            if manager_enabled && focus_gate_active_from_state() {
                open_focus_gate_recovery_tools(&mut state_map);
            }
            let context_governance = load_current_context_governance_config()?;
            apply_context_governance_auto_projection(&mut state_map, &context_governance);
            Ok(Self {
                specs,
                state_map,
                manager_enabled,
                fixed_projection,
                store: Some(loaded_store),
            })
        }

        fn load_for_persona_read_only(
            persona: crate::PersonaKind,
            force_manager_enabled: bool,
            extra_tools: &[String],
        ) -> Result<Self> {
            let specs = toolbox_specs_from_schema();
            let manager_enabled = force_manager_enabled || persona.tool_management_enabled();
            let fixed_projection = !manager_enabled;
            let mut state_map = persona_projection_state_map(persona);
            if manager_enabled {
                for spec in &specs {
                    if crate::mcp::external_tool_available(spec.tool_id.as_str()) {
                        state_map.insert(spec.tool_id.clone(), ToolboxToolState::Closed);
                    }
                }
            }
            for tool_id in extra_tools {
                if crate::mcp::external_tool_available(tool_id.as_str()) {
                    state_map.insert(tool_id.clone(), ToolboxToolState::Closed);
                }
            }
            let loaded_store = load_toolbox_store_read_only()?;
            for entry in &loaded_store.entries {
                let Some(current) = state_map.get_mut(entry.tool_id.as_str()) else {
                    continue;
                };
                if matches!(*current, ToolboxToolState::Hidden) {
                    continue;
                }
                *current = entry.state;
            }
            if manager_enabled && focus_gate_active_from_state() {
                open_focus_gate_recovery_tools(&mut state_map);
            }
            let context_governance = load_current_context_governance_config()?;
            apply_context_governance_auto_projection(&mut state_map, &context_governance);
            Ok(Self {
                specs,
                state_map,
                manager_enabled,
                fixed_projection,
                store: None,
            })
        }

        fn maintenance_memory() -> Self {
            Self {
                specs: toolbox_specs_from_schema(),
                state_map: ["memory_add", "memory_check", "memory_read"]
                    .iter()
                    .map(|tool_id| ((*tool_id).to_string(), ToolboxToolState::Expanded))
                    .collect(),
                manager_enabled: false,
                fixed_projection: true,
                store: None,
            }
        }

        fn allowed_local_tool_ids(&self) -> HashSet<String> {
            let mut allowed = HashSet::new();
            if self.manager_enabled {
                allowed.insert(String::from("tool_manage"));
            }
            for spec in &self.specs {
                if matches!(
                    self.state_map.get(spec.tool_id.as_str()).copied(),
                    Some(ToolboxToolState::Expanded | ToolboxToolState::Pinned)
                ) {
                    allowed.insert(spec.tool_id.clone());
                }
            }
            allowed
        }

        fn render_prompt(&self, header_note: Option<&str>) -> String {
            let mut lines = vec![
                "[Toolbox]".to_string(),
                if self.manager_enabled {
                    "manager: tool_manage (callable)".to_string()
                } else {
                    "manager: none (fixed projection)".to_string()
                },
                "rule: hidden tools are unavailable.".to_string(),
                "rule: closed tools are listed here but are not callable.".to_string(),
                "rule: expanded/pinned tools are callable through the active provider schema."
                    .to_string(),
            ];
            if self.manager_enabled {
                lines.push(
                    "rule: use tool_manage open/close/pin/unpin/reload to change visibility."
                        .to_string(),
                );
            } else {
                lines.push(
                    "rule: this round uses a fixed projection; do not try to mutate tool visibility."
                        .to_string(),
                );
            }
            if self.fixed_projection {
                lines.push(
                    "rule: only the tools shown as expanded below are directly callable in this round."
                        .to_string(),
                );
            }
            if let Some(note) = normalize_optional_text(header_note) {
                lines.push(format!("note: {note}"));
            }
            if self.specs.iter().any(|spec| {
                matches!(
                    spec.tool_id.as_str(),
                    "context_manage" | "context_summary" | "context_vision" | "context_compact"
                )
            }) {
                lines.push("drawer: context_system (collapsed)".to_string());
                lines.push(
                    "drawer rule: context_manage stays under 司; summary / vision / compact open only when the selected context mode authorizes them."
                        .to_string(),
                );
            }
            lines.push("tools:".to_string());
            for spec in &self.specs {
                let state = self
                    .state_map
                    .get(spec.tool_id.as_str())
                    .copied()
                    .unwrap_or(ToolboxToolState::Hidden);
                if matches!(state, ToolboxToolState::Hidden) {
                    continue;
                }
                lines.push(format!(
                    "- [{}] {} · {}",
                    state.key(),
                    spec.tool_id,
                    spec.summary
                ));
            }
            lines.join("\n")
        }

        fn persistable_entries(&self) -> Vec<ToolboxStateEntry> {
            self.state_map
                .iter()
                .filter(|(_, state)| !matches!(**state, ToolboxToolState::Hidden))
                .map(|(tool_id, state)| ToolboxStateEntry {
                    tool_id: tool_id.clone(),
                    state: *state,
                })
                .collect()
        }

        fn apply_manage_action(
            &mut self,
            action: &str,
            tool_ids: &[String],
        ) -> Result<Vec<String>> {
            if !self.manager_enabled {
                anyhow::bail!("当前 toolbox 未启用 tool_manage");
            }
            let known = self
                .specs
                .iter()
                .map(|spec| spec.tool_id.as_str())
                .collect::<HashSet<_>>();
            let normalized_tool_ids = tool_ids
                .iter()
                .map(|tool_id| normalize_text(tool_id))
                .filter(|tool_id| !tool_id.is_empty())
                .collect::<Vec<_>>();
            let mut changed = Vec::new();
            match action {
                "list" => {}
                "open" | "close" | "pin" | "unpin" => {
                    if normalized_tool_ids.is_empty() {
                        anyhow::bail!("tool_ids 不能为空");
                    }
                    for tool_id in &normalized_tool_ids {
                        if !known.contains(tool_id.as_str()) {
                            anyhow::bail!("未知工具：{tool_id}");
                        }
                        if matches!(
                            self.state_map.get(tool_id.as_str()).copied(),
                            Some(ToolboxToolState::Hidden)
                        ) {
                            anyhow::bail!("工具当前不在可管理投影内：{tool_id}");
                        }
                        let next_state = match action {
                            "open" => ToolboxToolState::Expanded,
                            "close" => ToolboxToolState::Closed,
                            "pin" => ToolboxToolState::Pinned,
                            "unpin" => ToolboxToolState::Expanded,
                            _ => ToolboxToolState::Closed,
                        };
                        if self.state_map.get(tool_id.as_str()).copied() != Some(next_state) {
                            self.state_map.insert(tool_id.clone(), next_state);
                            changed.push(format!("{tool_id} -> {}", next_state.key()));
                        }
                    }
                    let entries = self.persistable_entries();
                    if let Some(store) = self.store.as_mut() {
                        store.entries = entries;
                        save_toolbox_store(store)?;
                    }
                }
                other => anyhow::bail!("不支持的 tool_manage.action：{other}"),
            }
            Ok(changed)
        }

        fn expanded_tool_ids(&self) -> Vec<String> {
            self.specs
                .iter()
                .filter(|spec| {
                    matches!(
                        self.state_map.get(spec.tool_id.as_str()).copied(),
                        Some(ToolboxToolState::Expanded | ToolboxToolState::Pinned)
                    )
                })
                .map(|spec| spec.tool_id.clone())
                .collect()
        }
    }

    fn focus_gate_active_from_state() -> bool {
        crate::read_json_or_default_shared::<PersonaStateFile>(&state_path())
            .ok()
            .and_then(|state| normalize_optional_text(state.meta.focus_required_summary.as_deref()))
            .is_some()
    }

    pub fn load_toolbox_prompt() -> Result<String> {
        Ok(ToolboxProjectionGateway::load_for_current_persona()?.render_prompt(None))
    }

    fn sorted_tool_ids(iter: impl IntoIterator<Item = String>) -> Vec<String> {
        let mut values = BTreeSet::new();
        for value in iter {
            let normalized = normalize_text(value.as_str());
            if !normalized.is_empty() {
                values.insert(normalized);
            }
        }
        values.into_iter().collect()
    }

    fn load_current_context_governance_config() -> Result<ContextGovernanceConfig> {
        let state: PersonaStateFile = crate::read_json_or_default_shared(&state_path())?;
        Ok(normalize_context_governance_config(
            state.meta.context_governance,
        ))
    }

    fn context_governance_auto_tools_for_mode(mode: &str) -> Vec<String> {
        match mode.trim().to_ascii_lowercase().as_str() {
            "self_compact" | "summary_compact" | "compact" | "self" => {
                vec!["context_summary".to_string(), "context_compact".to_string()]
            }
            "vision_compact" | "context_vision" | "vision" | "fast" => {
                vec!["context_vision".to_string(), "context_compact".to_string()]
            }
            _ => Vec::new(),
        }
    }

    fn apply_context_governance_auto_projection(
        state_map: &mut BTreeMap<String, ToolboxToolState>,
        governance: &ContextGovernanceConfig,
    ) {
        for tool_id in context_governance_auto_tools_for_mode(governance.mode.as_str()) {
            if let Some(state) = state_map.get_mut(tool_id.as_str())
                && !matches!(*state, ToolboxToolState::Hidden)
            {
                *state = ToolboxToolState::Expanded;
            }
        }
    }

    fn context_governance_config_json(config: &ContextGovernanceConfig) -> Value {
        json!({
            "mode": config.mode,
            "manage_threshold_kb": config.manage_threshold_kb,
            "compact_threshold_kb": config.compact_threshold_kb,
            "report_to_matrix": config.report_to_matrix,
        })
    }

    fn role_governance_auto_tools(role: &crate::roles::DynamicRoleSpec) -> Vec<String> {
        context_governance_auto_tools_for_mode(role.context_governance.mode.as_str())
    }

    fn default_tool_ids_for_persona(
        persona: crate::PersonaKind,
        specs: &[ToolboxSpec],
    ) -> Vec<String> {
        specs
            .iter()
            .filter(|spec| {
                !matches!(
                    persona_fixed_tool_state(persona, spec.tool_id.as_str()),
                    ToolboxToolState::Hidden
                )
            })
            .map(|spec| spec.tool_id.clone())
            .collect()
    }

    fn build_tool_entry_snapshot(
        tool_id: &str,
        declared_state: ToolboxToolState,
        observe_state: ToolboxToolState,
        provider_exposed: bool,
        callable: bool,
        declared_tool: bool,
        governance_auto: bool,
    ) -> Value {
        let mut reason_bits = vec![
            format!("default={}", declared_state.key()),
            format!("observe={}", observe_state.key()),
            format!("provider={}", if provider_exposed { "yes" } else { "no" }),
            format!("callable={}", if callable { "yes" } else { "no" }),
        ];
        if declared_tool {
            reason_bits.push("declared=yes".to_string());
        }
        if governance_auto {
            reason_bits.push("governance=auto".to_string());
        }
        json!({
            "tool_id": tool_id,
            "default_state": declared_state.key(),
            "observe_state": observe_state.key(),
            "provider_exposed": provider_exposed,
            "callable": callable,
            "declared_tool": declared_tool,
            "governance_auto": governance_auto,
            "reason": reason_bits.join("; "),
        })
    }

    fn build_persona_tool_projection_snapshot(
        kind: &str,
        persona: crate::PersonaKind,
        role: Option<&crate::roles::DynamicRoleSpec>,
        observe_gateway: &ToolboxProjectionGateway,
        provider_exposed_tools: Vec<String>,
        projection_override: Option<&crate::mcp::ToolProjectionOverride>,
    ) -> Result<Value> {
        let builtin_context_governance = if role.is_none() {
            Some(load_current_context_governance_config()?)
        } else {
            None
        };
        let provider_set = provider_exposed_tools
            .iter()
            .cloned()
            .collect::<BTreeSet<_>>();
        let callable_tools = sorted_tool_ids(observe_gateway.allowed_local_tool_ids().into_iter());
        let callable_set = callable_tools.iter().cloned().collect::<BTreeSet<_>>();
        let default_tools = if let Some(role) = role {
            let governance_auto = role_governance_auto_tools(role);
            role.contract()
                .capability
                .default_tools
                .into_iter()
                .filter(|tool| !governance_auto.iter().any(|item| item == tool))
                .collect::<Vec<_>>()
        } else {
            default_tool_ids_for_persona(persona, observe_gateway.specs.as_slice())
        };
        let governance_auto_tools = role
            .map(role_governance_auto_tools)
            .or_else(|| {
                builtin_context_governance
                    .as_ref()
                    .map(|config| context_governance_auto_tools_for_mode(config.mode.as_str()))
            })
            .unwrap_or_default();
        let default_tool_set = default_tools.iter().cloned().collect::<BTreeSet<_>>();
        let governance_auto_set = governance_auto_tools
            .iter()
            .cloned()
            .collect::<BTreeSet<_>>();
        let observe_states = observe_gateway
            .specs
            .iter()
            .map(|spec| {
                let state = observe_gateway
                    .state_map
                    .get(spec.tool_id.as_str())
                    .copied()
                    .unwrap_or(ToolboxToolState::Hidden);
                json!({
                    "tool_id": spec.tool_id.as_str(),
                    "state": state.key(),
                })
            })
            .collect::<Vec<_>>();
        let entries = observe_gateway
            .specs
            .iter()
            .map(|spec| {
                let default_state = persona_fixed_tool_state(persona, spec.tool_id.as_str());
                let observe_state = observe_gateway
                    .state_map
                    .get(spec.tool_id.as_str())
                    .copied()
                    .unwrap_or(ToolboxToolState::Hidden);
                let provider_exposed = provider_set.contains(spec.tool_id.as_str());
                let callable = callable_set.contains(spec.tool_id.as_str());
                let declared_tool = default_tool_set.contains(spec.tool_id.as_str());
                let governance_auto = governance_auto_set.contains(spec.tool_id.as_str());
                build_tool_entry_snapshot(
                    spec.tool_id.as_str(),
                    default_state,
                    observe_state,
                    provider_exposed,
                    callable,
                    declared_tool,
                    governance_auto,
                )
            })
            .collect::<Vec<_>>();
        let observe_prompt = observe_gateway.render_prompt(None);
        let (role_id, context_dir, memory_dir, context_governance) = if let Some(role) = role {
            let contract = role.contract();
            (
                Some(contract.identity.id),
                Some(contract.storage.context_dir),
                Some(contract.storage.memory_dir),
                Some(json!({
                    "mode": contract.context_governance.mode,
                    "manage_threshold_kb": contract.context_governance.manage_threshold_kb,
                    "compact_threshold_kb": contract.context_governance.compact_threshold_kb,
                    "report_to_matrix": contract.context_governance.report_to_matrix,
                })),
            )
        } else {
            (
                None,
                None,
                None,
                builtin_context_governance
                    .as_ref()
                    .map(context_governance_config_json),
            )
        };
        let persona_key = role_id
            .clone()
            .unwrap_or_else(|| persona.slug().to_string());
        let label = role
            .map(|role| role.contract().identity.title)
            .unwrap_or_else(|| persona.context_dir_name().to_string());
        let default_tools_count = default_tools.len();
        let governance_auto_tools_count = governance_auto_tools.len();
        let provider_exposed_tools_count = provider_exposed_tools.len();
        let callable_tools_count = callable_tools.len();
        let observed_tools_count = observe_states.len();
        let tool_entries_count = entries.len();
        Ok(json!({
            "kind": kind,
            "persona": persona_key,
            "label": label,
            "base_persona": persona.slug(),
            "role_id": role_id,
            "context_dir": context_dir.unwrap_or_else(|| persona.context_dir_name().to_string()),
            "memory_dir": memory_dir.unwrap_or_else(|| persona.context_dir_name().to_string()),
            "context_governance": context_governance,
            "default_tools": default_tools,
            "governance_auto_tools": governance_auto_tools,
            "provider_exposed_tools": provider_exposed_tools,
            "callable_tools": callable_tools,
            "observe_view": {
                "prompt": observe_prompt,
                "entries": observe_states,
            },
            "tool_entries": entries,
            "counts": {
                "default_tools": default_tools_count,
                "governance_auto_tools": governance_auto_tools_count,
                "provider_exposed_tools": provider_exposed_tools_count,
                "callable_tools": callable_tools_count,
                "observed_tools": observed_tools_count,
                "tool_entries": tool_entries_count,
            },
            "projection_override_active": projection_override.is_some(),
        }))
    }

    pub(crate) fn tool_projection_snapshot() -> Result<Value> {
        let projection_override = crate::mcp::tool_projection_override();
        let builtin_personas = crate::PersonaKind::ALL
            .iter()
            .copied()
            .map(|persona| {
                with_persona_context(persona, || {
                    let observe_gateway =
                        ToolboxProjectionGateway::load_for_persona_read_only(persona, false, &[])?;
                    let provider_exposed_tools = projection_override
                        .as_ref()
                        .map(|override_config| {
                            sorted_tool_ids(override_config.allowed_tool_ids.iter().cloned())
                        })
                        .unwrap_or_else(|| {
                            sorted_tool_ids(observe_gateway.allowed_local_tool_ids().into_iter())
                        });
                    build_persona_tool_projection_snapshot(
                        "builtin_persona",
                        persona,
                        None,
                        &observe_gateway,
                        provider_exposed_tools,
                        projection_override.as_ref(),
                    )
                })
            })
            .collect::<Result<Vec<_>>>()?;

        let dynamic_roles = crate::roles::enabled_roles()
            .into_iter()
            .map(|role| {
                let base_persona = role.contract().capability.base_persona;
                let role_kind = role.clone();
                with_dynamic_role_context(&role_kind, || {
                    let observe_gateway = ToolboxProjectionGateway::load_for_persona_read_only(
                        base_persona,
                        base_persona.tool_management_enabled(),
                        &[],
                    )?;
                    let provider_gateway = with_persona_context(base_persona, || {
                        ToolboxProjectionGateway::load_for_persona_read_only(
                            base_persona,
                            base_persona.tool_management_enabled(),
                            &[],
                        )
                    })?;
                    let provider_exposed_tools = projection_override
                        .as_ref()
                        .map(|override_config| {
                            sorted_tool_ids(override_config.allowed_tool_ids.iter().cloned())
                        })
                        .unwrap_or_else(|| {
                            sorted_tool_ids(provider_gateway.allowed_local_tool_ids().into_iter())
                        });
                    build_persona_tool_projection_snapshot(
                        "dynamic_role",
                        base_persona,
                        Some(&role_kind),
                        &observe_gateway,
                        provider_exposed_tools,
                        projection_override.as_ref(),
                    )
                })
            })
            .collect::<Result<Vec<_>>>()?;

        let mut personas = builtin_personas;
        personas.extend(dynamic_roles);
        let summary = json!({
            "builtin_personas": crate::PersonaKind::ALL.len(),
            "dynamic_roles": personas.len().saturating_sub(crate::PersonaKind::ALL.len()),
            "personas": personas.len(),
            "tool_catalog": toolbox_specs_from_schema().len(),
        });
        let override_json = projection_override
            .as_ref()
            .map(|override_config| {
                let mut allowed = override_config
                    .allowed_tool_ids
                    .iter()
                    .cloned()
                    .collect::<Vec<_>>();
                allowed.sort();
                json!({
                    "active": true,
                    "allow_native_web_search": override_config.allow_native_web_search,
                    "allowed_tool_ids": allowed,
                })
            })
            .unwrap_or_else(|| {
                json!({
                    "active": false,
                    "allow_native_web_search": false,
                    "allowed_tool_ids": Vec::<String>::new(),
                })
            });
        Ok(json!({
            "protocol_version": 1,
            "ts_ms": crate::unix_timestamp_millis_u64_shared(),
            "summary": summary,
            "projection_override": override_json,
            "personas": personas,
        }))
    }

    pub fn persona_folded_observation(
        persona: crate::PersonaKind,
        include_recent: usize,
    ) -> Result<String> {
        with_persona_context(persona, || {
            let bundle = load_bundle()?;
            let mode = bundle.meta.mode.label();
            let focus = bundle
                .meta
                .focus_brief
                .as_deref()
                .map(normalize_text)
                .filter(|value| !value.is_empty())
                .unwrap_or_else(|| "(none)".to_string());
            let active_entries = active_context_entries(&bundle);
            let mut lines = vec![
                format!("persona: {}", persona.context_dir_name()),
                format!("tab: {}", persona.tab_title()),
                format!("mode: {mode}"),
                format!("focus: {focus}"),
                format!("active_entries: {}", active_entries.len()),
                "recent_folded_chat:".to_string(),
            ];
            let limit = include_recent.clamp(1, 24);
            let start = active_entries.len().saturating_sub(limit);
            for entry in active_entries.iter().skip(start) {
                let mut preview = render_context_entry_content(entry)
                    .unwrap_or_else(|| normalize_text(entry.text.as_str()));
                if entry.kind == "tool"
                    || (preview.lines().any(|line| line.trim() == "INPUT:")
                        && preview.lines().any(|line| line.trim() == "OUTPUT:"))
                {
                    let first = preview.lines().next().unwrap_or_default().trim();
                    let mut input_lines = Vec::new();
                    let mut in_input = false;
                    for line in preview.lines() {
                        let trimmed = line.trim();
                        if trimmed == "OUTPUT:" {
                            break;
                        }
                        if in_input {
                            input_lines.push(trimmed);
                            continue;
                        }
                        if trimmed == "INPUT:" {
                            in_input = true;
                        }
                    }
                    let input = input_lines.join(" ");
                    preview = [first, input.as_str()]
                        .into_iter()
                        .filter(|part| !part.is_empty())
                        .collect::<Vec<_>>()
                        .join(" / ");
                }
                if preview.is_empty() {
                    preview = "(empty)".to_string();
                }
                lines.push(format!(
                    "- e{} r{} {}:{} · {}",
                    entry.stable_id,
                    entry.round_id,
                    entry.role.label(),
                    entry.kind,
                    preview_inline_text(preview.as_str(), 180)
                ));
            }
            if active_entries.is_empty() {
                lines.push("- (empty)".to_string());
            }
            Ok(lines.join("\n"))
        })
    }

