    pub fn record_tool_context_visibility_request(
        requested_percent: Option<u8>,
        tool_name: &str,
        reason: Option<&str>,
    ) -> Result<u8> {
        let mut bundle = load_bundle()?;
        let previous = sanitize_context_visibility_percent(bundle.meta.context_visibility_percent);
        let mut percent = requested_percent
            .map(sanitize_context_visibility_percent)
            .unwrap_or(previous);
        bundle.meta.context_tool_round_streak =
            bundle.meta.context_tool_round_streak.saturating_add(1);
        if bundle.meta.context_tool_round_streak >= 5 && percent < MAX_CONTEXT_VISIBILITY_PERCENT {
            percent = MAX_CONTEXT_VISIBILITY_PERCENT;
        } else if bundle.meta.context_tool_round_streak >= 3
            && percent < CONTEXT_VISIBILITY_MEDIUM_PERCENT
        {
            percent = CONTEXT_VISIBILITY_MEDIUM_PERCENT;
        }
        bundle.meta.context_visibility_percent = percent;
        let tool_name = normalize_text(tool_name);
        bundle.meta.context_visibility_reason = Some(match normalize_optional_text(reason) {
            Some(reason) => format!("{tool_name}: {reason} · approx {percent}%"),
            None => match requested_percent {
                Some(raw) => format!(
                    "{tool_name} requested approx {}%; applied approx {percent}% after continuous-tool guard",
                    sanitize_context_visibility_percent(raw)
                ),
                None => format!(
                    "{tool_name} completed; continuous tool rounds = {}; applied approx {percent}%",
                    bundle.meta.context_tool_round_streak
                ),
            },
        });
        write_meta(&bundle.meta)?;
        Ok(percent)
    }

    pub fn sync_runtime_threshold_config(config: &RuntimeThresholdConfig) -> Result<()> {
        let mut bundle = load_bundle()?;
        let soft_context_limit_kb = sanitize_context_limit_kb(config.soft_context_limit_kb);
        let hard_context_limit_kb =
            sanitize_context_limit_kb(config.hard_context_limit_kb).max(soft_context_limit_kb);
        let soft_entry_limit = sanitize_context_entry_limit(config.soft_context_entry_limit);
        let hard_entry_limit =
            sanitize_context_entry_limit(config.hard_context_entry_limit).max(soft_entry_limit);
        let soft_focus_limit_kb = sanitize_context_limit_kb(config.soft_focus_limit_kb);
        let hard_focus_limit_kb =
            sanitize_context_limit_kb(config.hard_focus_limit_kb).max(soft_focus_limit_kb);
        let soft_focus_entry_limit = sanitize_context_entry_limit(config.soft_focus_entry_limit);
        let hard_focus_entry_limit =
            sanitize_context_entry_limit(config.hard_focus_entry_limit).max(soft_focus_entry_limit);
        let effective_soft_bytes = if config.context_threshold_enabled {
            soft_context_limit_kb.saturating_mul(1024)
        } else {
            OPEN_CONTEXT_BYTES_KB.saturating_mul(1024)
        };
        let effective_hard_bytes = if config.context_threshold_enabled {
            hard_context_limit_kb.saturating_mul(1024)
        } else {
            OPEN_CONTEXT_BYTES_KB.saturating_mul(1024)
        };
        let effective_soft_entry_limit = if config.context_threshold_enabled {
            soft_entry_limit
        } else {
            OPEN_CONTEXT_ENTRY_LIMIT
        };
        let effective_hard_entry_limit = if config.context_threshold_enabled {
            hard_entry_limit
        } else {
            OPEN_CONTEXT_ENTRY_LIMIT
        };
        let effective_soft_focus_bytes = if config.focus_threshold_enabled {
            soft_focus_limit_kb.saturating_mul(1024)
        } else {
            OPEN_CONTEXT_BYTES_KB.saturating_mul(1024)
        };
        let effective_hard_focus_bytes = if config.focus_threshold_enabled {
            hard_focus_limit_kb.saturating_mul(1024)
        } else {
            OPEN_CONTEXT_BYTES_KB.saturating_mul(1024)
        };
        let effective_soft_focus_entry_limit = if config.focus_threshold_enabled {
            soft_focus_entry_limit
        } else {
            OPEN_CONTEXT_ENTRY_LIMIT
        };
        let effective_hard_focus_entry_limit = if config.focus_threshold_enabled {
            hard_focus_entry_limit
        } else {
            OPEN_CONTEXT_ENTRY_LIMIT
        };
        let effective_fastmemory_item_limit = if config.fastmemory_threshold_enabled {
            sanitize_section_item_limit(config.fastmemory_item_limit)
        } else {
            OPEN_SECTION_ITEM_LIMIT
        };
        let meta = &mut bundle.meta;
        if meta.soft_context_bytes == effective_soft_bytes
            && meta.hard_context_bytes == effective_hard_bytes
            && meta.soft_context_entry_limit == effective_soft_entry_limit
            && meta.hard_context_entry_limit == effective_hard_entry_limit
            && meta.soft_focus_bytes == effective_soft_focus_bytes
            && meta.hard_focus_bytes == effective_hard_focus_bytes
            && meta.soft_focus_entry_limit == effective_soft_focus_entry_limit
            && meta.hard_focus_entry_limit == effective_hard_focus_entry_limit
            && meta.fastmemory_item_limit == effective_fastmemory_item_limit
        {
            return Ok(());
        }
        meta.soft_context_bytes = effective_soft_bytes;
        meta.hard_context_bytes = effective_hard_bytes;
        meta.soft_context_entry_limit = effective_soft_entry_limit;
        meta.hard_context_entry_limit = effective_hard_entry_limit;
        meta.soft_focus_bytes = effective_soft_focus_bytes;
        meta.hard_focus_bytes = effective_hard_focus_bytes;
        meta.soft_focus_entry_limit = effective_soft_focus_entry_limit;
        meta.hard_focus_entry_limit = effective_hard_focus_entry_limit;
        meta.fastmemory_item_limit = effective_fastmemory_item_limit;
        write_meta(meta)
    }

