    #[cfg(test)]
    pub fn load_status_stats() -> Result<ContextStatusStats> {
        load_status_stats_with_provider(None)
    }

    pub fn load_status_stats_for_provider(provider: &ProviderConfig) -> Result<ContextStatusStats> {
        load_status_stats_with_provider(Some(provider))
    }

    fn load_status_stats_with_provider(
        provider: Option<&ProviderConfig>,
    ) -> Result<ContextStatusStats> {
        let mut gateway = PersonaContextGateway::load()?;
        let active_entries = active_context_entries(gateway.bundle()).len();
        let provider_messages = gateway.provider_messages(None)?;
        let (provider_input_chars, provider_input_bytes) =
            message_chars_and_bytes(provider_messages.as_slice());
        let (codex_replay_chars, codex_replay_bytes) =
            codex_replay_chars_and_bytes(provider_messages.as_slice());
        let local_tool_schema =
            serde_json::to_string(&crate::mcp::codex_tools_for_provider()).unwrap_or_default();
        let tool_schema_chars = local_tool_schema.chars().count();
        let tool_schema_bytes = local_tool_schema.len();

        let (request_surface_chars, request_surface_bytes, active_context_kb) =
            if let Some(provider) = provider {
                let surface = crate::provider::estimate_request_surface_stats(
                    provider,
                    provider_messages.as_slice(),
                    true,
                );
                (
                    surface.body_chars,
                    surface.body_bytes,
                    (surface.body_bytes.saturating_add(1023) / 1024) as u64,
                )
            } else {
                let input_items =
                    crate::provider::build_codex_input_messages(provider_messages.as_slice());
                let request_body = json!({
                    "model": "status",
                    "input": input_items,
                    "stream": true,
                });
                let (body_chars, body_bytes) =
                    request_surface_stats_for_messages(provider_messages.as_slice(), &request_body);
                (
                    body_chars,
                    body_bytes,
                    ((body_bytes
                        .saturating_add(tool_schema_bytes)
                        .saturating_add(1023))
                        / 1024) as u64,
                )
            };
        Ok(ContextStatusStats {
            active_entries,
            active_context_kb,
            provider_input_chars,
            provider_input_bytes,
            request_surface_chars,
            request_surface_bytes,
            codex_replay_chars,
            codex_replay_bytes,
            tool_schema_chars,
            tool_schema_bytes,
        })
    }

