    pub fn append_tool_event(
        round_id: u64,
        tool_name: &str,
        brief: &str,
        action_label: &str,
        command_preview: &str,
        output_preview: &str,
    ) -> Result<()> {
        let mut lines = vec![format!(
            "Tool {} · {}{}",
            tool_name.trim(),
            action_label.trim(),
            if brief.trim().is_empty() {
                String::new()
            } else {
                format!(" · {}", brief.trim())
            }
        )];
        if !command_preview.trim().is_empty() {
            lines.push("INPUT:".to_string());
            lines.extend(
                normalize_text(command_preview)
                    .lines()
                    .map(str::to_string)
                    .collect::<Vec<_>>(),
            );
        }
        if !output_preview.trim().is_empty() {
            lines.push("OUTPUT:".to_string());
            lines.extend(
                normalize_text(output_preview)
                    .lines()
                    .map(str::to_string)
                    .collect::<Vec<_>>(),
            );
        }
        append_round_message_inner(
            Some(round_id),
            ContextRole::System,
            None,
            lines.join("\n").as_str(),
        )
    }

    pub fn append_codex_tool_replay(
        round_id: u64,
        replay_call_item_json: &str,
        replay_output_item_jsons: &[String],
    ) -> Result<()> {
        let mut bundle = load_bundle()?;
        let mut next_id = next_context_entry_id(active_context_entries(&bundle));
        let call_entry = build_codex_replay_context_entry(
            next_id,
            allocate_stable_context_id(&mut bundle.meta),
            round_id,
            replay_call_item_json,
            "function_call",
        );
        next_id = next_id.saturating_add(1);
        push_active_context_entry(&mut bundle, call_entry);
        for item_json in replay_output_item_jsons {
            let output_entry = build_codex_replay_context_entry(
                next_id,
                allocate_stable_context_id(&mut bundle.meta),
                round_id,
                item_json.as_str(),
                "tool_output",
            );
            next_id = next_id.saturating_add(1);
            push_active_context_entry(&mut bundle, output_entry);
        }
        save_bundle(&mut bundle)
    }

