    fn summarize_id_refs(label: &str, ids: &[u64]) -> String {
        if ids.is_empty() {
            return format!("{label}: none");
        }
        if ids.len() <= 6 {
            return format!("{label}: {:?}", ids);
        }
        format!(
            "{label}: {} items (e{}..e{})",
            ids.len(),
            ids.first().copied().unwrap_or_default(),
            ids.last().copied().unwrap_or_default()
        )
    }

