    fn context_entries_snapshot(
        entries: &[ContextEntry],
        ids: &[u64],
    ) -> Result<Vec<ContextEntry>> {
        let id_set = ids.iter().copied().collect::<HashSet<_>>();
        let matched = entries
            .iter()
            .filter(|entry| id_set.contains(&entry.stable_id))
            .cloned()
            .collect::<Vec<_>>();
        if matched.len() != ids.len() {
            return Err(anyhow!("目标 entry_ids 与现存上下文不一致"));
        }
        Ok(matched)
    }

    fn context_items_snapshot(items: &[ContextItem], ids: &[u64]) -> Result<Vec<ContextItem>> {
        let id_set = ids.iter().copied().collect::<HashSet<_>>();
        let matched = items
            .iter()
            .filter(|item| id_set.contains(&item.stable_id))
            .cloned()
            .collect::<Vec<_>>();
        if matched.len() != ids.len() {
            return Err(anyhow!("目标 item_ids 与现存条目不一致"));
        }
        Ok(matched)
    }

    fn replace_context_entries(
        entries: &mut Vec<ContextEntry>,
        ids: &[u64],
        replacement: ContextEntry,
    ) -> Result<usize> {
        let id_set = ids.iter().copied().collect::<HashSet<_>>();
        let mut matched = entries
            .iter()
            .enumerate()
            .filter(|(_, entry)| id_set.contains(&entry.stable_id))
            .map(|(index, entry)| (index, entry.round_id))
            .collect::<Vec<_>>();
        if matched.len() != ids.len() {
            return Err(anyhow!("目标 entry_ids 与现存上下文不一致"));
        }
        matched.sort_by_key(|(index, _)| *index);
        let insert_at = matched[0].0;
        entries.retain(|entry| !id_set.contains(&entry.stable_id));
        let insert_at = insert_at.min(entries.len());
        entries.insert(insert_at, replacement);
        Ok(insert_at)
    }

    fn folded_context_text(text: Option<&str>) -> String {
        normalize_optional_text(text).unwrap_or_else(|| "已折叠".to_string())
    }

    fn fold_context_entry(entry: &mut ContextEntry, folded_text: &str) {
        entry.thinking = None;
        if let Some(item_json) = entry.codex_item_json.as_deref()
            && let Ok(mut value) = serde_json::from_str::<serde_json::Value>(item_json)
        {
            match value.get("type").and_then(|value| value.as_str()) {
                Some("function_call_output") => {
                    value["output"] = json!(folded_text);
                    if let Ok(serialized) = serde_json::to_string(&value) {
                        entry.codex_item_json = Some(serialized.clone());
                        entry.text = ParsedCodexItem::parse(serialized.as_str())
                            .map(|item| item.summary(serialized.as_str()))
                            .unwrap_or_else(|| folded_text.to_string());
                        return;
                    }
                }
                Some("message") => {
                    let role = value
                        .get("role")
                        .and_then(|value| value.as_str())
                        .unwrap_or("system");
                    let content_type = if role == "assistant" {
                        "output_text"
                    } else {
                        "input_text"
                    };
                    value["content"] = json!([{
                        "type": content_type,
                        "text": folded_text,
                    }]);
                    if let Ok(serialized) = serde_json::to_string(&value) {
                        entry.codex_item_json = Some(serialized);
                        entry.text = folded_text.to_string();
                        return;
                    }
                }
                _ => {}
            }
        }
        entry.text = folded_text.to_string();
        entry.codex_item_json = build_context_entry_codex_item_json(entry);
    }

    fn replace_items(
        items: &mut Vec<ContextItem>,
        ids: &[u64],
        replacement: ContextItem,
    ) -> Result<usize> {
        let id_set = ids.iter().copied().collect::<HashSet<_>>();
        let mut matched = items
            .iter()
            .enumerate()
            .filter(|(_, item)| id_set.contains(&item.stable_id))
            .map(|(index, _)| index)
            .collect::<Vec<_>>();
        if matched.len() != ids.len() {
            return Err(anyhow!("目标 item_ids 与现存条目不一致"));
        }
        matched.sort_unstable();
        let insert_at = matched[0];
        items.retain(|item| !id_set.contains(&item.stable_id));
        let insert_at = insert_at.min(items.len());
        items.insert(insert_at, replacement);
        Ok(insert_at)
    }

