        #[test]
        fn load_status_stats_counts_provider_surface_and_tool_schema() {
            with_test_home(|| {
                set_persona(crate::PersonaKind::Matrix);
                crate::mcp::set_tool_persona(crate::PersonaKind::Matrix);
                clear_messages().expect("clear");
                manage_request(ContextManageRequest::Write {
                    target: ContextTarget::FastMemory,
                    section: Some(FastMemorySection::Surface),
                    role: None,
                    kind: None,
                    round_id: None,
                    text: "status fastmemory marker".to_string(),
                })
                .expect("write fastmemory");
                let round_id = begin_round().expect("begin round");
                append_round_message(
                    round_id,
                    ContextRole::User,
                    Some("status thinking marker"),
                    "status visible body",
                )
                .expect("append assistant");

                let messages = load_provider_messages().expect("load provider messages");
                let provider_input_chars = messages
                    .iter()
                    .map(|message| message.content.chars().count())
                    .sum::<usize>();
                let provider_input_bytes = messages
                    .iter()
                    .map(|message| message.content.len())
                    .sum::<usize>();
                let tool_schema = serde_json::to_string(&crate::mcp::codex_tools_for_provider())
                    .expect("serialize tool schema");
                let request_body = json!({
                    "model": "status",
                    "input": crate::provider::build_codex_input_messages(&messages),
                    "stream": true,
                });
                let request_surface =
                    serde_json::to_string(&request_body).expect("serialize request surface");
                let stats = load_status_stats().expect("load status stats");

                assert_eq!(stats.provider_input_chars, provider_input_chars);
                assert_eq!(stats.provider_input_bytes, provider_input_bytes);
                assert_eq!(stats.request_surface_bytes, request_surface.len());
                assert!(stats.request_surface_chars >= stats.provider_input_chars);
                assert!(stats.codex_replay_chars > 0);
                assert!(stats.codex_replay_bytes > 0);
                assert_eq!(stats.tool_schema_bytes, tool_schema.len());
                assert_eq!(
                    stats.active_context_kb,
                    ((request_surface
                        .len()
                        .saturating_add(tool_schema.len())
                        .saturating_add(1023))
                        / 1024) as u64
                );
                assert!(
                    messages[0].content.contains("[fastmemory area start]")
                        || messages[0].content.contains("[context state area start]")
                );
                assert!(messages[0].content.contains("status fastmemory marker"));
                assert!(messages.iter().any(|message| {
                    message.content.contains("status thinking marker")
                        && message.content.contains("status visible body")
                }));
            });
        }

