        #[test]
        fn transient_toolbox_expansions_collapse_after_request_boundary() {
            with_test_home(|| {
                set_persona(crate::PersonaKind::Matrix);
                crate::mcp::set_tool_persona(crate::PersonaKind::Matrix);
                clear_messages().expect("clear");

                tool_manage("open", &["command".to_string()], None, None, None)
                    .expect("open command transiently");
                tool_manage("pin", &["apply_patch".to_string()], None, None, None)
                    .expect("pin apply_patch");
                let before = projected_toolbox_local_tool_ids().expect("allowed before collapse");
                assert!(before.contains("command"));
                assert!(before.contains("apply_patch"));

                let changed =
                    collapse_transient_toolbox_expansions().expect("collapse transient tools");
                assert_eq!(changed, 1);
                let after = projected_toolbox_local_tool_ids().expect("allowed after collapse");
                assert!(!after.contains("command"));
                assert!(after.contains("apply_patch"));
            });
        }

