        #[test]
        fn context_manage_summary_supports_non_contiguous_entry_ids_with_fresh_stable_id() {
            with_test_home(|| {
                clear_messages().expect("clear");
                for idx in 1..=5 {
                    let round_id = begin_round().expect("begin round");
                    append_round_message(
                        round_id,
                        ContextRole::User,
                        None,
                        format!("跳跃消息 {idx}").as_str(),
                    )
                    .expect("append context");
                }

                let bundle = load_bundle().expect("bundle before");
                let old_ids = vec![
                    bundle.standard.entries[1].stable_id,
                    bundle.standard.entries[3].stable_id,
                ];
                manage_request(ContextManageRequest::Summary {
                    target: ContextTarget::Context,
                    section: None,
                    role: Some(ContextRole::System),
                    kind: Some("summary".to_string()),
                    entry_ids: old_ids.clone(),
                    entry_start_id: None,
                    entry_end_id: None,
                    item_ids: Vec::new(),
                    item_start_id: None,
                    item_end_id: None,
                    text: "跳跃收口摘要".to_string(),
                })
                .expect("summary non-contiguous context ids");

                let bundle = load_bundle().expect("bundle after");
                assert_eq!(
                    bundle
                        .standard
                        .entries
                        .iter()
                        .map(|entry| (entry.id, entry.text.as_str()))
                        .collect::<Vec<_>>(),
                    vec![
                        (1, "跳跃消息 1"),
                        (2, "跳跃收口摘要"),
                        (3, "跳跃消息 3"),
                        (4, "跳跃消息 5"),
                    ]
                );
                let replacement = bundle
                    .standard
                    .entries
                    .iter()
                    .find(|entry| entry.text == "跳跃收口摘要")
                    .expect("replacement entry");
                assert!(!old_ids.contains(&replacement.stable_id));
                assert!(
                    bundle
                        .standard
                        .entries
                        .iter()
                        .all(|entry| !old_ids.contains(&entry.stable_id))
                );
            });
        }

