        #[test]
        fn context_manage_summary_range_tolerates_missing_range_boundary_if_middle_entries_exist() {
            with_test_home(|| {
                clear_messages().expect("clear");
                for idx in 1..=4 {
                    let round_id = begin_round().expect("begin round");
                    append_round_message(
                        round_id,
                        ContextRole::User,
                        None,
                        format!("漂移消息 {idx}").as_str(),
                    )
                    .expect("append context");
                }

                let mut bundle = load_bundle().expect("bundle before");
                let start_id = bundle.standard.entries[1].stable_id;
                let middle_id = bundle.standard.entries[2].stable_id;
                let end_id = bundle.standard.entries[3].stable_id;
                bundle
                    .standard
                    .entries
                    .retain(|entry| entry.stable_id != end_id);
                save_bundle(&mut bundle).expect("save mutated bundle");

                manage_request(ContextManageRequest::Summary {
                    target: ContextTarget::Context,
                    section: None,
                    role: Some(ContextRole::System),
                    kind: Some("summary".to_string()),
                    entry_ids: Vec::new(),
                    entry_start_id: Some(start_id),
                    entry_end_id: Some(end_id),
                    item_ids: Vec::new(),
                    item_start_id: None,
                    item_end_id: None,
                    text: "漂移区间摘要".to_string(),
                })
                .expect("summary context drifted range");

                let bundle = load_bundle().expect("bundle after");
                assert!(
                    bundle
                        .standard
                        .entries
                        .iter()
                        .any(|entry| entry.text == "漂移区间摘要")
                );
                assert!(
                    !bundle
                        .standard
                        .entries
                        .iter()
                        .any(|entry| entry.stable_id == middle_id && entry.text == "漂移消息 3")
                );
            });
        }

