        #[test]
        fn load_provider_messages_repairs_legacy_raw_tool_codex_items_to_summary_messages() {
            with_test_home(|| {
                clear_messages().expect("clear");
                let raw_output = "RAW_TOOL_OUTPUT_SHOULD_NOT_SURVIVE_IN_CONTEXT";
                let mut bundle = load_bundle().expect("load bundle");
                bundle.standard.entries.push(ContextEntry {
                    id: 42,
                    stable_id: 42,
                    round_id: 7,
                    role: ContextRole::System,
                    kind: "function_call_output".to_string(),
                    thinking: None,
                    text: "function_call_output · call_legacy · folded summary".to_string(),
                    codex_item_json: Some(
                        json!({
                            "type": "function_call_output",
                            "call_id": "call_legacy",
                            "output": raw_output,
                        })
                        .to_string(),
                    ),
                    created_at: 42,
                });
                let state = persona_state_from_bundle(&bundle);
                write_persona_state(&state_path(), &state).expect("write legacy raw state");

                let messages = load_provider_messages().expect("load provider messages");
                let items = crate::provider::build_codex_input_messages(&messages);
                assert!(!items.iter().any(|item| {
                    item.get("type").and_then(|value| value.as_str())
                        == Some("function_call_output")
                }));
                assert!(items.iter().any(|item| {
                    item.get("type").and_then(|value| value.as_str()) == Some("message")
                        && item["role"] == json!("system")
                        && item["content"][0]["text"]
                            .as_str()
                            .is_some_and(|text| text.contains("folded summary"))
                }));
                assert!(
                    !serde_json::to_string(&items)
                        .expect("items json")
                        .contains(raw_output)
                );

                let repaired = load_bundle().expect("reloaded bundle");
                let repaired_item = repaired.standard.entries[0]
                    .codex_item_json
                    .as_deref()
                    .expect("repaired item");
                let repaired_value = serde_json::from_str::<serde_json::Value>(repaired_item)
                    .expect("valid repaired item");
                assert_eq!(repaired_value["type"], json!("message"));
                assert_eq!(repaired_value["role"], json!("system"));
                assert!(
                    repaired_value["content"][0]["text"]
                        .as_str()
                        .expect("summary text")
                        .contains("folded summary")
                );
                assert!(!repaired_item.contains(raw_output));
            });
        }

