        #[test]
        fn focus_enter_and_exit_switch_active_mode_and_clear_focus_store() {
            with_test_home(|| {
                clear_messages().expect("clear");
                manage_request(ContextManageRequest::FocusEnter {
                    brief: "修复上下文工程".to_string(),
                    task: "完成多文件上下文仓储".to_string(),
                    user_goal: Some("一次性收口".to_string()),
                    reason: Some("需要隔离主线时间线，快速收口专项施工".to_string()),
                    plan_a: Some("先改 store".to_string()),
                    plan_b: Some("再接工具".to_string()),
                    fallback: Some("若两条方案都不稳，就先总结阻塞后退出".to_string()),
                    expected_result: Some(
                        "focuscontext 只保留主任务，退出时带回 call_in/out".to_string(),
                    ),
                    exit_condition: Some("功能与测试通过".to_string()),
                })
                .expect("focus enter");
                let view = load_view_state().expect("view");
                assert_eq!(view.mode, ContextMode::Focus);
                assert_eq!(view.focus_brief.as_deref(), Some("修复上下文工程"));

                let focus_round = begin_round().expect("focus round");
                append_round_message(focus_round, ContextRole::User, None, "专注任务内发言")
                    .expect("append focus user");
                assert_eq!(load_bundle().expect("bundle").focus.entries.len(), 2);

                manage_request(ContextManageRequest::FocusExit {
                    summary: "已完成专注任务并回写总结".to_string(),
                    completed: Some("完成 focus 覆盖/恢复链路".to_string()),
                    implemented: Some("落地 task call_in/out 回灌".to_string()),
                    steps: Some("切换模式、追加专注消息、收尾退出".to_string()),
                    key_info: Some(
                        "focuscontext 只保留任务态主链，由 summary 动态治理".to_string(),
                    ),
                    result: Some("标准上下文新增 call_in + call_out".to_string()),
                    exit_reason: Some("专项任务已完成，恢复标准模式".to_string()),
                    fastmemory_section: Some(FastMemorySection::Experience),
                    fastmemory_text: Some("上下文工程已落地".to_string()),
                })
                .expect("focus exit");
                let bundle = load_bundle().expect("bundle after exit");
                assert_eq!(bundle.meta.mode, ContextMode::Standard);
                assert!(bundle.focus.entries.is_empty());
                assert!(
                    bundle
                        .standard
                        .entries
                        .iter()
                        .any(|entry| entry.kind == "focus_call_in")
                );
                assert!(
                    bundle
                        .standard
                        .entries
                        .iter()
                        .any(|entry| entry.kind == "focus_call_out")
                );
                assert!(bundle.fastmemory.entries.is_empty());
                assert_eq!(bundle.fastmemory.experience.len(), 1);
                assert_eq!(bundle.fastmemory.experience[0].text, "上下文工程已落地");
            });
        }

