        #[test]
        fn self_managed_context_does_not_soft_trigger_maintenance() {
            with_test_home(|| {
                for mode in ["summary_compact", "vision_compact"] {
                    clear_messages().expect("clear");
                    let mut bundle = load_bundle().expect("load bundle");
                    bundle.meta.context_governance = ContextGovernanceConfig {
                        mode: mode.to_string(),
                        manage_threshold_kb: 64,
                        compact_threshold_kb: 1024,
                        report_to_matrix: true,
                    };
                    bundle.meta.soft_context_bytes = 64;
                    bundle.meta.hard_context_bytes = 1024;
                    write_meta(&bundle.meta).expect("write meta");

                    let round_id = begin_round().expect("begin round");
                    append_round_message(
                        round_id,
                        ContextRole::User,
                        None,
                        "soft-threshold-only self managed payload xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx",
                    )
                    .expect("append");

                    let bundle = load_bundle().expect("bundle");
                    let context_bytes = current_context_bytes(&bundle.standard);
                    assert!(
                        context_bytes >= 64 && context_bytes < 1024,
                        "test payload must sit between soft and hard thresholds, got {context_bytes}"
                    );
                    let tickets = sync_maintenance_requests().expect("sync tickets");
                    assert!(
                        tickets.is_empty(),
                        "{mode} should not auto-queue context maintenance below hard threshold"
                    );
                }
            });
        }

