        #[test]
        fn load_provider_messages_in_focus_mode_uses_focus_markers_and_hint_block() {
            with_test_home(|| {
                clear_messages().expect("clear");
                let standard_round = begin_round().expect("begin round");
                append_round_message(
                    standard_round,
                    ContextRole::User,
                    None,
                    "进入专注模式前的对话",
                )
                .expect("append standard");

                manage_request(ContextManageRequest::FocusEnter {
                    brief: "排查上下文焦点".to_string(),
                    task: "验证 provider 注入的 focus 提示".to_string(),
                    user_goal: Some("避免历史参考抢走当前计划".to_string()),
                    reason: Some("专注模式必须明确谁是当前主任务".to_string()),
                    plan_a: Some("检查系统区块".to_string()),
                    plan_b: Some("检查 active area marker".to_string()),
                    fallback: Some("至少保证 call_in 任务卡在 focuscontext 顶部".to_string()),
                    expected_result: Some("provider 能明确区分冻结参考与当前主任务".to_string()),
                    exit_condition: Some("系统提示与 marker 验证通过".to_string()),
                })
                .expect("focus enter");

                let messages = load_provider_messages().expect("load provider messages");
                let system = messages
                    .iter()
                    .find(|message| message.role == "system")
                    .expect("system message");
                assert!(system.content.contains("[focus mode area start]"));
                assert!(
                    system
                        .content
                        .contains("focuscontext 尾部的 call_in plan 是本轮唯一主任务")
                );
                assert!(
                    messages
                        .iter()
                        .any(|message| message.content.contains("[focuscontext area start]"))
                );
                assert!(
                    messages
                        .iter()
                        .any(|message| message.content.contains("[focuscontext area end]"))
                );
                assert!(system.content.contains("最近 1 轮对话通常更接近当前任务"));
                assert!(!system.content.contains("[#"));
                assert!(!system.content.contains("e1"));
                assert!(!system.content.contains("i1"));
            });
        }

