        #[test]
        fn manage_request_summary_outputs_context_diff_preview() {
            with_test_home(|| {
                clear_messages().expect("clear");
                manage_request(ContextManageRequest::Write {
                    target: ContextTarget::Context,
                    section: None,
                    role: Some(ContextRole::System),
                    kind: Some("note".to_string()),
                    round_id: Some(1),
                    text: "旧的上下文笔记".to_string(),
                })
                .expect("write context");
                let bundle = load_bundle().expect("load bundle");
                let target_id = bundle.standard.entries[0].id;
                let target_stable_id = bundle.standard.entries[0].stable_id;

                let reply = manage_request(ContextManageRequest::Summary {
                    target: ContextTarget::Context,
                    section: None,
                    role: Some(ContextRole::System),
                    kind: Some("summary".to_string()),
                    entry_ids: vec![target_id],
                    entry_start_id: None,
                    entry_end_id: None,
                    item_ids: Vec::new(),
                    item_start_id: None,
                    item_end_id: None,
                    text: "新的上下文摘要".to_string(),
                })
                .expect("summary context");

                assert!(reply.output_preview.contains("ContextManage succeeded"));
                assert!(reply.output_preview.contains("• Context · SUMMARY"));
                assert!(reply.model_output.contains("Area: Context"));
                assert!(reply.model_output.contains("Action: SUMMARY"));
                assert!(
                    reply
                        .model_output
                        .contains(crate::context::CONTEXT_MANAGEMENT_ACTIVE_HINT)
                );
                assert!(
                    reply
                        .output_preview
                        .contains(crate::context::CONTEXT_MANAGEMENT_ACTIVE_HINT)
                );
                assert!(!reply.model_output.contains("旧的上下文笔记"));
                assert!(!reply.model_output.contains("新的上下文摘要"));
                assert!(reply.output_preview.contains("旧的上下文笔记"));
                assert!(reply.output_preview.contains("新的上下文摘要"));
                assert!(reply.output_preview.contains(&format!(
                    "{target_id} - · e{target_stable_id} [系统/note] 旧的上下文笔记"
                )));
                let bundle = load_bundle().expect("load bundle after");
                let replacement_stable_id = bundle.standard.entries[0].stable_id;
                assert_ne!(replacement_stable_id, target_stable_id);
                assert!(reply.output_preview.contains(&format!(
                    "{target_id} + · e{replacement_stable_id} [系统/summary] 新的上下文摘要"
                )));
            });
        }

        #[test]
        fn focus_context_over_threshold_warns_to_exit_without_maintenance_ticket() {
            with_test_home(|| {
                clear_messages().expect("clear");
                let mut bundle = load_bundle().expect("load bundle");
                bundle.meta.soft_focus_bytes = 96;
                bundle.meta.hard_focus_bytes = 192;
                write_meta(&bundle.meta).expect("write meta");

                manage_request(ContextManageRequest::FocusEnter {
                    brief: "长任务施工".to_string(),
                    task: "验证专注上下文维护".to_string(),
                    user_goal: None,
                    reason: None,
                    plan_a: None,
                    plan_b: None,
                    fallback: None,
                    expected_result: None,
                    exit_condition: None,
                })
                .expect("focus enter");

                for idx in 0..8 {
                    let round_id = begin_round().expect("begin round");
                    append_round_message(
                        round_id,
                        ContextRole::Assistant,
                        None,
                        format!(
                            "专注模式第 {idx} 条长消息，用来触发 focuscontext 压缩阈值。xxxxxxxxxxxxxxxxxxxxxxxxxxxx"
                        )
                        .as_str(),
                    )
                    .expect("append");
                }

                let tickets = sync_maintenance_requests().expect("sync tickets");
                assert!(
                    !tickets
                        .iter()
                        .any(|ticket| ticket.key.starts_with("focuscontext:")),
                    "focus mode must not enqueue summary/compact maintenance for focuscontext"
                );

                let messages = load_provider_messages().expect("load provider messages");
                let joined = messages
                    .iter()
                    .map(|message| message.content.as_str())
                    .collect::<Vec<_>>()
                    .join("\n");
                assert!(joined.contains("[sys:focus_context_exit_required]"));
                assert!(joined.contains("本模式不做 focuscontext 的 summary/compact"));
                assert!(joined.contains("focus_mode.exit"));
                assert!(
                    joined.contains("未完成内容") && joined.contains("下一步计划"),
                    "warning should tell the model what to carry out of focus"
                );
            });
        }

        #[test]
        fn stale_focus_mode_is_repaired_when_focus_store_is_empty() {
            with_test_home(|| {
                clear_messages().expect("clear");
                let mut bundle = load_bundle().expect("load bundle");
                bundle.meta.mode = ContextMode::Focus;
                bundle.meta.focus_brief = Some("残留任务态".to_string());
                bundle.meta.focus_entered_at = Some(123);
                bundle.focus.entries.clear();
                save_bundle(&mut bundle).expect("save stale bundle");

                let view = load_view_state().expect("view");
                assert_eq!(view.mode, ContextMode::Standard);
                assert!(view.focus_brief.is_none());

                let meta = crate::read_json_or_default_shared::<PersonaStateFile>(&state_path())
                    .expect("reload repaired state")
                    .meta;
                assert_eq!(meta.mode, ContextMode::Standard);
                assert!(meta.focus_brief.is_none());
                assert!(meta.focus_entered_at.is_none());
            });
        }

