    pub fn datememorycontext_size_bytes_for_persona(persona: crate::PersonaKind) -> usize {
        std::fs::metadata(persona_memory_root(persona).join(DATEMEMORY_CONTEXT_FILE))
            .map(|meta| meta.len() as usize)
            .unwrap_or(0)
    }

    fn datememorycontext_size_bytes_for_role_dir(memory_dir: &str) -> usize {
        std::fs::metadata(role_memory_root(memory_dir).join(DATEMEMORY_CONTEXT_FILE))
            .map(|meta| meta.len() as usize)
            .unwrap_or(0)
    }

    pub fn datememorycontext_total_size_bytes() -> usize {
        let persona_total = crate::PersonaKind::ALL
            .iter()
            .copied()
            .map(datememorycontext_size_bytes_for_persona)
            .sum::<usize>();
        let role_total = crate::roles::enabled_roles()
            .into_iter()
            .map(|role| {
                datememorycontext_size_bytes_for_role_dir(
                    role.contract().storage.memory_dir.as_str(),
                )
            })
            .sum::<usize>();
        persona_total.saturating_add(role_total)
    }

    pub fn datememorycontext_buffer_sizes() -> Vec<(String, usize)> {
        let mut buffers = crate::PersonaKind::ALL
            .iter()
            .copied()
            .map(|persona| {
                (
                    persona.slug().to_string(),
                    datememorycontext_size_bytes_for_persona(persona),
                )
            })
            .collect::<Vec<_>>();
        buffers.extend(crate::roles::enabled_roles().into_iter().map(|role| {
            (
                role.contract().identity.id,
                datememorycontext_size_bytes_for_role_dir(
                    role.contract().storage.memory_dir.as_str(),
                ),
            )
        }));
        buffers
    }

    pub fn datememory_sql_entry_count() -> usize {
        let path = datememory_db_path();
        let Ok(conn) = open_connection(&path) else {
            return 0;
        };
        if init_datememory_schema(&conn).is_err() {
            return 0;
        }
        conn.query_row("SELECT COUNT(*) FROM datememory_entries", [], |row| {
            row.get::<_, i64>(0)
        })
        .map(|count| count.max(0) as usize)
        .unwrap_or(0)
    }

