    fn current_memory_scope() -> MemoryScope {
        if let Some(persona) = MEMORY_PERSONA_OVERRIDE.with(Cell::get) {
            return MemoryScope::Persona(persona);
        }
        if let Some(role) = current_dynamic_role_memory_context() {
            return MemoryScope::DynamicRole(role);
        }
        ACTIVE_MEMORY_PERSONA
            .with(Cell::get)
            .map(MemoryScope::Persona)
            .unwrap_or_else(|| MemoryScope::Persona(crate::mcp::current_tool_persona()))
    }

