    fn filter_date_range(rows: &mut Vec<DateMemoryRow>, start: Option<&str>, end: Option<&str>) {
        rows.retain(|row| {
            start.is_none_or(|value| row.entry_date.as_str() >= value)
                && end.is_none_or(|value| row.entry_date.as_str() <= value)
        });
    }

    fn transcript_char_count(lines: &[String]) -> usize {
        lines
            .iter()
            .map(|line| line.chars().count())
            .sum::<usize>()
            .saturating_add(lines.len().saturating_sub(1))
    }

    fn format_datememory_entry_label(row: &DateMemoryRow) -> String {
        format!("#{}:{}", row.entry_id, row.segment_index)
    }

    fn format_entry_label_list(labels: &[String], limit: usize) -> String {
        if labels.is_empty() {
            return "(none)".to_string();
        }
        let visible = limit.max(1);
        let mut out = labels.iter().take(visible).cloned().collect::<Vec<_>>();
        if labels.len() > out.len() {
            out.push(format!("… +{}", labels.len() - out.len()));
        }
        out.join(", ")
    }

    fn format_datememory_entry_labels(rows: &[DateMemoryRow], limit: usize) -> String {
        let mut sorted = rows.to_vec();
        sorted.sort_by(|left, right| {
            left.created_at
                .cmp(&right.created_at)
                .then(left.entry_id.cmp(&right.entry_id))
        });
        let labels = sorted
            .iter()
            .map(format_datememory_entry_label)
            .collect::<Vec<_>>();
        format_entry_label_list(labels.as_slice(), limit)
    }

    fn datememory_match_haystack(row: &DateMemoryRow) -> String {
        format!(
            "{}\n{}\n{}\n{}",
            row.title,
            row.summary,
            row.keywords.join("\n"),
            row.content
        )
    }

    fn datememory_matched_rows(rows: &[DateMemoryRow], keywords: &[String]) -> Vec<DateMemoryRow> {
        rows.iter()
            .filter(|row| {
                !match_keywords(datememory_match_haystack(row).as_str(), keywords).is_empty()
            })
            .cloned()
            .collect()
    }

    fn collect_datememory_evidence_entry_ids(rows: &[DateMemoryRow]) -> Vec<u64> {
        let mut ids = rows
            .iter()
            .flat_map(|row| row.evidence_entry_ids.iter().copied())
            .collect::<Vec<_>>();
        ids.sort_unstable();
        ids.dedup();
        ids
    }

    fn contiguous_entry_id_range(entry_ids: &[u64]) -> Option<(u64, u64)> {
        if entry_ids.is_empty() {
            return None;
        }
        let mut sorted = entry_ids.to_vec();
        sorted.sort_unstable();
        sorted.dedup();
        let is_contiguous = sorted
            .windows(2)
            .all(|pair| pair.get(1).copied() == pair.first().copied().map(|id| id + 1));
        is_contiguous.then(|| (*sorted.first().unwrap_or(&0), *sorted.last().unwrap_or(&0)))
    }

    fn build_datememory_read_hint(rows: &[DateMemoryRow], focus_row: &DateMemoryRow) -> String {
        let entry_ids = rows.iter().map(|row| row.entry_id).collect::<Vec<_>>();
        if entry_ids.len() <= 1 {
            return format!("entry_id={}", focus_row.entry_id);
        }
        if let Some((start_id, end_id)) = contiguous_entry_id_range(entry_ids.as_slice()) {
            return format!(
                "date={} · entry_start_id={} · entry_end_id={} · focus_entry_id={}",
                focus_row.entry_date, start_id, end_id, focus_row.entry_id
            );
        }
        format!(
            "date={} · focus_entry_id={}",
            focus_row.entry_date, focus_row.entry_id
        )
    }

    fn build_datememory_entry_transcript_lines(row: &DateMemoryRow) -> Vec<String> {
        let mut lines = vec![format!(
            "[DateMemory {} #{}:{} · {}]",
            row.source_persona,
            row.entry_id,
            row.segment_index,
            if row.title.trim().is_empty() {
                "(untitled)"
            } else {
                row.title.trim()
            }
        )];
        if !row.keywords.is_empty() {
            lines.push(format!("keywords: {}", row.keywords.join(", ")));
        }
        if !row.evidence_entry_ids.is_empty() {
            lines.push(format!(
                "evidence_entry_ids: {}",
                row.evidence_entry_ids
                    .iter()
                    .map(u64::to_string)
                    .collect::<Vec<_>>()
                    .join(", ")
            ));
        }
        if !row.summary.trim().is_empty() {
            lines.push(format!("summary: {}", row.summary.trim()));
        }
        lines.extend(
            normalize_text(row.content.as_str())
                .lines()
                .map(str::to_string),
        );
        lines
    }

    fn build_datememory_day_transcript_lines(rows: &[DateMemoryRow]) -> Vec<String> {
        let mut sorted = rows.to_vec();
        sorted.sort_by(|left, right| {
            left.created_at
                .cmp(&right.created_at)
                .then(left.entry_id.cmp(&right.entry_id))
        });
        let mut lines = Vec::new();
        for (index, row) in sorted.iter().enumerate() {
            if index > 0 {
                lines.push(String::new());
            }
            lines.extend(build_datememory_entry_transcript_lines(row));
        }
        lines
    }

    fn build_metamemory_day_transcript_lines(rows: &[MetaMemoryRow]) -> Vec<String> {
        let mut sorted = rows.to_vec();
        sorted.sort_by(|left, right| {
            left.created_at.cmp(&right.created_at).then(
                left.entry_id
                    .unwrap_or(left.db_entry_id)
                    .cmp(&right.entry_id.unwrap_or(right.db_entry_id)),
            )
        });
        let mut lines = Vec::new();
        for (index, row) in sorted.iter().enumerate() {
            if index > 0 {
                lines.push(String::new());
            }
            let mut header = format!(
                "[{} {} · round {:?} · {}]",
                row.role,
                metamemory_entry_label(row),
                row.round_id,
                format_timestamp(row.created_at)
            );
            if row.entry_id.is_none() {
                header = format!(
                    "[{} · round {:?} · {}]",
                    row.role,
                    row.round_id,
                    format_timestamp(row.created_at)
                );
            }
            lines.push(header);
            if row.context_entry_ids.len() > 1 {
                lines.push(format!(
                    "context_entry_ids: {}",
                    row.context_entry_ids
                        .iter()
                        .map(u64::to_string)
                        .collect::<Vec<_>>()
                        .join(", ")
                ));
            }
            lines.extend(
                normalize_text(row.content.as_str())
                    .lines()
                    .map(str::to_string),
            );
        }
        lines
    }

    fn build_metamemory_entry_transcript_lines(row: &MetaMemoryRow) -> Vec<String> {
        let mut lines = if row.entry_id.is_some() {
            vec![format!(
                "[{} {} · round {:?} · {}]",
                row.role,
                metamemory_entry_label(row),
                row.round_id,
                format_timestamp(row.created_at)
            )]
        } else {
            vec![format!(
                "[{} · round {:?} · {}]",
                row.role,
                row.round_id,
                format_timestamp(row.created_at)
            )]
        };
        if row.context_entry_ids.len() > 1 {
            lines.push(format!(
                "context_entry_ids: {}",
                row.context_entry_ids
                    .iter()
                    .map(u64::to_string)
                    .collect::<Vec<_>>()
                    .join(", ")
            ));
        }
        lines.extend(
            normalize_text(row.content.as_str())
                .lines()
                .map(str::to_string),
        );
        lines
    }

    fn build_datememory_day_aggregates(
        rows: &[DateMemoryRow],
        keywords: &[String],
    ) -> Vec<DateMemoryDayAggregate> {
        let mut grouped = BTreeMap::<String, Vec<DateMemoryRow>>::new();
        for row in rows {
            grouped
                .entry(row.entry_date.clone())
                .or_default()
                .push(row.clone());
        }
        let mut out = Vec::new();
        for (entry_date, day_rows) in grouped {
            let mut day_keywords = Vec::new();
            let mut matched_entries = 0usize;
            let mut occurrence_hits = 0usize;
            let mut strongest = None::<(DateMemoryRow, Vec<String>, usize)>;
            for row in &day_rows {
                let haystack = datememory_match_haystack(row);
                let matched = match_keywords(haystack.as_str(), keywords);
                if matched.is_empty() {
                    continue;
                }
                matched_entries += 1;
                occurrence_hits += count_keyword_occurrences(haystack.as_str(), keywords);
                for keyword in &matched {
                    if !day_keywords.iter().any(|existing| existing == keyword) {
                        day_keywords.push(keyword.clone());
                    }
                }
                let score = matched.len();
                let stronger = strongest
                    .as_ref()
                    .is_none_or(|(_, _, current_score)| score > *current_score);
                if stronger {
                    strongest = Some((row.clone(), matched, score));
                }
            }
            if let Some((strongest_row, strongest_row_keywords, _)) = strongest {
                out.push(DateMemoryDayAggregate {
                    entry_date,
                    rows: day_rows,
                    matched_keywords: day_keywords,
                    occurrence_hits,
                    strongest_row,
                    strongest_row_keywords,
                    matched_entries,
                });
            }
        }
        out
    }

    fn load_metamemory_rows_for_dates(
        start_date: Option<&str>,
        end_date: Option<&str>,
    ) -> Result<Vec<MetaMemoryRow>> {
        ensure_memory_store()?;
        let conn = open_connection(&metamemory_db_path())?;
        let mut stmt = conn
            .prepare(
                "SELECT id, entry_date, created_at, round_id, role, content, chars, lines, head_preview, context_entry_id, context_entry_ids_json \
                 FROM metamemory_entries ORDER BY entry_date DESC, created_at ASC, id ASC",
            )
            .context("查询 metamemory 失败")?;
        let mapped = stmt
            .query_map([], |row| {
                let db_entry_id = row.get::<_, i64>(0)? as u64;
                let role: String = row.get(4)?;
                let context_entry_id = row
                    .get::<_, Option<i64>>(9)?
                    .map(|value| value as u64)
                    .filter(|id| *id > 0);
                let context_entry_ids_json: String = row.get(10)?;
                let mut context_entry_ids =
                    serde_json::from_str::<Vec<u64>>(&context_entry_ids_json).unwrap_or_default();
                if let Some(context_entry_id) = context_entry_id
                    && !context_entry_ids.contains(&context_entry_id)
                {
                    context_entry_ids.insert(0, context_entry_id);
                }
                context_entry_ids = normalize_memory_entry_ids(context_entry_ids.as_slice());
                Ok(MetaMemoryRow {
                    db_entry_id,
                    entry_id: metamemory_primary_entry_id(
                        role.as_str(),
                        db_entry_id,
                        context_entry_id,
                        context_entry_ids.as_slice(),
                    ),
                    context_entry_ids,
                    entry_date: row.get(1)?,
                    created_at: row.get::<_, i64>(2)? as u64,
                    round_id: row.get::<_, Option<i64>>(3)?.map(|value| value as u64),
                    role,
                    content: row.get(5)?,
                    chars: row.get::<_, i64>(6)? as usize,
                    lines: row.get::<_, i64>(7)? as usize,
                    head_preview: row.get(8)?,
                })
            })
            .context("读取 metamemory 行失败")?;
        let mut rows = mapped
            .collect::<std::result::Result<Vec<_>, _>>()
            .context("收集 metamemory 行失败")?;
        rows.retain(|row| {
            start_date.is_none_or(|start| row.entry_date.as_str() >= start)
                && end_date.is_none_or(|end| row.entry_date.as_str() <= end)
        });
        Ok(rows)
    }

    fn build_metamemory_day_aggregates(
        rows: &[MetaMemoryRow],
        keywords: &[String],
    ) -> Vec<MetaMemoryDayAggregate> {
        let mut grouped = BTreeMap::<String, Vec<MetaMemoryRow>>::new();
        for row in rows {
            grouped
                .entry(row.entry_date.clone())
                .or_default()
                .push(row.clone());
        }
        let mut out = Vec::new();
        for (entry_date, day_rows) in grouped {
            let mut day_keywords = Vec::new();
            let mut matched_entries = 0usize;
            let mut occurrence_hits = 0usize;
            let mut strongest = None::<(MetaMemoryRow, Vec<String>, usize)>;
            for row in &day_rows {
                let haystack = format!("{}\n{}\n{}", row.role, row.head_preview, row.content);
                let matched = match_keywords(haystack.as_str(), keywords);
                if matched.is_empty() {
                    continue;
                }
                matched_entries += 1;
                occurrence_hits += count_keyword_occurrences(haystack.as_str(), keywords);
                for keyword in &matched {
                    if !day_keywords.iter().any(|existing| existing == keyword) {
                        day_keywords.push(keyword.clone());
                    }
                }
                let score = matched.len();
                let stronger = strongest
                    .as_ref()
                    .is_none_or(|(_, _, current_score)| score > *current_score);
                if stronger {
                    strongest = Some((row.clone(), matched, score));
                }
            }
            if let Some((strongest_row, strongest_row_keywords, _)) = strongest {
                out.push(MetaMemoryDayAggregate {
                    entry_date,
                    rows: day_rows,
                    matched_keywords: day_keywords,
                    occurrence_hits,
                    strongest_row,
                    strongest_row_keywords,
                    matched_entries,
                });
            }
        }
        out
    }

    fn format_entry_id_list(entry_ids: &[u64], limit: usize) -> String {
        let mut sorted = entry_ids
            .iter()
            .copied()
            .filter(|id| *id > 0)
            .collect::<Vec<_>>();
        sorted.sort_unstable();
        sorted.dedup();
        if sorted.is_empty() {
            return "(none)".to_string();
        }
        let mut shown = sorted
            .iter()
            .take(limit.max(1))
            .map(u64::to_string)
            .collect::<Vec<_>>();
        if sorted.len() > shown.len() {
            shown.push(format!("... +{}", sorted.len() - shown.len()));
        }
        shown.join(", ")
    }

    fn build_metamemory_read_hint(rows: &[MetaMemoryRow], focus_row: &MetaMemoryRow) -> String {
        let entry_ids = collect_metamemory_entry_ids(rows);
        if entry_ids.len() <= 1 {
            return focus_row
                .entry_id
                .map(|entry_id| format!("entry_id={entry_id}"))
                .unwrap_or_else(|| format!("date={}", focus_row.entry_date));
        }
        if let Some((start_id, end_id)) = contiguous_entry_id_range(entry_ids.as_slice()) {
            return format!(
                "date={} · entry_start_id={} · entry_end_id={} · focus_entry_id={}",
                focus_row.entry_date,
                start_id,
                end_id,
                focus_row.entry_id.unwrap_or(start_id)
            );
        }
        if let Some(focus_entry_id) = focus_row.entry_id {
            format!(
                "date={} · entry_ids={} · focus_entry_id={}",
                focus_row.entry_date,
                format_entry_id_list(entry_ids.as_slice(), 10),
                focus_entry_id
            )
        } else {
            format!(
                "date={} · entry_ids={}",
                focus_row.entry_date,
                format_entry_id_list(entry_ids.as_slice(), 10)
            )
        }
    }

    const TOOLMEMORY_ROW_SELECT: &str = "id, tool_ref, entry_date, tool_name, brief, kind_label, action_label, chars, lines, head_preview, transcript";

    fn map_toolmemory_row(row: &rusqlite::Row<'_>) -> rusqlite::Result<ToolMemoryRow> {
        Ok(ToolMemoryRow {
            entry_id: row.get::<_, i64>(0)? as u64,
            tool_ref: row.get(1)?,
            entry_date: row.get(2)?,
            tool_name: row.get(3)?,
            brief: row.get(4)?,
            _kind_label: row.get(5)?,
            _action_label: row.get(6)?,
            chars: row.get::<_, i64>(7)? as usize,
            lines: row.get::<_, i64>(8)? as usize,
            _head_preview: row.get(9)?,
            transcript: row.get(10)?,
        })
    }

    fn load_toolmemory_rows_by_tool_ref(tool_ref: &str) -> Result<Vec<ToolMemoryRow>> {
        let conn = open_connection(&toolmemory_db_path())?;
        let mut stmt = conn
            .prepare(
                format!(
                    "SELECT {TOOLMEMORY_ROW_SELECT} \
                     FROM toolmemory_entries WHERE tool_ref = ?1 ORDER BY entry_date DESC, id DESC"
                )
                .as_str(),
            )
            .context("查询 toolmemory(tool_ref) 失败")?;
        stmt.query_map(params![tool_ref.trim()], map_toolmemory_row)
            .context("读取 toolmemory(tool_ref) 行失败")?
            .collect::<std::result::Result<Vec<_>, _>>()
            .context("收集 toolmemory(tool_ref) 行失败")
    }

    fn load_toolmemory_row_by_entry_id(entry_id: u64) -> Result<ToolMemoryRow> {
        let conn = open_connection(&toolmemory_db_path())?;
        conn.query_row(
            format!("SELECT {TOOLMEMORY_ROW_SELECT} FROM toolmemory_entries WHERE id = ?1 LIMIT 1")
                .as_str(),
            params![entry_id as i64],
            map_toolmemory_row,
        )
        .with_context(|| format!("找不到 toolmemory entry_id={entry_id}"))
    }

    fn build_toolmemory_window_excerpt(
        transcript_lines: &[String],
        start: usize,
        end: usize,
    ) -> String {
        (start..=end)
            .filter_map(|line_no| {
                transcript_lines
                    .get(line_no.saturating_sub(1))
                    .map(|line| format!("{line_no}: {line}"))
            })
            .collect::<Vec<_>>()
            .join(" / ")
    }

    fn push_toolmemory_match_context(
        lines: &mut Vec<String>,
        transcript_lines: &[String],
        matched_lines: &[usize],
        expanded: bool,
    ) {
        if matched_lines.is_empty() {
            return;
        }
        lines.push(format!(
            "  matched_lines: {}",
            format_line_ranges(matched_lines)
        ));
        let windows = merge_context_windows(
            matched_lines,
            transcript_lines.len(),
            TOOLMEMORY_MATCH_CONTEXT_LINES,
        );
        if windows.is_empty() {
            return;
        }
        if expanded {
            for (start, end) in windows {
                lines.push(format!("  excerpt[{start}-{end}]:"));
                for line_no in start..=end {
                    if let Some(line) = transcript_lines.get(line_no.saturating_sub(1)) {
                        lines.push(format!("    {line_no:>4} {line}"));
                    }
                }
            }
            return;
        }
        for (start, end) in windows.iter().copied() {
            let excerpt = build_toolmemory_window_excerpt(transcript_lines, start, end);
            lines.push(format!(
                "  excerpt[{start}-{end}]: {}",
                preview_inline_text(excerpt.as_str(), TOOLMEMORY_COMPACT_EXCERPT_CHARS)
            ));
        }
    }

    fn build_toolmemory_read_hint(
        row: &ToolMemoryRow,
        line_start: usize,
        line_end: usize,
    ) -> String {
        format!(
            "entry_id={} · line_start={} · line_end={} · tool_ref={}",
            row.entry_id, line_start, line_end, row.tool_ref
        )
    }

    fn check_datememory(request: &MemoryCheckRequest) -> Result<MemoryToolResult> {
        let keywords = normalize_memory_keywords(request.keywords.as_slice());
        if keywords.is_empty() {
            return Err(anyhow!("memory_check datememory 需要 keywords"));
        }
        ensure_memory_store()?;
        let conn = open_connection(&datememory_db_path())?;
        let (start, end) = if let Some(date) = request.date.as_deref() {
            let exact = parse_date(date)?.format("%Y-%m-%d").to_string();
            (Some(exact.clone()), Some(exact))
        } else {
            scope_bounds(request.scope.as_ref())?
        };
        let mut rows = if start.is_some() && end.is_some() {
            load_datememory_rows_for_dates(&conn, start.as_deref(), end.as_deref())?
        } else {
            load_datememory_rows_for_dates(&conn, None, None)?
        };
        filter_date_range(&mut rows, start.as_deref(), end.as_deref());
        let stats = build_corpus_stats(
            rows.iter().map(|row| row.entry_date.clone()),
            rows.len(),
            rows.iter().map(|row| row.chars).sum(),
            rows.iter().map(|row| row.lines).sum(),
        );
        let mut hits = build_datememory_day_aggregates(rows.as_slice(), keywords.as_slice());
        hits.sort_by(|left, right| {
            right
                .matched_keywords
                .len()
                .cmp(&left.matched_keywords.len())
                .then(right.occurrence_hits.cmp(&left.occurrence_hits))
                .then(right.entry_date.cmp(&left.entry_date))
        });
        let limit = request.limit.max(1);
        let mut lines = Vec::new();
        push_memory_check_header(
            &mut lines,
            "datememory",
            request.scope.as_ref(),
            keywords.as_slice(),
            &stats,
            hits.iter().map(|item| item.matched_entries).sum(),
            hits.len(),
        );
        if hits.is_empty() {
            lines.push("• (no matches)".to_string());
            return Ok(build_memory_tool_result(lines));
        }
        for (index, day) in hits.into_iter().take(limit).enumerate() {
            let matched_rows = datememory_matched_rows(day.rows.as_slice(), keywords.as_slice());
            let matched_evidence_entry_ids =
                collect_datememory_evidence_entry_ids(matched_rows.as_slice());
            let transcript_lines = build_datememory_day_transcript_lines(day.rows.as_slice());
            let (tier, preview_lines) = build_datememory_match_preview(
                &day.strongest_row,
                day.strongest_row_keywords.as_slice(),
            );
            lines.push(format!(
                "• {} · hit_keys={}/{} · matched_entries={}/{} · strongest={} · {} chars · {} lines",
                day.entry_date,
                day.matched_keywords.len(),
                keywords.len(),
                day.matched_entries,
                day.rows.len(),
                format_datememory_entry_label(&day.strongest_row),
                transcript_char_count(transcript_lines.as_slice()),
                transcript_lines.len(),
            ));
            lines.push(format!("  keywords: {}", day.matched_keywords.join(", ")));
            lines.push(format!(
                "  matched_entry_ids: {}",
                format_datememory_entry_labels(matched_rows.as_slice(), 6)
            ));
            if !matched_evidence_entry_ids.is_empty() {
                lines.push(format!(
                    "  evidence_entry_ids: {}",
                    matched_evidence_entry_ids
                        .iter()
                        .map(u64::to_string)
                        .collect::<Vec<_>>()
                        .join(", ")
                ));
            }
            if index == 0 {
                if !day.strongest_row.title.trim().is_empty() {
                    lines.push(format!(
                        "  title: {}",
                        preview_inline_text(day.strongest_row.title.trim(), 120)
                    ));
                }
                if !day.strongest_row.summary.trim().is_empty()
                    && !matches!(tier, Some(DateMemoryHitTier::DateOnly))
                {
                    lines.push(format!(
                        "  summary: {}",
                        preview_inline_text(day.strongest_row.summary.trim(), 160)
                    ));
                }
                lines.extend(preview_lines);
            }
            lines.push(format!(
                "  read_hint: {}",
                build_datememory_read_hint(matched_rows.as_slice(), &day.strongest_row)
            ));
        }
        Ok(build_memory_tool_result(lines))
    }

    fn check_metamemory(request: &MemoryCheckRequest) -> Result<MemoryToolResult> {
        let keywords = normalize_memory_keywords(request.keywords.as_slice());
        let selector = request.date.as_deref().ok_or_else(|| {
            anyhow!("memory_check metamemory 需要 date（YYYY-MM-DD）或 month（YYYY-MM）")
        })?;
        let selector = parse_exact_day_or_month(selector)?;
        let rows = load_metamemory_rows_for_dates(
            Some(selector.start_date.as_str()),
            Some(selector.end_date.as_str()),
        )?;
        let stats = build_corpus_stats(
            rows.iter().map(|row| row.entry_date.clone()),
            rows.len(),
            rows.iter().map(|row| row.chars).sum(),
            rows.iter().map(|row| row.lines).sum(),
        );
        if keywords.is_empty() {
            let transcript = build_metamemory_day_transcript_lines(rows.as_slice());
            let mut lines = Vec::new();
            push_memory_check_header(
                &mut lines,
                "metamemory",
                None,
                &keywords,
                &stats,
                rows.len(),
                usize::from(!rows.is_empty()),
            );
            if !rows.is_empty() {
                lines.push(format!(
                    "• {} · entries={} · {} chars · {} lines",
                    selector.label,
                    rows.len(),
                    transcript_char_count(transcript.as_slice()),
                    transcript.len(),
                ));
                lines.push(format!(
                    "  entry_ids: {}",
                    format_entry_id_list(
                        collect_metamemory_entry_ids(rows.as_slice()).as_slice(),
                        10
                    )
                ));
                if let Some((line_start, line_end)) = suggest_line_window(transcript.len(), &[]) {
                    lines.push(format!(
                        "  read_hint: date={} · line_start={} · line_end={}",
                        selector.label, line_start, line_end
                    ));
                }
            } else {
                lines.push("• (no rows)".to_string());
            }
            return Ok(build_memory_tool_result(lines));
        }
        let mut hits = build_metamemory_day_aggregates(rows.as_slice(), keywords.as_slice());
        hits.sort_by(|left, right| {
            right
                .matched_keywords
                .len()
                .cmp(&left.matched_keywords.len())
                .then(right.occurrence_hits.cmp(&left.occurrence_hits))
                .then(right.entry_date.cmp(&left.entry_date))
        });
        let limit = request.limit.max(1);
        let mut lines = Vec::new();
        push_memory_check_header(
            &mut lines,
            "metamemory",
            None,
            keywords.as_slice(),
            &stats,
            hits.iter().map(|item| item.matched_entries).sum(),
            hits.len(),
        );
        if hits.is_empty() {
            lines.push("• (no matches)".to_string());
            return Ok(build_memory_tool_result(lines));
        }
        for (index, day) in hits.into_iter().take(limit).enumerate() {
            let transcript_lines = build_metamemory_day_transcript_lines(day.rows.as_slice());
            let matched_lines = find_matching_line_numbers_in_lines(
                transcript_lines.as_slice(),
                keywords.as_slice(),
            );
            lines.push(format!(
                "• {} · hit_keys={}/{} · entries={} · {} chars · {} lines",
                day.entry_date,
                day.matched_keywords.len(),
                keywords.len(),
                day.rows.len(),
                transcript_char_count(transcript_lines.as_slice()),
                transcript_lines.len(),
            ));
            lines.push(format!("  keywords: {}", day.matched_keywords.join(", ")));
            let matched_entry_ids = day
                .rows
                .iter()
                .filter(|row| {
                    !match_keywords(
                        format!("{}\n{}\n{}", row.role, row.head_preview, row.content).as_str(),
                        keywords.as_slice(),
                    )
                    .is_empty()
                })
                .filter_map(|row| row.entry_id)
                .collect::<Vec<_>>();
            lines.push(format!(
                "  matched_entry_ids: {}",
                format_entry_id_list(matched_entry_ids.as_slice(), 10)
            ));
            if index == 0 {
                lines.push(format!(
                    "  preview: {}",
                    preview_inline_text(
                        extract_keyword_excerpt(
                            day.strongest_row.content.as_str(),
                            day.strongest_row_keywords.as_slice()
                        )
                        .as_str(),
                        240,
                    )
                ));
            }
            lines.push(format!(
                "  read_hint: {}",
                build_metamemory_read_hint(
                    day.rows
                        .iter()
                        .filter(|row| {
                            row.entry_id
                                .is_some_and(|entry_id| matched_entry_ids.contains(&entry_id))
                        })
                        .cloned()
                        .collect::<Vec<_>>()
                        .as_slice(),
                    &day.strongest_row
                )
            ));
            if let Some((line_start, line_end)) =
                suggest_line_window(transcript_lines.len(), matched_lines.as_slice())
            {
                lines.push(format!(
                    "  line_hint: date={} · line_start={} · line_end={}",
                    day.entry_date, line_start, line_end
                ));
            }
        }
        Ok(build_memory_tool_result(lines))
    }

    fn check_toolmemory(request: &MemoryCheckRequest) -> Result<MemoryToolResult> {
        let keywords = normalize_memory_keywords(request.keywords.as_slice());
        if request.date.is_some() || request.scope.is_some() {
            return Err(anyhow!(
                "memory_check toolmemory 不支持 date/scope；请指定 entry_id，tool_ref 只作兼容兜底"
            ));
        }
        let rows = if let Some(entry_id) = request.entry_id {
            vec![load_toolmemory_row_by_entry_id(entry_id)?]
        } else if request.tool_ref.is_some() {
            load_toolmemory_rows_by_tool_ref(request.tool_ref.as_deref().unwrap_or_default())?
        } else {
            return Err(anyhow!(
                "memory_check toolmemory 需要 entry_id，tool_ref 只作兼容参数"
            ));
        };
        let stats = build_corpus_stats(
            rows.iter().map(|row| row.entry_date.clone()),
            rows.len(),
            rows.iter().map(|row| row.chars).sum(),
            rows.iter().map(|row| row.lines).sum(),
        );
        if (request.entry_id.is_some() || request.tool_ref.is_some()) && keywords.is_empty() {
            let mut lines = Vec::new();
            push_memory_check_header(
                &mut lines,
                "toolmemory",
                None,
                &keywords,
                &stats,
                rows.len(),
                rows.len(),
            );
            if let Some(row) = rows.first() {
                lines.push(format!(
                    "• {} · {} · {} · {} chars · {} lines",
                    row.tool_ref, row.entry_date, row.tool_name, row.chars, row.lines
                ));
                if !row.brief.trim().is_empty() {
                    lines.push(format!(
                        "  brief: {}",
                        preview_inline_text(row.brief.trim(), 160)
                    ));
                }
                lines.push(format!("  entry_id: {}", row.entry_id));
                lines.push(format!("  ref: {}", row.tool_ref));
                lines.push(format!(
                    "  stats: {} chars · {} lines",
                    row.chars, row.lines
                ));
                if let Some((line_start, line_end)) = suggest_line_window(row.lines, &[]) {
                    lines.push(format!(
                        "  read_hint: {}",
                        build_toolmemory_read_hint(row, line_start, line_end)
                    ));
                }
                lines.push(format!(
                    "  note: 如需按关键词定位，请继续使用 memory_check target=toolmemory entry_id={} keywords=[...]",
                    row.entry_id
                ));
            } else {
                lines.push("• (no rows)".to_string());
            }
            return Ok(build_memory_tool_result(lines));
        }
        if keywords.is_empty() {
            return Err(anyhow!(
                "memory_check toolmemory 需要 keywords，或指定 entry_id / tool_ref 做定位"
            ));
        }
        let mut hits = rows
            .into_iter()
            .filter_map(|row| {
                let transcript_lines = normalize_text(row.transcript.as_str())
                    .lines()
                    .map(str::to_string)
                    .collect::<Vec<_>>();
                let haystack = format!("{}\n{}\n{}", row.tool_name, row.brief, row.transcript);
                let matched_keywords = match_keywords(haystack.as_str(), keywords.as_slice());
                if matched_keywords.is_empty() {
                    return None;
                }
                Some(ToolMemoryHitAggregate {
                    matched_lines: find_matching_line_numbers_in_lines(
                        transcript_lines.as_slice(),
                        keywords.as_slice(),
                    ),
                    occurrence_hits: count_keyword_occurrences(
                        haystack.as_str(),
                        keywords.as_slice(),
                    ),
                    row,
                    matched_keywords,
                    transcript_lines,
                })
            })
            .collect::<Vec<_>>();
        hits.sort_by(|left, right| {
            right
                .matched_keywords
                .len()
                .cmp(&left.matched_keywords.len())
                .then(right.occurrence_hits.cmp(&left.occurrence_hits))
                .then(right.row.entry_date.cmp(&left.row.entry_date))
        });
        let limit = request.limit.max(1);
        let mut lines = Vec::new();
        push_memory_check_header(
            &mut lines,
            "toolmemory",
            None,
            keywords.as_slice(),
            &stats,
            hits.len(),
            hits.len(),
        );
        if hits.is_empty() {
            lines.push("• (no matches)".to_string());
            return Ok(build_memory_tool_result(lines));
        }
        for (index, hit) in hits.into_iter().take(limit).enumerate() {
            lines.push(format!(
                "• #{} · {} · {} · {} · hit_keys={}/{} · {} chars · {} lines",
                hit.row.entry_id,
                hit.row.tool_ref,
                hit.row.entry_date,
                hit.row.tool_name,
                hit.matched_keywords.len(),
                keywords.len(),
                hit.row.chars,
                hit.row.lines,
            ));
            if !hit.row.brief.trim().is_empty() {
                lines.push(format!(
                    "  brief: {}",
                    preview_inline_text(hit.row.brief.trim(), 160)
                ));
            }
            lines.push(format!("  keywords: {}", hit.matched_keywords.join(", ")));
            lines.push(format!("  entry_id: {}", hit.row.entry_id));
            lines.push(format!("  ref: {}", hit.row.tool_ref));
            push_toolmemory_match_context(
                &mut lines,
                hit.transcript_lines.as_slice(),
                hit.matched_lines.as_slice(),
                index == 0 && hit.matched_lines.len() <= MEMORY_SEARCH_INLINE_HIT_LIMIT,
            );
            if let Some((line_start, line_end)) =
                suggest_line_window(hit.row.lines, hit.matched_lines.as_slice())
            {
                lines.push(format!(
                    "  read_hint: {}",
                    build_toolmemory_read_hint(&hit.row, line_start, line_end)
                ));
            }
        }
        Ok(build_memory_tool_result(lines))
    }

    pub fn check_memory(request: MemoryCheckRequest) -> Result<MemoryToolResult> {
        match request.target {
            MemoryTarget::Date => check_datememory(&request),
            MemoryTarget::Meta => check_metamemory(&request),
            MemoryTarget::Tool => check_toolmemory(&request),
        }
    }

    fn apply_line_range(
        lines: &[String],
        start: Option<usize>,
        end: Option<usize>,
    ) -> Result<Vec<String>> {
        if lines.is_empty() {
            return Ok(Vec::new());
        }
        let total = lines.len();
        let start = start.unwrap_or(1).max(1);
        let end = end.unwrap_or(total).max(start);
        if start > total {
            return Err(anyhow!("line_start 超出范围（总行数 {total}）"));
        }
        let end = end.min(total);
        Ok(lines
            .iter()
            .enumerate()
            .filter_map(|(index, line)| {
                let line_no = index + 1;
                (line_no >= start && line_no <= end).then_some(format!("{line_no:>4} {line}"))
            })
            .collect())
    }

    fn read_datememory(request: &MemoryReadRequest) -> Result<MemoryToolResult> {
        ensure_memory_store()?;
        let conn = open_connection(&datememory_db_path())?;
        let source_persona = current_memory_source_persona();
        let has_entry_range = request.entry_start_id.is_some() || request.entry_end_id.is_some();
        if request.entry_start_id.is_some() != request.entry_end_id.is_some() {
            return Err(anyhow!(
                "memory_read datememory 的 entry_start_id 与 entry_end_id 需要同时提供"
            ));
        }
        let is_entry_read = request.entry_id.is_some() || has_entry_range;
        let mut rows = if let Some(entry_id) = request.entry_id {
            let sql = format!(
                "SELECT {DATEMEMORY_ROW_SELECT} FROM datememory_entries WHERE source_persona = ?1 AND id = ?2"
            );
            let mut stmt = conn
                .prepare(sql.as_str())
                .context("查询 datememory(entry_id) 失败")?;
            let mapped = stmt
                .query_map(
                    params![source_persona.as_str(), entry_id as i64],
                    map_datememory_row,
                )
                .context("读取 datememory(entry_id) 行失败")?;
            mapped.collect::<std::result::Result<Vec<_>, _>>()?
        } else if let (Some(start_id), Some(end_id)) =
            (request.entry_start_id, request.entry_end_id)
        {
            if start_id > end_id {
                return Err(anyhow!(
                    "memory_read datememory 的 entry_start_id 不能大于 entry_end_id"
                ));
            }
            let sql = format!(
                "SELECT {DATEMEMORY_ROW_SELECT} FROM datememory_entries WHERE source_persona = ?1 AND id >= ?2 AND id <= ?3 ORDER BY created_at ASC, id ASC"
            );
            let mut stmt = conn
                .prepare(sql.as_str())
                .context("查询 datememory(entry_id range) 失败")?;
            let mapped = stmt
                .query_map(
                    params![source_persona.as_str(), start_id as i64, end_id as i64],
                    map_datememory_row,
                )
                .context("读取 datememory(entry_id range) 行失败")?;
            mapped.collect::<std::result::Result<Vec<_>, _>>()?
        } else {
            let entry_date = request.date.as_deref().ok_or_else(|| {
                anyhow!("memory_read datememory 需要 date、entry_id 或 entry range")
            })?;
            let entry_date = parse_date(entry_date)?.format("%Y-%m-%d").to_string();
            let sql = format!(
                "SELECT {DATEMEMORY_ROW_SELECT} FROM datememory_entries WHERE source_persona = ?1 AND entry_date = ?2 ORDER BY created_at ASC, id ASC"
            );
            let mut stmt = conn
                .prepare(sql.as_str())
                .context("查询 datememory(date) 失败")?;
            let mapped = stmt
                .query_map(
                    params![source_persona.as_str(), entry_date],
                    map_datememory_row,
                )
                .context("读取 datememory(date) 行失败")?;
            mapped.collect::<std::result::Result<Vec<_>, _>>()?
        };
        rows.sort_by(|left, right| {
            left.created_at
                .cmp(&right.created_at)
                .then(left.entry_id.cmp(&right.entry_id))
        });
        if request.line_start.is_some() || request.line_end.is_some() {
            let transcript_lines = if is_entry_read && rows.len() == 1 {
                rows.first()
                    .map(build_datememory_entry_transcript_lines)
                    .unwrap_or_default()
            } else {
                build_datememory_day_transcript_lines(rows.as_slice())
            };
            let ranged = apply_line_range(
                transcript_lines.as_slice(),
                request.line_start,
                request.line_end,
            )?;
            return Ok(build_memory_tool_result(ranged));
        }
        let mut lines = vec![format!(
            "MemoryRead succeeded · datememory · {} entry(s) · source={}",
            rows.len(),
            source_persona,
        )];
        for row in rows {
            lines.push(format!(
                "• {} · {} · #{}:{} · {}",
                row.source_persona,
                row.entry_date,
                row.entry_id,
                row.segment_index,
                if row.title.trim().is_empty() {
                    "(untitled)"
                } else {
                    row.title.trim()
                }
            ));
            lines.push(format!("  keywords: {}", row.keywords.join(", ")));
            if !row.evidence_entry_ids.is_empty() {
                lines.push(format!(
                    "  evidence_entry_ids: {}",
                    row.evidence_entry_ids
                        .iter()
                        .map(u64::to_string)
                        .collect::<Vec<_>>()
                        .join(", ")
                ));
            }
            if !row.summary.trim().is_empty() {
                lines.push(format!("  summary: {}", row.summary.trim()));
            }
            lines.extend(row.content.lines().map(|line| format!("  {line}")));
        }
        Ok(build_memory_tool_result(lines))
    }

    fn read_metamemory(request: &MemoryReadRequest) -> Result<MemoryToolResult> {
        if request.entry_start_id.is_some() != request.entry_end_id.is_some() {
            return Err(anyhow!(
                "memory_read metamemory 的 entry_start_id 与 entry_end_id 需要同时提供"
            ));
        }
        let mut rows = if !request.entry_ids.is_empty() {
            if request.entry_ids.len() > 10 {
                return Err(anyhow!(
                    "memory_read metamemory 的 entry_ids 最多只支持 10 个"
                ));
            }
            let wanted = request
                .entry_ids
                .iter()
                .copied()
                .filter(|id| *id > 0)
                .collect::<BTreeSet<_>>();
            expand_metamemory_rows_around_entry_ids(
                load_metamemory_rows_for_dates(None, None)?.as_slice(),
                &wanted,
                2,
            )
        } else if let Some(entry_id) = request.entry_id {
            expand_metamemory_rows_around_entry_ids(
                load_metamemory_rows_for_dates(None, None)?.as_slice(),
                &BTreeSet::from([entry_id]),
                2,
            )
        } else if let (Some(start_id), Some(end_id)) =
            (request.entry_start_id, request.entry_end_id)
        {
            if start_id > end_id {
                return Err(anyhow!(
                    "memory_read metamemory 的 entry_start_id 不能大于 entry_end_id"
                ));
            }
            load_metamemory_rows_for_dates(None, None)?
                .into_iter()
                .filter(|row| {
                    row.entry_id
                        .is_some_and(|entry_id| entry_id >= start_id && entry_id <= end_id)
                })
                .collect::<Vec<_>>()
        } else {
            let selector = request.date.as_deref().ok_or_else(|| {
                anyhow!("memory_read metamemory 需要 date、entry_id、entry_ids 或 entry range")
            })?;
            let selector = parse_exact_day_or_month(selector)?;
            load_metamemory_rows_for_dates(
                Some(selector.start_date.as_str()),
                Some(selector.end_date.as_str()),
            )?
        };
        rows.sort_by(|left, right| {
            left.created_at.cmp(&right.created_at).then(
                left.entry_id
                    .unwrap_or(left.db_entry_id)
                    .cmp(&right.entry_id.unwrap_or(right.db_entry_id)),
            )
        });
        if request.line_start.is_some() || request.line_end.is_some() {
            let transcript_lines = if rows.len() == 1 {
                rows.first()
                    .map(build_metamemory_entry_transcript_lines)
                    .unwrap_or_default()
            } else {
                build_metamemory_day_transcript_lines(rows.as_slice())
            };
            let ranged = apply_line_range(
                transcript_lines.as_slice(),
                request.line_start,
                request.line_end,
            )?;
            return Ok(build_memory_tool_result(ranged));
        }
        let mut lines = vec![format!(
            "MemoryRead succeeded · metamemory · {} entry(s)",
            rows.len()
        )];
        for row in rows {
            let mut line = format!("• {} · {}", row.entry_date, row.role);
            if let Some(entry_id) = row.entry_id {
                line.push_str(format!(" · #{entry_id}").as_str());
            }
            lines.push(line);
            if row.context_entry_ids.len() > 1 {
                lines.push(format!(
                    "  context_entry_ids: {}",
                    row.context_entry_ids
                        .iter()
                        .map(u64::to_string)
                        .collect::<Vec<_>>()
                        .join(", ")
                ));
            }
            lines.extend(row.content.lines().map(|line| format!("  {line}")));
        }
        Ok(build_memory_tool_result(lines))
    }

    fn expand_metamemory_rows_around_entry_ids(
        rows: &[MetaMemoryRow],
        wanted: &BTreeSet<u64>,
        radius: usize,
    ) -> Vec<MetaMemoryRow> {
        if wanted.is_empty() {
            return Vec::new();
        }
        let mut keep = BTreeSet::new();
        for (index, row) in rows.iter().enumerate() {
            let Some(entry_id) = row.entry_id else {
                continue;
            };
            if !wanted.contains(&entry_id) {
                continue;
            }
            let start = index.saturating_sub(radius);
            let end = (index + radius + 1).min(rows.len());
            for keep_index in start..end {
                keep.insert(keep_index);
            }
        }
        keep.into_iter()
            .filter_map(|index| rows.get(index).cloned())
            .collect()
    }

    fn read_toolmemory(request: &MemoryReadRequest) -> Result<MemoryToolResult> {
        let row = if let Some(entry_id) = request.entry_id {
            load_toolmemory_row_by_entry_id(entry_id)?
        } else if let Some(tool_ref) = request.tool_ref.as_deref() {
            load_toolmemory_rows_by_tool_ref(tool_ref)?
                .into_iter()
                .next()
                .ok_or_else(|| anyhow!("找不到 tool_ref={tool_ref}"))?
        } else {
            return Err(anyhow!(
                "memory_read toolmemory 需要 entry_id，tool_ref 只作兼容参数"
            ));
        };
        let raw_lines = row
            .transcript
            .lines()
            .map(str::to_string)
            .collect::<Vec<_>>();
        let ranged = apply_line_range(raw_lines.as_slice(), request.line_start, request.line_end)?;
        Ok(build_memory_tool_result(ranged))
    }

    pub fn read_memory(request: MemoryReadRequest) -> Result<MemoryToolResult> {
        match request.target {
            MemoryTarget::Date => read_datememory(&request),
            MemoryTarget::Meta => read_metamemory(&request),
            MemoryTarget::Tool => read_toolmemory(&request),
        }
    }

