        #[test]
        fn maintenance_sync_generates_memory_ticket_when_threshold_exceeded() {
            with_test_home(|| {
                let round_id = crate::context::begin_round().expect("begin round");
                crate::context::append_round_message(
                    round_id,
                    crate::context::ContextRole::User,
                    None,
                    "用户正在讨论 datememory 压缩策略",
                )
                .expect("append context user");
                let visible_message = "一条很长的可见消息".repeat(2048);
                let raw_message = "一条很长的原始正文".repeat(2048);
                let assistant_reply =
                    "这是一段很长很长的回复，用来触发 datememorycontext 的维护阈值。".repeat(1024);
                append_user_message(
                    Some(1),
                    "Ryo",
                    "江山谣",
                    visible_message.as_str(),
                    raw_message.as_str(),
                )
                .expect("append user");
                append_assistant_message(Some(1), "Matrix", "萤", assistant_reply.as_str())
                    .expect("append assistant");
                let requests = sync_maintenance_requests(MIN_CONTEXT_LIMIT_KB).expect("sync");
                assert_eq!(requests.len(), 1);
                assert!(requests[0].text.contains("memory_add"));
                assert!(requests[0].text.contains("[datememorycontext start]"));
                assert!(requests[0].text.contains("本轮只提供 datememorycontext"));
                assert!(requests[0].text.contains("不要只写一两句话"));
                assert!(requests[0].text.contains("至少约 80 字"));
                assert!(requests[0].text.contains("`keywords`"));
                assert!(requests[0].text.contains("不要尝试补读或压缩其它上下文"));
                assert!(
                    !requests[0]
                        .text
                        .contains("[memory maintenance context snapshot]")
                );
                assert!(!requests[0].text.contains("[StandardContextFull]"));
            });
        }

        #[test]
        fn memory_maintenance_triggers_when_aggregate_context_exceeds_limit() {
            fn save_scope_payload(persona: crate::PersonaKind, payload: String) {
                with_memory_persona(persona, || {
                    let mut store = DateMemoryContextStore::default();
                    store.next_entry_id = 2;
                    store.entries.push(DateMemoryContextEntry {
                        id: 1,
                        round_id: None,
                        role: DateMemoryContextRole::User,
                        title: "User · aggregate trigger".to_string(),
                        chars: payload.chars().count(),
                        lines: 1,
                        text: payload,
                        date: current_date_string(),
                        created_at: crate::unix_timestamp_secs_shared(),
                    });
                    save_datememorycontext(&store)
                })
                .expect("save datememorycontext scope");
            }

            with_test_home(|| {
                save_scope_payload(crate::PersonaKind::Matrix, "a".repeat(18 * 1024));
                save_scope_payload(crate::PersonaKind::Coding, "b".repeat(18 * 1024));

                let matrix_bytes =
                    datememorycontext_size_bytes_for_persona(crate::PersonaKind::Matrix);
                let coding_bytes =
                    datememorycontext_size_bytes_for_persona(crate::PersonaKind::Coding);
                let limit_bytes = (MIN_CONTEXT_LIMIT_KB as usize).saturating_mul(1024);
                assert!(matrix_bytes < limit_bytes, "matrix bytes={matrix_bytes}");
                assert!(coding_bytes < limit_bytes, "coding bytes={coding_bytes}");
                assert!(matrix_bytes.saturating_add(coding_bytes) >= limit_bytes);

                let requests = sync_maintenance_requests(MIN_CONTEXT_LIMIT_KB).expect("sync");
                assert!(
                    requests
                        .iter()
                        .any(|request| request.key.starts_with("matrix:datememorycontext:"))
                );
                assert!(
                    requests
                        .iter()
                        .any(|request| request.key.starts_with("coding:datememorycontext:"))
                );
            });
        }

