        #[test]
        fn proposed_plan_parser_streams_visible_text_and_plan_delta() {
            let mut parser = ProposedPlanParser::new();
            let first = parser.parse("前言\n<pro");
            let second = parser.parse("posed_plan>\n- step 1\n</proposed_plan>\n后记");
            let tail = parser.finish();
            assert_eq!(first.visible_text, "前言\n");
            assert_eq!(collect_proposed_plan_delta(&first), "");
            assert_eq!(second.visible_text, "后记");
            assert_eq!(collect_proposed_plan_delta(&second), "- step 1\n");
            assert!(tail.visible_text.is_empty());
        }

