        #[test]
        fn provider_sampling_controls_are_omitted_when_zero_and_sent_when_positive() {
            let mut provider = ProviderConfig {
                body: ApiBodyKind::Official,
                official_kind: Some(OfficialProviderKind::DeepSeek),
                name: "DEEPSEEK".to_string(),
                base_url: "https://api.deepseek.com/v1".to_string(),
                api_key: "sk-test".to_string(),
                api_keys: Vec::new(),
                current_api_key: 0,
                model: "deepseek-reasoner".to_string(),
                reasoning_effort: None,
                reasoning_summary: None,
                service_tier: None,
                temperature: 0.0,
                max_tokens: 0,
                sse_on: true,
                timeout_secs: 30,
                models: Vec::new(),
            };
            let messages = vec![json!({"role": "user", "content": "ping"})];
            let body = build_chat_request_bodies(&provider, &messages, true)
                .pop()
                .expect("body");
            assert!(body.get("temperature").is_none());
            assert!(body.get("max_tokens").is_none());

            provider.temperature = 0.7;
            provider.max_tokens = 1024;
            let body = build_chat_request_bodies(&provider, &messages, true)
                .pop()
                .expect("body");
            assert_eq!(
                body.get("temperature").and_then(|value| value.as_f64()),
                Some(0.7)
            );
            assert_eq!(
                body.get("max_tokens").and_then(|value| value.as_u64()),
                Some(1024)
            );
        }

