        #[test]
        fn codex_tool_request_body_for_matrix_exposes_tool_manage_without_execution_tools() {
            with_test_home(|_| {
                let previous = mcp::current_tool_persona();
                mcp::set_tool_persona(crate::PersonaKind::Matrix);
                crate::context::set_persona(crate::PersonaKind::Matrix);
                let provider = ProviderConfig {
                    body: ApiBodyKind::Official,
                    official_kind: Some(OfficialProviderKind::Codex),
                    name: "CODEX".to_string(),
                    base_url: "https://example.com/v1".to_string(),
                    api_key: "sk-test".to_string(),
                    api_keys: Vec::new(),
                    current_api_key: 0,
                    model: "gpt-5.5".to_string(),
                    reasoning_effort: Some("high".to_string()),
                    reasoning_summary: Some("auto".to_string()),
                    service_tier: None,
                    temperature: 0.0,
                    max_tokens: 0,
                    sse_on: true,
                    timeout_secs: 30,
                    models: Vec::new(),
                };
                let body = build_codex_tool_request_body(
                    &provider,
                    vec![json!({
                        "role": "user",
                        "content": [{
                            "type": "input_text",
                            "text": "hi",
                        }]
                    })],
                    Some("keep focus"),
                );

                assert_eq!(body["tool_choice"], json!("auto"));
                assert_eq!(body["parallel_tool_calls"], json!(true));
                assert_eq!(body["instructions"], json!("keep focus"));
                assert!(body.get("previous_response_id").is_none());
                let tools = body["tools"].as_array().expect("tools array");
                assert_eq!(tools[0]["type"], json!("web_search"));
                assert_eq!(tools[0]["external_web_access"], json!(true));
                assert!(
                    tools
                        .iter()
                        .any(|tool| tool["name"] == json!("tool_manage"))
                );
                assert!(
                    tools
                        .iter()
                        .any(|tool| tool["name"] == json!("memory_check"))
                );
                assert!(tools.iter().any(|tool| tool["name"] == json!("focus_mode")));
                assert!(
                    !tools
                        .iter()
                        .any(|tool| tool["name"] == json!("context_manage"))
                );
                assert!(tools.iter().any(|tool| tool["name"] == json!("draw_image")));
                assert!(!tools.iter().any(|tool| tool["name"] == json!("command")));
                assert!(
                    !tools
                        .iter()
                        .any(|tool| tool["name"] == json!("apply_patch"))
                );
                mcp::set_tool_persona(previous);
                crate::context::set_persona(previous);
            });
        }

        #[test]
        fn codex_tool_request_body_exposes_native_web_search_for_focus_personas() {
            let previous = mcp::current_tool_persona();
            for persona in [crate::PersonaKind::Coding, crate::PersonaKind::Server] {
                mcp::set_tool_persona(persona);
                let provider = ProviderConfig {
                    body: ApiBodyKind::Official,
                    official_kind: Some(OfficialProviderKind::Codex),
                    name: "CODEX".to_string(),
                    base_url: "https://example.com/v1".to_string(),
                    api_key: "sk-test".to_string(),
                    api_keys: Vec::new(),
                    current_api_key: 0,
                    model: "gpt-5.5".to_string(),
                    reasoning_effort: Some("high".to_string()),
                    reasoning_summary: Some("auto".to_string()),
                    service_tier: None,
                    temperature: 0.0,
                    max_tokens: 0,
                    sse_on: true,
                    timeout_secs: 30,
                    models: Vec::new(),
                };
                let body = build_codex_tool_request_body(
                    &provider,
                    vec![json!({
                        "role": "user",
                        "content": [{
                            "type": "input_text",
                            "text": "hi",
                        }]
                    })],
                    Some("focus"),
                );
                let tools = body["tools"].as_array().expect("tools array");
                assert_eq!(tools[0]["type"], json!("web_search"));
                assert_eq!(tools[0]["external_web_access"], json!(true));
                assert!(
                    tools
                        .iter()
                        .any(|tool| tool["name"] == json!("tool_manage")),
                    "focus personas should be able to self-open closed toolbox tools"
                );
                if persona == crate::PersonaKind::Coding {
                    let tool_manage = tools
                        .iter()
                        .find(|tool| tool["name"] == json!("tool_manage"))
                        .expect("tool_manage schema");
                    assert_eq!(
                        tool_manage["parameters"]["properties"]["action"]["enum"],
                        json!(["list", "reload", "open", "close", "pin", "unpin"])
                    );
                    assert!(
                        tool_manage["parameters"]["properties"]
                            .get("persona")
                            .is_none()
                    );
                }
            }
            mcp::set_tool_persona(previous);
        }

