        #[test]
        fn codex_request_body_moves_all_system_messages_into_instructions() {
            let provider = ProviderConfig {
                body: ApiBodyKind::Official,
                official_kind: Some(OfficialProviderKind::Codex),
                name: "CODEX".to_string(),
                base_url: "https://example.com/v1".to_string(),
                api_key: "sk-test".to_string(),
                api_keys: Vec::new(),
                current_api_key: 0,
                model: "gpt-5.5".to_string(),
                reasoning_effort: Some("high".to_string()),
                reasoning_summary: Some("concise".to_string()),
                service_tier: None,
                temperature: 0.0,
                max_tokens: 0,
                sse_on: true,
                timeout_secs: 30,
                models: Vec::new(),
            };
            let variants = build_request_variants(
                &provider,
                &[
                    ApiMessage::user("你好"),
                    ApiMessage::system(
                        "[system prompt area start]\nkeep focus\n[system prompt area end]",
                    ),
                    ApiMessage::with_codex_item(
                        "system",
                        "[sys:runtime_notice]\n只做系统提示",
                        Some(
                            json!({
                                "type": "message",
                                "role": "system",
                                "content": [{
                                    "type": "input_text",
                                    "text": "[sys:runtime_notice]\n只做系统提示",
                                }],
                            })
                            .to_string(),
                        ),
                    ),
                    ApiMessage::assistant("收到"),
                ],
                true,
            );

            assert_eq!(variants.len(), 1);
            let body = &variants[0].body;
            assert_eq!(
                body["instructions"],
                json!(
                    "[system prompt area start]\nkeep focus\n[system prompt area end]\n\n[sys:runtime_notice]\n只做系统提示"
                )
            );
            let input = body["input"].as_array().expect("input array");
            assert_eq!(input.len(), 2);
            assert_eq!(input[0]["role"], json!("user"));
            assert_eq!(input[1]["role"], json!("assistant"));
        }

