        #[test]
        fn sse_client_timeout_applies_to_idle_body_reads() {
            use std::io::{Read, Write};
            use std::net::TcpListener;

            let listener = TcpListener::bind("127.0.0.1:0").expect("bind local sse test server");
            let addr = listener.local_addr().expect("local addr");
            let server = std::thread::spawn(move || {
                let (mut stream, _) = listener.accept().expect("accept test client");
                let mut request_buf = [0u8; 1024];
                let _ = stream.read(&mut request_buf);
                stream
                    .write_all(
                        b"HTTP/1.1 200 OK\r\nContent-Type: text/event-stream\r\nTransfer-Encoding: chunked\r\n\r\n",
                    )
                    .expect("write headers");
                stream.flush().expect("flush headers");
                std::thread::sleep(Duration::from_secs(3));
            });

            let provider = ProviderConfig {
                body: ApiBodyKind::Official,
                official_kind: Some(OfficialProviderKind::Codex),
                name: "CODEX".to_string(),
                base_url: format!("http://{addr}/v1"),
                api_key: "sk-test".to_string(),
                api_keys: Vec::new(),
                current_api_key: 0,
                model: "gpt-5.5".to_string(),
                reasoning_effort: Some("high".to_string()),
                reasoning_summary: Some("auto".to_string()),
                service_tier: None,
                temperature: 0.0,
                max_tokens: 0,
                sse_on: true,
                timeout_secs: 1,
                models: Vec::new(),
            };
            let client = provider_client(&provider, true).expect("stream client");
            let mut resp = client
                .get(format!("http://{addr}/v1/responses"))
                .send()
                .expect("headers should arrive");
            let started = Instant::now();
            let mut body_buf = [0u8; 1];
            let err = resp
                .read(&mut body_buf)
                .expect_err("idle SSE body read should time out");

            assert!(
                started.elapsed() < Duration::from_secs(3),
                "read waited for server close instead of idle timeout"
            );
            assert!(
                err.to_string().to_ascii_lowercase().contains("timed out")
                    || err
                        .to_string()
                        .to_ascii_lowercase()
                        .contains("decoding response body"),
                "{err}"
            );
            server.join().expect("server thread");
        }

        #[test]
        fn sse_reader_treats_heartbeat_as_stream_activity() {
            let mut reader = std::io::Cursor::new(b": ping\n\n".to_vec());
            let mut last_stream_activity_at = Instant::now() - Duration::from_secs(2);
            let stream_idle_timeout = Duration::from_secs(1);
            let mut should_cancel = || false;

            let event = read_sse_data_event(
                &mut reader,
                &mut last_stream_activity_at,
                stream_idle_timeout,
                &mut should_cancel,
            )
            .expect("heartbeat-only stream should not time out while bytes arrive");

            assert!(event.is_none());
        }

