    // =============================================================================
    // 渲染工坊
    // - `SettingsRenderCtx` / `SettingsRenderTheme` / 行样式辅助函数只负责排版与命中区生成；
    // - 不在这里修改业务状态，保持“渲染纯函数化”。
    // =============================================================================
    #[derive(Debug)]
    struct SettingsRenderCtx {
        area: Rect,
        width: usize,
        height: usize,
        theme: SettingsRenderTheme,
        row: u16,
        lines: Vec<Line<'static>>,
        hits: Vec<SettingsHit>,
    }

    impl SettingsRenderCtx {
        fn new(area: Rect, theme: SettingsRenderTheme) -> Self {
            Self {
                area,
                width: area.width.max(1) as usize,
                height: area.height.max(1) as usize,
                theme,
                row: 0,
                lines: Vec::new(),
                hits: Vec::new(),
            }
        }

        fn push_line(&mut self, line: Line<'static>) {
            self.lines.push(line);
            self.row = self.row.saturating_add(1);
        }

        fn push_blank_line(&mut self) {
            self.push_line(Line::from(""));
        }

        fn finish(self) -> SettingsRender {
            SettingsRender {
                text: Text::from(self.lines),
                hits: self.hits,
            }
        }
    }

