    fn runtime_context_config_from_settings(
        context: &ContextSettings,
    ) -> crate::context::RuntimeThresholdConfig {
        let soft_size_kb = crate::context::sanitize_context_limit_kb(context.context_max_size_kb)
            .min(default_context_hard_size_kb());
        let hard_size_kb = default_context_hard_size_kb().max(soft_size_kb);
        crate::context::RuntimeThresholdConfig {
            context_threshold_enabled: true,
            soft_context_limit_kb: soft_size_kb,
            hard_context_limit_kb: hard_size_kb,
            soft_context_entry_limit: crate::context::OPEN_CONTEXT_ENTRY_LIMIT,
            hard_context_entry_limit: crate::context::OPEN_CONTEXT_ENTRY_LIMIT,
            focus_threshold_enabled: true,
            soft_focus_limit_kb: soft_size_kb,
            hard_focus_limit_kb: hard_size_kb,
            soft_focus_entry_limit: crate::context::OPEN_CONTEXT_ENTRY_LIMIT,
            hard_focus_entry_limit: crate::context::OPEN_CONTEXT_ENTRY_LIMIT,
            fastmemory_threshold_enabled: true,
            fastmemory_item_limit: crate::context::sanitize_section_item_limit(
                context.fastmemory_item_limit,
            ),
        }
    }

    pub(crate) fn apply_runtime_settings_side_effects(
        system: &SystemSettings,
        context: &ContextSettings,
    ) -> Result<()> {
        let system = sanitize_system_settings(system.clone());
        let context = sanitize_context_settings(context.clone());
        crate::mcp::set_agent_retention_limit(system.agent_retention_limit);
        crate::mcp::set_permission_mode(system.permission_mode);
        crate::context::sync_runtime_threshold_config(&runtime_context_config_from_settings(
            &context,
        ))?;
        Ok(())
    }

    pub(crate) fn apply_persona_settings_patch(
        persona: crate::PersonaKind,
        patch: PersonaSettingsPatch,
    ) -> Result<Vec<String>> {
        let mut lines = Vec::new();
        let mut tool_output_changed = false;
        let mut api_cfg = None;
        let mut system = None;
        let mut context = None;
        let mut theme = None;

        let (mut api, mut system_cfg, mut context_cfg, mut theme_cfg) =
            load_settings_bundle_for_persona(persona);

        if patch.provider_body.is_some()
            || patch.provider_index.is_some()
            || patch.provider_model.is_some()
        {
            let selected_index = if let Some(index) = patch.provider_index {
                if index >= api.providers.len() {
                    anyhow::bail!("provider_index 超出范围");
                }
                index
            } else {
                match patch.provider_body.unwrap_or(api.api_body) {
                    ApiBodyKind::Official => api.current_official_provider,
                    ApiBodyKind::ThirdParty => api.current_third_party_provider,
                }
            };
            let provider = api
                .providers
                .get_mut(selected_index)
                .ok_or_else(|| anyhow::anyhow!("provider_index 超出范围"))?;
            if let Some(body) = patch.provider_body {
                if provider.body != body {
                    let body_label = match body {
                        ApiBodyKind::Official => "official",
                        ApiBodyKind::ThirdParty => "third_party",
                    };
                    anyhow::bail!(
                        "provider_body 与 provider_index 指向的提供方不一致：{}",
                        body_label
                    );
                }
            }
            api.api_body = provider.body;
            match provider.body {
                ApiBodyKind::Official => api.current_official_provider = selected_index,
                ApiBodyKind::ThirdParty => api.current_third_party_provider = selected_index,
            }
            if let Some(model) = patch
                .provider_model
                .as_deref()
                .map(str::trim)
                .filter(|value| !value.is_empty())
            {
                provider.model = model.to_string();
            }
            lines.push(format!(
                "provider:selected -> body={} index={} name={} model={}",
                match provider.body {
                    ApiBodyKind::Official => "official",
                    ApiBodyKind::ThirdParty => "third_party",
                },
                selected_index,
                provider.name.as_str(),
                provider.model.as_str()
            ));
            api_cfg = Some(api);
        }

        if patch.default_tool_output_level.is_some()
            || patch.tool_output_small_kb.is_some()
            || patch.tool_output_normal_kb.is_some()
            || patch.tool_output_large_kb.is_some()
            || patch.name_en.is_some()
            || patch.name_zh.is_some()
            || patch.agent_retention_limit.is_some()
            || patch.permission_mode.is_some()
            || patch.terminal_audit_interval_secs.is_some()
            || patch.image_compression_quality.is_some()
            || patch.image_upload_max_mb.is_some()
            || patch.theme_preset.is_some()
        {
            if persona != crate::PersonaKind::Matrix {
                anyhow::bail!("系统体验参数与工具预算只允许 Matrix 统一管理");
            }
            if let Some(level) = patch.default_tool_output_level {
                context_cfg.default_tool_output_level = level;
                lines.push(format!("tool_output:default -> {}", level.user_label()));
            }
            if let Some(value) = patch.tool_output_small_kb {
                context_cfg.tool_output_small_kb = Some(value);
                lines.push(format!(
                    "tool_output:small -> {} KB",
                    crate::mcp::sanitize_tool_output_kb(value)
                ));
            }
            if let Some(value) = patch.tool_output_normal_kb {
                context_cfg.tool_output_normal_kb = Some(value);
                lines.push(format!(
                    "tool_output:normal -> {} KB",
                    crate::mcp::sanitize_tool_output_kb(value)
                ));
            }
            if let Some(value) = patch.tool_output_large_kb {
                context_cfg.tool_output_large_kb = Some(value);
                lines.push(format!(
                    "tool_output:large -> {} KB",
                    crate::mcp::sanitize_tool_output_kb(value)
                ));
            }
            if let Some(name) = patch.name_en {
                system_cfg.name_en = name;
                lines.push(format!("system:name_en -> {}", system_cfg.name_en));
            }
            if let Some(name) = patch.name_zh {
                system_cfg.name_zh = name;
                lines.push(format!("system:name_zh -> {}", system_cfg.name_zh));
            }
            if let Some(limit) = patch.agent_retention_limit {
                system_cfg.agent_retention_limit = limit;
                lines.push(format!(
                    "system:agent_retention_limit -> {}",
                    crate::mcp::sanitize_agent_retention_limit(limit)
                ));
            }
            if let Some(mode) = patch.permission_mode {
                system_cfg.permission_mode = mode;
                lines.push(format!("system:permission_mode -> {}", mode.label()));
            }
            if let Some(interval) = patch.terminal_audit_interval_secs {
                context_cfg.terminal_audit_interval_secs =
                    crate::mcp::sanitize_terminal_audit_interval_secs(interval);
                lines.push(format!(
                    "system:terminal_audit_interval_secs -> {}",
                    context_cfg.terminal_audit_interval_secs
                ));
            }
            if let Some(quality) = patch.image_compression_quality {
                context_cfg.image_compression_quality = quality;
                lines.push(format!(
                    "system:image_compression_quality -> {}",
                    quality.label()
                ));
            }
            if let Some(upload) = patch.image_upload_max_mb {
                context_cfg.image_upload_max_mb = upload;
                lines.push(format!(
                    "system:image_upload_max_mb -> {} MB",
                    crate::mcp::sanitize_view_image_upload_max_mb(upload)
                ));
            }
            if let Some(theme_preset) = patch.theme_preset {
                theme_cfg.preset = theme_preset;
                lines.push(format!("theme -> {}", theme_preset.label()));
            }
            context = Some(context_cfg);
            system = Some(system_cfg);
            theme = Some(theme_cfg);
            tool_output_changed = true;
        }

        let api = api_cfg.unwrap_or_else(|| {
            let (api_cfg, _, _, _) = load_settings_bundle_for_persona(persona);
            api_cfg
        });
        let system = system.unwrap_or_else(|| {
            let (_, system_cfg, _, _) = load_settings_bundle_for_persona(persona);
            system_cfg
        });
        let context = context.unwrap_or_else(|| {
            let (_, _, context_cfg, _) = load_settings_bundle_for_persona(persona);
            context_cfg
        });
        let theme = theme.unwrap_or_else(|| {
            let (_, _, _, theme_cfg) = load_settings_bundle_for_persona(persona);
            theme_cfg
        });

        let api = api.sanitize();
        save_settings_bundle_for_persona(persona, &api, &system, &context, &theme)?;
        if persona == crate::PersonaKind::Matrix && tool_output_changed {
            apply_runtime_settings_side_effects(&system, &context)?;
        }
        if lines.is_empty() {
            lines.push("no_changes".to_string());
        }
        Ok(lines)
    }

