    impl ContextSettings {
        pub fn default_tool_output_level(&self) -> crate::mcp::CommandOutputLevel {
            match self.default_tool_output_level {
                crate::mcp::CommandOutputLevel::Low => crate::mcp::CommandOutputLevel::Low,
                crate::mcp::CommandOutputLevel::Medium => crate::mcp::CommandOutputLevel::Medium,
                crate::mcp::CommandOutputLevel::High => crate::mcp::CommandOutputLevel::High,
            }
        }

        pub fn tool_output_settings(&self) -> crate::mcp::ToolOutputSettings {
            let low_kb = self.tool_output_small_kb.unwrap_or_else(|| {
                legacy_tool_output_kb(
                    self.legacy_tool_output_small_lines,
                    self.legacy_tool_output_small_chars,
                    default_tool_output_small_kb(),
                )
            });
            let medium_kb = self.tool_output_normal_kb.unwrap_or_else(|| {
                legacy_tool_output_kb(
                    self.legacy_tool_output_normal_lines,
                    self.legacy_tool_output_normal_chars,
                    default_tool_output_normal_kb(),
                )
            });
            let high_kb = self.tool_output_large_kb.unwrap_or_else(|| {
                legacy_tool_output_kb(
                    self.legacy_tool_output_large_lines,
                    self.legacy_tool_output_large_chars,
                    default_tool_output_large_kb(),
                )
            });
            crate::mcp::ToolOutputSettings {
                low_kb: crate::mcp::sanitize_tool_output_kb(low_kb),
                medium_kb: crate::mcp::sanitize_tool_output_kb(medium_kb),
                high_kb: crate::mcp::sanitize_tool_output_kb(high_kb),
            }
        }

        pub fn view_image_settings(&self) -> crate::mcp::ViewImageSettings {
            crate::mcp::ViewImageSettings {
                quality: self.image_compression_quality,
                upload_max_mb: crate::mcp::sanitize_view_image_upload_max_mb(
                    self.image_upload_max_mb,
                ),
            }
        }

        pub fn terminal_audit_interval_secs(&self) -> u64 {
            crate::mcp::sanitize_terminal_audit_interval_secs(self.terminal_audit_interval_secs)
        }
    }

    fn legacy_tool_output_kb(lines: usize, chars: usize, fallback_kb: usize) -> usize {
        if chars > 0 {
            return crate::mcp::sanitize_tool_output_kb(chars.saturating_add(1023) / 1024);
        }
        if lines > 0 {
            let chars = lines.saturating_mul(300);
            return crate::mcp::sanitize_tool_output_kb(chars.saturating_add(1023) / 1024);
        }
        fallback_kb
    }

