    fn fetch_models_blocking(provider: &ProviderConfig) -> Result<Vec<String>> {
        fn extract_model_ids(value: &serde_json::Value, out: &mut Vec<String>) {
            match value {
                serde_json::Value::Object(map) => {
                    if let Some(serde_json::Value::Array(arr)) = map.get("data") {
                        for item in arr {
                            if let Some(text) = item.as_str() {
                                out.push(text.to_string());
                            } else if let Some(id) = item.get("id").and_then(|value| value.as_str())
                            {
                                out.push(id.to_string());
                            }
                        }
                    }
                    for key in [
                        "models",
                        "model_list",
                        "available_models",
                        "availableModels",
                    ] {
                        if let Some(serde_json::Value::Array(arr)) = map.get(key) {
                            for item in arr {
                                if let Some(text) = item.as_str() {
                                    out.push(text.to_string());
                                } else if let Some(id) =
                                    item.get("id").and_then(|value| value.as_str())
                                {
                                    out.push(id.to_string());
                                }
                            }
                        }
                    }
                }
                serde_json::Value::Array(arr) => {
                    for item in arr {
                        if let Some(text) = item.as_str() {
                            out.push(text.to_string());
                        } else if let Some(id) = item.get("id").and_then(|value| value.as_str()) {
                            out.push(id.to_string());
                        }
                    }
                }
                _ => {}
            }
        }

        let client = Client::builder()
            .timeout(Duration::from_secs(provider.timeout_secs.max(1)))
            .build()?;

        let mut last_err: Option<String> = None;
        for url in apiurl::models_url_candidates(&provider.base_url) {
            let resp = match provider::get_with_bearer_retries(
                &client,
                &url,
                provider.effective_api_key(),
                Some("application/json"),
            ) {
                Ok(resp) => resp,
                Err(err) => {
                    last_err = Some(err);
                    continue;
                }
            };
            let text = resp.text().unwrap_or_default();
            let value: serde_json::Value = serde_json::from_str(&text)
                .with_context(|| format!("模型列表解析失败：{}", truncate_body(&text)))?;
            let mut ids = Vec::new();
            extract_model_ids(&value, &mut ids);
            ids.sort();
            ids.dedup();
            if !ids.is_empty() {
                return Ok(ids);
            }
        }
        Err(anyhow!(
            last_err.unwrap_or_else(|| "未获取到模型列表".to_string())
        ))
    }

    fn run_api_test(provider: &ProviderConfig) -> Result<ApiTestResult> {
        let sse = test_provider(provider, true)?;
        let sse_off = test_provider(provider, false)?;
        Ok(ApiTestResult { sse, sse_off })
    }

    fn test_provider(provider: &ProviderConfig, stream: bool) -> Result<TestOutcome> {
        let start = Instant::now();
        let timeout_secs = if stream {
            provider.timeout_secs.max(1)
        } else {
            provider.timeout_secs.max(API_TEST_TIMEOUT_MIN_SECS)
        };
        let client = if stream {
            Client::builder()
                .connect_timeout(Duration::from_secs(timeout_secs))
                .build()?
        } else {
            Client::builder()
                .timeout(Duration::from_secs(timeout_secs))
                .build()?
        };

        let resp = match official_provider_kind(provider) {
            Some(OfficialProviderKind::Codex) => {
                let mut body = serde_json::json!({
                    "model": provider.model,
                    "input": [{
                        "role": "user",
                        "content": [{"type": "input_text", "text": "ping"}]
                    }],
                    "stream": stream,
                });
                provider::apply_codex_reasoning_config(&mut body, provider);
                let mut last_err = None;
                let accept = if stream {
                    "text/event-stream"
                } else {
                    "application/json"
                };
                let mut response = None;
                for url in apiurl::codex_responses_url_candidates(provider.base_url.as_str()) {
                    match provider::post_json_with_auth_retries(
                        &client,
                        url.as_str(),
                        &body,
                        provider.effective_api_key(),
                        provider::AuthVariant::Bearer,
                        Some(accept),
                        "bearer",
                    ) {
                        Ok(resp) => {
                            response = Some(resp);
                            break;
                        }
                        Err(err) => {
                            last_err = Some(anyhow!("{err}"));
                            continue;
                        }
                    }
                }
                response.ok_or_else(|| {
                    last_err.unwrap_or_else(|| anyhow!("provider test request failed"))
                })?
            }
            _ => {
                let body = serde_json::json!({
                    "model": provider.model,
                    "messages": [{ "role": "user", "content": "ping" }],
                    "stream": stream,
                    "temperature": 0.0,
                    "max_tokens": 16,
                });
                let mut last_err = None;
                let accept = if stream {
                    "text/event-stream"
                } else {
                    "application/json"
                };
                let mut response = None;
                for url in apiurl::chat_completions_url_candidates(provider.base_url.as_str()) {
                    match provider::post_json_with_auth_retries(
                        &client,
                        url.as_str(),
                        &body,
                        provider.effective_api_key(),
                        provider::AuthVariant::Bearer,
                        Some(accept),
                        "bearer",
                    ) {
                        Ok(resp) => {
                            response = Some(resp);
                            break;
                        }
                        Err(err) => {
                            last_err = Some(anyhow!("{err}"));
                            continue;
                        }
                    }
                }
                response.ok_or_else(|| {
                    last_err.unwrap_or_else(|| anyhow!("provider test request failed"))
                })?
            }
        };

        let elapsed_ms = start.elapsed().as_millis();
        let status = resp.status();
        if !status.is_success() {
            let note = format!("HTTP {status} | {}", err_body_snippet(resp));
            return Ok(TestOutcome {
                ok: false,
                elapsed_ms,
                note,
            });
        }

        let body = resp.text().unwrap_or_default();
        let note = if stream {
            if body.trim().is_empty() {
                "empty SSE body".to_string()
            } else if body.contains("data:") {
                "SSE stream ready".to_string()
            } else {
                truncate_body(&body)
            }
        } else if body.trim().is_empty() {
            "empty response".to_string()
        } else {
            "request succeeded".to_string()
        };
        Ok(TestOutcome {
            ok: true,
            elapsed_ms,
            note,
        })
    }

    fn err_body_snippet(resp: reqwest::blocking::Response) -> String {
        let text = resp.text().unwrap_or_default();
        truncate_body(&text)
    }

    fn mask_api_key(key: &str) -> String {
        let trimmed = key.trim();
        if trimmed.is_empty() {
            return "empty".to_string();
        }
        let chars = trimmed.chars().collect::<Vec<_>>();
        if chars.len() <= 12 {
            return trimmed.to_string();
        }
        let head = chars.iter().take(6).collect::<String>();
        let tail = chars.iter().rev().take(4).rev().collect::<String>();
        format!("{head}…{tail}")
    }

    fn truncate_body(text: &str) -> String {
        let trimmed = text.trim();
        if trimmed.is_empty() {
            "(empty body)".to_string()
        } else if trimmed.len() > 180 {
            format!("{}...", &trimmed[..180])
        } else {
            trimmed.to_string()
        }
    }

    fn interval_secs_value_label(value_secs: u64) -> String {
        if value_secs.is_multiple_of(60) {
            format!("{} min", value_secs / 60)
        } else {
            format!("{value_secs} s")
        }
    }

