    fn step_preset_index<T: Copy + Ord>(value: T, presets: &[T], dir: i32) -> T {
        let index = presets
            .iter()
            .position(|candidate| *candidate == value)
            .unwrap_or_else(|| {
                presets
                    .iter()
                    .position(|candidate| *candidate >= value)
                    .unwrap_or_else(|| presets.len().saturating_sub(1))
            });
        let next = if dir < 0 {
            index.saturating_sub(1)
        } else {
            (index + 1).min(presets.len().saturating_sub(1))
        };
        presets[next]
    }

