        #[test]
        fn settings_api_visible_fields_allow_official_provider_management() {
            with_test_home(|_root| {
                let (task_tx, _task_rx) = std::sync::mpsc::channel();
                let mut state = SettingsState::new(task_tx);
                let fields = state.visible_fields();
                assert!(!fields.contains(&SettingsField::NewProvider));
                assert!(!fields.contains(&SettingsField::DeleteProvider));
                assert!(!fields.contains(&SettingsField::RenameProvider));

                state.api_interface_list_selected = ApiInterfaceKind::all()
                    .iter()
                    .position(|item| *item == ApiInterfaceKind::RelayCodex)
                    .unwrap();
                state.apply_api_interface_selection();
                let fields = state.visible_fields();
                assert!(fields.contains(&SettingsField::NewProvider));
                assert!(fields.contains(&SettingsField::DeleteProvider));
                assert!(fields.contains(&SettingsField::RenameProvider));
                assert!(fields.contains(&SettingsField::BaseUrl));
                assert!(!fields.contains(&SettingsField::Temperature));
                assert!(!fields.contains(&SettingsField::MaxTokens));
            });
        }

        #[test]
        fn settings_api_interface_overlay_responds_to_arrow_keys() {
            with_test_home(|_root| {
                let (task_tx, _task_rx) = std::sync::mpsc::channel();
                let mut state = SettingsState::new(task_tx);
                state.activate_selected();
                assert!(state.api_interface_list_open);
                assert_eq!(state.api_interface_list_selected, 0);
                state.move_next(10);
                assert_eq!(state.api_interface_list_selected, 1);
                state.move_prev(10);
                assert_eq!(state.api_interface_list_selected, 0);
            });
        }

