        #[test]
        fn load_or_default_backs_up_invalid_local_config() {
            with_test_home(|root| {
                let legacy_config_dir = root.join("AItermux/projectying/config/Matrix");
                fs::create_dir_all(&legacy_config_dir).expect("create legacy Matrix config dir");
                let config_dir = root.join("AItermux/projectying/config/matrix");
                let config_path = legacy_config_dir.join("api.json");
                fs::write(&config_path, "{ invalid json").expect("write invalid config");

                let (cfg, system, context, theme) = load_settings_bundle();

                assert_eq!(cfg.current_official_provider, 0);
                assert_eq!(cfg.providers[0].name, "CODEX");
                assert_eq!(system.name_en, default_user_name_en());
                assert_eq!(
                    context.context_summary_entry_limit,
                    default_context_summary_entry_limit()
                );
                assert_eq!(theme.preset, default_theme_preset());
                let backups = fs::read_dir(&config_dir)
                    .expect("read config dir")
                    .filter_map(|entry| entry.ok())
                    .map(|entry| entry.file_name().to_string_lossy().to_string())
                    .filter(|name| name.starts_with("api.invalid-") && name.ends_with(".json"))
                    .collect::<Vec<_>>();
                assert!(
                    !backups.is_empty(),
                    "invalid config should be preserved in config/matrix"
                );
            });
        }

